export const SPECIES_ENTRIES = {"Mesopotamian Aesthetic":{"summary":"The earliest codified fashion system, rooted in Sumerian and Babylonian court dress of ancient Iraq.","era":"c.3000–500 BCE, Mesopotamia","mood":"Monumental, priestly, civilisation-founding","visual":"Draped woollen garments in layered fringe tiers (kaunakes). Heavy lapis lazuli and gold jewellery. Tall conical headdresses for royalty. Both men and women wear wrapped tunics; fabric quality and jewellery weight denote rank.","garments":["Tiered fringe kaunakes robe","Cylinder seal pendant","Lapis lazuli collar","Wrapped wool tunic","Conical ceremonial headdress"],"habitat":"Museums, ancient history exhibitions, academic costume reconstruction, fantasy cosplay drawing on Babylonian imagery.","context":"Mesopotamia produced the first recorded fashion system. Sumerian court dress established hierarchy through textile quality and jewellery weight. The tiered fringe robe was the defining silhouette for over two millennia.","rarity":"Extinct","see_also":["Egyptian Priestess","Ottoman Court Dress","Byzantine Empress"],"colors":["#C4956A Terracotta","#1A3A5C Lapis Blue","#D4AF37 Gold","#F5E6C8 Linen"],"media":["The Epic of Gilgamesh (c.2100 BCE) — literature","The Fall of Babylon (1919) — film","Ur: The First City (2003) — documentary"]},"Ancient Indus Aesthetic":{"summary":"Dress of the Harappan civilisation — draped cotton and carved stone jewellery from the world's first planned cities.","era":"c.2600–1900 BCE, Indus Valley","mood":"Austere, refined, quietly civilised","visual":"Draped cotton garments in natural undyed cream and terracotta tones. Elaborate beaded necklaces of carnelian and steatite. Women wear bangles stacked from wrist to shoulder. Minimal ornamentation with high material quality.","garments":["Draped cotton wrap","Carnelian bead necklace","Steatite bangles","Terra cotta figurine headdress","Simple leather sandals"],"habitat":"Archaeological exhibitions, South Asian art history, contemporary South Asian designers drawing on Harappan motifs.","context":"The Indus Valley Civilisation produced sophisticated cotton textiles and standardised jewellery forms without the monumental excess of Egypt or Mesopotamia. Their aesthetic was functional and refined — ahead of its time.","rarity":"Extinct","see_also":["Indian Festive Wear","Saree Aesthetic","Mughal Court Aesthetic"],"colors":["#F5E6C8 Cream Cotton","#C1440E Terracotta","#5B7B4E Verdigris","#8B7355 Steatite"],"media":["Cities of the Indus Valley (2002) — documentary","The Harappan Enigma (2014) — documentary"]},"Egyptian Priestess":{"summary":"Sacred feminine dress of ancient Egypt — white linen sheath dresses, kohl-rimmed eyes, and gold divine jewellery.","era":"c.3000–30 BCE, Ancient Egypt","mood":"Sacred, regal, eternally composed","visual":"Fine white pleated linen sheaths, often semi-transparent. Wide gold collar (usekh) with turquoise and carnelian inlay. Black kohl extending to temples. Wigs with straight-cut fringes or elaborate braiding. Leather or papyrus sandals.","garments":["White pleated linen sheath","Gold usekh collar","Black extended kohl","Braided ceremonial wig","Leather sandals"],"habitat":"Museums, Cleopatra-themed events, opera productions, editorial fashion drawing on Egyptomania.","context":"Egyptian priestly dress was codified for millennia. White linen signified purity; gold represented divine light. The wide collar distributed jewellery weight across the chest. This aesthetic has been continuously revived since Napoleon's Egyptian campaign of 1798.","rarity":"Extinct","see_also":["Pharaonic Aesthetic","Byzantine Empress","Art Deco Egyptian"],"colors":["#FAF8F5 White Linen","#D4AF37 Gold","#1B4F72 Kohl Blue","#C1440E Carnelian"],"media":["The Mummy (1932) — film","Cleopatra (1963) — film","The Egyptian (1954) — film","Egyptian Book of the Dead — literature"]},"Pharaonic Aesthetic":{"summary":"The imperial dress of ancient Egyptian kings — the nemes headdress, crook and flail, and the visual grammar of divine monarchy.","era":"c.3100–30 BCE, Ancient Egypt","mood":"Absolute power, divine authority, eternal","visual":"The gold-striped linen nemes headdress. Shendyt kilt with decorative apron. False braided beard in blue. Broad usekh collar. Sandals with bound enemies depicted underfoot. Each element carries specific political meaning.","garments":["Nemes headdress","Shendyt kilt","Gold usekh collar","False beard of kingship","Crook and flail sceptres"],"habitat":"Egyptomania fashion editorials, Halloween, Met Gala references, opera, museum galas, theatrical costume.","context":"Pharaonic dress codified royal divinity over three millennia. Revived obsessively in Western fashion after the 1922 Tutankhamun discovery. The crook (shepherd king) and flail (fertility) made ideology into accessories.","rarity":"Extinct","see_also":["Egyptian Priestess","Art Deco Egyptian","Hollywood Egyptian"],"colors":["#D4AF37 Gold","#C1440E Carnelian","#1B4F72 Royal Blue","#FAF8F5 Linen White"],"media":["The Ten Commandments (1956) — film","Tutankhamun (2016) — TV series","Death on the Nile (2022) — film"]},"Minoan Aesthetic":{"summary":"The startlingly modern dress of ancient Crete — bare-breasted open bodices, tiered flounced skirts, and snake goddess iconography.","era":"c.2700–1450 BCE, Crete","mood":"Sensual, sophisticated, surprisingly modern","visual":"Women wear open-fronted bodices exposing the breast with a structured fitted waist. Tiered flounced skirts in vivid patterns. Men in loin-cloths. Intricate gold jewellery. Hair elaborately dressed with curls and ribbons — this aesthetic shocked early 20th-century archaeologists.","garments":["Open-fronted bodice","Tiered flounced skirt","Gold waist cincher","Snake goddess armband","Ribbon-dressed elaborate hair"],"habitat":"Art history exhibitions, Aegean Bronze Age scholarship, fashion history references for structured bodices.","context":"Minoan Crete produced one of the ancient world's most sophisticated fashion cultures. The bare-breasted female silhouette is unique in ancient dress. The society appears to have been relatively egalitarian by ancient standards.","rarity":"Extinct","see_also":["Grecian Goddess","Ancient Persian Court","Byzantine Empress"],"colors":["#C85A4A Fresco Red","#2E86AB Aegean Blue","#F5D76E Ochre Yellow","#FAF8F5 Plaster White"],"media":["The Bull from the Sea, Mary Renault (1962) — novel","Knossos and the Prophets of Modernism (2008) — book"]},"Zhou Dynasty Aesthetic":{"summary":"The layered ritual dress of ancient China's longest dynasty, establishing the silk and jade foundations of Chinese court fashion.","era":"c.1046–256 BCE, China","mood":"Hierarchical, ceremonial, cosmologically ordered","visual":"Deep-lapelled silk robes with colour denoting rank. Jade pendants hanging from the waist in multiple tiers, creating musical sound while walking. Embroidered hems. Wide sleeves. Women in pleated skirts. Hair in high elaborate arrangements with lacquered pins.","garments":["Deep-lapelled silk robe","Jade pendant set","Wide-sleeved ceremonial coat","Embroidered silk hem","Lacquered hairpin"],"habitat":"Chinese history exhibitions, Hanfu revival communities, court drama productions.","context":"Zhou Dynasty dress codified Chinese court aesthetics for centuries. Jade represented virtue and standing. The colour system (yellow for the emperor, red for officials) established conventions that persisted into the 20th century.","rarity":"Extinct","see_also":["Chinese Han Dynasty Court Dress","Tang Dynasty Aesthetic","Chinese Hanfu"],"colors":["#1C3A1C Jade Green","#8B2500 Lacquer Red","#D4AF37 Bronze Gold","#F5E6C8 Silk Ivory"],"media":["Confucius (2010) — film","The Book of Songs (c.600 BCE) — literature","Hero (2002) — film"]},"Ancient Persian Court":{"summary":"The opulent imperial dress of the Achaemenid Empire — elaborately pleated robes, tiara crowns, and the first luxury textile trade network.","era":"c.550–330 BCE, Persia","mood":"Imperial grandeur, refined luxury, cosmopolitan","visual":"Elaborately pleated robes in wool and linen with fringed hems. Persian kings wore purple and saffron. Enormous wrapped turbans on men — size and wrapping style indicating rank. Gold jewellery. Conical tiaras. The word 'tiara' enters European languages through Persian court dress.","garments":["Pleated wool kandys overcoat","Purple imperial robe","Conical golden tiara","Fringed ceremonial hem","Massive gold cuff bracelet"],"habitat":"Persepolis, Iranian history exhibitions, Achaemenid archaeology, ancient history cosplay.","context":"The Achaemenid Persian court was the first great multicultural fashion empire, drawing textiles and motifs from Egypt, Mesopotamia, Greece, and the East. The word 'tiara' enters European languages through Persian court dress.","rarity":"Extinct","see_also":["Mughal Court Aesthetic","Ottoman Court Dress","Central Asian Nomadic Dress"],"colors":["#6B3A8A Imperial Purple","#D4AF37 Gold","#C1440E Saffron","#2C5530 Forest Green"],"media":["300 (2006) — film","The Persian Boy, Mary Renault (1972) — novel","Persepolis documentary series"]},"Celtic Warrior Aesthetic":{"summary":"The fearsome and flamboyant dress of Iron Age Celtic peoples — gold torcs, proto-tartan wool, and woad-painted battle charging.","era":"c.800–50 BCE, Northern Europe","mood":"Fierce, flamboyant, violently free","visual":"Bright woven woolens in checks and stripes (proto-tartan). Massive gold torcs worn at the neck. Long flowing hair, sometimes limed with chalk for battle. Tattoos in woad blue. Warriors sometimes charged naked. Women wore elaborate brooch-pinned garments.","garments":["Gold torc necklace","Checked wool cloak","Woad-dyed linen tunic","Iron brooch fastening","Limed battle-spiked hair"],"habitat":"Celtic heritage festivals, Iron Age living history reenactment, Highland games, Scottish and Irish national dress.","context":"Celtic dress defied Roman expectations of barbarian simplicity — technically sophisticated, brightly coloured, and heavily jewelled. The Romans were simultaneously horrified and fascinated. Their textile legacy survives in Scottish tartan.","rarity":"Extinct","see_also":["Scottish Highland Dress","Viking Aesthetic","Norse Shieldmaiden"],"colors":["#2E5A1C Woad Green","#8B0000 Madder Red","#D4AF37 Torc Gold","#8B7355 Undyed Wool"],"media":["Braveheart (1995) — film","The Eagle (2011) — film","Asterix series — comics"]},"Iron Age Tribal Dress":{"summary":"The functional and deeply regional dress of pre-Roman European tribal societies, characterised by local wool, bronze, and amber.","era":"c.1200–50 BCE, Northern Europe","mood":"Earthy, practical, deeply local","visual":"Undyed or plant-dyed wool tunics and cloaks. Bronze fibula pins. Amber and bone jewellery. Wrapped leather footwear. Animal fur trim. Hair braided or wrapped. Enormous variation by region — Hallstatt, La Tène, and Germanic traditions each distinct.","garments":["Wool tunic","Bronze fibula pin","Amber bead necklace","Wrapped leather shoes","Woven belt"],"habitat":"Iron Age museums, living history reenactment, Dark Ages cosplay.","context":"Iron Age dress varied enormously by region. All shared dependence on local materials. The traditions fed into the Medieval European textile cultures that followed.","rarity":"Extinct","see_also":["Celtic Warrior Aesthetic","Anglo-Saxon Folk","Dark Ages Aesthetic"],"colors":["#8B7355 Undyed Wool","#5B3A29 Leather Brown","#4A7C59 Plant Dye Green","#B8860B Bronze"],"media":["The Last Kingdom (TV series) — TV","Asterix series — comics"]},"Druid Aesthetic":{"summary":"The sacred white-robed dress of Celtic priestly class — mostly a Romantic 18th-century invention, but now inseparable from the aesthetic.","era":"c.500 BCE–100 CE origin; c.1700s reimagined","mood":"Mystical, ancient, ceremonially austere","visual":"Long white or undyed robes. Mistletoe and oak leaf garlands. Wooden or gold sickle. Long beards and hair. Simple leather belt. The Romantic revival added elaborate regalia not found historically. The historical reality is largely unknown.","garments":["White ceremonial robe","Oak leaf garland","Simple leather belt","Golden sickle","Long natural beard"],"habitat":"Neo-Druid ceremonies (modern practice), Pagan festivals, Stonehenge solstice gatherings, Arthurian cosplay.","context":"Historical Druids left no written records. Most descriptions come from biased Roman writers. The white-robed Druid image is largely an 18th-century Romantic invention, revived by neo-Druid orders and now inseparable from the aesthetic.","rarity":"Rare","see_also":["Celtic Warrior Aesthetic","Pagan Fashion","Forest Witch Aesthetic"],"colors":["#FAF8F5 Undyed White","#2E5A1C Oak Green","#D4AF37 Gold","#8B7355 Bark Brown"],"media":["The Wicker Man (1973) — film","Merlin (TV series) — TV","The Druids, Peter Berresford Ellis (1994) — book"]},"Chiton Aesthetic":{"summary":"The draped rectangular garment of ancient Greece — deceptively simple, architecturally sophisticated, philosophically pure.","era":"c.700–300 BCE, Ancient Greece","mood":"Rational, graceful, philosophically pure","visual":"A rectangle of linen or wool pinned at the shoulders and belted at the waist. The Doric chiton in heavy wool, the Ionic in fine linen with more pleating. White or saffron. Himation cloak wrapped over. Greek sculptors spent centuries mastering its folds.","garments":["Linen chiton rectangle","Shoulder fibula pin","Braided belt","Himation cloak","Greek leather sandals"],"habitat":"Classical studies, Greek heritage events, drama productions, museum living history.","context":"The chiton's apparent simplicity masked sophisticated understanding of drape and proportion. The garment required no cutting — just expert wrapping and pinning. Greek sculptors' obsession with its folds drove art history forward.","rarity":"Extinct","see_also":["Grecian Goddess","Roman Toga Style","Neoclassical Revival Dress"],"colors":["#FAF8F5 White Linen","#E8D5B0 Natural Wool","#C4956A Terracotta Trim","#1B4F72 Tyrian Blue"],"media":["Troy (2004) — film","Helen of Troy (1956) — film","The Odyssey, Homer — literature"]},"Grecian Goddess":{"summary":"The contemporary revival of ancient Greek draped aesthetics — flowing white fabric, goddess sandals, and column silhouettes.","era":"c.500 BCE origin; revived continuously","mood":"Ethereal, divine, effortlessly elevated","visual":"Floor-length draped jersey or chiffon in white, ivory, or gold. One-shoulder or asymmetric necklines. Gathered at waist with braided cord. Strappy flat sandals with ankle lacing. Laurel-inspired headbands. Minimal jewellery. The aesthetic recurs every generation.","garments":["Draped floor-length gown","One-shoulder asymmetric top","Braided waist cord","Strappy gladiator sandals","Laurel leaf headband"],"habitat":"Formal events, summer weddings, Grecian-themed fashion editorials, runway collections inspired by antiquity.","context":"The Grecian goddess silhouette recurs in Western fashion roughly every generation. Madeleine Vionnet codified the bias-cut version in the 1930s. Halston revived it in the 1970s. It resurfaces reliably whenever fashion seeks elemental simplicity.","rarity":"Niche","see_also":["Neoclassical Revival Dress","Roman Toga Style","Ethereal Feminine"],"colors":["#FAF8F5 Pure White","#D4AF37 Gold","#C4956A Warm Ivory","#E8D5B0 Natural Linen"],"media":["Clash of the Titans (1981) — film","Mamma Mia! (2008) — film","Donna Summer's 'Last Dance' (1978) — music video"]},"Olympian Dress":{"summary":"The athletic and ceremonial dress of ancient Greek games — the nude male athlete, the olive wreath, and competition as sacred rite.","era":"c.776–393 BCE, Olympia","mood":"Athletic nobility, sun-bronzed, competitive","visual":"Male athletes competed nude, oiled with olive oil. Winning athletes crowned with olive wreaths. Formal spectators wore the chiton and himation. The revival aesthetic: athletic whites, laurel crowns, and the ancient Greek ideal of the body as worthy of display.","garments":["Olive wreath crown","Linen loincloth for some events","White spectator chiton","Athletic sandals","Olive oil-oiled skin"],"habitat":"Olympic opening ceremonies, classical athletics references, ancient history cosplay.","context":"The nude male athletic ideal was a specifically Greek invention, inseparable from their concept of arete (excellence). It shocked other ancient cultures. The laurel wreath became the universal symbol of victory and persists in every Olympic medal ceremony.","rarity":"Extinct","see_also":["Chiton Aesthetic","Grecian Goddess","Athletic Masculine"],"colors":["#FAF8F5 Marble White","#D4AF37 Olympic Gold","#2E5A1C Olive Green","#C4956A Terracotta"],"media":["Chariots of Fire (1981) — film","The Olympic Games in Ancient Greece (documentary)"]},"Greek Philosopher":{"summary":"The deliberately plain dress of ancient Greek thinkers — the threadbare cloak as philosophical statement, anti-fashion before the word existed.","era":"c.500–300 BCE, Athens","mood":"Intellectually austere, contemptuous of luxury","visual":"Simple undyed wool himation, often worn directly on bare skin to reject luxury. Worn and patched as a mark of seriousness. Sandals or barefoot. Long beard. No jewellery. Socrates, Diogenes, and the Stoics made poverty-dress into philosophy.","garments":["Worn undyed himation","Simple leather sandals","Long natural beard","Walking staff"],"habitat":"Philosophy faculty offices, academic circles, intellectual cosplay, Stoicism revival communities.","context":"Greek philosophers weaponised their clothing. Diogenes of Sinope performed public acts in his cloak to mock social norms. The himation-as-philosophy was the first recorded instance of deliberate anti-fashion as intellectual statement.","rarity":"Extinct","see_also":["Flaneur Aesthetic","Intellectual Masculine","Dark Academia"],"colors":["#8B7355 Undyed Himation","#5B3A29 Worn Leather","#E8D5B0 Natural Wool","#2C2C2C Ash Grey"],"media":["Socrates (1971) — film","Agora (2009) — film","The Symposium, Plato — literature"]},"Cleopatra Aesthetic":{"summary":"The iconic visual language of Egypt's last pharaoh — kohl eyes, gold collar, and the power of a woman performing divinity through dress.","era":"c.51–30 BCE, Alexandria; revival 1963–present","mood":"Seductive, politically formidable, theatrically divine","visual":"Fine white pleated linen. Wide gold usekh collar. Black kohl extending dramatically past the outer eye. Braided black wig. Gold snake armband. Henna-stained palms. The look is both Egyptian and Hellenistic Greek — a political hybrid.","garments":["Pleated white linen gown","Gold usekh collar","Extended dramatic kohl","Braided black wig","Gold serpent armband"],"habitat":"Halloween, themed parties, opera productions, Elizabeth Taylor legacy events, fashion editorials.","context":"Cleopatra VII was actually Greek (Ptolemaic dynasty) but adopted Egyptian pharaonic dress as political strategy, performing her divinity through costume. Elizabeth Taylor's 1963 film performance became the definitive Western visual reference.","rarity":"Niche","see_also":["Egyptian Priestess","Pharaonic Aesthetic","Dark Feminine"],"colors":["#FAF8F5 White Linen","#1A1A1A Kohl Black","#D4AF37 Gold","#1B4F72 Lapis Blue"],"media":["Cleopatra (1963) — film","Cleopatra Jones (1973) — film","Antony and Cleopatra, Shakespeare — theatre"]},"Roman Toga Style":{"summary":"The draped wool toga of Roman citizens — a garment that encoded citizenship, rank, and the entire Roman social hierarchy in a single piece of fabric.","era":"c.500 BCE–500 CE, Roman Empire","mood":"Civic authority, monumental, formally democratic","visual":"A large semicircular piece of undyed wool draped over the left shoulder and under the right arm. White for citizens, purple stripe for senators, all purple for emperors. Underneath: a simple white tunic. Enormously difficult to wear correctly — that was the point.","garments":["Wool toga virilis","White linen tunic","Senator's purple-striped border","Leather calcei shoes","Gold signet ring"],"habitat":"Classical studies events, ancient Rome cosplay, Senate and political satire references, opera.","context":"The toga's complexity was its point — only Roman citizens could wear it. It required practice and a slave to help drape. Later Romans found it increasingly impractical but wore it for formal occasions as an identity statement.","rarity":"Extinct","see_also":["Roman Matron","Chiton Aesthetic","Neoclassical Revival Dress"],"colors":["#FAF8F5 Citizen White","#6B2D8B Senator Purple","#C1440E Imperial Red","#E8D5B0 Natural Wool"],"media":["Gladiator (2000) — film","I, Claudius (1976) — TV","Rome (HBO series) — TV"]},"Roman Matron":{"summary":"The respectable dress of Roman upper-class women — the stola, palla, and the visual performance of matronly virtue.","era":"c.200 BCE–400 CE, Rome","mood":"Virtuous, respectably composed, architecturally layered","visual":"The stola: a long garment with a distinctive band at the hem (instita) marking the wearer as a matron of standing. The palla: a large draped shawl worn over everything. Deep colours and fine wool for wealthy women. The instita marked sexual unavailability and social status.","garments":["Long stola with instita hem","Draped palla shawl","Gold fibula pins","Roman sandals","Pearl ear drops"],"habitat":"Roman living history, classical studies, opera productions, ancient history cosplay.","context":"Roman women's dress was explicitly a moral performance. The instita marked a matron's social status. Prostitutes were forbidden to wear it. Dressing correctly was civic duty. This double standard did not go unnoticed in ancient Rome.","rarity":"Extinct","see_also":["Roman Toga Style","Byzantine Empress","Regency Morning Dress"],"colors":["#8B4513 Madder Red","#2C5530 Malachite Green","#D4AF37 Gold","#FAF8F5 Linen White"],"media":["I, Claudius (1976) — TV","Rome (HBO series) — TV","The Roman Woman documentary"]},"Centurion Aesthetic":{"summary":"The military dress of the Roman professional soldier — lorica segmentata, transverse crested helmet, and the red of the legion.","era":"c.100 BCE–400 CE, Roman legions","mood":"Martial, disciplined, empire-building","visual":"Lorica segmentata plate armour in iron and brass. Transverse horsehair crested helmet identifying centurion rank. Wool tunic. Balteus sword belt. Caligae nail-studded sandals. Red cloak. Vine stick as symbol of authority.","garments":["Lorica segmentata armour","Transverse crested helmet","Military wool tunic","Balteus sword belt","Nail-studded caligae sandals"],"habitat":"Roman living history groups, historical film productions, ancient history cosplay, museum demonstrations.","context":"The centurion was the backbone of the Roman army. His transverse crest distinguished him from regular soldiers at a glance in battle. The aesthetic is one of the most recognisable in Western history and has been continuously referenced in film.","rarity":"Extinct","see_also":["Roman Toga Style","Medieval Knight Dress","Military Masculine"],"colors":["#8B0000 Legion Red","#C0C0C0 Iron Silver","#D4AF37 Brass Gold","#5B3A29 Leather Brown"],"media":["Gladiator (2000) — film","Ben-Hur (1959) — film","Rome (HBO series) — TV"]},"Chinese Han Dynasty Court Dress":{"summary":"The formal court dress of the Han Empire — deep-lapelled silk robes with colour encoding rank, the foundation of Chinese dress for two millennia.","era":"c.206 BCE–220 CE, China","mood":"Ceremonially precise, hierarchically encoded","visual":"Deep-lapelled cross-collar robes (paofu) in silk, wrapping right over left. Colour denotes rank — yellow approaching imperial. Long hanging sleeves. Jade pendants. The right-over-left wrap distinguished living people from burial garments.","garments":["Cross-collar silk robe","Rank colour sash","Jade pendant belt","Silk ribbon trim","Lacquered hairpin"],"habitat":"Chinese history exhibitions, Han Dynasty drama productions, Hanfu revival communities.","context":"Han Dynasty dress codified the cross-collar wrapped robe that became the foundation of Chinese dress for 2,000 years. The silk quality and colour system created a legible rank system that persisted through successive dynasties.","rarity":"Extinct","see_also":["Tang Dynasty Aesthetic","Chinese Hanfu","Zhou Dynasty Aesthetic"],"colors":["#8B0000 Imperial Red","#D4AF37 Gold","#1C3A1C Jade Green","#FAF8F5 Silk White"],"media":["The Emperor and the Assassin (1998) — film","Nirvana in Fire (TV series) — TV","Mulan (2020) — film"]},"Japanese Heian Court Dress":{"summary":"The extraordinarily layered court dress of Heian Japan — twelve-layered robes in colour gradations expressing the natural world and poetic sensibility.","era":"c.794–1185, Kyoto, Japan","mood":"Refined, seasonal, poetically complex","visual":"The jūnihitoe (twelve-layer robe) for women: multiple layered kimonos visible at collar and sleeves, with colour combinations (kasane no irome) named after flowers and seasons. Each combination had a name and meaning. Slow, deliberate movement required.","garments":["Twelve-layer jūnihitoe","Colour-gradient layered collars","Trailing outer uchigi","Fan as status accessory","Black lacquered court cap"],"habitat":"Imperial Palace ceremonies (surviving practice), Kyoto festivals, Japanese court drama, textile museums.","context":"Heian court culture elevated dress to high art. Each layered colour combination had a name — 'kerria rose', 'autumn leaves'. Poetry, calligraphy, and dress were aesthetically unified. The look survives in imperial ceremonies today.","rarity":"Rare","see_also":["Wamono Aesthetic","Japanese Lolita","Traditional Qipao"],"colors":["#8B2500 Crimson","#5B3A8A Deep Violet","#2E5A1C Willow Green","#FAF8F5 Paper White"],"media":["The Tale of Genji, Murasaki Shikibu — literature","The Pillow Book (1996) — film","Princess Mononoke (1997) — film"]},"Byzantine Empress":{"summary":"The jewel-encrusted, highly formal imperial dress of Constantinople — gold brocade, enamel pendants, and the absolute authority of divine empire.","era":"c.330–1453, Constantinople","mood":"Hieratic, jewelled, divine authority","visual":"Heavily structured silk brocade dalmatic robes with gold thread. Elaborate crown (stemma) with hanging enamel pendants (prependoulia). Wide jewelled collar (maniakion). Rigid silhouette. Purple reserved for imperial family.","garments":["Gold silk dalmatic robe","Jewelled stemma crown","Enamel prependoulia pendants","Jewelled maniakion collar","Purple imperial embroidered hem"],"habitat":"Byzantine art exhibitions, medieval history cosplay, opera productions, Eastern Orthodox contexts.","context":"Byzantine imperial dress was deliberately theatrical — designed to embody divine order. The rigid hieratic posture and jewelled surfaces appear in countless mosaics. Justinian and Theodora's Ravenna mosaics are the defining visual references.","rarity":"Extinct","see_also":["Orthodox Ceremonial","Venetian Court Dress","Egyptian Priestess"],"colors":["#4B0082 Imperial Purple","#D4AF37 Gold","#C1440E Carnelian Red","#1B4F72 Lapis Blue"],"media":["Ravenna mosaics (c.547 CE) — art","The Secret History, Procopius — literature","Byzantium: A Tale of Three Cities (documentary)"]},"Orthodox Ceremonial":{"summary":"The surviving liturgical vestments of Eastern Orthodox Christianity — gold embroidery, icons, and two millennia of essentially unchanged sacred dress.","era":"c.330 CE–present, Eastern Christendom","mood":"Sacred, timeless, liturgically precise","visual":"The patriarch's sakkos in heavy gold brocade. Gold-embroidered vestments with icon panels. Tall black kamilavka hat for monks. Rich deep jewel tones. Most vestment forms unchanged since Byzantine court dress.","garments":["Gold brocade sakkos robe","Embroidered epitrachelion stole","Tall black kamilavka","Gold crozier staff","Pectoral cross"],"habitat":"Orthodox churches worldwide, Greek and Russian religious festivals, Easter services, monastic communities.","context":"Eastern Orthodox vestments are living Byzantine dress, essentially unchanged since Constantinople. The church preserved the court aesthetic when the empire fell in 1453. Many vestments in use today are antiques of enormous age.","rarity":"Niche","see_also":["Byzantine Empress","Trad Catholic Aesthetic","Russian Folk Aesthetic"],"colors":["#D4AF37 Liturgical Gold","#8B0000 Vestment Red","#1C3A1C Priestly Green","#FAF8F5 Baptismal White"],"media":["Andrei Rublev (1966) — film","The Island (2006) — film","Easter services globally — cultural event"]},"Mali Empire Court Dress":{"summary":"The royal and court dress of medieval West Africa's wealthiest empire — gold-heavy, strip-cloth rich, and internationally traded.","era":"c.1235–1600, West Africa","mood":"Magnificent, gold-laden, culturally sovereign","visual":"Hand-woven strip cloth in bright colours (ancestor of kente). Gold ornaments of extreme weight. Embroidered boubou robes. Animal skin details. Elaborate headwrapping. Mansa Musa's 1324 pilgrimage to Mecca, during which he distributed so much gold that Egyptian markets crashed, is the defining event.","garments":["Embroidered boubou robe","Woven strip cloth garment","Heavy gold armband","Gold pendant necklace","Elaborate head wrap"],"habitat":"African history exhibitions, West African cultural events, Mansa Musa historical references.","context":"The Mali Empire was one of the medieval world's wealthiest states. Mansa Musa's hajj in 1324 brought his court's dress to the attention of the entire medieval world. The strip cloth tradition led directly to modern kente.","rarity":"Extinct","see_also":["Kente Cloth Aesthetic","Ankara / African Print Fashion","Ghanaian Fashion"],"colors":["#D4AF37 Gold","#8B4513 Earth Brown","#2E5A1C Kente Green","#C1440E Kente Red"],"media":["Keita! The Heritage of the Griot (1995) — film","Sundiata: An Epic of Old Mali — literature","Mali: The Ancient Cultures documentary"]},"Aztec Ceremonial Dress":{"summary":"The sacred ritual dress of the Mexica people — feather mosaics, jade, and garments that were theology made wearable.","era":"c.1300–1521, Mesoamerica","mood":"Sacred, cosmologically charged, devastating","visual":"Feather mosaics (amantecayotl) in quetzal green. Turquoise mosaic masks. Xicolli sleeveless jacket with fringed hem denoting priestly rank. Cotton tilmatli cloaks with complex iconographic weavings. Elaborate headdresses specific to deities.","garments":["Quetzal feather headdress","Turquoise mosaic mask","Xicolli fringed jacket","Iconographic cotton cloak","Jade and obsidian jewellery"],"habitat":"Anthropology museums, Mexican heritage contexts. Must be framed as documented ceremonial tradition, not costume.","context":"Aztec ceremonial dress was sacred technology — each garment was a theological statement. The featherworking tradition (amantecayotl) was a high art form. The famous quetzal headdress attributed to Moctezuma II is held in Vienna's Museum of Ethnology.","rarity":"Extinct","see_also":["Tehuana Aesthetic","Frida Kahlo Aesthetic","Mexican Traditional Dress"],"colors":["#006400 Quetzal Green","#C1440E Ochre Red","#D4AF37 Gold","#1B4F72 Turquoise"],"media":["Apocalypto (2006) — film","The Aztec Empire (documentary)","The Feathered Serpent (TV series) — TV"]},"Mughal Court Aesthetic":{"summary":"The opulent synthesis-driven court dress of India's Mughal Empire — pietra dura jewels, Kashmiri shawls, and Persian-Indian fusion at its most magnificent.","era":"c.1526–1857, Indian subcontinent","mood":"Sumptuous, multicultural, architecturally layered","visual":"Jama (long coat) in muslin or silk with geometric patterns. Churidar trousers. Patka waist sash. Embroidered jootie shoes with turned-up toes. Spectacular jewellery in hair, ears, nose, wrists, fingers, and waist. Kashida embroidery.","garments":["Embroidered silk jama coat","Churidar trousers","Patka waist sash","Jootie embroidered shoes","Multi-strand jewelled necklace"],"habitat":"Indian museums, Bollywood historical films, South Asian heritage exhibitions, bridal jewellery reference.","context":"The Mughal court synthesised Persian, Central Asian, and Indian aesthetics into the most sophisticated dress culture the subcontinent had seen. Joséphine Bonaparte's adoption of Kashmiri shawls in France was indirectly a Mughal fashion export.","rarity":"Extinct","see_also":["Indian Festive Wear","Bridal Indian Fashion","Pakistani Bridal"],"colors":["#8B0000 Ruby Red","#D4AF37 Gold","#1B4F72 Lapis Blue","#2E5A1C Emerald"],"media":["Jodhaa Akbar (2008) — film","The Taj Mahal (documentary)","Mughal-E-Azam (1960) — film"]},"Ottoman Court Dress":{"summary":"The magnificent layered dress of the Ottoman imperial court — silk velvet kaftans, enormous turbans, and tulip motifs in cut velvet.","era":"c.1299–1922, Istanbul","mood":"Imperial, layered, magnificently patterned","visual":"The kaftan: long silk velvet or brocade robe in two or three layers. Tulip and carnation motifs in cut velvet. Enormous wrapped turbans on men — size indicating rank. Women in entari robes with şalvar trousers. Gold embroidery (zerduz).","garments":["Silk velvet kaftan","Layered entari robe","Wrapped silk turban","Şalvar trousers","Gold zerduz embroidered hem"],"habitat":"Topkapi Palace Museum, Turkish cultural events, Ottoman history drama productions.","context":"Ottoman court dress reached its height in the 16th century under Suleiman the Magnificent. The kaftan was used as a diplomatic gift — hundreds survive in the Topkapi Palace collection. The kaftancıbaşı (keeper of the kaftans) was a significant court position.","rarity":"Extinct","see_also":["Middle Eastern Modest Chic","Turkish Modern Fashion","Persian Maximalism"],"colors":["#8B0000 Ottoman Red","#D4AF37 Gold","#2C5530 Ottoman Green","#1B4F72 İznik Blue"],"media":["Magnificent Century (TV series) — TV","Topkapi (1964) — film","Lawrence of Arabia (1962) — film"]},"Ethiopian Imperial Aesthetic":{"summary":"The ceremonial dress of the Ethiopian imperial court and Orthodox church — elaborate crowns, lion imagery, and sovereign African grandeur.","era":"c.100 CE–1974, Ethiopia","mood":"Sovereignly African, divinely imperial","visual":"White shamma (cotton shawl) with coloured border for nobility. Elaborate gold crowns. Lion skin for highest ranks. Imperial silk cape. Jewelled Coptic cross. Embroidered border ceremonial dress. Haile Selassie's coronation in 1930 was one of the most photographed state ceremonies of the century.","garments":["White shamma with coloured border","Imperial gold crown","Lion skin ceremonial cape","Jewelled Coptic cross","Embroidered ceremonial dress"],"habitat":"Ethiopian cultural events, Orthodox church ceremonies, Haile Selassie historical contexts, Rastafarian cultural references.","context":"Ethiopia maintained an imperial court tradition from ancient Axum through Haile Selassie (deposed 1974). The cross of Christianity and the lion of Judah are its defining symbols. Rastafarianism made Ethiopian imperial iconography globally recognisable.","rarity":"Rare","see_also":["Ankara / African Print Fashion","African American Church Fashion","Kente Cloth Aesthetic"],"colors":["#FAF8F5 White Shamma","#D4AF37 Imperial Gold","#2E5A1C Ethiopian Green","#8B0000 Lion Red"],"media":["Haile Selassie's coronation (1930) — historical footage","Rastaman Vibration, Bob Marley (1976) — music","The Lion of Judah (documentary)"]},"Dark Ages Aesthetic":{"summary":"The practical, sparse dress of post-Roman Europe — wool, leather, and the loss of Mediterranean refinement.","era":"c.476–900, Western Europe","mood":"Austere, functional, dimly elemental","visual":"Undyed or plant-dyed wool tunics to the knee. Linen undergarments. Wrapped leg-bindings. Simple leather belt. Cloak fastened with a pin. Almost no surviving jewellery except ecclesiastical pieces. Enormous regional variation.","garments":["Undyed wool tunic","Linen under-tunic","Cross-gartered leg wraps","Simple leather belt","Iron pin brooch"],"habitat":"Dark Ages living history groups, early medieval cosplay, post-apocalyptic aesthetic references.","context":"The term 'Dark Ages' is historiographically contested — artistic and intellectual traditions continued. But materially, dress became less elaborate than Roman periods, more regional, more functional. Surviving textiles are rare.","rarity":"Extinct","see_also":["Anglo-Saxon Folk","Viking Aesthetic","Medieval Peasant"],"colors":["#8B7355 Undyed Wool","#5B3A29 Leather Brown","#4A7C59 Weld Green","#2C2C2C Ash"],"media":["Beowulf (2007) — film","The 13th Warrior (1999) — film","Beowulf — epic poem"]},"Anglo-Saxon Folk":{"summary":"The linen and wool dress of Anglo-Saxon England — paired shoulder brooches, tablet-braid trim, and the material culture of Beowulf's world.","era":"c.450–1066, England","mood":"Earthy, dignified, folk-rooted","visual":"Women in long linen gown with over-dress (peplos), pinned at shoulders with matching brooches. Men in tunic and trousers with leg bindings. Woven tablet-braid trim at cuffs and necklines. Amber and garnet jewellery. Blue woad dyeing for festive occasions.","garments":["Linen under-dress","Woollen peplos over-dress","Paired shoulder brooches","Woven tablet-braid trim","Amber bead necklace"],"habitat":"Early medieval history reenactment, Sutton Hoo exhibitions, Viking adjacent communities.","context":"Anglo-Saxon dress is known primarily from grave goods — Sutton Hoo and other burial sites reveal elaborate jewellery and textile sophistication. The Staffordshire Hoard shows the metalwork complexity of the period.","rarity":"Extinct","see_also":["Viking Aesthetic","Medieval Peasant","Dark Ages Aesthetic"],"colors":["#8B7355 Natural Wool","#C1440E Madder Red","#4A7C59 Woad Green","#D4AF37 Amber Gold"],"media":["The Last Kingdom (TV series) — TV","Sutton Hoo (documentary)","Beowulf — epic poem"]},"Viking Aesthetic":{"summary":"The Norse dress of seafarers, traders, and raiders — wool, silver arm rings, and the practical-magnificent aesthetic of the longship crew.","era":"c.793–1066, Scandinavia","mood":"Weatherproof, silver-laden, practically magnificent","visual":"Undyed or plant-dyed wool. Men: tunic, trousers, cloak. Women: pleated underdress, over-dress hung from paired oval brooches. Silver arm rings in multiples. Rune-carved wooden accessories. Long hair for women; men with beard. Wool cape for harsh weather.","garments":["Paired oval brooch over-dress","Wool cloak","Silver arm ring","Leather belt with buckle","Leather and wool shoes"],"habitat":"Viking festivals worldwide, historical reenactment, Norse heritage events, television Vikings-era cosplay.","context":"Viking dress was functional first — wool's lanolin resisted water, layers provided warmth at sea. Silver jewellery was a form of portable currency as much as adornment. Recent textile archaeology has definitively overturned the horned helmet myth.","rarity":"Extinct","see_also":["Norse Shieldmaiden","Norse Court Dress","Celtic Warrior Aesthetic"],"colors":["#8B7355 Undyed Wool","#5B3A29 Leather Brown","#C0C0C0 Silver","#4A7C59 Norse Blue"],"media":["Vikings (TV series) — TV","The Northman (2022) — film","Vinland Saga (anime) — animation"]},"Norse Shieldmaiden":{"summary":"The warrior woman figure of Norse culture — the valkyrie made mortal, and an ongoing historical debate about real armed women.","era":"c.793–1066, Scandinavia","mood":"Fierce, silver-armed, mythologically charged","visual":"The archaeological reality: equipped burials with both female-coded dress and weapons exist. The Birka burial (Bj 581) confirmed female by DNA in 2017. The romanticised aesthetic: mail shirt over wool, seax, shield, leather bracers. Battle-braided hair.","garments":["Short mail hauberk","Seax short sword","Round wooden shield","Battle-braided hair","Leather bracers"],"habitat":"Norse reenactment, shield-maiden cosplay, Valkyrie-inspired fashion, feminist history communities.","context":"The 2017 DNA confirmation of the Birka burial reignited debate about shield-maidens. The figure is now one of the most contested and celebrated in Norse history — simultaneously real archaeological evidence and powerful cultural symbol.","rarity":"Rare","see_also":["Viking Aesthetic","Valkyrie Aesthetic","Celtic Warrior Aesthetic"],"colors":["#8B7355 Battle Wool","#C0C0C0 Iron Grey","#8B0000 Shield Red","#D4AF37 Silver Gold"],"media":["Vikings (TV series) — TV","The Last Kingdom (TV series) — TV","The Northman (2022) — film"]},"Norse Court Dress":{"summary":"The formal dress of Norse chieftains and jarls — better textiles, more silver, and the ostentatious prosperity of successful raiding and trading.","era":"c.793–1066, Scandinavia","mood":"Prosperous, silver-heavy, rank-displaying","visual":"Higher quality wool in brighter dyes. More elaborate jewellery — large disc brooches, multiple arm rings. Silk imported from the East via trade routes. Women of high status had keys at the waist as symbols of household authority.","garments":["Fine wool brooch-fastened cloak","Large disc brooch clasp","Multiple silver arm rings","Imported silk panel","Household key pendant"],"habitat":"Norse history exhibitions, chieftain-level Viking cosplay, Scandinavian heritage events.","context":"Norse society had sharp material distinctions between thrall, karls, and jarls. The key at a woman's belt was the sign of a householder's authority — she controlled the stores. Keys as jewellery = power.","rarity":"Extinct","see_also":["Viking Aesthetic","Norse Shieldmaiden","Landed Gentry Aesthetic"],"colors":["#2C5530 Norse Green","#D4AF37 Silver Hoard","#8B7355 Fine Wool","#C1440E Scarlet"],"media":["Vikings (TV series) — TV","The Saga of the Völsungs — literature"]},"Early Christian Modest":{"summary":"The deliberately plain dress of the early Christian movement — rejection of Roman luxury as spiritual statement.","era":"c.30–400 CE, Roman Empire","mood":"Theologically austere, morally legible","visual":"Simple undyed wool or linen tunics. Head covering for women. Avoidance of jewellery, cosmetics, and luxury fabric. White for baptism. Dark for clergy. The ichthus fish as modest jewellery. Simple sandals. Everything the opposite of Roman display.","garments":["Undyed linen tunic","Modest head veil","Simple leather sandals","Ichthus fish pendant","Unadorned wool robe"],"habitat":"Early church history exhibitions, Christian living history, Reformation aesthetic references.","context":"Early Christian writers were obsessed with dress modesty — Tertullian, Clement, and others wrote extensively about what Christians should not wear. The avoidance of luxury was both spiritual practice and social signal.","rarity":"Extinct","see_also":["Trad Catholic Aesthetic","Orthodox Ceremonial","Modest Fashion General"],"colors":["#FAF8F5 Undyed Linen","#E8D5B0 Natural Wool","#2C2C2C Dark Undyed","#FAF8F5 Baptismal White"],"media":["Ben-Hur (1959) — film","The Gospel According to St. Matthew (1964) — film","Quo Vadis (1951) — film"]},"Carolingian Court":{"summary":"The revived imperial dress of Charlemagne's court — a self-conscious attempt to restore Roman dignity as political legitimisation.","era":"c.750–900, France/Germany","mood":"Imperially aspirational, Roman-nostalgic","visual":"Long silk tunics for courtiers. Roman-influenced heavy mantles. Crown for Charlemagne. Cross-gartered leg bindings. Fine embroidered borders on ceremonial dress. The entire aesthetic designed to say: we are the heirs of Rome.","garments":["Long embroidered silk tunic","Heavy mantle cloak","Gold cross pectoral","Cross-gartered leg bindings","Crown or circlet"],"habitat":"Medieval history exhibitions, Charlemagne cultural references.","context":"Charlemagne deliberately revived Roman imperial aesthetics as political legitimisation — being crowned Emperor of the Romans in 800 CE required looking the part. His court dress bridged Frankish and Roman traditions.","rarity":"Extinct","see_also":["Frankish Noble","Medieval Romantic","Dark Ages Aesthetic"],"colors":["#D4AF37 Imperial Gold","#8B0000 Royal Red","#2C5530 Forest Green","#FAF8F5 Ivory Silk"],"media":["Charlemagne (TV film) — TV","The Name of the Rose (1986) — film"]},"Frankish Noble":{"summary":"The practical yet status-conscious dress of Frankish aristocracy — quality wool, sword-bearing rights, and the seriousness of early medieval lordship.","era":"c.500–1000, Francia","mood":"Martial, hierarchically precise, no-nonsense","visual":"Long tunic over trousers. Quality wool cloak with gold fibula. Sword at belt (sword-bearing was a noble right). Fine leather belt with decorated buckle. Gold and garnet cloak pins. Limited but high-quality jewellery.","garments":["Quality wool long tunic","Gold fibula cloak pin","Noble sword at belt","Decorated leather belt","Gold and garnet brooch"],"habitat":"Early medieval history reenactment, Carolingian court cosplay.","context":"Frankish nobility expressed rank through sword-bearing rights, jewellery weight, and textile quality. The transition from Merovingian to Carolingian periods shows increasing Roman influence on court dress.","rarity":"Extinct","see_also":["Carolingian Court","Medieval Knight Dress","Dark Ages Aesthetic"],"colors":["#5B3A29 Leather Brown","#8B7355 Wool Grey","#D4AF37 Gold Fibula","#8B0000 Noble Red"],"media":["Kingdom of Heaven (2005) — film","The Name of the Rose (1986) — film"]},"Medieval Peasant":{"summary":"The functional dress of the medieval majority — undyed wool, rough linen, and nothing the sumptuary laws didn't permit.","era":"c.1000–1500, Europe","mood":"Practical, earthbound, uncommonly dignified","visual":"Undyed or plant-dyed wool tunics. Linen undergarments. Leather or wooden pattens. Wraparound apron for work. Linen coif tied under chin. Simple leather belt. Women in long kirtle with linen chemise underneath. Clean and pressed despite poverty.","garments":["Undyed wool tunic","Linen coif cap","Leather pattens shoes","Work apron","Simple leather belt"],"habitat":"Medieval living history, Renaissance faire, historical film productions.","context":"Medieval peasant dress was tightly regulated by sumptuary laws — specific colours and fabrics reserved for specific classes. Despite this, surviving records show peasants were particular about their dress. Sunday best was a real concept.","rarity":"Extinct","see_also":["Village Folk Dress","Merchant Class Dress","Anglo-Saxon Folk"],"colors":["#8B7355 Undyed Wool","#C1440E Madder Red","#4A7C59 Weld Yellow","#5B3A29 Earth Brown"],"media":["Monty Python and the Holy Grail (1975) — film","The Name of the Rose (1986) — film","Ladyhawke (1985) — film"]},"Village Folk Dress":{"summary":"The regional and seasonal dress of medieval village communities — festival embroidery, market day best, and the rhythm of agricultural life.","era":"c.1000–1600, Rural Europe","mood":"Communal, seasonal, quietly proud","visual":"Best wool for market days and festivals, work wool for daily use. Regional variations enormous. Smocks for agricultural work. Festival embroidery at cuffs and collars. Wooden clogs. Linen aprons.","garments":["Embroidered festival smock","Market-day wool dress","Wooden clogs","Linen work apron","Regional wool cap"],"habitat":"Folk museum living history, European folk festivals, craft fair aesthetic, Cottagecore historical roots.","context":"Village folk dress was highly regional — each area of Europe developed distinct colour palettes, embroidery patterns, and silhouettes. Festivals were the moment for displaying finery. The aesthetic feeds into 18th-century folk costume traditions.","rarity":"Extinct","see_also":["Medieval Peasant","European Folk Dress","Cottagecore"],"colors":["#8B7355 Natural Wool","#C1440E Folk Red","#4A7C59 Plant Green","#F5E6C8 Linen Cream"],"media":["Into the Woods (2014) — film","The VVitch (2015) — film","Midsommar (2019) — film"]},"Merchant Class Dress":{"summary":"The aspirational, carefully calibrated dress of medieval Europe's emerging middle class — good wool, beaver hats, and the navigation of sumptuary laws.","era":"c.1200–1500, European cities","mood":"Prosperous, aspirational, legally careful","visual":"Good-quality wool in permitted dyes. Beaver felt hat (enormously expensive). Fine linen collar visible at neck. Fur lining at cuffs (marten, fox — grades of fur were legally regulated). Purse on belt. Quality without ostentation.","garments":["Fine wool cotehardie","Beaver felt hat","Fur-lined cuff","Leather purse on belt","Quality leather shoes"],"habitat":"Medieval history exhibitions, merchant guild living history, Hanseatic League events.","context":"The medieval merchant class drove sumptuary law negotiations for centuries — prosperous enough to afford noble dress, legally forbidden to wear it. They focused on quality of permitted materials, creating a distinct aesthetic of restrained luxury.","rarity":"Extinct","see_also":["Guild Artisan Aesthetic","Preppy","Old Money"],"colors":["#2C2C2C Quality Black","#FAF8F5 White Linen","#8B7355 Good Wool","#B8860B Beaver Felt"],"media":["The Merchant of Venice (1973) — film","Pillars of the Earth (TV series) — TV"]},"Guild Artisan Aesthetic":{"summary":"The professional dress of medieval craftspeople — the leather apron, the guild badge, and pride in skilled labour made visible.","era":"c.1200–1600, European cities","mood":"Professional, craft-proud, communally organised","visual":"Work apron over everyday dress. Guild badge or seal. Specific to craft: blacksmiths in leather aprons, weavers in wool-stained smocks, goldsmiths in fine working dress. Festival processions in full guild regalia.","garments":["Leather work apron","Guild badge","Craft-specific smock","Sturdy leather shoes","Belt with tool pouch"],"habitat":"Craft fairs, artisan communities, historical workshops.","context":"Medieval guilds were powerful organisations controlling quality, wages, and training. Guild dress in festival processions was an elaborate statement of collective professional pride. The craft apron is one of the oldest persistent items of work dress.","rarity":"Extinct","see_also":["Workshop Aesthetic","Blacksmith Aesthetic","Artisanal Craft Aesthetic"],"colors":["#5B3A29 Leather Apron","#8B7355 Work Wool","#2C2C2C Forge Black","#D4AF37 Guild Gold"],"media":["The Name of the Rose (1986) — film","Pillars of the Earth (TV series) — TV"]},"Medieval Herbalist":{"summary":"The dress of the village wisewoman — dark wool, herb-stained apron, and the aesthetic of folk medicine before the university.","era":"c.1000–1500, Rural Europe","mood":"Earthy, quietly knowledgeable, practically botanical","visual":"Dark wool dress in green, brown, or grey. Herb-stained apron. Deep pockets for gathered plants. Leather belt with knife and pouch. Simple head covering. Warm cloak for outdoor foraging. Hands darkened by plant dyes.","garments":["Dark wool dress","Herb-stained work apron","Deep-pocket belt pouch","Foraging cloak","Simple linen coif"],"habitat":"Herbalism and folk medicine communities, Cottage Witch aesthetic inspiration, Renaissance faire.","context":"The medieval herbalist operated at the intersection of practical medicine, spiritual tradition, and communal service. Most were women. Their knowledge was transmitted orally. The Church alternately tolerated and persecuted them.","rarity":"Extinct","see_also":["Forest Witch Aesthetic","Apothecarycore","Herbalistcore"],"colors":["#4A7C59 Herb Green","#8B7355 Dark Wool","#C1440E Plant Red","#5B3A29 Earth Brown"],"media":["The VVitch (2015) — film","Ever After (1998) — film","Brother Cadfael (TV series) — TV"]},"Crusader Aesthetic":{"summary":"The distinctive dress of Crusading knights — surcoat over mail, heraldic devices, and the visual language of holy war.","era":"c.1096–1291, Middle East and Europe","mood":"Militarily austere, divinely motivated","visual":"Chainmail hauberk with coif. White surcoat with cross (Hospitallers) or other heraldic device. Flat-topped great helm. Leather gauntlets. Large heater shield with device. Pilgrim cross badge.","garments":["Chainmail hauberk","White crusader surcoat","Flat-topped great helm","Heraldic heater shield","Leather-over-mail boots"],"habitat":"Medieval history reenactment, Crusades exhibitions, heraldry enthusiasts, Templar cosplay.","context":"Crusader dress developed from functional military need to elaborate symbolic system. The white surcoat displaying heraldic devices solved the practical problem of identifying friends in battle while creating the system of noble visual identity that persists in heraldry today.","rarity":"Extinct","see_also":["Medieval Knight Dress","Heraldic Aesthetic","Military Masculine"],"colors":["#FAF8F5 Crusader White","#8B0000 Cross Red","#C0C0C0 Mail Grey","#5B3A29 Leather Brown"],"media":["Kingdom of Heaven (2005) — film","Arn: The Knight Templar (2007) — film","The Pillars of the Earth (TV series) — TV"]},"Gothic Court Dress":{"summary":"The fantastically elongated fashion of 14th–15th century European courts — pointed toes, high hennin hats, and the extreme decoration of late medieval wealth.","era":"c.1340–1480, Northern Europe","mood":"Extravagantly vertical, sartorially competitive","visual":"Extremely pointed poulaine shoes (toes up to 24 inches). Tall conical hennin hats with transparent veiling. Fitted cotehardie with elaborate dagging at hems. Fur-lined houpelande. Men in tight doublet and hose with very short hemlines. Philip of Burgundy's court as the reference.","garments":["Pointed poulaine shoes","Tall conical hennin hat","Fur-lined houpelande robe","Dagged hem cotehardie","Fitted doublet and hose"],"habitat":"Medieval history, Gothic fashion editorials, Faire Maiden cosplay.","context":"Gothic court dress was explicitly competitive — poulaine toe length signalled rank, hennin height indicated status. Sumptuary laws constantly tried to limit extremes; fashion constantly exceeded them.","rarity":"Extinct","see_also":["Medieval Noblewoman","Medieval Knight Dress","Gothic Lolita"],"colors":["#2E5A8B Cobalt Blue","#C1440E Scarlet","#D4AF37 Gold","#1A1A1A Silk Black"],"media":["Sleeping Beauty (1959) — animation","The Name of the Rose (1986) — film","A Knight's Tale (2001) — film"]},"Medieval Noblewoman":{"summary":"The carefully regulated dress of medieval noble women — wimple, surcoat, heraldic embroidery, and the visual performance of dynasty.","era":"c.1100–1450, Europe","mood":"Dynastically encoded, appropriately modest, magnificent","visual":"Linen wimple and veil covering hair and neck. Tight-laced surcoat over kirtle. Heraldic embroidery announcing family alliances. Jewelled belt at hips. Long trailing hem indicating rank. Wide sleeves revealing contrasting lining.","garments":["Linen wimple and veil","Heraldic embroidered surcoat","Jewelled hip belt","Long trailing hem","Gold circlet crown"],"habitat":"Medieval history reenactment, heraldry communities, cosplay.","context":"Noble women's dress was a vehicle for dynastic display — heraldic embroidery announced family alliances, wedding robes displayed new connections. The wimple conveyed Christian modesty while the jewelled belt conveyed wealth.","rarity":"Extinct","see_also":["Gothic Court Dress","Medieval Romantic","Faire Maiden Aesthetic"],"colors":["#2E5A8B Heraldic Blue","#8B0000 Crimson","#D4AF37 Gold","#2C5530 Heraldic Green"],"media":["Braveheart (1995) — film","Pillars of the Earth (TV series) — TV","Anne of a Thousand Days (1969) — film"]},"Medieval Knight Dress":{"summary":"The plate armour and heraldic dress of the late medieval knight — tournament armour, heraldic surcoat, and the apex of chivalric culture.","era":"c.1300–1500, Europe","mood":"Chivalric, heraldically magnificent, tournament-ready","visual":"Full plate armour in polished steel. Heraldic surcoat. Great helm with crest. Heraldic caparisoned horse. Off-armour: doublet and hose in household livery. Tournament favours from lady. A knight's equipment at a major tournament might equal the cost of a house.","garments":["Full plate armour","Heraldic surcoat","Plumed great helm","Chivalric livery doublet","Lady's tournament favour"],"habitat":"Medieval reenactment, jousting events, chivalry cosplay, Arthurian festivals.","context":"The tournament was medieval sport, theatre, and fashion show simultaneously. A knight's equipment at a major tournament might cost a small fortune. The chivalric aesthetic was self-consciously theatrical.","rarity":"Extinct","see_also":["Heraldic Aesthetic","Knightcore","Arthurian Aesthetic"],"colors":["#C0C0C0 Polished Steel","#D4AF37 Heraldic Gold","#8B0000 Chivalric Red","#FAF8F5 Surcoat White"],"media":["Excalibur (1981) — film","A Knight's Tale (2001) — film","Kingdom of Heaven (2005) — film"]},"Heraldic Aesthetic":{"summary":"The visual language of medieval heraldry applied to dress — blazoned devices, livery colours, and the world's first systematic visual identity system.","era":"c.1150–present, Europe","mood":"Proud, symbolically coded, dynastically precise","visual":"Bold primary colours: gules, azure, sable, or, argent. Simple geometric shapes and charges. Strong contrast between colours (tincture rules forbid colour on colour). Livery colours identifying household. College blazer as modern survival.","garments":["Quartered heraldic surcoat","Livery badge","Blazon-patterned fabric","Pennant and banner","Heraldic signet ring"],"habitat":"Heraldry societies, historical reenactment, college blazers, coat of arms design.","context":"Heraldry was the first systematic visual identity system in European history — a grammar of symbols allowing identification across language barriers in battle. Its precise rules (tincture on tincture forbidden) persist in graphic design today.","rarity":"Rare","see_also":["Medieval Knight Dress","Gothic Court Dress","British Heritage Fashion"],"colors":["#8B0000 Gules Red","#2E5A8B Azure Blue","#D4AF37 Or Gold","#1A1A1A Sable Black"],"media":["A Knight's Tale (2001) — film","Monty Python and the Holy Grail (1975) — film","Game of Thrones (TV series) — TV"]},"Tournament Dress":{"summary":"The spectacular dress worn at medieval tournaments — the pinnacle of medieval secular fashion, worn to be seen.","era":"c.1150–1520, Europe","mood":"Spectacular, competitive, theatrically festive","visual":"For noble spectators: finest available dress, heraldic colours. Women in elaborate headdresses with flowing veils. Men in fitted doublets in household colours. Tournament favours given to knights. Elaborate tents in heraldic patterns.","garments":["Finest heraldic dress","Elaborate veil headdress","Household-colour doublet","Embroidered tournament favour","Jewelled belt"],"habitat":"Medieval festivals, jousting events, tournament reenactment.","context":"The tournament was one of the most fashion-conscious events of the medieval world. Courts competed for spectacle. Ladies awarded prizes. The occasion drove innovation in textile and jewellery.","rarity":"Extinct","see_also":["Medieval Knight Dress","Heraldic Aesthetic","Gothic Court Dress"],"colors":["#D4AF37 Tournament Gold","#8B0000 Chivalric Red","#2E5A8B Azure Blue","#FAF8F5 Pennant White"],"media":["A Knight's Tale (2001) — film","Ivanhoe (1952) — film"]},"Faire Maiden Aesthetic":{"summary":"The romantically imagined medieval feminine aesthetic of Renaissance Faire culture — flower crowns, flowing sleeves, and an idealized Middle Ages.","era":"c.1960s–present, United States","mood":"Romantically medieval, flower-crowned, timelessly pastoral","visual":"Flowing linen or cotton dress in earthy or jewel tones. Fitted laced bodice. Very wide draped sleeves. Flower crown. Wooden or leather accessories. Braided or loose hair. Period-adjacent rather than accurate.","garments":["Fitted laced bodice","Wide draped sleeves","Fresh flower crown","Long linen skirt","Leather belt pouch"],"habitat":"Renaissance Faire events, fantasy conventions, outdoor festivals.","context":"The Renaissance Faire aesthetic emerged in 1960s California and spread nationwide. It represents a romantically imagined Middle Ages — comfortable, flower-scented, and entirely unlike actual medieval experience. It is now an established subculture.","rarity":"Niche","see_also":["Medieval Romantic","Medieval Noblewoman","Fairycore"],"colors":["#C1440E Terracotta","#4A7C59 Forest Green","#D4AF37 Marigold","#FAF8F5 Cream Linen"],"media":["A Knight's Tale (2001) — film","Ever After (1998) — film","Ladyhawke (1985) — film"]},"Medieval Romantic":{"summary":"The 19th-century Romantic movement's idealised vision of the Middle Ages — Pre-Raphaelite gowns, unpinned hair, and the medieval as spiritual antidote to industry.","era":"c.1820s–1900s, Britain and Europe","mood":"Dreamily medieval, Pre-Raphaelite, nostalgic","visual":"Loose Pre-Raphaelite gowns in muted jewel tones. Flowing unpinned hair. Simple girdle belt. Trailing sleeves. Minimal corsetry by Victorian standards. Embroidered with medieval motifs. Often depicted in painting: Ophelia, Guinevere, Lady of Shalott.","garments":["Loose jewel-tone gown","Simple girdle belt","Flowing wide sleeves","Flower-wound hair","Pre-Raphaelite embroidery"],"habitat":"Pre-Raphaelite art contexts, Morris-era design communities.","context":"The Romantic Medieval was a 19th-century reaction against industrialisation. William Morris built an aesthetic movement on it. The Pre-Raphaelite Brotherhood painted it. It feeds directly into contemporary Cottagecore.","rarity":"Rare","see_also":["Faire Maiden Aesthetic","Pre-Raphaelite Aesthetic","Aesthetic Dress Reform"],"colors":["#2E5A8B Pre-Raphaelite Blue","#8B4513 Russet","#4A7C59 Sage Green","#D4AF37 Illuminated Gold"],"media":["The Lady of Shalott, Tennyson (1832) — poetry","Ophelia (John Everett Millais, 1851–52) — painting","Camelot (1967) — film"]},"Plague Doctor":{"summary":"The iconic beaked mask and leather coat of the historical plague physician — simultaneously terrifying and strangely compelling across centuries.","era":"c.1619, Europe","mood":"Uncanny, liminal, death-adjacent","visual":"Long waxed leather coat. Wide-brimmed hat. The iconic beaked mask stuffed with aromatics. Heavy gloves. Walking cane. Thick glass goggles. The entire suit designed to prevent contagion — it did not work, but the image endured.","garments":["Beaked leather mask","Long waxed overcoat","Wide-brimmed leather hat","Heavy gloves","Glass goggle lenses"],"habitat":"Halloween, Dark & Eerie Internet aesthetics, Gothic fashion, Venice Carnival.","context":"The plague doctor costume was invented by Charles de Lorme in 1619. The beak's aromatics offered no protection. It became one of history's most iconic designs — now belonging as much to mythology as history.","rarity":"Niche","see_also":["Gaslight Gothic","Victorian Death Aesthetic","Weirdcore"],"colors":["#2C2C2C Waxed Black","#8B7355 Leather Brown","#C0C0C0 Glass Grey","#1B4F72 Dark Blue"],"media":["The Physician (2013) — film","The Name of the Rose (1986) — film","Carnival Row (TV series) — TV"]},"Florentine Renaissance":{"summary":"The refined civic dress of 15th-century Florence — soft wool, humanist balance, and the birth of the fashion designer as artist.","era":"c.1420–1530, Florence","mood":"Humanist, civic, intellectually elegant","visual":"Fitted wool giornea (overgown) with contrasting sleeves. Silk undergown in jewel tones. Low square neckline for women. Men in short doublet and hose. Moderate gold jewellery. Natural hair with pearl net. Warm palette: siena, terracotta, deep green.","garments":["Fitted wool giornea","Contrasting silk sleeves","Pearl-net hair covering","Short doublet and hose","Gold chain"],"habitat":"Art history, Florentine museum exhibitions, Renaissance cosplay.","context":"Florence was the fashion capital of 15th-century Europe. Merchant wealth funded extraordinary textiles and the humanist philosophy that personal appearance could express inner virtue. Botticelli's paintings are the defining visual reference.","rarity":"Extinct","see_also":["Medici Aesthetic","Venetian Court Dress","Baroque Excess"],"colors":["#C1440E Terracotta","#2C5530 Verdigris Green","#D4AF37 Gold","#8B2500 Madder Red"],"media":["The Agony and the Ecstasy (1965) — film","Botticelli's Birth of Venus (1484–86) — art","Da Vinci's Demons (TV series) — TV"]},"Medici Aesthetic":{"summary":"The magnificently political dress of the Medici dynasty — banking wealth transformed into civic grandeur and cultural patronage.","era":"c.1430–1537, Florence","mood":"Magnificently powerful, culturally patronising","visual":"Finest silk brocade in jewel tones. Multiple layers glimpsed at slashings. Massive gold chain for men. Pearl and ruby jewellery for women. Specific Medici colours: green, gold, and white. Lorenzo the Magnificent's festivals displayed magnificence as governance.","garments":["Silk brocade overgown","Gold Medici chain","Slashed doublet revealing silk","Pearl and ruby jewellery","Medici green and gold palette"],"habitat":"Florentine heritage events, Medici drama productions, Renaissance history cosplay.","context":"The Medici used dress as power politics — their wealth had to be made visually legible to maintain influence. The word 'magnificence' was literally a political virtue in 15th-century Florence.","rarity":"Extinct","see_also":["Florentine Renaissance","Venetian Court Dress","Renaissance Noblewoman"],"colors":["#2C5530 Medici Green","#D4AF37 Gold","#8B0000 Crimson","#FAF8F5 Ivory Silk"],"media":["Medici: Masters of Florence (TV series) — TV","The Agony and the Ecstasy (1965) — film"]},"Renaissance Noblewoman":{"summary":"The jewelled and layered dress of 15th–16th century European noblewomen — split sleeves, pearls, and the dynastic portrait as fashion document.","era":"c.1450–1600, Europe","mood":"Stately, jewelled, dynastically encoded","visual":"Stiff brocade bodice with square or V-neckline. Separate elaborate sleeves tied on. Very long train. Gable or French hood. Multiple pearl strings. Embroidered underskirt visible through front opening. Corset beginning to shape the torso.","garments":["Stiff brocade bodice","Elaborate tied-on sleeves","Multiple pearl strings","Gable or French hood","Embroidered underskirt"],"habitat":"Tudor history cosplay, art history, Renaissance portrait study, period drama.","context":"Renaissance noblewoman dress was designed primarily for portrait display. Holbein's portraits of Henry VIII's wives are defining examples. The dress was architectural: it defined the body as a surface for political display.","rarity":"Extinct","see_also":["Florentine Renaissance","Tudor Court Dress","Elizabethan Aesthetic"],"colors":["#2E5A8B Cobalt Silk","#D4AF37 Gold","#8B0000 Crimson","#FAF8F5 Pearl White"],"media":["Girl with a Pearl Earring (2003) — film","Anne of the Thousand Days (1969) — film","Wolf Hall (TV series) — TV"]},"Venetian Court Dress":{"summary":"The uniquely opulent dress of the Venetian Republic — impossible black velvet, the state-regulated chopine heel, and maritime empire wealth.","era":"c.1450–1700, Venice","mood":"Opulently theatrical, darkly watery","visual":"Black silk velvet (most expensive textile in Europe) over contrasting crimson or gold. The chopine: platform shoe up to 24 inches high worn by noblewomen. Elaborate wigs. Low neckline with pearl trim. State-regulated Carnival masks.","garments":["Black silk velvet gown","Towering chopine platform shoes","Elaborately curled wig","Pearl-trimmed low neckline","Carnival mask"],"habitat":"Venice Carnival, Baroque theatrical events, Renaissance cosplay, masquerade theme events.","context":"Venice's unique position produced a unique fashion culture. The chopine's extreme height required two attendants to walk and was simultaneously absurd and magnificent. The state actively regulated dress — black velvet was reserved for the ruling class.","rarity":"Extinct","see_also":["Venetian Masquerade","Patrician Venetian","Baroque Excess"],"colors":["#1A1A1A Velvet Black","#8B0000 Venetian Crimson","#D4AF37 Gold","#2E5A8B Lagoon Blue"],"media":["Othello (various adaptations) — theatre","Dangerous Beauty (1998) — film","Wings of the Dove (1997) — film"]},"Patrician Venetian":{"summary":"The sober republican dress of Venice's ruling class — black as political statement, and the toga-like senatorial robes of a mercantile republic.","era":"c.1400–1797, Venice","mood":"Soberly republican, commercially proud","visual":"Black toga (cloaca) for senators. Deep crimson for the Doge. Specific colours for specific offices. Men in long black gowns. Sumptuary laws among Europe's most comprehensive. A distinct sober public aesthetic despite enormous private wealth.","garments":["Black senatorial cloaca robe","Office-specific colour trim","Crimson Doge ceremonial","Black public overgown","Simple gold ring seal"],"habitat":"Venetian heritage events, Republic of Venice cosplay, political history contexts.","context":"Venice's sumptuary laws were attempts to preserve republican equality among the ruling class. They failed as completely as sumptuary laws always do, but created a distinct sober public aesthetic that contrasted with the private magnificence of Venetian life.","rarity":"Extinct","see_also":["Venetian Court Dress","Venetian Masquerade","Old Money"],"colors":["#1A1A1A Republican Black","#8B0000 Dogal Crimson","#D4AF37 Senatorial Gold","#FAF8F5 Linen White"],"media":["The Merchant of Venice — theatre","Dangerous Beauty (1998) — film"]},"Venetian Masquerade":{"summary":"The elaborate masked dress of Venetian Carnival — permission to become anyone, expressed through feathers, silk, and anonymous licence.","era":"c.1500–present, Venice","mood":"Sensually anonymous, theatrically transformative","visual":"The bauta: white mask with exaggerated chin, black tricorn hat, black tabarro cloak. The columbina: half-mask with feathers. Elaborate silk gown in jewel colours. The entire point is concealment through extravagance.","garments":["White bauta mask","Black tricorn hat","Black tabarro cloak","Elaborate silk gown","Feathered columbina half-mask"],"habitat":"Venice Carnival (annual event), masquerade balls worldwide, Halloween, theatre, luxury event design.","context":"Venetian Carnival was legally mandated — during its period, masks were required. This created a licensed social equality: class distinctions temporarily erased. The Church repeatedly tried to suppress it; the state repeatedly defended it.","rarity":"Niche","see_also":["Venetian Court Dress","Baroque Excess","Camp Aesthetic"],"colors":["#1A1A1A Tabarro Black","#FAF8F5 Bauta White","#D4AF37 Gilded Gold","#8B0000 Carnival Crimson"],"media":["Eyes Wide Shut (1999) — film","Don Giovanni (opera) — music","Casanova (2005) — film"]},"Flemish Portrait Aesthetic":{"summary":"The precise, merchant-wealthy dress of 15th-century Flanders — supreme black wool, white linen precision, and the merchant's earnest pride.","era":"c.1420–1520, Flanders","mood":"Precisely prosperous, linen-white, commercially proud","visual":"Pure black wool of the highest quality. Stark white linen collar and cuffs in extreme precision. Minimal jewellery — quality over quantity. Women in elaborate white headdresses. Van Eyck, Memling, and van der Weyden as definitive visual references.","garments":["Black finest-wool gown","Precisely white linen collar","Minimal gold ring","Elaborate white headdress","Small devotional object"],"habitat":"Art history (van Eyck, Memling), museum exhibition contexts.","context":"The Flemish portrait aesthetic emerged from a deeply literate merchant class that valued precision and quality over showy excess. The Arnolfini Portrait by van Eyck is the canonical image. Black wool of this quality was enormously expensive.","rarity":"Extinct","see_also":["Dutch Golden Age","Protestant Modest","Old Money"],"colors":["#1A1A1A Flemish Black","#FAF8F5 White Linen","#D4AF37 Gold Ring","#8B7355 Brown Wool"],"media":["Girl with a Pearl Earring (2003) — film","The Arnolfini Portrait (van Eyck, 1434) — art","The Mill and the Cross (2011) — film"]},"Protestant Modest":{"summary":"The deliberately plain dress of the Reformation — rejection of Catholic luxury as theological statement.","era":"c.1520–1700, Northern Europe","mood":"Theologically austere, morally legible","visual":"Black or dark grey. White linen at collar and cuffs, precisely clean. No jewellery. No colour. Simple cut. Dutch Reformed and Calvinist communities especially. The message is Christian interiority against Catholic theatrical excess.","garments":["Black wool dress or coat","Precisely white linen collar","No jewellery","White linen cuffs","Simple leather shoes"],"habitat":"Dutch Golden Age history, Puritan cosplay, Reformation exhibitions.","context":"Protestant dress reform was a theological statement — reformers attacked Catholic luxury dress as idolatry. Calvin's Geneva had strict sumptuary codes. The aesthetic of restraint paradoxically produced enormous prosperity displays as merchant success.","rarity":"Extinct","see_also":["Puritan Aesthetic","Dutch Golden Age","Amish & Plain Dress"],"colors":["#1A1A1A Calvinist Black","#FAF8F5 White Linen","#5B5B5B Grey Wool","#8B7355 Brown Serge"],"media":["The Crucible (1996) — film","A Man for All Seasons (1966) — film"]},"Dutch Golden Age":{"summary":"The quietly magnificent dress of 17th-century Dutch commercial supremacy — millstone ruffs, black silk, and the world's most prosperous merchants.","era":"c.1600–1672, Netherlands","mood":"Quietly wealthy, commercially supreme","visual":"Enormous starched white millstone ruff (later falling collar). Black silk of supreme quality. Minimal expensive jewellery. Women in black with white linen. Men in black doublet. Pearl earrings as understated luxury.","garments":["Starched white millstone ruff","Black silk doublet","Pearl drop earrings","Falling white lace collar","Black silk skirt"],"habitat":"Dutch museum exhibitions, Golden Age art history (Rembrandt, Vermeer, Hals), Netherlands heritage.","context":"The Dutch Republic's extraordinary commercial wealth produced a merchant class that dressed to display prosperity without ostentation. Rembrandt's group portraits and Vermeer's domestic scenes are the defining visual records.","rarity":"Extinct","see_also":["Protestant Modest","Flemish Portrait Aesthetic","Old Money"],"colors":["#1A1A1A Black Silk","#FAF8F5 White Linen","#D4AF37 Pearl Yellow","#8B7355 Brown Velvet"],"media":["Girl with a Pearl Earring (2003) — film","Rembrandt (1936) — film","The Mill and the Cross (2011) — film"]},"Tudor Court Dress":{"summary":"The architectural, power-shouldered dress of Henry VIII's court — extreme padded shoulders and the silhouette of absolute monarchy made fabric.","era":"c.1485–1603, England","mood":"Monumentally powerful, architecturally imposing","visual":"Extreme padded shoulder width. Flat decorative bonnet. Slashed sleeves revealing contrasting silk. Very low square neckline for women. Stiff farthingale under skirt. Gable hood. The portraits by Holbein shaped how England projected royal power across Europe.","garments":["Padded square-shoulder doublet","Slashed sleeve over silk","Flat decorative bonnet","Stiff farthingale underskirt","Gable hood"],"habitat":"Tudor history reenactment, Henry VIII and Anne Boleyn cosplay, period drama, Hampton Court events.","context":"Tudor court dress was explicitly about power display. Henry VIII's wardrobe was a political instrument — his extreme shoulder padding was deliberately superhuman. The Holbein portraits of him are among history's most influential fashion images.","rarity":"Extinct","see_also":["Tudor Merchant","Elizabethan Aesthetic","Medieval Knight Dress"],"colors":["#8B0000 Tudor Crimson","#D4AF37 Gold","#1A1A1A Black Velvet","#FAF8F5 Ermine White"],"media":["Wolf Hall (TV series) — TV","The Six Wives of Henry VIII (TV) — TV","The Other Boleyn Girl (2008) — film"]},"Tudor Merchant":{"summary":"The solid, prosperous dress of Tudor England's rising merchant class — good wool, fur trim, and careful navigation of sumptuary laws.","era":"c.1485–1603, England","mood":"Solidly prosperous, legally careful","visual":"Good wool doublet with modest fur trim. Clean linen at collar. Moderate hat. Leather belt with purse. Quality without ostentation. Women in fitted kirtle with contrasting sleeves. The merchant's version of the court aesthetic.","garments":["Good wool doublet","Modest fur-trimmed collar","Clean linen neckband","Leather belt purse","Well-made leather shoes"],"habitat":"Tudor history living history, merchant guild cosplay, period drama.","context":"Tudor merchants occupied a precise and anxious social position — wealthy enough to dress well, legally forbidden to dress above their station. The city of London was constantly negotiating between actual wealth and permitted display.","rarity":"Extinct","see_also":["Tudor Court Dress","Merchant Class Dress","Dutch Golden Age"],"colors":["#5B3A29 Wool Brown","#FAF8F5 Linen White","#2C2C2C Dark Serge","#D4AF37 Modest Gold"],"media":["Wolf Hall (TV series) — TV","The Merchant of Venice — theatre"]},"Elizabethan Aesthetic":{"summary":"The fantastical excess of late Tudor England — enormous ruffs, farthingales, bejewelled gowns, and Elizabeth I as history's first fashion-as-propaganda monarch.","era":"c.1558–1603, England","mood":"Architecturally fantastical, portrait-obsessed","visual":"The cartwheel ruff — up to 12 inches deep in starched lace layers. Drum-shaped French farthingale. Embroidered bodice covered in jewels. Elaborate coiled hairstyle or wig. Painted face: white lead, red cheeks.","garments":["Cartwheel starched ruff","French farthingale drum skirt","Jewel-encrusted embroidered bodice","Elaborate wig or coiled hair","White lead painted face"],"habitat":"Elizabethan period drama, Shakespeare productions, Tudor history reenactment, Elizabeth I cosplay.","context":"Elizabeth I was the first monarch to use fashion as calculated propaganda. Her wardrobe included over 2,000 dresses. The Armada Portrait is a fashion document as much as a royal portrait. Her unmarried status made her dress hyper-political.","rarity":"Extinct","see_also":["Tudor Court Dress","Baroque Excess","Renaissance Noblewoman"],"colors":["#FAF8F5 White Ruff","#8B0000 Crimson","#D4AF37 Gold","#2C5530 Elizabethan Green"],"media":["Shakespeare in Love (1998) — film","Elizabeth (1998) — film","The Virgin Queen (TV) — TV"]},"Spanish Court Dress":{"summary":"The rigid, black-encased fashion of the Spanish Habsburg court — the most imitated and feared aesthetic of 16th-century Europe.","era":"c.1520–1650, Spain","mood":"Sombrely imperial, rigidly religious","visual":"Black as the dominant colour of power (expensive Spanish blacks were technically difficult to achieve). Rigid boning and structure. Very high neck ruff. Gold and pearl jewellery. Men in rigid doublet and trunk hose. Women in stiff farthingale.","garments":["Rigid black doublet","High starched neck ruff","Black structured gown","Pearl and gold jewellery","Stiff Spanish farthingale"],"habitat":"Habsburg history, Spanish court cosplay, Velázquez portrait study.","context":"Spanish Habsburg court dress dominated European fashion for over a century. Its stiffness and black palette were explicitly religious. When Philip II dressed the entire court in black for his father's funeral, it became fashion.","rarity":"Extinct","see_also":["Habsburg Black","Velázquez Aesthetic","Elizabethan Aesthetic"],"colors":["#1A1A1A Spanish Black","#D4AF37 Gold","#FAF8F5 White Ruff","#8B0000 Inquisition Red"],"media":["Goya's Ghosts (2006) — film","The Favourite (2018) — film","Velázquez (documentary)"]},"Habsburg Black":{"summary":"The sombre, power-saturated black of the Habsburg dynasty — when an empire dresses in mourning and makes it magnificent.","era":"c.1520–1780, Habsburg Empire","mood":"Dynastically mourning, magnificently sombre","visual":"True black wool and silk of supreme quality. Gold and silver embroidery. Diamond and pearl jewellery. The colour is dark as political statement — wealth displayed through quality, not colour. Spread from Spain to all of Catholic Europe.","garments":["Supreme-quality black silk gown","Black doublet with silver embroidery","Diamond clasp","Black velvet bonnet","Pearl and gold chain"],"habitat":"Habsburg history exhibitions, Austrian and Spanish court cosplay.","context":"The Habsburgs made black the dynastic colour of imperial Catholic Europe. Philip I of Castile adopted it; Charles V spread it. It spread to every Catholic court as an expression of Spanish hegemony.","rarity":"Extinct","see_also":["Spanish Court Dress","Velázquez Aesthetic","Protestant Modest"],"colors":["#1A1A1A Habsburg Black","#D4AF37 Gold","#C0C0C0 Silver","#FAF8F5 White Ruff"],"media":["Amadeus (1984) — film","Goya in Bordeaux (1999) — film"]},"Velázquez Aesthetic":{"summary":"The honest, slightly melancholy dress captured in Velázquez's Spanish court paintings — black silk, silver embroidery, and eyes that see through everything.","era":"c.1623–1660, Madrid","mood":"Melancholically honest, courtly, psychologically deep","visual":"Black silk in soft gradations. Silver and grey embroidery. Golilla lace collar (replacing the ruff under Philip IV). Subdued colours for servants. Children in miniature adult dress. The feel is slightly off — always slightly wrong, always deeply observed.","garments":["Black silk court dress","Golilla lace collar","Silver embroidered sleeves","Subdued servant wool","Miniature adult child dress"],"habitat":"Art history, Velázquez exhibition contexts, Spanish Baroque study.","context":"Velázquez painted more honestly than any other court painter — his figures look like people, not icons. Las Meninas is simultaneously group portrait and meditation on representation. His palette influenced Manet, Sargent, and Francis Bacon.","rarity":"Extinct","see_also":["Spanish Court Dress","Habsburg Black","Old Hollywood Glamour"],"colors":["#2C2C2C Silver-Black","#C0C0C0 Silver Grey","#8B7355 Muted Brown","#D4AF37 Understated Gold"],"media":["Las Meninas (Velázquez, 1656) — art","Goya's Ghosts (2006) — film"]},"Mannerist Aesthetic":{"summary":"The deliberately distorted, anti-classical elegance of 16th-century Mannerism — elongated proportions and studied artifice as artistic statement.","era":"c.1520–1600, Italy","mood":"Artificially elegant, anti-naturalistic","visual":"Extremely elongated figures. Slightly too-long necks. Colours in unexpected combinations. Elaborately uncomfortable poses. Parmigianino's Madonna with the Long Neck is the visual definition. In dress: elongated silhouettes, studied elegance over natural proportion.","garments":["Elongated silk gown","Unnaturally long sleeves","Pale unexpected colour combinations","Studied elaborate pose","Pearl ornament in hair"],"habitat":"Art history, Italian Renaissance study, fashion editorial drawing on Mannerist imagery.","context":"Mannerism was the first post-classical European art movement, deliberately departing from Renaissance harmony. Its influence on fashion is indirect — it created a vocabulary of studied artifice and beautiful distortion that recurs in fashion photography.","rarity":"Extinct","see_also":["Florentine Renaissance","Venetian Court Dress","Art Hoe"],"colors":["#7B68EE Acid Lavender","#C1440E Acid Orange","#4A7C59 Sickly Green","#D4AF37 Gold"],"media":["Parmigianino's Madonna with the Long Neck (1534–40) — art","Pontormo's Deposition (1525–28) — art"]},"Versailles Court":{"summary":"The theatrical magnificence of Louis XIV's Versailles — fashion as the instrument of absolute political control.","era":"c.1660–1789, Versailles","mood":"Magnificently theatrical, politically compelled","visual":"For women: the grand habit — off-shoulder bodice, enormous pannier skirt, long train. For men: knee-length coat with elaborate embroidery, breeches, stockings. Towering powdered wig for both. Heeled shoes. Face patches.","garments":["Off-shoulder grand habit bodice","Pannier-wide court skirt","Elaborate embroidered coat","Powdered white wig","Heeled court shoes"],"habitat":"Versailles, French court history cosplay, Marie Antoinette references, opera productions.","context":"Louis XIV made fashion a political instrument — he required nobility to spend at Versailles, and attending required constant new, expensive, correct dress. The fashion industry of France was born as a royal political project.","rarity":"Extinct","see_also":["Louis XIV Aesthetic","Marie Antoinette Aesthetic","Baroque Excess"],"colors":["#D4AF37 Gold","#C0C0C0 Silver","#8B0000 Royal Red","#2E5A8B Royal Blue"],"media":["Sofia Coppola's Marie Antoinette (2006) — film","Versailles (TV series) — TV","The Favourite (2018) — film"]},"Louis XIV Aesthetic":{"summary":"The Solar King's personal aesthetic — the most powerful man in Europe expressed through lace, red heels, and absolute self-presentation.","era":"c.1643–1715, Versailles","mood":"Absolutely regal, self-consciously supreme","visual":"Extremely high red-heeled shoes (only royalty could wear red heels). Enormous lace cravat. Long embroidered coat (justaucorps). Wig of enormous size and curled splendour. Diamond-encrusted Order badge. Ermine-lined cloak.","garments":["Red-heeled court shoes","Enormous curled wig","Lace cravat","Embroidered justaucorps coat","Diamond Order badge"],"habitat":"Versailles history, Sun King cosplay, French Baroque study.","context":"Louis XIV wore red heels specifically to visually elevate himself above other men. He understood that visual magnificence was political power. His court dress was copied across every European court within years.","rarity":"Extinct","see_also":["Versailles Court","Baroque Excess","French Girl Style"],"colors":["#D4AF37 Solar Gold","#8B0000 Royal Crimson","#2E5A8B Royal Blue","#C0C0C0 Silver"],"media":["Versailles (TV series) — TV","The Man in the Iron Mask (1998) — film","Molière (2007) — film"]},"Baroque Excess":{"summary":"The aesthetic of more-is-more in 17th-century European courts — lace, gold, wig, and the deliberate overwhelming of the senses.","era":"c.1600–1720, Europe","mood":"Deliberately overwhelming, magnificently excessive","visual":"Gold everywhere. Enormous wigs. Deep lace at collar and cuffs. Silk in multiple colours. Every surface embroidered. Pearls and diamonds. The point is excess — to demonstrate that you have so much you can waste it.","garments":["Gold-embroidered silk coat","Enormous curled wig","Deep lace collar and cuffs","Diamond clasp","Silk pannier skirts"],"habitat":"Baroque history, period drama, operatic costume, Versailles tourism.","context":"Baroque excess was a deliberate aesthetic and political strategy — conspicuous consumption as power display. The church equally embraced it as Counter-Reformation propaganda. Both secular and sacred Baroque competed in magnificence.","rarity":"Extinct","see_also":["Versailles Court","Louis XIV Aesthetic","Venetian Court Dress"],"colors":["#D4AF37 Gold","#8B0000 Crimson","#2E5A8B Deep Blue","#C0C0C0 Silver"],"media":["Versailles (TV series) — TV","Amadeus (1984) — film","The Favourite (2018) — film"]},"Puritan Aesthetic":{"summary":"The theologically austere dress of English and American Puritanism — the sartorial rejection of Anglican luxury as religious statement.","era":"c.1620–1700, England and New England","mood":"Theologically severe, morally legible","visual":"Black, grey, or dark colours only. No lace, no embroidery, no colour. Clean white linen collar. Simple broadcloth. Modest head covering for women. Avoidance of all ornament as theological principle.","garments":["Black broadcloth coat","Plain white linen collar","Simple white cap","Dark grey dress","Buckled leather shoes"],"habitat":"Colonial American history, Thanksgiving reenactment, Salem witch trial contexts, Halloween.","context":"Puritanism attacked Anglican ceremony as Catholic idolatry, extending to dress. The Massachusetts Bay Colony had exceptionally strict sumptuary codes. The pointed hat is a later invention; historical Puritans wore many styles.","rarity":"Extinct","see_also":["Protestant Modest","Amish & Plain Dress","Colonial American Dress"],"colors":["#1A1A1A Black","#FAF8F5 White Collar","#5B5B5B Dark Grey","#5B3A29 Brown Serge"],"media":["The Crucible (1996) — film","The Witch (2015) — film","Midsommar (2019) — film"]},"Colonial American Dress":{"summary":"The trans-Atlantic dress of British North America — English fashion interpreted through local materials, frontier practicality, and growing independence.","era":"c.1620–1776, British North America","mood":"Practically aspirational, trans-Atlantic","visual":"English fashions in local materials — homespun wool, buckskin, flax linen. Gentry attempting London fashions. Tradespeople in aprons and practical dress. Homespun became a political statement pre-Revolution: wearing it was a patriot act.","garments":["Homespun linen shirt","Practical wool petticoat","Frock coat for gentry","Work apron","Buckled leather shoes"],"habitat":"Colonial Williamsburg, American heritage events, Revolutionary War reenactment.","context":"Colonial American dress is the story of fashion under tension — between aspiring to English metropolitan style and developing distinctly American pragmatism. Homespun fabric as political choice is the first example of fashion as political statement in American history.","rarity":"Extinct","see_also":["Vintage Americana","Frontier Workwear Aesthetic","Heritage Core"],"colors":["#8B7355 Homespun","#4A7C59 Indigo Blue","#C1440E Madder Red","#FAF8F5 Linen White"],"media":["The Patriot (2000) — film","Hamilton (musical) — theatre","John Adams (TV series) — TV"]},"Georgian Town Dress":{"summary":"The practical fashionable dress of 18th-century urban England — the sack-back gown, the stomacher, and the negotiation between fashion and daily life.","era":"c.1714–1790, England","mood":"Fashionably practical, urban and sociable","visual":"The open robe (sack-back gown): wide pleats falling from shoulders to floor at back. Stomacher at front. Matching petticoat. Hooped underskirt. Women in soft jewel tones and pastels. Men in frock coat, waistcoat, breeches. Hair powdered.","garments":["Sack-back open robe","Embroidered stomacher","Hooped petticoat","Men's frock coat and breeches","Powdered wig or hair"],"habitat":"Georgian living history, Jane Austen-adjacent cosplay, English Heritage events, period drama.","context":"Georgian town dress was the first truly seasonal fashion system in England. The fashion press emerged in this period to communicate style to those not in London. Fashion magazines were born here.","rarity":"Extinct","see_also":["Georgian Country House","Regency Morning Dress","Versailles Court"],"colors":["#C1440E Madder Pink","#4A7C59 Georgian Green","#D4AF37 Straw Yellow","#FAF8F5 Muslin White"],"media":["Tom Jones (1963) — film","Barry Lyndon (1975) — film","Gentleman Jack (TV series) — TV"]},"Georgian Country House":{"summary":"The relaxed fashionable dress of 18th-century English aristocracy in the country — less formal, more natural, and the origin of 'country casual'.","era":"c.1714–1790, English countryside","mood":"Relaxed aristocratic, naturalistic","visual":"Less formal than town dress. Women in more practical round gown. Men in riding coat and buckskin breeches. Morning dress simpler. Wool predominates over silk. The country house weekend begins to have its own aesthetic.","garments":["Practical round gown","Wool riding habit","Buckskin breeches","Country house morning dress","Leather riding boots"],"habitat":"Country house heritage events, English Heritage, period drama.","context":"The English country house aesthetic invented the idea that dressing down in the country was itself a mark of taste — an aristocratic privilege. This logic persists: only the secure can dress down.","rarity":"Extinct","see_also":["Georgian Town Dress","British Heritage Fashion","Country House Style"],"colors":["#4A7C59 Country Green","#8B7355 Tweed Brown","#C1440E Hunting Red","#FAF8F5 Muslin White"],"media":["Pride and Prejudice (2005) — film","Tom Jones (1963) — film","Barry Lyndon (1975) — film"]},"Georgian Street Dress":{"summary":"The everyday dress of the 18th-century urban working and middle class — practical, less fashionable, vividly documented in Hogarth's engravings.","era":"c.1714–1790, English cities","mood":"Practically urban, Hogarth-vivid","visual":"Working women in short gown, apron, and cap. Tradeswomen in practical wool. Men in plain coat and breeches. Street sellers in aprons and mob caps. The fashionable elements present but adapted for practical life. Striped fabric common among working class.","garments":["Short practical gown","Work apron","Mob cap","Plain wool coat","Wooden pattens"],"habitat":"Georgian social history, Hogarth art contexts, working-class history.","context":"Hogarth's engravings are the definitive record of Georgian street dress — full of vivid individuals in their actual daily clothes. The gulf between fashionable prints and lived reality was enormous.","rarity":"Extinct","see_also":["Georgian Town Dress","Medieval Peasant","Victorian Street Dress"],"colors":["#8B7355 Street Brown","#C1440E Striped Red","#4A7C59 Apron Blue","#FAF8F5 Mob Cap White"],"media":["Tom Jones (1963) — film","Hogarth's London paintings (1730s–50s) — art"]},"Servant Aesthetic":{"summary":"The formal livery and practical dress of domestic servants across the 18th and 19th centuries — the precise visual grammar of service.","era":"c.1700–1900, Europe and Britain","mood":"Precisely hierarchical, service-coded","visual":"Upper servants in quality black or dark formal dress. Footmen in full livery — knee breeches, powdered wig, house colours. Housemaids in grey or blue print dress with white apron and cap. Each position had specific dress codes.","garments":["Footman's livery coat","White housemaid apron","Mob cap","Black formal dress for housekeeper","Powdered wig for formal livery"],"habitat":"Downton Abbey fan contexts, Victorian heritage events, domestic service history.","context":"Servant dress was a precise status system — each position in the domestic hierarchy had specific dress codes. Upper servants policed these distinctions carefully. A housekeeper's black silk was a hard-won distinction from the housemaid's print cotton.","rarity":"Extinct","see_also":["Victorian Factory Worker","Hospitality Uniform Aesthetic","Gothic Court Dress"],"colors":["#1A1A1A Housekeeper Black","#FAF8F5 Apron White","#5B5B5B Grey Work","#2C5530 Livery Green"],"media":["Downton Abbey (TV series) — TV","Upstairs Downstairs (TV series) — TV","The Remains of the Day (1993) — film"]},"Bath Assembly Rooms":{"summary":"The fashionable resort dress of Regency-adjacent Bath — the intersection of health, society, and fashion at England's premier spa city.","era":"c.1750–1830, Bath, England","mood":"Fashionably sociable, spa-elegant","visual":"Muslins and light fabrics reflecting watered-down Parisian styles. White as dominant colour for women. Spencer jackets. Reticule bags. Bonnets. Men in tailored town wear. The Pump Room demanded a standard of appearance.","garments":["White muslin gown","Spencer jacket","Silk bonnet","Reticule drawstring bag","Long gloves"],"habitat":"Jane Austen events, Regency cosplay, Bath living history, period drama.","context":"Bath was the primary English social destination for those not rich enough for London. Jane Austen's novels document it precisely — its rigid social codes, fashion consciousness, and function as marriage market.","rarity":"Extinct","see_also":["Regency Morning Dress","Jane Austen Aesthetic","Georgian Town Dress"],"colors":["#FAF8F5 Muslin White","#C1440E Warm Pink","#4A7C59 Sage Green","#D4AF37 Straw"],"media":["Persuasion (2022) — film","Northanger Abbey (2007) — film","The Beau Brummell Story (1954) — film"]},"Macaroni Aesthetic":{"summary":"The extreme fashion youth cult of 1770s London — enormous wigs, tiny hats, continental excess, and the first documented British fashion tribe.","era":"c.1764–1780, London","mood":"Outrageously fashionable, continental, queerly coded","visual":"Enormous powdered wig of impossible height. Tiny flat hat perched at a rakish angle. Tight striped breeches. Bright embroidered coat. Long queue wig. Face patches. Heeled shoes with large buckles. The look of 'Yankee Doodle Dandy'.","garments":["Enormous powdered wig","Tiny perched flat hat","Tight striped breeches","Bright embroidered coat","High-buckled heeled shoes"],"habitat":"18th century fashion history, the song 'Yankee Doodle', British fashion tribe history.","context":"The Macaroni were the first specifically English fashion tribe — young men who had been on the Grand Tour and returned with Continental excess. 'Yankee Doodle Dandy called it macaroni' directly references them. They were widely satirised in prints.","rarity":"Extinct","see_also":["Beau Brummell Aesthetic","Dandy Aesthetic","Camp Aesthetic"],"colors":["#E8C547 Straw Yellow","#C1440E Poppy Red","#4A7C59 Eau de Nil","#D4AF37 Powder Gold"],"media":["Barry Lyndon (1975) — film","Midnight in Paris (2011) — film (adjacent)"]},"French Rococo Court":{"summary":"The pastel, feathered, playfully excessive dress of pre-Revolutionary Versailles — the Marquise de Pompadour as supreme arbiter of taste.","era":"c.1720–1789, Versailles","mood":"Playfully excessive, pastel-pretty, pre-Revolutionary","visual":"Silk robe à la française in pastel pink, blue, or yellow. Enormous side panniers creating wide horizontal silhouette. Lace fichu at neckline. Hair powdered and dressed to enormous height with jewels, feathers, ships, and gardens as decorations.","garments":["Pastel silk robe à la française","Enormous side panniers","Lace fichu","Towering powdered hair architecture","Beauty patch"],"habitat":"French Rococo art history, Versailles, pre-Revolutionary France cosplay.","context":"French Rococo fashion reached heights of fantasy that made it a target of Revolutionary satire. The hair architecture of the 1780s — sometimes 3 feet high — required ladders for dressing and made entering carriages impossible.","rarity":"Extinct","see_also":["Marie Antoinette Aesthetic","Versailles Court","Louis XIV Aesthetic"],"colors":["#F5C6CB Blush Pink","#B0C4DE Powder Blue","#F5E6C8 Champagne","#D4AF37 Gold"],"media":["Marie Antoinette (2006) — film","Ridicule (1996) — film","Jefferson in Paris (1995) — film"]},"Marie Antoinette Aesthetic":{"summary":"The legendary excess of France's last queen — towering wigs, pastoral games, and the fashion that helped ignite a revolution.","era":"c.1770–1793, Versailles","mood":"Exquisitely excessive, tragically oblivious","visual":"The pouf hairstyle — hair architecture 3 feet high, decorated with ships, fruit, pastoral scenes. Rose Bertin as the first named celebrity fashion designer. The chemise à la reine: revolutionary in its muslin simplicity (and scandalous in its apparent undress).","garments":["Towering pouf hairstyle","Embroidered silk court dress","Chemise à la reine muslin","Diamond necklace","Shepherd pastoral costume"],"habitat":"Versailles, French history, Sofia Coppola film contexts, Marie Antoinette cosplay.","context":"Marie Antoinette's fashion expenditure was politically explosive. Her chemise à la reine (simple white muslin) was interpreted as appearing in her underwear. Rose Bertin was the world's first celebrity fashion designer.","rarity":"Extinct","see_also":["French Rococo Court","Versailles Court","Lady Gaga Aesthetic"],"colors":["#F5C6CB Rose Poudré","#B0C4DE Ciel Blue","#FAF8F5 Powder White","#D4AF37 Gold"],"media":["Marie Antoinette (2006, Sofia Coppola) — film","Farewell My Queen (2012) — film","The Affair of the Necklace (2001) — film"]},"Rococo Pastoral":{"summary":"The aristocratic fantasy of rural simplicity — silk shepherdesses and silver-buckled shoes playing at farming in 18th-century courts.","era":"c.1720–1789, France","mood":"Playfully pastoral, aristocratically artificial","visual":"Pale silk dress with floral pastoral embroidery. Straw hat with silk ribbon (the bergère). Silver crook. Fine lawn apron. Low-heeled shoes with silver buckles. The entire point is the artifice of simplicity — luxury performing poverty.","garments":["Floral silk pastoral gown","Silk-ribboned bergère hat","Silver shepherd's crook","Fine lawn apron","Silver-buckled low heels"],"habitat":"French Rococo art, Watteau painting study, 18th century pastoral fashion.","context":"Marie Antoinette's Hameau de la Reine at Versailles — a fake farm — is the most famous example of aristocratic pastoral play. Watteau's fêtes galantes paintings are the visual document. Cottagecore is its direct 21st-century descendant.","rarity":"Extinct","see_also":["French Rococo Court","Marie Antoinette Aesthetic","Cottagecore"],"colors":["#F5C6CB Pastoral Pink","#B8D8A0 Meadow Green","#F5E6C8 Cream","#87CEEB Sky Blue"],"media":["Marie Antoinette (2006) — film","The Watteau Room (documentary)","Watteau's fêtes galantes paintings — art"]},"Boucher Aesthetic":{"summary":"The rosy, confected femininity of François Boucher's paintings — pink silk, tumbling ribbons, and the decorative female body as luxury object.","era":"c.1720–1770, Paris","mood":"Pink-confected, frivolously beautiful","visual":"Pale rose and sky blue silk. Tumbling ribbons and bows at every point. Ruffled fichu at neck. Lace at cuffs. Hair loosely dressed. The look is slightly disarrayed — caught in a private moment. Soft indoor dress.","garments":["Rose silk gown","Ribbon-tied fichu","Lace cuff ruffles","Tumbling ribbons in hair","Silk indoor slippers"],"habitat":"Rococo art history, 18th century femininity study.","context":"Boucher's work represents the female decorative ideal of the Ancien Régime — woman as exquisite luxury object. His patron Madame de Pompadour was the defining figure, sitting for multiple portraits.","rarity":"Extinct","see_also":["French Rococo Court","Rococo Pastoral","Soft Feminine"],"colors":["#F5C6CB Rose Pink","#87CEEB Soft Blue","#F5E6C8 Cream","#D4AF37 Gilt"],"media":["Portrait of Madame de Pompadour (Boucher, 1756) — art","Marie Antoinette (2006) — film"]},"Fragonard Aesthetic":{"summary":"The swing and the stolen kiss of Fragonard — outdoor flirtation, billowing skirts, and the aesthetic of pleasure before the Revolution.","era":"c.1760–1789, France","mood":"Flirtatious, light-dappled, pre-Revolutionary","visual":"Billowing silk skirts in pastel pink and yellow. Outdoor summer dress. Hair dressed simply with flowers. Light linen for warm weather. Garden-dappled light. The aesthetic of romantic encounter and aristocratic play.","garments":["Billowing pastel silk skirt","Summer garden bodice","Flower-dressed hair","Light linen chemise","Silk ribbon sash"],"habitat":"Fragonard art history, 18th century garden party aesthetics.","context":"Fragonard painted the last generation that could afford frivolity. 'The Swing' (1767) is one of the most analysed fashion paintings in art history — everything is about the petticoat. His patrons were swept away in the Revolution.","rarity":"Extinct","see_also":["French Rococo Court","Rococo Pastoral","Bloomcore"],"colors":["#F5C6CB Fragonard Pink","#F5E6C8 Garden Cream","#B8D8A0 Leaf Green","#87CEEB Garden Sky"],"media":["The Swing (Fragonard, 1767) — art","Marie Antoinette (2006) — film"]},"Painted Lady":{"summary":"The fashionable women of 18th-century Europe painted with extreme artifice — white lead foundation, rouge patches, and beauty as applied art.","era":"c.1700–1790, Europe","mood":"Theatrically artificial, beauty-as-performance","visual":"Face painted chalk white with lead-based foundation. Two spots of vivid rouge. Beauty patches (mouches) in shapes — star, moon, crescent — indicating availability or political affiliation. Hair powdered and dressed to height.","garments":["White lead face paint","Vivid cheek rouge spots","Shaped silk beauty patches","Powdered and dressed hair","Pearl choker necklace"],"habitat":"18th century fashion history, theatrical makeup history, Rococo art.","context":"18th-century cosmetics were toxic — lead-based foundation caused slow poisoning, mercury in rouge, belladonna eye drops caused blindness. Women died fashionably. The beauty patch system was an entire semaphore code of desire and politics.","rarity":"Extinct","see_also":["French Rococo Court","Marie Antoinette Aesthetic","Macaroni Aesthetic"],"colors":["#FAF8F5 White Lead","#FF6B6B Rouge Red","#1A1A1A Beauty Patch","#F5E6C8 Powder Cream"],"media":["Barry Lyndon (1975) — film","Marie Antoinette (2006) — film"]},"Founding Era Dress":{"summary":"The late 18th-century dress of America's founding generation — revolutionary simplicity influenced by classical ideals and the deliberate break from monarchy.","era":"c.1776–1800, United States","mood":"Republicanly classical, deliberately undynastic","visual":"Women in high-waisted white muslin influenced by Neoclassicism. Men in frock coat transitioning to long trousers. Homespun as patriotic statement. No royal court trappings. The toga appeared in portraits.","garments":["High-waisted white muslin","Frock coat and waistcoat","Knee breeches","Simple leather shoes","Republican simplicity palette"],"habitat":"American heritage, Fourth of July, Hamilton musical contexts, Smithsonian exhibitions.","context":"America's founding generation consciously constructed a republican dress aesthetic — avoiding monarchical excess while maintaining classical references that legitimised their democratic project.","rarity":"Extinct","see_also":["Colonial American Dress","Neoclassical Revival Dress","Regency Morning Dress"],"colors":["#FAF8F5 Republican White","#1B4F72 Patriot Blue","#8B0000 Colonial Red","#D4AF37 Brass"],"media":["Hamilton (musical) — theatre","John Adams (HBO series) — TV","The Patriot (2000) — film"]},"French Revolutionary Dress":{"summary":"The politically charged dress of the French Revolution — red Phrygian caps, tricolour cockades, and the deliberate assault on aristocratic fashion.","era":"c.1789–1799, France","mood":"Politically charged, egalitarian, violently symbolic","visual":"Red Phrygian liberty cap. Tricolour cockade pinned at all times (legally mandatory). Long pantalon trousers instead of aristocratic breeches. Simple carmagnole jacket. All powder and aristocratic artifice rejected.","garments":["Red Phrygian liberty cap","Tricolour cockade","Long pantalon trousers","Carmagnole jacket","White republican dress"],"habitat":"French Revolution history, political costume references, liberty cap symbolism.","context":"The French Revolution produced the first example of politicised mass dress in European history — the cockade was legally mandatory, and the trouser versus breeches distinction marked who would live and who would die.","rarity":"Extinct","see_also":["French Rococo Court","Liberty Aesthetic","Political & Ideological"],"colors":["#8B0000 Revolutionary Red","#FAF8F5 Republican White","#1B4F72 Liberty Blue","#2C2C2C Sansculotte"],"media":["La Marseillaise (1938) — film","Scaramouche (1952) — film","A Tale of Two Cities (1935) — film"]},"Sans-Culotte Aesthetic":{"summary":"The dress of the French revolutionary working class — long trousers as political statement, the rejection of aristocratic breeches.","era":"c.1789–1799, France","mood":"Revolutionary, working-class, politically fundamental","visual":"Long trousers (pantalon) versus aristocratic knee-length breeches — the defining distinction. Short carmagnole jacket. Red Phrygian cap. Clogs or plain shoes. Striped fabric. The name literally means 'without breeches'.","garments":["Long pantalon trousers","Short carmagnole jacket","Red Phrygian cap","Striped working cloth","Wooden clogs or plain shoes"],"habitat":"French Revolution history, radical politics references.","context":"The sans-culotte trouser was the most politically charged garment in European history. Wearing or not wearing it determined how you were treated at Revolutionary checkpoints. Modern men's trousers descend directly from this moment.","rarity":"Extinct","see_also":["French Revolutionary Dress","Liberty Aesthetic","Union Workwear Aesthetic"],"colors":["#5B5B5B Working Grey","#8B0000 Phrygian Red","#4A7C59 Republican Green","#8B7355 Rough Linen"],"media":["Danton (1983) — film","A Tale of Two Cities (various) — film","La Révolution (TV series) — TV"]},"Liberty Aesthetic":{"summary":"The radical aesthetic of political liberation movements — from the French Republic's Marianne to 19th-century feminist reform dress.","era":"c.1789–1900, Western democracies","mood":"Idealistic, heroically classical, reform-minded","visual":"Classical draped white dress for feminine Liberty figures. Phrygian cap. Tricolour. Marching dress for reform movements. Rational dress reform. Simple, classical, aspirationally equal.","garments":["White classical draped dress","Phrygian liberty cap","Tricolour sash","Reform movement marching dress"],"habitat":"Political history, liberty iconography, democratic republic contexts.","context":"Liberty as a personified figure in white draped dress runs from Delacroix's Liberty Leading the People to the Statue of Liberty. The aesthetic connects Greek democratic ideals to modern political aspirations.","rarity":"Extinct","see_also":["French Revolutionary Dress","Suffragette Dress","Neoclassical Revival Dress"],"colors":["#FAF8F5 Liberty White","#8B0000 Phrygian Red","#1B4F72 Republic Blue","#4A7C59 Hope Green"],"media":["Liberty Leading the People (Delacroix, 1830) — art","Les Misérables (2012) — film","Hamilton (musical) — theatre"]},"Directoire Aesthetic":{"summary":"The brief, scandalously thin fashion of post-Revolutionary France — transparent muslin, visible silhouette, and Greek democracy made dress.","era":"c.1795–1799, Paris","mood":"Scandalously neo-classical, deliberately transgressive","visual":"Transparent white muslin with very little underneath. Extremely high waistline just below the bust. No hoop or petticoat — the body's silhouette visible. Some wore flesh-toned body stockings. Greek sandals with laces up the calf.","garments":["Transparent white muslin gown","Flesh-toned body stocking","Greek sandals with leg lacing","High empire waistline","Simple ribbon sash"],"habitat":"French Revolutionary period cosplay, fashion history.","context":"The Directoire fashion was a deliberate provocation — the most revealing fashion in modern European history to that point. Women like Madame Récamier wore transparent muslin to political events. It lasted about five years before Napoleon imposed decorum.","rarity":"Extinct","see_also":["French Revolutionary Dress","Neoclassical Revival Dress","Chiton Aesthetic"],"colors":["#FAF8F5 Transparent White","#F5E6C8 Flesh Tone","#C1440E Pompeian Red","#1B4F72 Greek Blue"],"media":["Dangerous Liaisons (1988) — film","Jefferson in Paris (1995) — film"]},"Neoclassical Revival Dress":{"summary":"The empire-line gown of the early 19th century — white muslin, high waist, and the Greek democratic ideal made Regency fashion.","era":"c.1795–1820, Europe","mood":"Classically pure, democratically elegant","visual":"High empire waist just below bust. Soft white or pale muslin. Short sleeves or long gloves. Simple Greek key embroidery at hem. Flat sandals or slippers. Cashmere shawl for warmth. Hair in loose Grecian style.","garments":["White empire-line muslin gown","Short puffed sleeves","Greek key embroidered hem","Flat silk slippers","Cashmere shawl"],"habitat":"Regency cosplay, Jane Austen events, early 19th century living history.","context":"Neoclassical dress emerged from intellectual enthusiasm for Greco-Roman democracy that drove both the American and French Revolutions. The empire line gown was simultaneously democratic (simple) and idealistic (classical).","rarity":"Extinct","see_also":["Directoire Aesthetic","Regency Morning Dress","Jane Austen Aesthetic"],"colors":["#FAF8F5 Muslin White","#C1440E Greek Key Red","#1B4F72 Neoclassical Blue","#D4AF37 Greek Gold"],"media":["Emma (2020) — film","Mansfield Park (1999) — film","Pride and Prejudice (2005) — film"]},"Josephine Aesthetic":{"summary":"The imperial glamour of Empress Joséphine — Kashmiri shawls, empire gowns, and the world's first celebrity fashion influencer.","era":"c.1796–1814, France","mood":"Imperially glamorous, trend-setting, Martiniquaise","visual":"Empire line gown in silk or muslin. Imperial purple and gold embroidery for state occasions. Kashmiri shawl — she popularised them in Europe. Jewellery from Napoleon's campaigns. Diadems. Hair in loose Grecian curls.","garments":["Empire gown in imperial silk","Kashmiri shawl","Golden diadem crown","Campaign-jewellery necklace","Purple imperial embroidery"],"habitat":"Napoleonic history, empire fashion exhibitions, period drama.","context":"Joséphine was the first modern celebrity fashion influencer — her adoption of Kashmiri shawls created a fashion industry for them across Europe. She spent enormous sums on dress while Napoleon was bankrolling military campaigns.","rarity":"Extinct","see_also":["Neoclassical Revival Dress","Marie Antoinette Aesthetic","Empire Court Dress"],"colors":["#6B2D8A Imperial Purple","#D4AF37 Imperial Gold","#FAF8F5 Muslin White","#C1440E Kashmir Red"],"media":["Désirée (1954) — film","Napoleon (TV series) — TV","Joséphine ou la Comédie des Ambitions — film"]},"Empire Court Dress":{"summary":"The formal court dress of Napoleonic France — back to the grand habit, but in neoclassical style with imperial bee embroidery.","era":"c.1804–1815, Paris","mood":"Imperial, neoclassically grand","visual":"For women: court train attached at shoulders, low decolletage, short puffed sleeves, velvet or silk in imperial colours. For men: embroidered court coat with knee breeches (reversing the trouser liberation). Gold bee embroidery — Napoleon's symbol.","garments":["Imperial velvet court train","Gold bee-embroidered bodice","Short puffed sleeves","Court knee breeches for men","Jewelled diadem"],"habitat":"Napoleonic history, Empire period drama, Louvre art contexts.","context":"Napoleon reinstituted formal court dress to rehabilitate the court system inherited from Revolution. He required women to wear court dress regardless of age or comfort. He was creating an empire, not a republic.","rarity":"Extinct","see_also":["Josephine Aesthetic","Versailles Court","Neoclassical Revival Dress"],"colors":["#6B2D8A Imperial Purple","#D4AF37 Napoleonic Gold","#8B0000 Imperial Red","#FAF8F5 Court White"],"media":["Waterloo (1970) — film","Napoleon (2023) — film","The Duchess (2008) — film"]},"Napoleonic Military Fashion":{"summary":"The spectacularly theatrical military dress of the Napoleonic wars — hussar braiding, cuirassier armour, and the most elaborately dressed army in history.","era":"c.1799–1815, France and Europe","mood":"Theatrically martial, colour-saturated, heroic","visual":"Hussar dolman jacket with looped braiding (frogging) across the chest. Shako or czapka helmet. Tall bearskin for the Grenadiers de la Garde. Cuirassier armour. Vivid colours by regiment. Campaign medals.","garments":["Hussar frogged dolman","Tall bearskin bonnet","Cuirassier breastplate","Colourful regimental coat","Campaign medal row"],"habitat":"Napoleonic reenactment groups, Waterloo commemorations, military history exhibitions.","context":"Napoleon understood that military dress was propaganda — his army was spectacularly uniformed to serve morale and intimidation. Waterloo reenactment is one of Europe's largest living history events.","rarity":"Extinct","see_also":["Heraldic Aesthetic","Military Masculine","Wall Street Aesthetic"],"colors":["#1B4F72 Imperial Blue","#8B0000 Legion Red","#D4AF37 Brass Gold","#C0C0C0 Silver"],"media":["Waterloo (1970) — film","War and Peace (1966) — film","Napoleon (2023) — film"]},"Regency Morning Dress":{"summary":"The informal morning dress of the Regency period — the original casual wear of the early 19th century upper class.","era":"c.1800–1820, England","mood":"Gently informal, muslin-soft","visual":"White or pale muslin. Higher neck than evening dress. Long sleeves. Simple pelisse coat for outdoors. Straw bonnet. Morning cap at home. Comfortable by Regency standards — no elaborate hairdressing required.","garments":["Pale muslin morning gown","Long-sleeved chemisette","Pelisse coat","Simple straw bonnet","Morning cap at home"],"habitat":"Regency living history, Jane Austen events, Bridgerton aesthetic inspiration.","context":"Morning dress was the Regency concept of casual wear — still muslin and carefully made, but simpler than afternoon or evening dress. Jane Austen spent most of her day in morning dress. The distinction between morning, afternoon, and evening dress was rigidly maintained.","rarity":"Extinct","see_also":["Jane Austen Aesthetic","Neoclassical Revival Dress","Spencer Jacket Aesthetic"],"colors":["#FAF8F5 Muslin White","#F5C6CB Sprig Pink","#B0C4DE Morning Blue","#E8D5B0 Natural Linen"],"media":["Pride and Prejudice (1995 BBC) — TV","Sense and Sensibility (1995) — film","Bridgerton (TV series) — TV"]},"Spencer Jacket Aesthetic":{"summary":"The short cropped jacket of the Regency period — the original crop top, functionally brilliant at adding warmth without obscuring the empire waistline.","era":"c.1795–1820, England","mood":"Proto-modern, smartly cropped","visual":"Short jacket ending at the empire waist, worn over high-waisted muslin gown. Long sleeves. Military-influenced frogging or plain. Worn for outdoors and walking. Wool, silk, or velvet according to occasion.","garments":["Short cropped spencer jacket","Long-sleeved fitted arms","Military frogging trim","Empire-line gown beneath","Matching fabric bonnet"],"habitat":"Regency cosplay, fashion history, early cropped jacket history.","context":"The Spencer was functionally brilliant — it added warmth to thin muslin without obscuring the empire waistline. Its cropped silhouette anticipates the crop top by 200 years. It remained fashionable until the waist dropped to its natural position.","rarity":"Extinct","see_also":["Regency Morning Dress","Jane Austen Aesthetic","Napoleonic Military Fashion"],"colors":["#8B0000 Scarlet Spencer","#1B4F72 Navy Spencer","#FAF8F5 White Muslin","#4A7C59 Green Spencer"],"media":["Pride and Prejudice (2005) — film","Northanger Abbey (2007) — film"]},"Regency Promenade":{"summary":"The smart walking dress of the Regency period — the outfit designed to be seen on the fashionable morning promenade.","era":"c.1800–1825, London and Bath","mood":"Smart, socially conscious, display-oriented","visual":"Pelisse coat in silk or fine wool over muslin. Straw or silk bonnet. Half-boots. Long gloves. Reticule bag. Parasol. The entire outfit assembled for maximum visibility on the fashionable walk.","garments":["Silk pelisse walking coat","Silk or straw bonnet","Half-boots","Long white gloves","Silk reticule bag"],"habitat":"Regency living history, Jane Austen events, Bath period tourism.","context":"The morning promenade was a social performance — you dressed to be seen. Hyde Park's Rotten Row, Bath's Sydney Gardens, Brighton's seafront were all stages for Regency social theatre.","rarity":"Extinct","see_also":["Regency Morning Dress","Jane Austen Aesthetic","Bath Assembly Rooms"],"colors":["#FAF8F5 Promenade White","#F5C6CB Pelisse Pink","#1B4F72 Navy Blue","#D4AF37 Straw"],"media":["Emma (2020) — film","Persuasion (2022) — film","Bath (documentary)"]},"Jane Austen Aesthetic":{"summary":"The embodied dress aesthetic of Austen's novels — white muslin, sprig patterns, spencer jackets, and the social choreography of dress.","era":"c.1800–1820; revival 1995–present","mood":"Gently aspirational, socially coded, quietly witty","visual":"White or sprigged muslin with embroidered motifs. Spencer jacket for warmth. Straw bonnet. Long gloves for formal occasions. Pelisse coat in walking. Reticule. Half-boots. The look that fills every Austen adaptation.","garments":["Sprigged muslin gown","Short spencer jacket","Decorated straw bonnet","Long white gloves","Small reticule"],"habitat":"Jane Austen Society events, Chawton House, Regency cosplay, film adaptations (1995 Pride and Prejudice onwards).","context":"Jane Austen herself wrote about dress with great precision — her letters record purchases, prices, and opinions. The 1995 BBC Pride and Prejudice established the visual canon. Annual Regency balls happen worldwide.","rarity":"Niche","see_also":["Regency Morning Dress","Spencer Jacket Aesthetic","Neoclassical Revival Dress"],"colors":["#FAF8F5 Muslin White","#F5C6CB Sprigged Pink","#B0C4DE Wedgwood Blue","#E8D5B0 Natural Linen"],"media":["Pride and Prejudice (1995 BBC) — TV","Emma (2020) — film","Bridgerton (TV series) — TV","Sense and Sensibility (1995) — film"]},"Beau Brummell Aesthetic":{"summary":"The revolutionary simplicity of the first dandy — the invention of the modern man's suit through studied understatement.","era":"c.1794–1816, London","mood":"Perfectly understated, quietly revolutionary","visual":"Dark coat of perfect cut — no embroidery. Pale pantaloons. Impeccably white, perfectly tied cravat (hours of daily effort). Highly polished Hessian boots. The entire effect is of effortless perfection achieved through extreme effort.","garments":["Dark perfectly cut coat","Pale pantaloons","Impeccably tied white cravat","Highly polished Hessian boots","Simple waistcoat"],"habitat":"Dandy history, men's tailoring study, Savile Row heritage.","context":"Brummell invented the modern suit by removing decoration entirely and placing all value on cut, fabric, and fit. His famous routine required hours of dressing. His influence on menswear is immeasurable — the dark business suit descends from him.","rarity":"Extinct","see_also":["Dandy Aesthetic","Savile Row Aesthetic","Old Money"],"colors":["#1A1A1A Black Coat","#FAF8F5 White Cravat","#8B7355 Buff Pantaloon","#5B3A29 Hessian Brown"],"media":["Beau Brummell (1954) — film","Brummell (TV film) — TV","Barry Lyndon (1975) — film"]},"Regency Gentleman":{"summary":"The fashionable dress of the Regency male — between Brummell's severity and the more colourful dandyism of lesser imitators.","era":"c.1811–1820, England","mood":"Fashionably masculine, smartly moderate","visual":"Frock coat or morning coat. Pantaloons or tight breeches with Hessian boots. White shirt with complex tied cravat. Waistcoat in brighter colour. Top hat. Walking stick. Moderate — not as severe as Brummell, not as excessive as later dandies.","garments":["Frock coat","Tight pantaloons","Complex tied cravat","Colourful waistcoat","Top hat"],"habitat":"Regency history, Bridgerton contexts, men's fashion history.","context":"The Regency gentleman occupied a precise fashion space — the Prince Regent (future George IV) was the social model, and his own excesses paradoxically legitimised a slightly more colourful style than Brummell's severity.","rarity":"Extinct","see_also":["Beau Brummell Aesthetic","Dandy Aesthetic","Victorian Factory Worker"],"colors":["#1B4F72 Navy Coat","#FAF8F5 White Cravat","#8B7355 Buff Breeches","#D4AF37 Gold Watch"],"media":["Bridgerton (TV series) — TV","Pride and Prejudice (1995) — TV","Jonathan Strange & Mr Norrell (TV) — TV"]},"Regency Buck":{"summary":"The sporting gentleman of the Regency era — the horse, the curricle, and the studied negligence of aristocratic athleticism.","era":"c.1811–1820, England","mood":"Athletically negligent, sporting-proud","visual":"Riding boots over buckskin breeches. Driving coat (multiple-caped greatcoat for the curricle). More casual tied cravat. Top hat. Gloves. The look is practical for sport but still socially correct.","garments":["Multiple-caped driving greatcoat","Buckskin breeches","Riding boots","Casual tied cravat","Top hat"],"habitat":"Regency history, sporting gentleman cosplay.","context":"The Regency Buck was obsessed with horses and physical sports. Byron represented this athletic negligence. The curricle (two-wheeled open carriage) was the sports car of the Regency. The Buck saw Brummell's fussiness as effeminate.","rarity":"Extinct","see_also":["Regency Gentleman","Beau Brummell Aesthetic","Country Club"],"colors":["#8B7355 Buckskin Brown","#1B4F72 Navy","#D4AF37 Brass Buttons","#FAF8F5 White Linen"],"media":["Tom Jones (1963) — film","Barry Lyndon (1975) — film"]},"Regencycore":{"summary":"The contemporary TikTok revival of Regency aesthetics, driven by Bridgerton, Jane Austen content, and Cottagecore-adjacent fashion.","era":"c.2020–present, global social media","mood":"Romantically Regency, Bridgerton-inflected","visual":"Empire-line floral dresses in muslin-adjacent fabrics. Puff sleeves. Pearl accessories. Ribbon sashes. Loose or curled hair. Modern interpretations — not historically accurate — in romantic florals and pastels.","garments":["Empire-waist floral dress","Short puff sleeves","Pearl earrings","Silk ribbon waist sash","Modern sun hat or bonnet"],"habitat":"TikTok, Pinterest, Bridgerton fan communities, Cottagecore adjacent fashion.","context":"Regencycore exploded after Netflix's Bridgerton (2020) — a deliberately anachronistic, racially diverse, romantically heightened Regency world. It merged with Cottagecore's pastoral romanticism to create a dominant social media aesthetic.","rarity":"Common","see_also":["Cottagecore","Jane Austen Aesthetic","Dark Academia"],"colors":["#F5C6CB Bridgerton Pink","#B0C4DE Powder Blue","#FAF8F5 Muslin White","#D4AF37 Pearl Gold"],"media":["Bridgerton (Netflix, 2020–) — TV","Emma (2020) — film","Pride and Prejudice (2005) — film"]},"Modern Regency":{"summary":"Contemporary fashion drawing directly on Regency silhouettes — empire waists, puff sleeves, and the Regency vocabulary in modern fabrics.","era":"c.2019–present","mood":"Historically informed, romantically contemporary","visual":"Empire waistline in contemporary fabrics — jersey, linen, sustainable textiles. Short puff sleeves. Modest neckline. Modern length variations. Pearl accessories. The Regency silhouette without historical accuracy.","garments":["Empire-waist jersey dress","Short puff sleeves","Pearl drop earrings","Ribbon or gathered waist","Modern flat or low-heeled shoes"],"habitat":"Contemporary fashion, sustainable brands drawing on historical silhouettes.","context":"Modern Regency draws on the early 19th century silhouette as a sustainable and flattering alternative to fast fashion trends. The empire line requires less structured undergarments and flatters a wide range of body types.","rarity":"Niche","see_also":["Regencycore","Jane Austen Aesthetic","Neoclassical Revival Dress"],"colors":["#FAF8F5 Ivory","#F5C6CB Blush","#B0C4DE Dusty Blue","#D4AF37 Soft Gold"],"media":["Bridgerton (Netflix) — TV","Emma (2020) — film"]},"Pastel Regency":{"summary":"A soft, pastel-toned interpretation of Regency aesthetics filtered through contemporary romanticism and social media.","era":"c.2020–present","mood":"Dreamily soft, romantically pastel","visual":"Empire-line dress in pastel pink, blue, yellow, or lavender. Muslin or cotton in light tones. Lace trim. Floral embroidery. Soft ribbon details. Hair in loose romantic curls. Less historically specific than Jane Austen cosplay — more about the feeling.","garments":["Pastel muslin empire dress","Lace-trimmed hem","Floral embroidered bodice","Soft ribbon sash","Pearl and flower hair accessories"],"habitat":"Pinterest, Instagram, soft aesthetic communities, Bridgerton fan events.","context":"Pastel Regency emerged from the intersection of Bridgerton's success and the broader pastel aesthetic trend of 2020–2022. It is less about historical accuracy and more about the romantic emotional register of the period.","rarity":"Niche","see_also":["Regencycore","Soft Girl Aesthetic","Coquette"],"colors":["#F5C6CB Blush Pink","#B0C4DE Powder Blue","#F5E6C8 Cream","#D4EA9B Soft Sage"],"media":["Bridgerton (Netflix) — TV","Marie Antoinette (2006) — film"]},"Early Victorian Morning":{"summary":"The restrained morning dress of the 1840s–50s — full skirts without crinoline, and the beginning of Victoria's long domestic shadow.","era":"c.1837–1856, England","mood":"Quietly modest, domestically proper","visual":"Natural waist returning after empire line. Increasingly full skirts on petticoats. High neck with white collar. Long tight sleeves. Dark wool for ordinary days. Hair parted centre and smoothed to side ringlets. White indoor cap for married women.","garments":["Full dark wool skirt","Tight-sleeved bodice","White collar and cuffs","Centre-parted ringlets","Indoor morning cap"],"habitat":"Victorian living history, early Victorian period drama.","context":"The early Victorian period saw fashion pulling back from Regency openness — necklines rose, sleeves tightened, waists cinched. Victoria herself was fashion-conscious early in her reign; after Albert's death in 1861 she wore black for 40 years.","rarity":"Extinct","see_also":["Crinoline Aesthetic","Victorian Street Dress","Worth Couture Aesthetic"],"colors":["#1A1A1A Day Black","#FAF8F5 White Collar","#8B4513 Muted Brown","#5B5B5B Morning Grey"],"media":["North and South (TV, 2004) — TV","Jane Eyre (various) — film/TV","Cranford (BBC) — TV"]},"Victoria Era Modest":{"summary":"The earnest, middle-class respectability dress of the Victorian era — the visual grammar of British bourgeois propriety.","era":"c.1837–1901, England","mood":"Respectably modest, class-conscious","visual":"Dark wool for everyday. White collar and cuffs always pristine — changed daily. Crinoline skirt (1850s–60s), bustle (1870s–80s), slimmer (1890s). Hair severely dressed. No cosmetics. The domestic Victorian woman changed dress multiple times a day.","garments":["Dark wool day dress","Pristine white collar","Moderate crinoline or bustle","Hairnet or chignon","Jet mourning brooch"],"habitat":"Victorian living history, Downton Abbey-adjacent contexts.","context":"Victorian middle-class dress was an exhausting performance of respectability — the cleanliness of your collar and cuffs signalled your standing. The collar change was a daily ritual.","rarity":"Extinct","see_also":["Early Victorian Morning","Victorian Street Dress","Worth Couture Aesthetic"],"colors":["#1A1A1A Day Black","#FAF8F5 Collar White","#5B5B5B Respectable Grey","#8B4513 Muted Brown"],"media":["Victoria (TV series) — TV","Cranford (BBC series) — TV","Middlemarch (1994) — TV"]},"Victorian Factory Worker":{"summary":"The practical, worn dress of industrial Britain's working class — the aesthetic of the mill, the mine, and the servant's kitchen.","era":"c.1840–1900, Industrial Britain","mood":"Practically worn, working-class dignified","visual":"Rough cotton or wool. Apron always. Shawl instead of coat (coats caught in machinery). Heavy boots. Work dress rolled and pinned. Hair covered for factory safety. Dark and stainable colours.","garments":["Rough cotton work dress","Heavy canvas apron","Head-and-shoulders shawl","Heavy leather boots","Simple neckerchief"],"habitat":"Industrial Revolution history, factory heritage, social history living history.","context":"Victorian factory dress was determined by industrial necessity — shawls instead of coats (coats caught in machinery), tied-up hair (same reason), heavy boots for stone floors. The aesthetic is simultaneously dignified and economically constrained.","rarity":"Extinct","see_also":["Medieval Peasant","Victorian Street Dress","Union Workwear Aesthetic"],"colors":["#8B7355 Work Brown","#FAF8F5 Apron White","#5B5B5B Soot Grey","#4A7C59 Dye Blue"],"media":["North and South (2004) — TV","Oliver! (1968) — film","Mary Barton, Elizabeth Gaskell — novel"]},"Victorian Street Dress":{"summary":"The vivid, class-stratified dress of Victorian urban streets — every class present simultaneously, fashion as visible social order.","era":"c.1840–1901, British cities","mood":"Stratified, vivid, urban-alive","visual":"Every class present simultaneously. Upper: silk with parasol. Middle: neat wool. Working: shawl and apron. Vendors in distinctive trade dress. The street as fashion stage for every level. Victorian street photography documents this with extraordinary richness.","garments":["Class-appropriate wool or silk","Trade-specific work apron","Shawl wrapped over head","Heavy leather boots","Parasol for upper class"],"habitat":"Victorian London history, Dickens adaptation contexts, social history study.","context":"Victorian street photography (from the 1840s) documents the extreme class stratification of dress. The gap between the silk-clad lady and the flower seller was absolute. Dickens described these contrasts obsessively.","rarity":"Extinct","see_also":["Victorian Factory Worker","Victoria Era Modest","Guild Artisan Aesthetic"],"colors":["#1A1A1A Street Black","#8B7355 Shawl Brown","#FAF8F5 Apron White","#5B5B5B Grey Wool"],"media":["My Fair Lady (1964) — film","Oliver! (1968) — film","Sherlock Holmes (various) — film/TV"]},"Cockney Aesthetic":{"summary":"The working-class street aesthetic of Victorian and Edwardian East London — the Pearly Kings and Queens, and the pride of the costermonger.","era":"c.1840–1950, East London","mood":"Working-class proud, street-smart, pearl-decorated","visual":"Costermonger dress: men in flat cap and waistcoat; women in dark skirt and shawl. Pearly King and Queen ceremonial dress: suit or dress covered in thousands of mother-of-pearl buttons arranged in complex patterns. Sunday best a priority.","garments":["Flat cap","Waistcoat","Dark work skirt and shawl","Pearly King button-covered suit","Mother-of-pearl button trim"],"habitat":"East London heritage events, Pearly Kings and Queens charity events, Cockney culture celebrations.","context":"The Pearly Kings and Queens tradition began c.1880 when Henry Croft, an orphaned street sweeper, covered his suit in buttons for charity. The tradition continues — there are still active Pearly families in London today.","rarity":"Rare","see_also":["Victorian Street Dress","Victorian Factory Worker","British Heritage Fashion"],"colors":["#C0C0C0 Pearl Silver","#1A1A1A Button Black","#8B0000 Cockney Red","#D4AF37 Mother of Pearl"],"media":["My Fair Lady (1964) — film","Oliver! (1968) — film","EastEnders (TV series) — TV"]},"Crinoline Aesthetic":{"summary":"The cage-skirted fashion of the 1850s–60s — the steel-hooped crinoline creating the most extreme silhouette in Victorian fashion.","era":"c.1856–1869, Europe","mood":"Fantastically spherical, engineering-dependent","visual":"The steel-hooped cage crinoline creating a dome up to 6 feet in diameter. Silk or cotton gown over the cage. Extremely tight bodice. Off-shoulder evening dress. Required planning — doorways, carriages, all needed navigation.","garments":["Steel cage crinoline","Silk dome-shaped skirt","Tight boned bodice","Off-shoulder evening neckline","Silk ribbon sash"],"habitat":"Victorian history, Civil War era cosplay, fashion history.","context":"The cage crinoline killed approximately 40 women in Britain in one year — catching fire, getting caught in machinery. Fashion magazine advice on crinoline fire safety was a genuine editorial category. Despite this, it remained fashionable for over a decade.","rarity":"Extinct","see_also":["Worth Couture Aesthetic","Bustle Aesthetic","Baroque Excess"],"colors":["#F5C6CB Crinoline Pink","#B0C4DE Steel Blue","#D4AF37 Gold Trim","#FAF8F5 Silk White"],"media":["Gone with the Wind (1939) — film","Victoria (TV series) — TV","The Young Victoria (2009) — film"]},"Worth Couture Aesthetic":{"summary":"The first named fashion house — Charles Frederick Worth's vision of Paris couture as art, the beginning of the modern fashion industry.","era":"c.1858–1895, Paris","mood":"Innovatively opulent, architect-of-fashion","visual":"Extremely precise construction. Luxurious silk fabrics. Princess line (seams without a waistline) revolutionising fit. Court trains. Elaborate embroidery. Worth's innovation: making the couturier a named artist whose signature was sold alongside the dress.","garments":["Princess-line silk gown","Court train for formal occasions","Elaborate floral embroidery","Fitted boned bodice","Ivory or deep colour silk"],"habitat":"Fashion history, Costume Institute exhibitions, couture history study.","context":"Charles Frederick Worth was an Englishman who invented the French haute couture system in Paris. He is the father of the fashion designer as named artist. Empress Eugénie of France was his primary patron.","rarity":"Extinct","see_also":["Haute Couture Spectacle","Crinoline Aesthetic","Old Money"],"colors":["#8B0000 Worth Crimson","#D4AF37 Gold Embroidery","#FAF8F5 Ivory Silk","#1B4F72 Deep Blue"],"media":["The Young Victoria (2009) — film","Victoria (TV series) — TV"]},"Pre-Raphaelite Aesthetic":{"summary":"The flowing, historically inspired dress of the Pre-Raphaelite Brotherhood's models — medieval romanticism against Victorian propriety.","era":"c.1848–1900, England","mood":"Medievally romantic, loosely natural","visual":"Long loose gowns without tight corseting. Medieval-inspired styling. Flowing unpinned copper or auburn hair. Jewel tones: deep blue, green, gold. Simple girdle belt. William Morris fabrics. No crinoline.","garments":["Loose medieval-style gown","Simple girdle belt","Flowing unpinned hair","Deep jewel-tone fabric","Morris-pattern textile"],"habitat":"Pre-Raphaelite exhibitions, Aesthetic Movement contexts, Arts and Crafts communities.","context":"The Pre-Raphaelites created an alternative to mainstream Victorian fashion by looking backward. Their models — Jane Morris, Elizabeth Siddal — became alternative fashion icons. The loose unpinned hair was a deliberate challenge to Victorian modesty.","rarity":"Extinct","see_also":["Aesthetic Dress Reform","Medieval Romantic","Aesthetic Movement Dress"],"colors":["#8B2500 Russet Red","#2C5530 Sage Green","#1B4F72 Medieval Blue","#D4AF37 Gold"],"media":["Ophelia (John Everett Millais, 1851–52) — art","Beata Beatrix (Rossetti, 1864–70) — art","Desperate Romantics (BBC) — TV"]},"Aesthetic Dress Reform":{"summary":"The 1870s–80s movement against corsets and crinolines — rational dress, loose gowns, and the first feminist fashion rebellion.","era":"c.1868–1900, England","mood":"Reformingly rational, artistically principled","visual":"Loose non-structured gown without corset. Subdued tones and natural dyes. Long loose sleeves. Simple Liberty-fabric prints. No bustle or crinoline. Worn by artists, intellectuals, women's rights advocates. Oscar Wilde's circle.","garments":["Loose Liberty cotton gown","Simple unfitted bodice","Long wide sleeves","Natural dye palette","Simple belt"],"habitat":"Arts and Crafts exhibitions, feminist fashion history, Liberty London heritage.","context":"The Rational Dress Society (founded 1881) specified maximum acceptable weight for women's underwear and campaigned against tight lacing. The movement was laughed at and deeply influential simultaneously.","rarity":"Extinct","see_also":["Aesthetic Movement Dress","New Woman Aesthetic","Victorian Rational Dress"],"colors":["#4A7C59 Sage Green","#C1440E Terracotta","#8B7355 Natural","#D4AF37 Honey Gold"],"media":["Patience (Gilbert and Sullivan, 1881) — theatre","Oscar Wilde documentary — documentary"]},"Aesthetic Movement Dress":{"summary":"The 'art dress' of the Aesthetic Movement — sunflowers, peacock feathers, Oscar Wilde, and beauty for its own sake.","era":"c.1870–1900, England","mood":"Aesthetically principled, art-for-art's-sake","visual":"Loose gowns in muted olive, sage, and peacock blue. Peacock feather motifs. Sunflower embroidery. Japanese influences. Draped without tight structure. The dress was part of a total lifestyle aesthetic.","garments":["Loose olive-toned gown","Peacock feather motif","Japanese-influenced pattern","Simple Liberty fabric","Sunflower embroidery"],"habitat":"Aesthetic Movement exhibitions, Oscar Wilde contexts, Arts and Crafts style.","context":"Oscar Wilde wore aesthetic dress to lecture in America and was the first fashion influencer in the modern sense. Gilbert and Sullivan satirised the aesthetes in Patience (1881). Liberty of London was its commercial home.","rarity":"Extinct","see_also":["Aesthetic Dress Reform","Pre-Raphaelite Aesthetic","Bohemian"],"colors":["#4A7C59 Peacock Green","#2E5A8B Peacock Blue","#D4AF37 Sunflower Gold","#8B4513 Olive"],"media":["Patience (Gilbert and Sullivan, 1881) — theatre","The Importance of Being Earnest (various) — theatre","Dorian Gray (2009) — film"]},"Mourning Dress Aesthetic":{"summary":"The elaborate, codified black of Victorian mourning — the visual language of grief systematised into a complete fashion system.","era":"c.1840–1910, Victorian England","mood":"Grief ritualised, fashion-systematised","visual":"Full mourning: complete black for up to two years. Crape (dull black fabric) as the specific mourning material. Black jewellery — jet, vulcanite, black enamel. Gradually lighter: half-mourning in mauve and grey. Very precise time rules.","garments":["Full black crape dress","Widow's black cap","Jet mourning brooch","Half-mourning mauve dress","Black bonnet with veiling"],"habitat":"Victorian history, mourning culture exhibitions, Gothic adjacent aesthetics.","context":"Victoria's 40-year mourning for Albert drove a mourning industry. Department stores had dedicated mourning departments. Etiquette guides specified precise mourning timelines — two years for a husband, one for a parent. Getting it wrong was social death.","rarity":"Extinct","see_also":["Victorian Death Aesthetic","Widow's Weeds","Gothic Lolita"],"colors":["#1A1A1A Full Mourning","#5B5B5B Half Mourning Grey","#9370DB Mauve","#2C2C2C Crape"],"media":["Victoria (TV series) — TV","Great Expectations (various) — film/TV","Middlemarch (1994) — TV"]},"Widow's Weeds":{"summary":"The black mourning dress of the Victorian widow — the most codified and longest-lasting of all Victorian mourning protocols.","era":"c.1840–1950, Britain","mood":"Grief-encoded, socially prescriptive","visual":"Complete black crape dress. Black widow's cap. Black veiling over face. No jewellery except jet. Black gloves. Black-edged handkerchief and stationery. The complete elimination of colour for the prescribed period.","garments":["Complete black crape dress","Widow's cap","Black face veil","Jet brooch and earrings","Black gloves"],"habitat":"Victorian mourning history, Gothic fashion references.","context":"Widow's weeds were socially compulsory. A widow seen without mourning dress was judged harshly. Widowers faced no similar requirements. This double standard did not go unnoticed by early feminists — it was one of many.","rarity":"Extinct","see_also":["Mourning Dress Aesthetic","Victorian Death Aesthetic","Gothic Lolita"],"colors":["#1A1A1A Widow Black","#2C2C2C Crape","#5B5B5B Veil Grey","#1A1A1A Jet Black"],"media":["Queen Victoria's funeral (1901) — historical footage","Great Expectations (various) — film/TV"]},"Victorian Death Aesthetic":{"summary":"The Victorian obsession with beautiful death — mourning jewellery, post-mortem photography, and the aestheticisation of grief as domestic practice.","era":"c.1840–1901, Britain","mood":"Morbidly beautiful, grief-aestheticised","visual":"Black mourning dress as base. Post-mortem photography as family record. Hair jewellery woven from deceased's hair. Memento mori jewellery. Black-edged correspondence. The aestheticisation of death as part of the family parlour.","garments":["Black jet mourning brooch","Hair locket with deceased's hair","Post-mortem photography backdrop","Black mourning stationery","Memento mori ring"],"habitat":"Gothic communities, Victorian death culture exhibitions, mourning jewellery collecting.","context":"Victorian death culture produced extraordinary material objects — post-mortem photography (often the only photograph of working-class people), hair jewellery, elaborate mourning pieces. The Victorians brought death into the parlour.","rarity":"Niche","see_also":["Mourning Dress Aesthetic","Widow's Weeds","Memento Mori Aesthetic"],"colors":["#1A1A1A Mourning Black","#8B7355 Jet Brown","#C0C0C0 Silver","#5B5B5B Death Grey"],"media":["Beloved (1998) — film","The Others (2001) — film","The Conjuring (2013) — film"]},"Bustle Aesthetic":{"summary":"The dramatically rear-enhanced fashion of the 1870s–80s — all the volume shifted to the back, creating the most extreme silhouette shift in Victorian fashion.","era":"c.1869–1889, Europe","mood":"Architecturally posterior-focused","visual":"The bustle: a structure worn at the rear creating an exaggerated curved protrusion. Very flat front. Tight bodice. Long train. The second bustle phase (1883–89) was even more extreme — a horizontal shelf at the back.","garments":["Bustle-supported draped skirt","Fitted bodice with train","Horizontal shelf bustle structure","Elaborately trimmed silk","Tight sleeves"],"habitat":"Victorian history, late 19th century costume, fashion history.","context":"The bustle represented a complete reversal of the crinoline's spherical volume. The second bustle phase of the 1880s created what appear in portraits to be literally impossible silhouettes.","rarity":"Extinct","see_also":["Crinoline Aesthetic","Worth Couture Aesthetic","Edwardian Promenade"],"colors":["#8B0000 Victorian Crimson","#2C5530 Bottle Green","#D4AF37 Gold Trim","#8B4513 Sepia Brown"],"media":["The Crimson Petal and the White (BBC) — TV","Tipping the Velvet (BBC) — TV"]},"High Victorian Evening":{"summary":"The formal evening dress of the Victorian upper class — low décolletage, trains, jewels, and the theatrical display of Society.","era":"c.1870–1901, London Season","mood":"Theatrically formal, jewelled, socially coded","visual":"Very low off-shoulder neckline for formal occasions. Long train. Elaborate silk with lace and embroidery. Tiaras for married women. Matched parure of jewels. White gloves to above elbow. The Victorian paradox: more revealing in the evening.","garments":["Elaborate silk evening gown","Off-shoulder low bodice","Long formal train","Tiara for married women","Elbow-length evening gloves"],"habitat":"Victorian history, London Season events, opera production costuming.","context":"Victorian formal dress was paradoxically more revealing than everyday dress — extremely low necklines were correct for evening while high necks were required during the day. The London Season (May–July) organised entirely around elaborate formal events.","rarity":"Extinct","see_also":["Worth Couture Aesthetic","Victorian Hostess","Red Carpet Aesthetic"],"colors":["#FAF8F5 Cream Silk","#D4AF37 Diamond Gold","#C0C0C0 Pearl Silver","#8B0000 Evening Crimson"],"media":["The Age of Innocence (1993) — film","Victoria (TV series) — TV","An Inspector Calls — theatre"]},"Victorian Hostess":{"summary":"The domestic formal dress of the Victorian mistress of the house — the aesthetic of At Home days, afternoon calling, and the tea table ritual.","era":"c.1860–1901, England","mood":"Domestically formal, perfectly composed","visual":"Day dress rather than evening dress — higher neck. Good wool or silk. Elaborate trim. Tea gown for more informal afternoons. Perfect coiffure. Gloves for receiving. The house itself as social performance space.","garments":["Smart silk day dress","High collar with brooch","Elaborate cuff and collar trim","Tea gown for informal hours","Good gloves for receiving"],"habitat":"Victorian living history, Downton Abbey-era events, At Home day reenactment.","context":"The Victorian At Home was an elaborate social performance — specific days and hours for receiving callers, precise rules about calling cards, who could call and when. The hostess dress was designed for hours of social management.","rarity":"Extinct","see_also":["Victoria Era Modest","High Victorian Evening","Homemaker Aesthetic"],"colors":["#2C5530 Hostess Green","#8B4513 Tea Silk","#D4AF37 Gold Trim","#FAF8F5 Collar White"],"media":["Cranford (BBC) — TV","Downton Abbey (TV series) — TV","The Remains of the Day (1993) — film"]},"Liberty Dress Reform":{"summary":"The Liberty of London approach to rational dress — beautiful art-inspired fabrics in unconstructed silhouettes as fashionable reform.","era":"c.1875–1910, London","mood":"Artistically rational, beautifully reforming","visual":"Liberty printed silk or cotton in soft muted tones. Artistic non-structured gowns. Aesthetic embroidery. Japanese-influenced patterns. No tight corsetry. The alternative fashion system for artistic women who rejected mainstream Victorian dress.","garments":["Liberty printed silk gown","Japanese-influenced pattern","Soft gathering at waist","Simple belt or sash","Arts and Crafts embroidery"],"habitat":"Liberty London, Arts and Crafts exhibitions, Aesthetic Movement contexts.","context":"Liberty's opened in 1875 specifically to sell alternative, art-inspired dress materials. Their printed silks and cottons became the fabric of the Aesthetic and Arts and Crafts movements. The brand still uses many of those original patterns.","rarity":"Rare","see_also":["Aesthetic Dress Reform","Aesthetic Movement Dress","Pre-Raphaelite Aesthetic"],"colors":["#4A7C59 Liberty Green","#C1440E Terracotta","#8B7355 Natural","#D4AF37 Arts & Crafts Gold"],"media":["Desperate Romantics (BBC) — TV","Liberty (Liberty London documentary) — documentary"]},"New Woman Aesthetic":{"summary":"The practical, cycling, voting dress of the 1890s New Woman — divided skirts, shorter hems, and the first major feminist fashion statement in modern history.","era":"c.1890–1910, Britain and America","mood":"Practically emancipated, determinedly modern","visual":"Practical divided skirt or rational bloomers under a shorter skirt for cycling. Walking dress with shorter hem. Sensible boots. Shirtwaist (blouse) worn with skirt as separates — practicality and feminism combined.","garments":["Practical divided cycling skirt","Rational bloomers","Shirtwaist blouse","Shorter walking hem","Sensible laced boots"],"habitat":"Feminist fashion history, cycling culture history, first wave feminism contexts.","context":"Susan B. Anthony said the bicycle 'has done more to emancipate women than anything else in the world.' The dress required for cycling was politically explosive — shorter skirts and rational clothing for women claiming physical mobility.","rarity":"Extinct","see_also":["Victorian Rational Dress","Victorian Cyclist","Women's Liberation Fashion"],"colors":["#1B4F72 Reform Blue","#4A7C59 Rational Green","#8B7355 Tweed Brown","#FAF8F5 Shirtwaist White"],"media":["Tipping the Velvet (BBC) — TV","The Women (1939) — film","Suffragette (2015) — film"]},"Victorian Rational Dress":{"summary":"The dress reform movement's practical alternative to the corset and crinoline — health, reason, and feminism applied to fashion.","era":"c.1881–1910, Britain and America","mood":"Rationally healthy, reform-principled","visual":"No tight corset. No heavy petticoats. No trailing hem. Weight distributed from shoulders not waist. Divided skirts for cycling. The Rational Dress Society's specifications. Comfortable, practical, and derided in the mainstream press.","garments":["Uncorseted loose gown","Divided rational skirt","Sensible flat-heeled shoes","Shoulder-distributed construction","No tight waistline"],"habitat":"Feminist fashion history, dress reform exhibitions.","context":"The Rational Dress Society (founded 1881) was laughed at and deeply influential. Dr Mary Walker won the right to wear trousers legally. The movement's arguments about corsets causing physical damage are now accepted medical history.","rarity":"Extinct","see_also":["New Woman Aesthetic","Victorian Cyclist","Aesthetic Dress Reform"],"colors":["#4A7C59 Sage Green","#8B7355 Natural Brown","#FAF8F5 Clean White","#2C5530 Rational Green"],"media":["Suffragette (2015) — film","Mrs Doubtfire (adjacent rational dress history)"]},"Victorian Cyclist":{"summary":"The practical dress of the Victorian cycling craze — bloomers, divided skirts, and the bicycle as feminist mobility technology.","era":"c.1890–1910, Britain and America","mood":"Practically mobile, scandalously rational","visual":"Bloomer suit: full pants gathered below knee, worn under short jacket. Or divided skirt in tweed. Short-heeled practical boots. Straw hat pinned firmly. The aesthetic is practical first — cycling required freedom of movement.","garments":["Bloomer trousers below knee","Matching short jacket","Or tweed divided skirt","Practical pinned hat","Low-heeled leather boots"],"habitat":"Cycling history, feminist fashion history, rational dress contexts.","context":"Frances Willard wrote 'A Wheel Within a Wheel' about learning to cycle at 53; it became a feminist text. The dress required for cycling forced discussions about women's clothing that the suffrage movement drew on directly.","rarity":"Extinct","see_also":["New Woman Aesthetic","Victorian Rational Dress","Cycling Aesthetic"],"colors":["#8B7355 Tweed Brown","#4A7C59 Cycling Green","#FAF8F5 White Blouse","#1B4F72 Navy"],"media":["Mary Poppins (1964) — film (adjacent)","Tipping the Velvet (BBC) — TV"]},"Victorian Gothic":{"summary":"The Gothic literary tradition applied to Victorian dress — the aesthetic of sensation novels, ghost stories, and the haunted house made wearable.","era":"c.1840–1901, England","mood":"Darkly literary, ghost-story adjacent","visual":"Black silk for Gothic atmosphere. Jet jewellery. Mourning dress repurposed for effect. Dramatic silhouettes. Velvet and lace. The aesthetic of Wilkie Collins, M.R. James, and the sensation novel.","garments":["Black silk gown","Jet and black enamel jewellery","Dramatic velvet trim","Black lace veil","Gothic cameo brooch"],"habitat":"Victorian Gothic literature events, sensation novel fan communities, Gothic adjacent fashion.","context":"Victorian Gothic dress drew on mourning dress, Romantic medievalism, and the aesthetic of the sensation novel. Collins's 'Woman in White' and 'Woman in Black' are fashion documents as much as thrillers.","rarity":"Rare","see_also":["Gothic Lolita","Trad Goth","Mourning Dress Aesthetic"],"colors":["#1A1A1A Gothic Black","#8B0000 Gothic Crimson","#2C2C2C Velvet","#C0C0C0 Jet Silver"],"media":["Crimson Peak (2015) — film","Penny Dreadful (TV series) — TV","Dracula (various) — film"]},"Neo-Victorian":{"summary":"The contemporary revival of Victorian aesthetics in modern fashion — corsets as outerwear, bustle silhouettes, and steam-and-lace dress.","era":"c.1990s–present","mood":"Historically revived, steam-and-lace","visual":"Victorian silhouettes in modern contexts. Corsets worn as outerwear. Bustle-inspired structured skirts. Victorian blouses with high necks and puffed sleeves. Lace and velvet. Pocket watches and fob chains. Often mixed with anachronistic modern elements.","garments":["Corset worn as outerwear","High-necked Victorian blouse","Bustle-structured skirt","Lace-trimmed garments","Pocket watch and fob"],"habitat":"Steampunk communities, Gothic fashion, alternative fashion, Victorian revival events.","context":"Neo-Victorianism draws on the Victorian aesthetic while explicitly departing from its social norms — Victorian dress without Victorian values. The corset as fashion statement (rather than medical apparatus) is entirely Neo-Victorian.","rarity":"Niche","see_also":["Steampunk","Trad Goth","Aesthetic Dress Reform"],"colors":["#1A1A1A Neo Black","#8B0000 Corset Red","#C0C0C0 Steampunk Silver","#D4AF37 Brass"],"media":["Penny Dreadful (TV series) — TV","Crimson Peak (2015) — film","The League of Extraordinary Gentlemen (2003) — film"]},"Belle Époque Parisienne":{"summary":"The exquisitely feminine dress of Paris at the turn of the 20th century — the S-bend corset, the enormous hat, and the final flowering of elaborate dressing.","era":"c.1890–1914, Paris","mood":"Exquisitely feminine, gloriously elaborate","visual":"The S-bend corset pushing chest forward and hips back into an extreme S silhouette. Enormous hat requiring vast hatpins. Blouse and skirt as separates. Elaborate lace jabots. Long A-line skirt. Pastel silks.","garments":["S-bend corseted bodice","Enormous decorated hat","High lace jabot","Long A-line silk skirt","Long hatpins"],"habitat":"Belle Époque exhibitions, Moulin Rouge imagery, early 20th century fashion history.","context":"The Belle Époque was a genuine golden age for French fashion — Poiret, Doucet, and Redfern were creating, new department stores made fashion accessible, and the fashion press was international. The hat reached perhaps its greatest elaboration.","rarity":"Extinct","see_also":["Art Nouveau Aesthetic","Gibson Girl Aesthetic","Paul Poiret Aesthetic"],"colors":["#F5C6CB Belle Rose","#D4AF37 Gold","#FAF8F5 Ivory Silk","#B0C4DE Powder Blue"],"media":["Moulin Rouge! (2001) — film","An Education (2009) — film","Midnight in Paris (2011) — film"]},"Art Nouveau Aesthetic":{"summary":"The organic, sinuous fashion of the Art Nouveau movement — flowing lines, floral motifs, and dress as decorative art.","era":"c.1890–1910, Europe","mood":"Organically sinuous, decoratively natural","visual":"Long sinuous lines following the body. Flowing sleeves. Iris, lily, and poppy motifs in fabric and jewellery. René Lalique jewellery combining enamel, glass, and semi-precious stones. Liberty silk in organic patterns.","garments":["Long sinuous-line gown","Flowing draped sleeves","Lalique enamel iris brooch","Liberty organic-print silk","Loosely flowing hair"],"habitat":"Art Nouveau exhibitions, Liberty London, decorative arts contexts.","context":"Art Nouveau was the first truly international design movement — from Glasgow to Vienna to Prague to Paris. Its jewellery (Lalique, Mucha) is among the most collected in the world.","rarity":"Extinct","see_also":["Belle Époque Parisienne","Aesthetic Movement Dress","Liberty Dress Reform"],"colors":["#4A7C59 Organic Green","#C1440E Lily Red","#D4AF37 Lalique Gold","#7B68EE Iris Purple"],"media":["Alfons Mucha documentary","Art Nouveau: Whiplash (documentary)","The Pillow Book (1996) — film"]},"Mucha Woman":{"summary":"The specific feminine ideal of Alphonse Mucha's posters — flowing copper hair, Byzantine jewellery, and the Art Nouveau decorative woman.","era":"c.1894–1910, Paris","mood":"Decoratively Byzantine, poster-perfect","visual":"Flowing, loosely dressed hair in rich copper tones. Byzantine-inspired jewellery. Loose flowing garments in Mucha's distinctive muted gold, green, and rose tones. Garlands of flowers or Byzantine ornament at head.","garments":["Flowing copper hair","Byzantine enamel jewellery","Loose flowing garment","Flower or ornament garland","Muted gold and rose tones"],"habitat":"Art Nouveau exhibitions, Mucha poster art contexts, Prague cultural events.","context":"Mucha's women were advertising images for Nestlé and Sarah Bernhardt plays, but became one of the defining aesthetic images of the fin de siècle. They synthesised Byzantine, Japanese, and Celtic visual vocabulary into a new feminine ideal.","rarity":"Extinct","see_also":["Art Nouveau Aesthetic","Belle Époque Parisienne","Ethereal Feminine"],"colors":["#C4956A Copper Hair","#D4AF37 Muted Gold","#4A7C59 Byzantine Green","#F5C6CB Rose"],"media":["Mucha's Sarah Bernhardt posters (1894–1900) — art","Alphonse Mucha retrospectives — exhibition"]},"Gibson Girl Aesthetic":{"summary":"The confident, athletic, modern American feminine ideal of the 1890s–1910s — the shirtwaist and skirt, piled-up hair, and the New Woman made beautiful.","era":"c.1890–1910, United States","mood":"Confidently modern, athletically feminine","visual":"High-necked white shirtwaist blouse with puffed sleeves. Dark long skirt, slightly flared at hem. Hair piled up in a relaxed pompadour. Sporty and practical compared to European fashion. Straw boater for outdoor occasions.","garments":["White shirtwaist blouse","Puffed shoulder sleeves","Dark long flared skirt","Piled-up pompadour hair","Straw boater hat"],"habitat":"American turn-of-century history, Gibson Girl illustration study.","context":"Charles Dana Gibson's illustrations created a mass-media feminine ideal for a newly literate American middle class. The Gibson Girl was aspirational but achievable — you could buy the shirtwaist at a department store.","rarity":"Extinct","see_also":["Belle Époque Parisienne","New Woman Aesthetic","Edwardian Promenade"],"colors":["#FAF8F5 Shirtwaist White","#1A1A1A Dark Skirt","#C1440E Accent Red","#8B7355 Straw"],"media":["Meet Me in St. Louis (1944) — film","Hello, Dolly! (1969) — film"]},"Edwardian Promenade":{"summary":"The formal walking dress of Edward VII's England — the S-bend figure displayed on the fashionable morning promenade at Hyde Park.","era":"c.1901–1910, London","mood":"Formally fashionable, socially precise","visual":"S-bend silhouette achieved by corset. Large hat in wide brim. Pastel silk or lawn dress. Long gloves. Parasol. Small waist, full chest, full hips. Boa or fur stole.","garments":["S-bend corseted promenade dress","Wide-brimmed Edwardian hat","Parasol","Long gloves","Fur stole or boa"],"habitat":"Edwardian history, Hyde Park heritage events, period drama costuming.","context":"Edward VII's reign (1901–10) was short but fashion-conscious. His mistresses (Lillie Langtry, Alice Keppel) were influential style figures. The King's appetite for pleasure drove a relaxation of Victorian severity.","rarity":"Extinct","see_also":["Belle Époque Parisienne","Gibson Girl Aesthetic","Edwardian Tea Dress"],"colors":["#F5C6CB Edwardian Pink","#FAF8F5 Ivory Silk","#D4AF37 Gold","#4A7C59 Sage Green"],"media":["My Fair Lady (1964) — film","Gosford Park (2001) — film","Downton Abbey (TV series) — TV"]},"Edwardian Tea Dress":{"summary":"The informal at-home dress of Edwardian women — the tea gown as predecessor of the modern lounge wear.","era":"c.1901–1914, England","mood":"Softly informal, domestic and elegant","visual":"Loose uncorseted gown for the afternoon at home. Soft silk or lawn. Lace and ribbon trim. Often orientalist (Japanese or Chinese) inspired. Long and flowing. Hair loosely dressed. The Edwardian version of dressing down.","garments":["Loose silk tea gown","Lace and ribbon trim","Oriental-pattern motif","Loose flowing sleeves","Indoor slippers"],"habitat":"Edwardian living history, tea party aesthetics.","context":"The tea gown occupied a precise social category — too informal for company, too elaborate for the bedroom. It was worn for afternoon tea with intimate friends or family. The orientalist influences reflected Edwardian fascination with Japan and China.","rarity":"Extinct","see_also":["Edwardian Promenade","Belle Époque Parisienne","Homemaker Aesthetic"],"colors":["#FAF8F5 Lawn White","#F5C6CB Blush","#4A7C59 Sage","#D4AF37 Straw"],"media":["A Room with a View (1985) — film","Downton Abbey (TV series) — TV"]},"Country House Weekend":{"summary":"The sporting and social dress of the Edwardian country house — from shooting tweeds to evening dress in twelve costume changes a day.","era":"c.1890–1914, English countryside","mood":"Leisurely aristocratic, seasonally specific","visual":"Tweed for shooting. Practical walking dress. Tennis whites. Riding habit. Afternoon tea dress. Elaborate evening gown. The Edwardian house party required multiple daily costume changes. Lady's maid essential.","garments":["Tweed shooting jacket and skirt","Practical walking dress","Tennis whites","Riding habit","Elaborate evening gown"],"habitat":"Downton Abbey aesthetic, Edwardian heritage events, country house period drama.","context":"The Edwardian country house weekend was the apex of elaborate dress culture — each hour and activity required different dress. The logistics of transporting wardrobes for house parties required substantial staff. It ended with the First World War.","rarity":"Extinct","see_also":["Georgian Country House","British Heritage Fashion","Downton Abbey Effect"],"colors":["#8B7355 Shooting Tweed","#4A7C59 Country Green","#FAF8F5 Tennis White","#8B0000 Hunting Red"],"media":["Gosford Park (2001) — film","Downton Abbey (TV series) — TV","The Remains of the Day (1993) — film"]},"Edwardian Ball Gown":{"summary":"The spectacular formal evening dress of Edwardian society — white or pale silk, court train, diamonds, and the London Season.","era":"c.1901–1914, London","mood":"Spectacularly formal, diamond-lit","visual":"Pale or white silk with lace overlay. Shallow sweetheart or square neckline. Court train for presentations. Elaborate lace and embroidery. Full parure of diamonds for married women. White for debutantes.","garments":["Pale silk lace-overlay gown","Shallow sweetheart neckline","Long court train","Diamond parure","Long white evening gloves"],"habitat":"Edwardian history, London Season events, Titanic-era costuming.","context":"The Edwardian ball gown's white and pale palette came from Queen Alexandra who established pale colours and lace as the court aesthetic. Debutante presentations at court required white gowns.","rarity":"Extinct","see_also":["Edwardian Promenade","Red Carpet Aesthetic","Worth Couture Aesthetic"],"colors":["#FAF8F5 Ivory Silk","#C0C0C0 Diamond Silver","#D4AF37 Gold","#F5C6CB Blush"],"media":["Titanic (1997) — film","Gosford Park (2001) — film","Downton Abbey (TV series) — TV"]},"Edwardian Suffragette":{"summary":"The politically coded dress of the women's suffrage movement — purple, white, and green as the visual grammar of the vote.","era":"c.1908–1914, Britain","mood":"Politically encoded, dignified, determined","visual":"Ordinary Edwardian dress in suffragette colours: purple (dignity), white (purity), green (hope). WSPU rosettes and badges. Smart, respectable dress to counter the 'unsexed woman' caricature. Suffragette sashes and banners.","garments":["Purple, white, and green dress","WSPU enamel badge","Suffragette sash","Smart respectable Edwardian outfit","Protest banner"],"habitat":"Women's history events, suffragette commemorations, feminist history contexts.","context":"The WSPU's colour code was sophisticated propaganda — women could publicly identify as suffragettes without carrying signs. The colours were chosen specifically because they weren't associated with any existing political party.","rarity":"Extinct","see_also":["Women's Liberation Fashion","New Woman Aesthetic","Civil Rights Movement Fashion"],"colors":["#6B2D8A Dignity Purple","#FAF8F5 Purity White","#4A7C59 Hope Green"],"media":["Suffragette (2015) — film","Votes for Women (documentary)","Pankhurst documentary series"]},"Paul Poiret Aesthetic":{"summary":"The revolution in dress that freed women from the corset — Orientalist, theatrical, and the first designer as total lifestyle brand.","era":"c.1903–1929, Paris","mood":"Orientally theatrical, anti-corset revolutionary","visual":"High Empire waist abandoning S-bend. Harem pants shocking in 1911. Lampshade tunic over hobble skirt. Vivid colours: turquoise, orange, black, gold. Turban headdress. Theatrical rather than social.","garments":["Lampshade tunic","Harem pants","Hobble skirt","Vivid Oriental colour","Turban headdress"],"habitat":"Fashion history, Poiret revival exhibitions.","context":"Paul Poiret claimed to liberate women from the corset (though the hobble skirt simply imprisoned them at the ankles instead). He introduced the designer as total lifestyle brand — perfumes, interiors, and theatre costumes as well as dress.","rarity":"Extinct","see_also":["Belle Époque Parisienne","Art Nouveau Aesthetic","Orientalist 1920s"],"colors":["#2E5A8B Oriental Blue","#D4AF37 Gold","#8B0000 Crimson","#C1440E Saffron Orange"],"media":["Midnight in Paris (2011) — film","Poiret: King of Fashion documentary — documentary"]},"Titanic Era Dress":{"summary":"The dress of the brief golden age before the First World War — its final flowering forever associated with the Titanic's April 1912.","era":"c.1910–1914, Europe and America","mood":"Elegantly poised between eras","visual":"Narrowing silhouette moving away from Edwardian curves. Empire influence returning. Simple draped effects. Hobble skirt at its narrowest. First hints of 1920s simplification.","garments":["Draped pre-war evening gown","Hobble skirt","High neck with lace","Simple Empire influence bodice","Edwardian hat narrowing"],"habitat":"Titanic memorial events, Edwardian period drama.","context":"The Titanic (April 1912) is the last moment of the Belle Époque captured in documentary evidence. Survivor accounts and salvaged objects give an extraordinary picture of dress at every class level on a single night.","rarity":"Extinct","see_also":["Edwardian Promenade","Belle Époque Parisienne","Paul Poiret Aesthetic"],"colors":["#FAF8F5 Ivory Silk","#D4AF37 Gold","#1B4F72 Atlantic Blue","#5B5B5B Steel"],"media":["Titanic (1997) — film","Downton Abbey (TV series) — TV"]},"Edwardian Motoring":{"summary":"The extraordinary dress required for the early automobile — the dust coat, the veil, the goggles, and fashion adapting to technology.","era":"c.1900–1914, Europe and America","mood":"Technologically adaptive, adventurously modern","visual":"Long linen or cotton duster coat to protect dress from dust and oil. Large hat veiled or tied down with scarf. Goggles over eyes. Gauntlet gloves. The first technology-driven fashion development in the modern era.","garments":["Long linen duster coat","Veiled or tied-down hat","Motoring goggles","Gauntlet gloves","Waterproof driving coat"],"habitat":"Vintage car shows, early motoring history, Edwardian technology exhibitions.","context":"The early automobile created a fashion crisis — travelling at 20 mph in open cars in Edwardian dress was impossible without special protective clothing. The motoring duster and veil were genuinely innovative solutions to a technological problem.","rarity":"Extinct","see_also":["Edwardian Promenade","Country House Weekend","Techwear"],"colors":["#8B7355 Linen Dust","#5B5B5B Motoring Grey","#4A7C59 Goggles Green","#FAF8F5 Duster White"],"media":["The Wind in the Willows — literature","Downton Abbey (TV series) — TV"]},"Edwardian Tennis":{"summary":"The voluminous white dress of Edwardian lawn tennis — the most impractical competitive dress in sports history.","era":"c.1880–1914, England","mood":"Impractically sporting, voluminously white","visual":"Full white lawn dress with long sleeves, high neck, and floor-length hem — for competitive tennis. Corset worn underneath. Elaborate hat. Gradually simplified but remaining maximally impractical.","garments":["Full white lawn tennis dress","Long sleeves","Corseted bodice","Long skirt to ground","Elaborate hat"],"habitat":"Wimbledon history, Victorian/Edwardian sport history, early tennis culture.","context":"Wimbledon began in 1877. Its early decades saw women competing in full Victorian/Edwardian dress. The gradual simplification of tennis dress tracks women's liberation — by the 1920s hemlines had risen dramatically.","rarity":"Extinct","see_also":["New Woman Aesthetic","Victorian Rational Dress","Tennis Aesthetic"],"colors":["#FAF8F5 Tennis White","#C1440E Trim Red","#4A7C59 Lawn Green","#D4AF37 Straw Hat"],"media":["Wimbledon historical footage","A Room with a View (1985) — film"]},"De Stijl Dress":{"summary":"The geometric primary-colour aesthetic of the Dutch De Stijl movement applied to dress — Mondrian grids made wearable.","era":"c.1917–1931, Netherlands; 1966 revival","mood":"Geometrically pure, primary-coded","visual":"Primary red, blue, and yellow with black and white grid. Rectangular geometric forms. Flat, non-structural. Yves Saint Laurent's 1965 Mondrian dress is the definitive revival.","garments":["Mondrian-grid colour blocks","Primary red yellow blue palette","Black grid lines","Geometric rectangular silhouette","Flat minimal structure"],"habitat":"Design history, De Stijl exhibitions, Mondrian dress references.","context":"De Stijl produced almost no actual fashion in its day — it was architectural and fine art. Its influence on fashion came retrospectively through YSL's 1966 Mondrian dress.","rarity":"Extinct","see_also":["Bauhaus Aesthetic","Modernist Design Aesthetic","Memphis Design Aesthetic"],"colors":["#FF0000 Primary Red","#0000FF Primary Blue","#FFFF00 Primary Yellow","#1A1A1A Grid Black"],"media":["The Mondrian Dress (YSL, 1966) — fashion","De Stijl: The Total Work of Art (documentary) — documentary"]},"Bauhaus Aesthetic":{"summary":"The functional, form-follows-function dress of the Weimar Bauhaus school — geometric, practical, and the philosophical ancestor of modern design.","era":"c.1919–1933, Dessau/Berlin","mood":"Functionally rational, form-follows-function","visual":"Simple geometric forms. Primary colours or neutrals. Functional construction without decoration. Metal jewellery from the metalwork workshop. NOTE: Bauhaus here refers to the design school, not Bauhaus the band.","garments":["Simple geometric silhouette","Primary or neutral palette","Metal workshop jewellery","Undecorated functional form","Black and white with accents"],"habitat":"Bauhaus exhibitions, design history, Dessau cultural events.","context":"The Bauhaus weaving workshop produced some of the most influential textile designs of the 20th century. The school's aesthetic descended into modern corporate design and minimalist fashion.","rarity":"Extinct","see_also":["De Stijl Dress","Modernist Design Aesthetic","Dieter Rams Aesthetic"],"colors":["#FF0000 Bauhaus Red","#0000FF Bauhaus Blue","#FFFF00 Bauhaus Yellow","#1A1A1A Bauhaus Black"],"media":["Bauhaus Spirit (2019 documentary) — documentary","The Bauhaus (documentary) — documentary"]},"Constructivist Fashion":{"summary":"The Soviet avant-garde attempt to design a functional, class-less dress system — Rodchenko, Stepanova, and ideology made clothing.","era":"c.1919–1932, Soviet Russia","mood":"Functionally ideological, geometrically Soviet","visual":"Geometric forms with practical function. Overalls as basis. Red, black, and white. Diagonal and angular cut. Varvara Stepanova's sports dress. Production clothing as fine art. Communist ideology expressed in anti-decorative dress.","garments":["Geometric production overalls","Red and black diagonal cut","Sports dress without ornament","Workers' cap","Functional visible construction"],"habitat":"Soviet design history, Constructivism exhibitions, avant-garde fashion study.","context":"Soviet Constructivist fashion was one of the 20th century's great failed utopian design projects — the attempt to create a truly classless, functional dress system. The Stalin era suppressed it entirely.","rarity":"Extinct","see_also":["De Stijl Dress","Bauhaus Aesthetic","Modernist Design Aesthetic"],"colors":["#8B0000 Soviet Red","#1A1A1A Black","#FAF8F5 White","#5B5B5B Grey Steel"],"media":["October (1928, Eisenstein) — film","Constructivist Textiles documentary — documentary"]},"Functionalist Modernism":{"summary":"The idealistic dress of the modernist intellectual between the wars — simple cuts, quality materials, and the philosophy that ornament is crime.","era":"c.1920–1940, Europe","mood":"Ideologically simple, philosophically pure","visual":"Adolf Loos's maxim 'ornament is crime' applied to dress. Simple undecorated forms. Quality materials. Neutral or primary colours. No historical reference. The dress of the Viennese intellectual circle.","garments":["Simple undecorated gown","Quality neutral fabric","No ornament or trim","Clean geometric cut","Simple leather shoes"],"habitat":"Modernist design history, Viennese intellectual contexts.","context":"Adolf Loos's 1908 essay 'Ornament and Crime' was architecture criticism that became fashion philosophy. Its influence on 20th-century minimalism is enormous — from Chanel's simplification to contemporary minimalist fashion.","rarity":"Extinct","see_also":["Bauhaus Aesthetic","Modernist Design Aesthetic","Minimalist Design Aesthetic"],"colors":["#FAF8F5 Neutral White","#5B5B5B Functional Grey","#1A1A1A Black","#8B7355 Natural"],"media":["Adolf Loos: Ornament and Crime (documentary)","Bauhaus documentary series"]},"Flapper Aesthetic":{"summary":"The defining dress of the 1920s Jazz Age — dropped waist, short hem, bobbed hair, and the first great youth fashion rebellion.","era":"c.1920–1929, Europe and America","mood":"Joyfully transgressive, dance-ready, youth-claiming","visual":"Short dropped-waist dress (knee-length — scandalous). Flat chest, no natural waist. Flesh-coloured stockings. Bobbed or shingled hair. Cloche hat. Long pearl necklace. Mary Jane shoes. Red lipstick.","garments":["Short dropped-waist dress","Cloche hat","Long strand of pearls","Mary Jane shoes","Bobbed or shingled hair"],"habitat":"1920s themed parties, Great Gatsby events, Halloween, Jazz Age cultural references.","context":"The flapper was the first modern youth fashion — specifically made by and for young women in rebellion against their mothers' corseted generation. The short dress, bobbed hair, and public dancing were simultaneously fashion and feminism.","rarity":"Extinct","see_also":["Gatsby Girl","Jazz Baby","Art Deco Geometric"],"colors":["#1A1A1A Beaded Black","#D4AF37 Gold","#C0C0C0 Silver","#8B0000 Jazz Red"],"media":["The Great Gatsby (2013) — film","Chicago (2002) — film","Downton Abbey (TV series) — TV"]},"Chanel Aesthetic":{"summary":"Coco Chanel's revolutionary simplification of women's dress — jersey, the little black dress, pearls, and the liberation of the female body.","era":"c.1910–1971, Paris","mood":"Classically simple, luxuriously understated","visual":"The little black dress as wardrobe foundation. Jersey knit in the 1910s — previously only used for men's underwear. Boxy cardigan suit (1920s). Real and fake pearls worn together. Two-tone shoes. Quilted bag. No corsetry.","garments":["Little black dress","Boxy cardigan suit","Layered pearls (real and faux)","Two-tone slingback shoes","Quilted chain bag"],"habitat":"Fashion history, Chanel No. 5 culture, simple elegance aesthetic.","context":"Chanel's greatest achievement was making simplicity look like an aesthetic statement rather than poverty. She took working-class fabrics (jersey, tweed) and made them luxury. Her rivalry with Schiaparelli defined interwar Paris fashion.","rarity":"Rare","see_also":["Schiaparelli Aesthetic","Jazz Baby","Quiet Luxury"],"colors":["#1A1A1A Chanel Black","#FAF8F5 Pearl White","#C0C0C0 Chain Silver","#8B7355 Beige"],"media":["Coco before Chanel (2009) — film","The September Issue (2009) — documentary","Chanel (TV film) — TV"]},"Schiaparelli Aesthetic":{"summary":"The surrealist, intellectually subversive couture of Elsa Schiaparelli — lobster dresses, shoe hats, and fashion as art collaboration.","era":"c.1927–1954, Paris","mood":"Surreally intellectual, artistically subversive","visual":"Collaboration with Dalí and Cocteau — the lobster dress, the shoe hat, the skeleton dress. Shocking pink (her signature colour). Trompe l'oeil effects. Fashion as conceptual art statement.","garments":["Lobster print organza gown","Shoe hat","Skeleton embroidered dress","Shocking pink statement piece","Trompe l'oeil illusion"],"habitat":"Fashion history, Surrealism exhibitions, Schiaparelli revival (2012–present).","context":"Schiaparelli collaborated with Dalí and Cocteau to create fashion as Surrealist art objects. Her rivalry with Chanel ('that little black dress maker') defined interwar Paris. Her house was revived in 2012 under Daniel Roseberry.","rarity":"Niche","see_also":["Chanel Aesthetic","Surrealist Fashion","Art Nouveau Aesthetic"],"colors":["#FF00FF Shocking Pink","#1A1A1A Surrealist Black","#C1440E Red","#D4AF37 Lobster Gold"],"media":["Schiaparelli and Prada: Impossible Conversations (2012) — exhibition","The September Issue — documentary"]},"Jazz Baby":{"summary":"The music-driven fashion of the early 1920s jazz scene — slinky, dancing, and Black cultural style filtering into mainstream fashion.","era":"c.1920–1929, New York and Paris","mood":"Rhythmically slinky, music-driven","visual":"Bias-cut silk that moved with the body. Beaded fringe that shimmered while dancing. Short hemlines. Headbands with feathers. Stage makeup. The aesthetic of Harlem Renaissance jazz clubs before white appropriation.","garments":["Bias-cut beaded silk dress","Fringe that moves while dancing","Feathered headband","Short Charleston-length hem","Stage makeup"],"habitat":"Jazz Age events, Harlem Renaissance cultural contexts, 1920s dance events.","context":"The Jazz Baby aesthetic originated in Black American musical and social culture before being appropriated into the mainstream Flapper look. The Harlem Renaissance was simultaneously producing the world's most innovative cultural output.","rarity":"Extinct","see_also":["Flapper Aesthetic","Harlem Renaissance Fashion","Gatsby Girl"],"colors":["#D4AF37 Beaded Gold","#1A1A1A Jazz Black","#8B0000 Speakeasy Red","#C0C0C0 Silver Fringe"],"media":["Chicago (2002) — film","Josephine Baker documentary","Harlem Renaissance documentary"]},"Gatsby Girl":{"summary":"The fictional-but-perfect encapsulation of 1920s wealth excess — the dress not of jazz clubs but of the East Egg party, Fitzgerald's American Dream made silk.","era":"c.1920–1929; 2013 film revival","mood":"Wealth-drunk, romantically doomed","visual":"White or pale silk. Elaborate pearl and crystal embroidery. Long strands of pearls. Long white gloves. Elaborate hair or headband. The aesthetic is richer and more formal than the flapper — old money in Jazz Age drag.","garments":["White embroidered silk gown","Long pearl strands","Crystal-beaded headband","Long white gloves","Pale silk shoes"],"habitat":"Great Gatsby themed parties, Baz Luhrmann film references, 1920s themed events.","context":"F. Scott Fitzgerald's 1925 novel and Baz Luhrmann's 2013 film (costumes by Catherine Martin, jewellery by Tiffany) keep this aesthetic constantly in circulation. The green light remains the most powerful symbol in American literature.","rarity":"Niche","see_also":["Flapper Aesthetic","Jazz Baby","Art Deco Geometric"],"colors":["#FAF8F5 Ivory Silk","#D4AF37 Champagne Gold","#C0C0C0 Pearl Silver","#E8D5B0 Cream"],"media":["The Great Gatsby (2013) — film","The Great Gatsby (1974) — film","The Great Gatsby, Fitzgerald (1925) — novel"]},"Art Deco Geometric":{"summary":"The streamlined geometric aesthetic of the 1920s–30s — zigzags, chevrons, sunbursts, and the marriage of machine age and luxury.","era":"c.1920–1939, global","mood":"Geometrically streamlined, machine-age luxurious","visual":"Bold geometric patterns in vivid or metallic colours. Zigzag and chevron motifs. Sunburst radiating designs. Metallic gold and silver. Angular cut. Beaded geometrics. The aesthetic of the Chrysler Building in dress form.","garments":["Beaded geometric evening dress","Chevron or zigzag pattern","Metallic gold or silver fabric","Angular cut silhouette","Art Deco jewellery"],"habitat":"Art Deco exhibitions, 1920s–30s themed events, interior design contexts.","context":"Art Deco was both a fine arts movement (Exposition Internationale 1925) and a mass aesthetic — from Parisian couture to department store fashion, from jewellery to everyday objects. One of the most immediately recognisable visual vocabularies in history.","rarity":"Niche","see_also":["Flapper Aesthetic","Gatsby Girl","Memphis Design Aesthetic"],"colors":["#D4AF37 Art Deco Gold","#1A1A1A Black","#C0C0C0 Silver","#8B0000 Deco Red"],"media":["The Great Gatsby (2013) — film","Midnight in Paris (2011) — film","The Artist (2011) — film"]},"Orientalist 1920s":{"summary":"The vogue for 'Eastern' aesthetics in 1920s Western fashion — Poiret's harem pants, Egyptian revival, Chinese silks, and imperialist fantasy.","era":"c.1910–1930, Europe and America","mood":"Fantastically Eastern, imperially imagined","visual":"Kimono-influenced sleeves. Turban headdresses. Egyptian motifs post-Tutankhamun (1922). Chinese embroidered silks. Draped 'Eastern' forms. The Oriental is imagined and appropriated, not authentic.","garments":["Kimono-sleeved evening coat","Turban headdress","Egyptian motif jewellery","Chinese embroidered silk","Harem pant suit"],"habitat":"1920s–30s fashion history, Orientalism in fashion study.","context":"The 1920s Orientalist vogue was driven by Poiret's pre-war Orientalism, the 1922 Tutankhamun discovery, and Western fascination with a stylised 'East'. It is now understood as imperial fantasy, not cultural engagement.","rarity":"Extinct","see_also":["Paul Poiret Aesthetic","Art Deco Egyptian","Art Deco Geometric"],"colors":["#1B4F72 Oriental Blue","#D4AF37 Gold","#8B0000 Eastern Red","#2C5530 Jade Green"],"media":["The Thief of Bagdad (1924) — film","Poiret: King of Fashion documentary — documentary"]},"Art Deco Egyptian":{"summary":"The Tutankhamun-inspired Egyptian motif fashion of the 1920s — scarabs, lotus flowers, and Howard Carter's discovery made into jewellery.","era":"c.1922–1935, Europe and America","mood":"Egyptomanically enchanted, archaeologically inspired","visual":"Scarab beetle motifs in jewellery. Lotus flower embroidery. Egyptian blue and gold. Sphinx and pyramid references. Howard Carter's 1922 discovery of Tutankhamun's tomb triggered the most intense Egyptomania since Napoleon.","garments":["Scarab beetle brooch","Lotus flower motif","Egyptian blue and gold palette","Hieroglyph pattern trim","Art Deco Egyptian bracelet"],"habitat":"Art Deco exhibitions, Egyptology cultural contexts, 1920s themed events.","context":"Carter's opening of Tutankhamun's tomb in November 1922 was arguably the media event of the 20th century — coverage was global and immediate. The resulting Egyptomania in fashion lasted throughout the decade.","rarity":"Extinct","see_also":["Art Deco Geometric","Orientalist 1920s","Egyptian Priestess"],"colors":["#D4AF37 Tutankhamun Gold","#1B4F72 Lapis Blue","#C1440E Carnelian","#1A1A1A Kohl Black"],"media":["The Mummy (1932) — film","Cleopatra (1934) — film","Tutankhamun documentary series"]},"Hollywood Egyptian":{"summary":"The Hollywood version of ancient Egypt — DeMille excess, Elizabeth Taylor, and the continual reinvention of Egypt as cinematic spectacle.","era":"c.1923–1963, Hollywood","mood":"Cinematically spectacular, historically approximate","visual":"Extended dramatic kohl eyeliner. White pleated linen approximation. Gold collar. Exotic jewellery. DeMille's 1923 Ten Commandments set the template. Elizabeth Taylor's Cleopatra (1963) defined it for generations.","garments":["Extended dramatic kohl","Approximated pleated linen","Wide gold collar","Cinematic Egyptian crown","Dark wig with straight fringe"],"habitat":"Hollywood history, Cleopatra cosplay, Halloween, Egyptian-themed fashion editorials.","context":"Hollywood's Egypt is a consistent fantasy — from the first silent Cleopatra (1917) through Taylor's iconic 1963 film. The look is historically inaccurate but visually coherent. It feeds a continuous cultural obsession.","rarity":"Niche","see_also":["Art Deco Egyptian","Egyptian Priestess","Cleopatra Aesthetic"],"colors":["#D4AF37 Hollywood Gold","#1A1A1A Kohl Black","#FAF8F5 White Linen","#1B4F72 Cinematic Blue"],"media":["Cleopatra (1963) — film","The Mummy (1999) — film"]},"Harlem Renaissance Fashion":{"summary":"The sophisticated, self-defining dress of the 1920s–30s Harlem Renaissance — elegance as resistance, style as political statement.","era":"c.1920–1937, Harlem, New York","mood":"Elegantly resistant, culturally assertive","visual":"The 'New Negro' aesthetic applied to dress — high-quality tailoring as a statement of dignity and equality. Women in couture or excellent copies. Men in sharp suits. The ballrooms of Harlem demanded the best.","garments":["Couture or excellent reproduction gown","Sharp tailored suit","Quality silk or crepe dress","Elegant accessorising","Gloves and hat for formal occasions"],"habitat":"Harlem Renaissance exhibitions, NAACP cultural contexts, African American history.","context":"The Black community in New York dressed up as a statement of equality in a segregated society. Langston Hughes, Josephine Baker, and Duke Ellington were style as much as cultural figures.","rarity":"Extinct","see_also":["Jazz Baby","Jazz Age Elegance","Civil Rights Movement Fashion"],"colors":["#1A1A1A Formal Black","#D4AF37 Gold","#8B0000 Crimson","#FAF8F5 Cream Silk"],"media":["Bessie (2015) — film","Harlem Renaissance documentary","Ma Rainey's Black Bottom (2020) — film"]},"Jazz Age Elegance":{"summary":"The sophisticated nightclub and cabaret dress of the late 1920s–30s — Vionnet's bias cut, Art Deco jewellery, and the body-conscious revolution.","era":"c.1926–1939, Paris and New York","mood":"Sophisticated, body-conscious, jazz-lit","visual":"Madeleine Vionnet's bias cut — silk that moved and clung. Low or cowl back. Minimal ornamentation. Art Deco jewellery. Platinum and diamonds. Silk in ivory, silver, and gold. Long evening gloves.","garments":["Bias-cut silk evening gown","Low cowl back","Platinum Art Deco jewellery","Long silk evening gloves","Gardenia hair ornament"],"habitat":"Art Deco exhibitions, 1930s Hollywood glamour contexts.","context":"Vionnet's bias cut (c.1927) was a technical revolution — cutting fabric diagonally made it drape and cling in ways impossible with conventional cutting. It defined 1930s eveningwear and remains a fundamental couture technique.","rarity":"Extinct","see_also":["Flapper Aesthetic","Art Deco Geometric","Old Hollywood Glamour"],"colors":["#C0C0C0 Silver Bias","#FAF8F5 Ivory Silk","#D4AF37 Gold","#1A1A1A Black"],"media":["The Great Gatsby (2013) — film","Chicago (2002) — film","Some Like It Hot (1959) — film"]},"Blues Singer Aesthetic":{"summary":"The performance dress of the classic blues era — Ma Rainey, Bessie Smith, and the theatrical self-presentation of the first Black female music stars.","era":"c.1920–1940, American South and Chicago","mood":"Theatrically powerful, crown-wearing, voice-embodied","visual":"Elaborate beaded and sequined gowns. Feather boas. Elaborate hair with jewels. Theatrical makeup. The dress compensated for racist exclusion from mainstream entertainment venues — making Black women visible as stars.","garments":["Beaded and sequined gown","Feather boa","Jewelled hair ornament","Theatrical face makeup","Long elbow gloves"],"habitat":"Blues history exhibitions, classic blues revival events.","context":"Bessie Smith and Ma Rainey were the first Black women to achieve national stardom in America, and they dressed accordingly — opulently and theatrically. The aesthetic is simultaneously performance costume and political statement of visibility.","rarity":"Extinct","see_also":["Harlem Renaissance Fashion","Jazz Baby","Pop Star Aesthetic"],"colors":["#D4AF37 Stage Gold","#8B0000 Crimson","#C0C0C0 Sequin Silver","#1A1A1A Stage Black"],"media":["Ma Rainey's Black Bottom (2020) — film","Bessie (2015) — film","The Color Purple (1985) — film"]},"Old Hollywood Glamour":{"summary":"The silver screen perfection of 1930s–40s Hollywood — Jean Harlow's white satin, Lauren Bacall's shoulders, and the studio system's manufactured feminine ideal.","era":"c.1927–1960, Hollywood","mood":"Silver-screen perfect, studio-manufactured","visual":"White or silver satin bias-cut gown. Platinum blonde or brunette with perfect waves. Red lips on black-and-white film. Deep back or shoulder cut. Fur stole. Floor-length. The aesthetic is simultaneously attainable ideal and impossible fantasy.","garments":["White or silver satin bias-cut gown","Platinum wave-set hair","Red lipstick","Fur stole","Floor-length with slight train"],"habitat":"Old Hollywood themed events, vintage Hollywood photography, Turner Classic Movies culture.","context":"The studio system manufactured beauty precisely — stars were dressed, lit, and photographed to a specific ideal. Adrian at MGM, Travis Banton at Paramount, Orry-Kelly at Warners shaped how America imagined femininity.","rarity":"Niche","see_also":["Silver Screen Aesthetic","Jazz Age Elegance","Film Noir Femme"],"colors":["#C0C0C0 Silver Satin","#FAF8F5 White Gown","#D4AF37 Gold","#1A1A1A Black Film"],"media":["All About Eve (1950) — film","Sunset Boulevard (1950) — film","Gentlemen Prefer Blondes (1953) — film"]},"Silver Screen Aesthetic":{"summary":"The constructed visual language of classic Hollywood cinema — the grammar of beauty that movies taught audiences to see and replicate.","era":"c.1927–1960, Hollywood","mood":"Cinematically constructed, aesthetically aspirational","visual":"Day dress with a specific cinematic quality: soft focus, perfect fit, aspirational. The Hollywood aesthetic was not only evening gowns — it was the grammar of looking beautiful that films taught to mass audiences.","garments":["Precisely fitted day dress","Shoulder-padded suit jacket","Perfect waves or victory rolls","Red lipstick","High-heeled Mary Janes"],"habitat":"Turner Classic Movies, vintage film culture, 1940s style communities.","context":"Hollywood's greatest influence wasn't the gowns — it was the grammar of beauty it taught. Every woman in every town learned from movies how to sit, stand, and dress to look cinematic.","rarity":"Niche","see_also":["Old Hollywood Glamour","Film Noir Femme","Audrey Hepburn Aesthetic"],"colors":["#C0C0C0 Silver Screen","#FAF8F5 Studio White","#1A1A1A Film Black","#D4AF37 Gold"],"media":["Sunset Boulevard (1950) — film","Singin' in the Rain (1952) — film","All About Eve (1950) — film"]},"Film Noir Femme":{"summary":"The dangerous, shadowed femininity of film noir — shoulder pads, Barbara Stanwyck's anklet, and fashion as weapon.","era":"c.1940–1958, Hollywood","mood":"Dangerously composed, shadow-dressed, fatally elegant","visual":"Sharp shoulder pads creating an architectural silhouette. Deep red or dark lipstick. Dark sunglasses as armour. Pencil skirt. Platform shoes. Hair in dramatic waves. Everything slightly too controlled.","garments":["Sharp shoulder-padded suit jacket","Pencil skirt","Dark dramatic lipstick","Large dark sunglasses","Platform heeled shoes"],"habitat":"Film noir screenings, classic Hollywood events, Dark Feminine adjacent aesthetics.","context":"The film noir femme fatale is one of cinema's great visual archetypes — created in the 1940s as a projection of male anxiety about women entering the workforce. But many of these women are the most compelling characters in their films.","rarity":"Niche","see_also":["Old Hollywood Glamour","Silver Screen Aesthetic","Dark Feminine"],"colors":["#1A1A1A Shadow Black","#8B0000 Femme Red","#C0C0C0 Cigarette Silver","#5B5B5B Film Grey"],"media":["Double Indemnity (1944) — film","Sunset Boulevard (1950) — film","The Big Sleep (1946) — film"]},"Depression Era Dress":{"summary":"The practical, make-do-and-mend dress of the Great Depression — flour sack dresses, careful repair, and dignity under economic catastrophe.","era":"c.1929–1939, United States","mood":"Dignified under deprivation","visual":"Flour sack dresses — manufacturers printed patterns on cotton flour sacks so families could reuse them. Careful repair and alteration. Natural cotton. Muted colours. Clean and pressed despite poverty. Hat still worn for Sunday.","garments":["Flour-sack cotton dress","Carefully repaired wool coat","Neutral muted cotton","Simple apron for work","Mended stockings"],"habitat":"Depression era history, make-do-and-mend culture, American hardship history.","context":"American flour manufacturers began printing patterns on cotton flour sacks knowing families would reuse them for clothing. At the height of the Depression, approximately 3.5 million dresses were made from flour sacks annually.","rarity":"Extinct","see_also":["Wartime Utility Aesthetic","Colonial American Dress","Vintage Americana"],"colors":["#8B7355 Flour Sack Brown","#C1440E Feedsack Red","#4A7C59 Dustbowl Green","#E8D5B0 Natural Cotton"],"media":["The Grapes of Wrath (1940) — film","Of Mice and Men (1939) — film","Paper Moon (1973) — film"]},"Wartime Utility Aesthetic":{"summary":"The rationed, practical dress of Second World War Britain — make do and mend, CC41 utility cloth, and dignity under restriction.","era":"c.1941–1947, Britain and America","mood":"Resourcefully dignified, patriotically practical","visual":"Utility cloth (rationed fabric with minimal waste). Shorter skirts. Fewer buttons, no cuffs, no deep hems. Suits with minimal decoration. Women's Land Army in dungarees. Turban headscarf for factory work. Still neat, still smart.","garments":["Utility cloth square-shouldered suit","Simple dress with no unnecessary detail","Turban factory headscarf","Land Army dungarees","Carefully preserved stockings"],"habitat":"Second World War history, Blitz spirit events, Goodwood Revival.","context":"CC41 (Civilian Clothing 1941) was the British utility clothing scheme — standardised, rationed, with no unnecessary detail. Norman Hartnell designed within its constraints. 'Make do and mend' became both policy and cultural identity.","rarity":"Extinct","see_also":["Land Girl","Victory Roll Aesthetic","Depression Era Dress"],"colors":["#5B5B5B Utility Grey","#4A7C59 Land Army Green","#8B7355 Khaki","#FAF8F5 Collar White"],"media":["Mrs Miniver (1942) — film","Foyle's War (TV series) — TV","Land Girls (TV series) — TV"]},"Land Girl":{"summary":"The practical working dress of the Women's Land Army — dungarees, breeches, the WLA shirt, and British women farming in wartime.","era":"c.1939–1950, Britain","mood":"Practically patriotic, rural and working","visual":"Women's Land Army uniform: green pullover, brown breeches or dungarees, fawn shirt, brown felt hat. Wellington boots for mud. The uniform of 80,000 women who kept British agriculture going.","garments":["Brown breeches","Green WLA pullover","Fawn WLA shirt","Brown felt hat","Wellington boots"],"habitat":"Women's Land Army history, Second World War history, agricultural heritage events.","context":"The Women's Land Army was revived in 1939 and 80,000 women served. The uniform was practical agricultural dress but also a statement about women's capabilities. It challenged gender norms as thoroughly as any suffragette dress.","rarity":"Extinct","see_also":["Wartime Utility Aesthetic","Victory Roll Aesthetic","New Woman Aesthetic"],"colors":["#4A7C59 WLA Green","#8B7355 Breeches Brown","#D4AF37 Straw Amber","#FAF8F5 Shirt White"],"media":["Land Girls (TV series) — TV","The Land Girls (1998) — film","Mrs Miniver (1942) — film"]},"Victory Roll Aesthetic":{"summary":"The pinned and rolled hairstyle of wartime women — beauty maintained under bombs, and lipstick as a patriotic act.","era":"c.1940–1945, Britain and America","mood":"Patriotically beautiful, resourcefully styled","visual":"Victory roll: hair rolled back from temples and pinned. Red lipstick — Churchill declared cosmetics essential to morale. Tailored suit or practical dress. Stockings or painted-on leg makeup when stockings unavailable.","garments":["Victory roll hairstyle","Red lipstick","Tailored utility suit","Rolled ankle socks or painted leg makeup","Patterned headscarf"],"habitat":"1940s fashion communities, Goodwood Revival, wartime reenactment, vintage hair styling.","context":"The British government made cosmetics non-rationed and Max Factor supplied American troops with lipstick specifically because lipstick was seen as essential to morale — for women on the home front and for men receiving letters.","rarity":"Rare","see_also":["Wartime Utility Aesthetic","Land Girl","Andrews Sisters Aesthetic"],"colors":["#8B0000 Patriot Red","#FAF8F5 Collar White","#1B4F72 Naval Blue","#5B5B5B Utility"],"media":["Blitz Street documentary","Foyle's War (TV series) — TV","1940s Weekend events"]},"Andrews Sisters Aesthetic":{"summary":"The matching harmonies and matching dress of the Andrews Sisters — sailor suits, fitted sweaters, and the best-selling sound of the Second World War.","era":"c.1937–1967, United States","mood":"Harmoniously matching, patriotically cheerful","visual":"Matching trio dress — the sisters wore identical or coordinating outfits. Sailor suit for military context. Fitted knit sweater and skirt. Neat patterned dress. Victory rolls. Red lipstick.","garments":["Matching sister trio outfits","Sailor suit","Fitted knit sweater","Victory roll hair","Red lipstick"],"habitat":"1940s swing dance events, Andrews Sisters tribute performances, big band contexts.","context":"The Andrews Sisters sold 75 million records. Their matching aesthetic was part of the package: unified, patriotic, cheerful. They defined the visual as well as sonic character of wartime American pop music.","rarity":"Extinct","see_also":["Victory Roll Aesthetic","Wartime Utility Aesthetic","Pop Star Aesthetic"],"colors":["#1B4F72 Navy","#8B0000 Patriotic Red","#FAF8F5 White","#D4AF37 Gold Star"],"media":["Buck Privates (1941) — film","In the Mood documentary","Glenn Miller Story (1954) — film"]},"Dior New Look":{"summary":"The 1947 revolution in fashion — Christian Dior's full skirts, nipped waists, and the return to feminine excess after wartime austerity.","era":"c.1947–1957, Paris","mood":"Luxuriously reactionary, femininely excess","visual":"Extremely full skirt (sometimes 100 metres of fabric). Nipped waist with corseted foundation. Padded hips. Below-the-knee hemline. Rounded, softened shoulders. White gloves. Small hat. Everything the opposite of wartime utility.","garments":["Full calf-length skirt","Sharply nipped waist","Padded hip skirt","Rounded padded shoulders","White gloves and small hat"],"habitat":"Fashion history, Dior retrospectives, 1950s inspired fashion.","context":"The New Look was simultaneously celebrated (luxury after austerity) and attacked (fabric waste, return to pre-feminist corseting). Harold Wilson in Britain denounced it in Parliament. Women burned the skirts in some American cities.","rarity":"Extinct","see_also":["Worth Couture Aesthetic","Society Matron Aesthetic","Atomic Housewife Aesthetic"],"colors":["#F5C6CB New Look Pink","#1A1A1A Black Waist","#FAF8F5 Ivory Silk","#D4AF37 Gold"],"media":["Dior and I (2014) — documentary","Christian Dior: Designer of Dreams (V&A) — exhibition","Coco Chanel & Igor Stravinsky (2009) — film"]},"Society Matron Aesthetic":{"summary":"The formal lunch dress of the upper-class mid-century woman — tailored suit, costume jewellery, and the aesthetic of the charity gala committee.","era":"c.1945–1970, Western cities","mood":"Formally charitable, tastefully conservative","visual":"Tailored suit or smart day dress. Excellent costume jewellery (Dior, Chanel, Miriam Haskell). Gloves for formal occasions. Smart court shoes. Pearls. Mink stole. The aesthetic of a woman who lunches and chairs committees.","garments":["Tailored Chanel-adjacent suit","Important costume jewellery","White gloves","Mink stole","Low-heel court shoes"],"habitat":"1950s–60s fashion history, charity gala aesthetic, old money contexts.","context":"The Society Matron aesthetic was the apex of the 1950s–60s establishment feminine ideal. It has been absorbed into Old Money and Quiet Luxury aesthetics — those of us who know the distinction can still trace it.","rarity":"Extinct","see_also":["Dior New Look","Old Money","Ladies Who Lunch"],"colors":["#2C5530 Establishment Green","#5B5B5B Matron Grey","#D4AF37 Costume Gold","#FAF8F5 Glove White"],"media":["The Women (1939) — film","All About Eve (1950) — film","Mad Men (TV series) — TV"]},"The Luncheon Aesthetic":{"summary":"The precisely calibrated dress of the midcentury ladies who lunch — the right restaurant, the right dress, the right company.","era":"c.1950–1975, New York, London, Paris","mood":"Precisely social, fashionably poised","visual":"Day dress at its most elegant. Smart suit. Good hat for formal lunches. White gloves. Quality handbag. Perfect hair. The appropriate jewellery. Everything considered, nothing accidental.","garments":["Smart silk day dress","Good felt or straw hat","White gloves","Quality leather handbag","Important brooch"],"habitat":"Ladies' lunch culture, 1960s fashion history, New York social history.","context":"The Ladies Who Lunch aesthetic was famously satirised by Sondheim in Company (1970), but represented a genuine and serious female social world — one of the few public spaces where women had real agency and power in the 1950s–60s.","rarity":"Extinct","see_also":["Society Matron Aesthetic","Ladies Who Lunch","Old Money"],"colors":["#2C5530 Lunch Green","#FAF8F5 White Gloves","#D4AF37 Gold Brooch","#C0C0C0 Silver"],"media":["The Women (1939) — film","All About Eve (1950) — film","Company (Sondheim musical) — theatre"]},"Ladies Who Lunch":{"summary":"Truman Capote's 'swans' — Babe Paley and her circle, the apex of mid-century American feminine style and its tragic ending.","era":"c.1955–1975, New York","mood":"Impeccably swanned, socialite-perfected","visual":"Balenciaga or Mainbocher. Perfect hair set by Kenneth. Minimal but important jewellery. Simple elegant dress or suit. Nothing out of place. The aesthetic of extreme wealth expressed through extreme restraint.","garments":["Balenciaga or couture day dress","Kenneth-set perfect hair","Important but minimal jewellery","Quality gloves","Perfect court shoes"],"habitat":"New York social history, Capote cultural references, old money contexts.","context":"Truman Capote's 'swans' were the apex of mid-century feminine style. His publication of thinly veiled portraits of them in 1975 ended his social life — Babe Paley never spoke to him again.","rarity":"Extinct","see_also":["The Luncheon Aesthetic","Society Matron Aesthetic","Old Money"],"colors":["#2C5530 Restrained Green","#5B5B5B Discreet Grey","#D4AF37 Important Gold","#FAF8F5 Perfect White"],"media":["Company (Sondheim, 1970) — theatre","Answered Prayers, Truman Capote — novel","All About Eve (1950) — film"]},"Rockabilly":{"summary":"The retro-futurist fusion of 1950s rock and roll with country music — full skirts, cuffed jeans, and American working-class rebellion.","era":"c.1954–1960; revival 1980s–present","mood":"Rebelliously retro, American-roots charged","visual":"Women: full circle skirts with petticoats, fitted blouse, red lipstick, ponytail with scarf. Men: cuffed jeans, white T-shirt, leather jacket, quiff. Elvis, Eddie Cochran, Gene Vincent as style models.","garments":["Full circle skirt with petticoat","Fitted button blouse","Men's cuffed jeans","White T-shirt","Leather jacket and quiff"],"habitat":"Rockabilly revival music scene, psychobilly adjacent culture, vintage car shows, '50s themed diners.","context":"Rockabilly was working-class American youth expressing itself through music and dress before Elvis made it mainstream. The 1980s neo-rockabilly movement (Stray Cats) kept it alive. It has a dedicated global community today.","rarity":"Niche","see_also":["Poodle Skirt Aesthetic","Grease Aesthetic","Vintage Americana"],"colors":["#8B0000 Hot Rod Red","#1A1A1A Black Leather","#FAF8F5 White Tee","#D4AF37 Gold Trim"],"media":["Grease (1978) — film","Cry Baby (1990) — film","Stray Cats discography — music"]},"Poodle Skirt Aesthetic":{"summary":"The full-skirted, bobby-socked, teenage dress of the 1950s — the aesthetic of sock hops, diners, and the original American teenage consumer culture.","era":"c.1950–1958, United States","mood":"Cheerfully teenage, sock-hop ready","visual":"Full circle skirt in felt with poodle or other appliqué. White bobby socks with saddle shoes. Fitted twin set or blouse. Ponytail. Charm bracelet. The dress of the first generation of American teenagers as a cultural category.","garments":["Felt circle skirt with appliqué","White ankle socks","Saddle shoes","Fitted blouse or cardigan","Ponytail with scarf"],"habitat":"1950s themed diners, sock hop events, American nostalgia culture, Grease.","context":"The poodle skirt represents the first specifically teenage consumer culture in American history — in the 1950s, teenagers for the first time had pocket money and a cultural world of their own.","rarity":"Niche","see_also":["Rockabilly","Grease Aesthetic","American Heritage"],"colors":["#F5C6CB Felt Pink","#4A7C59 Mint Green","#D4AF37 Marigold","#1B4F72 Baby Blue"],"media":["Grease (1978) — film","American Graffiti (1973) — film","Back to the Future (1985) — film"]},"Grease Aesthetic":{"summary":"The 1978 film's vision of 1950s teen culture — Pink Ladies, T-Birds, and the most influential pop-culture 1950s revival ever made.","era":"c.1978 film; perpetual revival","mood":"Nostalgically rebellious, cinema-mediated","visual":"Sandy's Pink Ladies jacket. Sandy's final black spandex transformation. Danny Zuko's T-Birds leather. White saddle shoes. Poodle skirt. The film's aesthetic is as much 1970s as 1950s — it's nostalgia for an era the creators barely lived.","garments":["Pink Ladies satin jacket","T-Birds leather jacket","Black spandex trousers","Poodle skirt","White saddle shoes"],"habitat":"Grease screenings and singalongs, school productions, Halloween, 1950s themed events.","context":"Grease (1978) is not the 1950s — it's the 1970s imagining the 1950s. Sandy's final transformation outfit (black spandex) is entirely 1970s. The film has been so influential that it has replaced the actual 1950s in popular memory.","rarity":"Niche","see_also":["Poodle Skirt Aesthetic","Rockabilly","Y2K Pop Princess"],"colors":["#F5C6CB Pink Ladies Pink","#1A1A1A T-Birds Black","#FAF8F5 Sandra Dee White","#D4AF37 Gold Trim"],"media":["Grease (1978) — film","Grease 2 (1982) — film","Grease: Live (2016) — TV"]},"Atomic Housewife Aesthetic":{"summary":"The paradoxically modern-and-domestic 1950s housewife — atomic prints, shirtwaist dresses, and the era of the perfect suburban home.","era":"c.1950–1962, United States","mood":"Domestically optimistic, atomically patterned","visual":"Shirtwaist dress in bright prints — including atomic and space-age motifs. Apron for cooking. Sensible but stylish court shoes. Set hair. Pearls for the suburban dinner party. The aesthetic of The Donna Reed Show and Mad Men's Betty Draper.","garments":["Shirtwaist dress in bright prints","Practical apron","Court shoes","Pearls","Set hair in waves"],"habitat":"Mad Men cultural contexts, 1950s suburban history, retro homemaking communities.","context":"The Atomic Housewife aesthetic represents the tension of the postwar feminine ideal — expected to be modern (atomic prints, modern appliances) and domestic simultaneously. Betty Friedan's The Feminine Mystique (1963) documented the psychological cost.","rarity":"Extinct","see_also":["Dior New Look","Homemaker Aesthetic","Atomic Age Fashion"],"colors":["#F5C6CB Suburban Pink","#87CEEB Atomic Blue","#D4AF37 Cheerful Yellow","#FAF8F5 Apron White"],"media":["Mad Men (TV series) — TV","Far from Heaven (2002) — film","Pleasantville (1998) — film"]},"Atomic Age Fashion":{"summary":"The 1950s–60s love affair with space, nuclear energy, and scientific optimism expressed in fashion — Sputnik shapes, metallic fabrics, and the future as salvation.","era":"c.1957–1969, global","mood":"Optimistically futurist, space-race excited","visual":"Metallics and silver. Geometric shapes. Pierre Cardin's space-age silhouettes. Sputnik-inspired spherical forms. Go-go boots. Shift dresses in metallic or space-inspired prints.","garments":["Metallic shift dress","Geometric sculptural shapes","Vinyl go-go boots","Space-age print","Minimal jewellery"],"habitat":"Space Race cultural history, Pierre Cardin archives, 1960s fashion history.","context":"The 1957 Sputnik launch gave fashion a new vocabulary of optimism — metallic fabrics, space-age shapes. Pierre Cardin and André Courrèges led the exploration. The future was a place fashion could go.","rarity":"Extinct","see_also":["Atomic Housewife Aesthetic","Courrèges Aesthetic","Space Age 1950s"],"colors":["#C0C0C0 Space Silver","#D4AF37 Atomic Gold","#1B4F72 Space Blue","#87CEEB Sky Blue"],"media":["Forbidden Planet (1956) — film","Mad Men (TV series) — TV","The Jetsons (1962) — animation"]},"Space Age 1950s":{"summary":"The pre-Sputnik American vision of space as gleaming optimism — tailfin cars, Googie architecture, and the atom as pure promise.","era":"c.1950–1958, United States","mood":"Gleamingly optimistic, tailfin-shaped","visual":"Metallic details. Boomerang and atomic shapes in jewellery. Googie architecture influence. Chrome accessories. The aesthetic predates actual space travel — it imagines space as science fiction envisioned it.","garments":["Atomic pattern print dress","Chrome jewellery","Tailfin-inspired silhouette","Metallic accessory","Futurist-pattern fabric"],"habitat":"Googie architecture appreciation, 1950s Americana, atomic age nostalgia.","context":"The American 1950s imagined a future of atomic power and space travel as pure optimism. The Atomic Age aesthetic — atoms as jewellery, Sputnik shapes, tailfin cars — was genuine popular utopian design.","rarity":"Extinct","see_also":["Atomic Housewife Aesthetic","Atomic Age Fashion","Googie Aesthetic"],"colors":["#C0C0C0 Chrome Silver","#D4AF37 Rocket Gold","#87CEEB Sky Blue","#FAF8F5 Pure White"],"media":["The Jetsons (1962) — animation","Forbidden Planet (1956) — film"]},"Googie Aesthetic":{"summary":"The Space Age architectural style of 1950s America applied to fashion — boomerangs, atoms, starbursts, and the visual vocabulary of diners and bowling alleys.","era":"c.1950–1965, United States","mood":"Roadside futurist, optimistically angular","visual":"Boomerang and starburst patterns. Atomic and molecular motifs. Sweeping angular shapes. Chrome. The visual vocabulary of the Jetsons, flying saucer-roofed diners, and bowling alley signage.","garments":["Atomic starburst pattern","Boomerang motif print","Angular geometric silhouette","Chrome detail","Space Age pop colour"],"habitat":"Googie architecture appreciation groups, 1950s diner aesthetic, Mid-Century Modern communities.","context":"Googie is the design style named after Googie's coffee shop in Los Angeles (designed by John Lautner) — sweeping roofs, starbursts, atoms, boomerangs. The architectural expression of space-race optimism.","rarity":"Niche","see_also":["Atomic Age Fashion","Space Age 1950s","Atomic Housewife Aesthetic"],"colors":["#D4AF37 Starburst Yellow","#8B0000 Boomerang Red","#1B4F72 Atomic Blue","#C0C0C0 Chrome"],"media":["The Jetsons (1962) — animation","Catch Me If You Can (2002) — film","Populuxe, Thomas Hine (1986) — book"]},"Carnaby Street":{"summary":"The swinging epicentre of 1960s London fashion — Mary Quant's miniskirt, mod boys, and the first youth-led fashion revolution.","era":"c.1955–1973, London","mood":"Youth-revolutionary, swinging, mod-primary","visual":"The miniskirt — 6 inches above the knee, revolutionary. Op art bold graphic patterns. PVC and patent leather. Shift dress. Geometric cuts. Go-go boots. False eyelashes. Mary Quant's daisy logo.","garments":["Mary Quant mini shift dress","Op art geometric print","Go-go vinyl boots","False eyelashes","Patent leather belt"],"habitat":"Carnaby Street London (still exists), 1960s fashion exhibitions, Swinging Sixties events.","context":"Carnaby Street replaced Paris as the fashion capital for under-25s in the 1960s. It was the first time youth specifically had a fashion capital of their own. Mary Quant's miniskirt was the most politically charged hemline since the French Revolution.","rarity":"Extinct","see_also":["Twiggy Aesthetic","Courrèges Aesthetic","Mod Aesthetic"],"colors":["#FF6B6B Op Art Red","#1A1A1A Mod Black","#FAF8F5 White","#D4AF37 Gold Go-Go"],"media":["Blow-Up (1966) — film","Absolute Beginners (1986) — film","Ready Steady Go! (TV, 1963–66) — TV"]},"Twiggy Aesthetic":{"summary":"The Lesley Lawson look — mod waifish femininity that defined 1966–67 and changed the fashion body standard.","era":"c.1966–1969, London","mood":"Waifish, wide-eyed, mod-iconic","visual":"Extremely short shift dresses. Giant painted lashes on lower lid. Sculpted short geometric hair. No curves — the opposite of 1950s voluptuousness. Op art prints. White and pale palette.","garments":["Ultra-short shift dress","Painted lower lash liner","Sculpted short geometric hair","Flat chest silhouette","White patent boots"],"habitat":"1960s fashion history, mod revival communities, fashion photography history.","context":"Twiggy became the world's first supermodel at 17 in 1966 — her image was everywhere simultaneously. She embodied the 1960s rejection of the 1950s feminine ideal. She retired the 'Twiggy' character when she grew too old for it.","rarity":"Extinct","see_also":["Carnaby Street","Courrèges Aesthetic","Go-Go Girl"],"colors":["#FAF8F5 Shift White","#1A1A1A Mod Black","#F5C6CB Pale Pink","#D4AF37 Mod Gold"],"media":["Blow-Up (1966) — film","Twiggy: A Life in Photographs — book"]},"Courrèges Aesthetic":{"summary":"The space-age couturier who anticipated the moon landing in fashion — white boots, geometric shapes, and dressing for the future.","era":"c.1964–1975, Paris","mood":"Space-age optimistic, geometrically futurist","visual":"White mid-calf boot. Short above-knee geometrically cut dress. White with accents. Helmet or visor. Clean minimal lines. The specific futurism of a designer who believed fashion should prepare for the 21st century.","garments":["White above-knee geometric dress","White mid-calf Courrèges boot","Visor or helmet accessory","Clean minimal line","Space-inspired contrast"],"habitat":"Fashion history, 1960s space-age design, couture archives.","context":"Courrèges predicted the miniature ten years before Apollo 11. He and Pierre Cardin were making fashion literally futuristic in the early 1960s.","rarity":"Extinct","see_also":["Twiggy Aesthetic","Carnaby Street","Space Age 1950s"],"colors":["#FAF8F5 Space White","#D4AF37 Gold","#1A1A1A Black Trim","#C0C0C0 Silver"],"media":["Courrèges retrospective documentaries — documentary","Blow-Up (1966) — film"]},"Go-Go Girl":{"summary":"The white-booted, miniskirted dancer of 1960s nightclubs — the Whisky a Go Go, go-go boots, and the first professional dancing-as-spectacle culture.","era":"c.1964–1969, United States","mood":"Energetically performative, dance-platform ready","visual":"White go-go boots (knee-high, block-heeled). Mini skirt or shift. False eyelashes and pale lipstick. Mod geometric pattern. Hair in a flipped or straight bob.","garments":["White knee-high go-go boots","Mini shift dress","Pale frosted lipstick","False eyelashes","Mod geometric pattern"],"habitat":"1960s themed events, go-go aesthetic revival, disco adjacent events.","context":"The go-go dancer emerged from the Whisky a Go Go in Los Angeles (1964). The go-go boot became one of the defining objects of 1960s fashion.","rarity":"Extinct","see_also":["Twiggy Aesthetic","Carnaby Street","Disco Aesthetic"],"colors":["#FAF8F5 White Boots","#1A1A1A Black Dress","#F5C6CB Pink","#D4AF37 Gold"],"media":["Laugh-In (TV show) — TV","Austin Powers: International Man of Mystery (1997) — film"]},"Flower Child Early":{"summary":"The gentle, idealistic dress of the early hippie movement — flowers, beads, and the genuinely utopian aesthetic before commercialisation.","era":"c.1965–1967, San Francisco","mood":"Genuinely utopian, peace-believing","visual":"Flowers in hair. Indian printed fabric. Fringed leather. Long flowing skirts or bell-bottoms. Bare feet or sandals. Ethnic jewellery and beads. The genuine aesthetic before it became a costume — Haight-Ashbury, 1966–67.","garments":["Fresh flowers in hair","Indian cotton print dress","Fringed leather vest","Long bell-bottom jeans","Multiple bead necklaces"],"habitat":"Summer of Love commemorations, Haight-Ashbury cultural history.","context":"The Haight-Ashbury Summer of Love in 1967 was a genuine counterculture moment before it was a fashion. Between 1965 and 1967, the hippie aesthetic was a sincere expression of alternative values. Commercialisation happened with extraordinary speed.","rarity":"Extinct","see_also":["Swinging Sixties Boho","Festival Folk","Earth Mother Aesthetic"],"colors":["#F5C6CB Flower Pink","#4A7C59 Meadow Green","#D4AF37 Marigold","#87CEEB Sky Blue"],"media":["Hair (1979) — film","Easy Rider (1969) — film","Woodstock (1970 documentary) — documentary"]},"Swinging Sixties Boho":{"summary":"The middle-class bohemian dress of the later 1960s — the mod aesthetic loosening into ethnic fabrics, Hendrix fringe, and creative London.","era":"c.1967–1971, London","mood":"Creatively eclectic, ethnically curious","visual":"Ethnic and vintage mixing. Afghan coat. Indian kurta. Vintage military jacket. Wide-brimmed hat. Bell-bottoms. Layered ethnic jewellery. The aesthetic of Chelsea and Notting Hill in the late 1960s.","garments":["Afghan embroidered coat","Indian print kurta","Vintage military jacket","Wide floppy hat","Layered ethnic jewellery"],"habitat":"1960s London cultural history, Notting Hill heritage, bohemian fashion.","context":"The late 1960s London bohemian aesthetic mixed Carnaby Street mod with ethnic shopping from the newly multicultural city. The Afghan coat, the Indian kurta, and vintage military jacket were all part of an aesthetic simultaneously curious and appropriative.","rarity":"Extinct","see_also":["Flower Child Early","Festival Folk","Bohemian"],"colors":["#C1440E Afghan Orange","#D4AF37 Indian Gold","#4A7C59 Ethnic Green","#8B4513 Suede Brown"],"media":["Blow-Up (1966) — film","Easy Rider (1969) — film","The Doors documentary — documentary"]},"Festival Folk":{"summary":"The outdoor festival dress of the late 1960s–70s — Woodstock, Glastonbury, and the aesthetic of 100,000 people in a field.","era":"c.1969–1980; revival 2000s–present","mood":"Mud-comfortable, music-saturated","visual":"Practical but bohemian. Wellies. Fringed suede. Crochet tops. Bell-bottoms. Festival poncho. Hat for sun and rain. Layered jewellery. The authentic version before it became a fashion category.","garments":["Fringed suede jacket","Bell-bottom jeans","Crochet top","Wide-brimmed hat","Wellington boots"],"habitat":"Glastonbury and music festival culture worldwide.","context":"Woodstock (1969) and the Isle of Wight Festival (1970) created a specific aesthetic vocabulary for large outdoor music events. The 2000s Hunter boot industry turned festival fashion into commerce.","rarity":"Niche","see_also":["Flower Child Early","Swinging Sixties Boho","Coachella Fashion"],"colors":["#8B7355 Festival Brown","#4A7C59 Field Green","#D4AF37 Sunshine Gold","#C1440E Mud Orange"],"media":["Woodstock (1970) — documentary","Glastonbury (2006) — documentary","Almost Famous (2000) — film"]},"Earth Mother Aesthetic":{"summary":"The natural, un-made-up, barefoot dress of the early environmental and feminist consciousness — maxi skirts, beeswax, and living close to the land.","era":"c.1969–1977, rural communes","mood":"Naturally grounded, un-cosmetic","visual":"Long natural fabrics. No makeup. Unshaved and unapologetically so. Bare feet or Birkenstocks. Handmade and repaired. Natural colours. Long flowing hair. The visual culture of back-to-the-land.","garments":["Long natural cotton maxi dress","No makeup","Birkenstock sandals","Handwoven or handmade garments","Long natural hair"],"habitat":"Commune living history, back-to-the-land communities, early environmental movement.","context":"The Earth Mother aesthetic emerged from the late 1960s back-to-the-land movement — thousands of young people leaving cities for rural communes. It was a complete rejection of both fashion and consumer culture.","rarity":"Rare","see_also":["Flower Child Early","Crunchy Mom Aesthetic","Cottagecore"],"colors":["#8B7355 Earth Brown","#4A7C59 Natural Green","#F5E6C8 Undyed Linen","#C1440E Terracotta"],"media":["The Joni Mitchell Anthology — music","Easy Rider (1969) — film","A Woman Under the Influence (1974) — film"]},"Prairie Dress 1970s":{"summary":"The anti-fashion, gingham-and-lace prairie dress of the 1970s — Laura Ashley, Little House on the Prairie, and the romanticisation of simple rural life.","era":"c.1968–1980, Britain and America","mood":"Rurally romantic, historically nostalgic","visual":"Long calico or gingham dress. High neck with lace or eyelet trim. Long sleeve with gathered cuff. Pinafore apron over. Flat boots or Mary Janes. Long braided hair with ribbon. The Laura Ashley universe.","garments":["Gingham or calico long dress","High neck with eyelet trim","Long gathered sleeves","Pinafore apron over","Long braided hair with ribbon"],"habitat":"Laura Ashley heritage, 1970s fashion revival, prairie adjacent communities.","context":"Laura Ashley built a global brand on romanticised Victorian and Edwardian rural dress. It was explicitly anti-fashion. It fed directly into 2010s Cottagecore's pastoral romanticism.","rarity":"Extinct","see_also":["Cottagecore","Earth Mother Aesthetic","Regencycore"],"colors":["#C1440E Calico Red","#4A7C59 Prairie Green","#D4AF37 Wheat Gold","#FAF8F5 Lace White"],"media":["Little House on the Prairie (TV series) — TV","Badlands (1973) — film"]},"Stevie Nicks Aesthetic":{"summary":"The mystical, layered, witchy femininity of Fleetwood Mac's front woman — chiffon, velvet, platforms, and the original witchcore.","era":"c.1975–present","mood":"Mystically layered, witchy-feminine, enduringly enchanting","visual":"Layers of chiffon and lace in black, grey, and ivory. Platform boots. Shawls draped multiple times. Velvet vest or jacket. Top hat. Rings on every finger. Long wavy blonde hair.","garments":["Layered chiffon and lace shawl","Platform boots","Velvet vest or jacket","Top hat","Multiple rings"],"habitat":"Stevie Nicks fan communities, Witchcore adjacent fashion, 1970s rock revival.","context":"Stevie Nicks's aesthetic was never trend-driven — she dressed in a consistent personal style across five decades. Her witchy romanticism fed directly into Gothic female aesthetics of the 1980s–90s and contemporary Witchcore.","rarity":"Niche","see_also":["Witchcore","Boho Feminine","Glam Rock"],"colors":["#2C2C2C Witchy Black","#8B7355 Chiffon Grey","#C0C0C0 Silver Shawl","#D4AF37 Platform Gold"],"media":["Rumours (Fleetwood Mac, 1977) — music","The Dance (Fleetwood Mac, 1997) — concert film","Stop Draggin' My Heart Around (video) — music video"]},"T. Rex Aesthetic":{"summary":"The glitter-and-boa glamour of Marc Bolan and T. Rex — the original glam rock, and being beautiful before Bowie.","era":"c.1970–1977, London","mood":"Glitteringly beautiful, pre-Bowie glam","visual":"Glitter on face and body. Feather boa. Satin jumpsuit. Corkscrew curls with flowers or glitter. Platform shoes or boots. The look is self-adorned, pretty, and deliberately non-heteronormative.","garments":["Face glitter and glam makeup","Feather boa","Satin or velvet top","Corkscrew curls with flowers","Platform boots"],"habitat":"Glam rock events, T. Rex appreciation, early 1970s music history.","context":"Marc Bolan popularised glitter and glamour on men in Britain from 1970 — two years before Bowie's Ziggy Stardust. His death in 1977, days before his 30th birthday, prevented him from becoming as retrospectively famous.","rarity":"Rare","see_also":["Glam Rock","Bowie Aesthetic","Rockstar Aesthetic"],"colors":["#D4AF37 Glitter Gold","#8B0000 Bolan Red","#C0C0C0 Silver","#2C2C2C Velvet Black"],"media":["Born to Boogie (1972) — documentary/film","20th Century Boy (documentary) — documentary","T. Rextasy documentary — documentary"]},"Glam Rock":{"summary":"The spectacular, gender-bending dress of 1970s British glam rock — platforms, silver jumpsuits, and the most glamorous pop era in history.","era":"c.1971–1977, Britain","mood":"Spectacularly glamorous, gender-transgressive","visual":"Extreme platform boots or shoes. Silver, gold, or holographic fabric. Glitter. Jumpsuits. Full face makeup for men. Outsize and theatrical. T. Rex, Bowie, Sweet, Slade, Roxy Music — each with distinct variation on the glam vocabulary.","garments":["Platform boots or shoes","Silver or holographic jumpsuit","Full face makeup and glitter","Feather or fur trim","Outsize theatrical silhouette"],"habitat":"Glam rock events, 1970s music history, Ziggy Stardust cultural references.","context":"Glam rock was unique in being a commercially mainstream movement that was simultaneously queer-coded and gender-transgressive. Bowie, Bolan, and Bryan Ferry all presented an alternative masculine ideal in full makeup on mainstream TV.","rarity":"Extinct","see_also":["T. Rex Aesthetic","Bowie Aesthetic","Rockstar Aesthetic"],"colors":["#C0C0C0 Silver","#D4AF37 Glam Gold","#8B0000 Glam Red","#C185A0 Ziggy Pink"],"media":["Velvet Goldmine (1998) — film","Todd Haynes documentary","Ziggy Stardust and the Spiders from Mars (1973) — documentary"]},"Bowie Aesthetic":{"summary":"David Bowie's multiple-identity fashion performance — from Ziggy to the Thin White Duke to Berlin, the most documented personal style evolution in pop history.","era":"c.1972–2016, London/Berlin/New York","mood":"Identity-fluid, perpetually reinventing","visual":"Ziggy Stardust: red spiky hair, lightning bolt face, metallic jumpsuits. Thin White Duke: white shirt, black waistcoat, cigarette. Berlin era: deconstructed. Each persona fully thought through. The V&A 2013 exhibition is the definitive document.","garments":["Ziggy metallic jumpsuit","Lightning bolt face makeup","Thin White Duke white shirt and waistcoat","Berlin deconstructed look","Platform boots"],"habitat":"Bowie exhibitions, music history, androgynous fashion.","context":"The V&A's 'David Bowie Is' (2013) toured the world and became the most visited exhibition in the museum's history. Each of his persona changes — Ziggy, Aladdin Sane, the Thin White Duke, Jareth — was fully conceived as a character.","rarity":"Niche","see_also":["Glam Rock","T. Rex Aesthetic","Glam Androgyny"],"colors":["#C185A0 Ziggy Pink","#D4AF37 Gold","#1B4F72 Space Blue","#F5C6CB Kabuki White"],"media":["Ziggy Stardust and the Spiders from Mars (1973) — documentary","Stardust (2020) — film","Moonage Daydream (2022) — documentary"]},"Blaxploitation Aesthetic":{"summary":"The self-defined Black style of 1970s Blaxploitation cinema — afros, leather, and the first films where Black characters dressed themselves.","era":"c.1971–1979, United States","mood":"Self-defined, politically assertive, defiantly stylish","visual":"Natural afro. Leather coat. Platform shoes. Wide-collar shirts in vivid prints. Dashiki. Large hoop earrings. The aesthetic of Shaft, Pam Grier, Foxy Brown — self-defined Black style on screen for the first time.","garments":["Natural afro","Wide-collar vivid print shirt","Leather trench coat","Platform shoes","Large hoop earrings"],"habitat":"Blaxploitation film revival, 1970s Black style history, afrofuturism adjacent contexts.","context":"Blaxploitation films were controversial within Black communities — some saw them as exploitative, others as the first chance to see Black characters as powerful protagonists. Their fashion was uniformly extraordinary.","rarity":"Extinct","see_also":["Funk Goddess Aesthetic","Hip-Hop & R&B","Afrofuturism"],"colors":["#8B4513 Leather Brown","#D4AF37 Gold","#8B0000 Power Red","#C0C0C0 Platform Silver"],"media":["Shaft (1971) — film","Foxy Brown (1974) — film","Coffy (1973) — film"]},"Funk Goddess Aesthetic":{"summary":"The spectacular, political, Black-feminine dress of 1970s funk music — Chaka Khan, Donna Summer, and dress as power.","era":"c.1972–1982, United States","mood":"Powerfully spectacular, funky-feminine","visual":"Elaborate natural hairstyles. Platform shoes of enormous height. Jumpsuits in vivid colours. Halterneck. Sequins and metallics. Dashiki-influenced prints. The aesthetic of Parliament-Funkadelic, Earth Wind & Fire, Chaka Khan.","garments":["Large natural hairstyle","Platform shoes","Vivid halterneck jumpsuit","Sequins or metallics","Large statement jewellery"],"habitat":"Funk music history, 1970s soul contexts, Black feminine style history.","context":"Funk music produced some of the most spectacular stage fashion in history — Parliament-Funkadelic's costumes were entire theatrical productions. George Clinton's vision combined Afrofuturism, ancient Egypt, and glam rock.","rarity":"Extinct","see_also":["Blaxploitation Aesthetic","Disco Aesthetic","Afrofuturism"],"colors":["#D4AF37 Funk Gold","#C1440E Orange","#C0C0C0 Silver Platform","#8B0000 Funky Red"],"media":["What's Going On (Marvin Gaye, 1971) — music","Rufus featuring Chaka Khan (1975) — music","Parliament-Funkadelic live concerts — music"]},"Disco Aesthetic":{"summary":"The escapist, hedonistic, inclusive dress of 1970s disco — sequins, platforms, and dancing all night at Studio 54.","era":"c.1974–1980, New York","mood":"Hedonistically escapist, sequin-lit, democratically inclusive","visual":"Sequins everywhere. Spandex. Halterneck. Platforms. Wrap dress (Diane von Fürstenberg). Bold patterns. Everything designed to move, reflect light, and last the night. Disco emerged from Black and gay communities before crossing over.","garments":["Full-sequin disco dress","Platform heels","Spandex flare trousers","Halterneck","Wrap dress in bold print"],"habitat":"Disco revival nights, Studio 54 themed events, 1970s parties worldwide.","context":"Disco emerged from underground Black and LGBTQ+ club culture before crossing over into global mainstream fashion. The Disco Sucks campaign and backlash had explicitly racist and homophobic dimensions.","rarity":"Niche","see_also":["Funk Goddess Aesthetic","Studio 54","Electronic & Club Culture"],"colors":["#D4AF37 Disco Gold","#C0C0C0 Mirror Ball Silver","#FF6B6B Neon Pink","#1A1A1A Sleek Black"],"media":["Saturday Night Fever (1977) — film","Boogie Nights (1997) — film","Studio 54 (2018) — documentary"]},"Disco Dollies Aesthetic":{"summary":"The specifically female, decoratively maximalist expression of peak disco — the women who made Studio 54 spectacular.","era":"c.1977–1980, New York","mood":"Maximally spectacular, studio-floor ready","visual":"Maximum sequins. Platforms at highest. Feather trim. Dramatic makeup. Elaborate hair. Halterneck in metallic. Everything as excessive as possible.","garments":["Full-length sequin gown","Feather-trimmed hem","Extremely high platform","Dramatic eye makeup","Elaborate upswept hair"],"habitat":"Studio 54 themed events, 1970s disco parties, drag-adjacent aesthetics.","context":"The Disco Dolly aesthetic was the female performance side of Studio 54 — the women who dressed to be seen, to compete, and to celebrate.","rarity":"Extinct","see_also":["Disco Aesthetic","Studio 54","Maximalism"],"colors":["#C0C0C0 Mirror Ball Silver","#D4AF37 Sequin Gold","#FF6B6B Neon Pink","#8B0000 Crimson"],"media":["Studio 54 (2018) — documentary","Saturday Night Fever (1977) — film"]},"Studio 54":{"summary":"The door-selected, celebrity-saturated aesthetic of New York's most exclusive disco — Bianca Jagger, Liza Minnelli, and Andy Warhol in one room.","era":"c.1977–1980, New York","mood":"Exclusively excessive, celebrity-adjacent, hedonistically historic","visual":"You needed to look extraordinary to get in. Mick and Bianca Jagger. Liza Minnelli. Andy Warhol. Halston. Sequins, feathers, platforms. Confetti and disco balls descending at the end of the night.","garments":["Halston jersey dress","Celebrity-worthy sequin gown","Platform shoes","Feather accessory","Perfect Studio 54 face"],"habitat":"Studio 54 themed events, disco history, New York 1970s cultural history.","context":"Studio 54 lasted only 33 months (April 1977–February 1980) before owners were arrested for tax evasion. In that time it became the most famous nightclub in history. The door policy was as famous as the interior.","rarity":"Extinct","see_also":["Disco Aesthetic","Disco Dollies Aesthetic","Met Gala Aesthetic"],"colors":["#D4AF37 Halston Gold","#C0C0C0 Mirror Ball","#FF00FF Fuchsia","#1A1A1A Manhattan Black"],"media":["Studio 54 (2018) — documentary","54 (1998) — film","Saturday Night Fever (1977) — film"]},"Mod Revival":{"summary":"The 1970s–80s revival of 1960s mod style — The Jam, two-tone suits, and the Vespa as fashion accessory.","era":"c.1977–1985, Britain","mood":"Sharp-suited, Vespa-riding, sharply nostalgic","visual":"Two-tone suit in sharp grey or navy. Fred Perry polo shirt. Parka with target badge. Slim tie. Chelsea boots. Ben Sherman shirt. Hair cut short and sharp. Vespa scooter essential.","garments":["Two-tone slim suit","Fred Perry polo shirt","Parka with target badge","Slim tie","Chelsea boots"],"habitat":"Mod revival communities, The Jam fan events, British heritage scooter rallies.","context":"The Mod Revival of 1977–83 was partly about punk's relation to 1960s mod, partly about working-class youth culture reclaiming sharp tailoring. Quadrophenia (1979) was the cultural document.","rarity":"Rare","see_also":["Mod Aesthetic","Post-Punk Fashion","Britpop Aesthetic"],"colors":["#1B4F72 Mod Blue","#1A1A1A Sharp Black","#FAF8F5 White","#8B0000 Target Red"],"media":["Quadrophenia (1979) — film","The Jam: Beat Surrender documentary — documentary","This Is England (2006) — film"]},"Post-Punk Fashion":{"summary":"The darkly intellectual, artfully dishevelled dress of the post-punk generation — Joy Division, Wire, and fashion as critical statement.","era":"c.1977–1983, Britain","mood":"Darkly intellectual, artfully minimal","visual":"Worn black. Deliberately wrong silhouettes. Men's shirts on women. Narrow trousers. Black polo neck. Secondhand and worn. The look of someone who doesn't care about fashion but has thought very carefully about that not-caring.","garments":["Worn black clothing","Slightly wrong deliberate silhouette","Narrow black trousers","Men's secondhand shirt","Black polo neck"],"habitat":"Post-punk music appreciation, Factory Records cultural contexts.","context":"Post-punk fashion was a critique of punk's commercialisation and of fashion itself — calculated dishevelment. Wire, Gang of Four, and Joy Division all had a visual aesthetic as considered as their music.","rarity":"Rare","see_also":["Punk Lineage","Proto-Goth Aesthetic","Indie Rock Aesthetic"],"colors":["#1A1A1A Post-Punk Black","#5B5B5B Concrete Grey","#8B7355 Worn Brown","#4A7C59 Dour Green"],"media":["Joy Division: Control (2007) — film","24 Hour Party People (2002) — film","Urgh! A Music War (1981) — documentary"]},"Blitz Kids Aesthetic":{"summary":"The outrageous dress of the Blitz club, Covent Garden — the New Romantics before they had a name, Steve Strange's door policy.","era":"c.1979–1981, London","mood":"Outrageously theatrical, self-invented","visual":"Theatrical costume-as-dress. Historical references remixed. Elaborate makeup. Cross-dressing elements. Ultra-specific individual looks — every person competed for originality. Vivienne Westwood and charity shops combined.","garments":["Theatrical historical costume","Full face elaborate makeup","Cross-dressing elements","Individually invented look","Charity shop and designer mixed"],"habitat":"New Romantic history, Blitz Club legacy, Steve Strange cultural contexts.","context":"The Blitz Club ran from 1979–1980. Steve Strange ran the door and turned away those whose costumes weren't sufficiently original. Boy George worked the cloakroom. The club launched New Romanticism, Culture Club, and Spandau Ballet.","rarity":"Extinct","see_also":["New Romantic","Duran Duran Aesthetic","Camp Aesthetic"],"colors":["#D4AF37 Theatrical Gold","#8B0000 Blitz Red","#4A7C59 Costume Green","#C185A0 Makeup Rose"],"media":["Fashionation documentary","New Romantics: The Look (documentary) — documentary","Absolute Beginners (1986) — film"]},"New Romantic":{"summary":"The synthesiser-era spectacle of early 1980s Britain — frills, piracy, medieval references, and the music video as fashion show.","era":"c.1981–1986, Britain","mood":"Spectacularly theatrical, synth-era romantic","visual":"Pirate imagery. Elaborate frills at collar. Waistcoats. Long coats. Elaborate makeup for both men and women. Japanese fashion influence. The look of Duran Duran, Spandau Ballet, Culture Club.","garments":["Frilled pirate shirt","Elaborate waistcoat","Full dramatic makeup","Long theatrical coat","Statement accessories"],"habitat":"New Romantic events, 1980s music nights, Duran Duran fan contexts.","context":"The New Romantics used the newly dominant music video as a fashion showcase — MTV launched in 1981 and immediately made visual style as important as sound. Duran Duran's budgets for videos were feature-film scale.","rarity":"Niche","see_also":["Blitz Kids Aesthetic","Duran Duran Aesthetic","Post-Punk Fashion"],"colors":["#8B0000 Pirate Crimson","#D4AF37 Gold","#4A7C59 New Wave Green","#C185A0 Mascara Rose"],"media":["New Romantics documentary","Pop video era archives","Absolute Beginners (1986) — film"]},"Duran Duran Aesthetic":{"summary":"The jet-set, yacht-and-video glamour of early Duran Duran — sharp tailoring, exotic locations, and MTV as fashion magazine.","era":"c.1981–1986, Birmingham/global","mood":"Glamorously jet-set, MTV-launched","visual":"Sharp Italian tailoring. White shirts open at neck. Sunglasses. Yacht settings. Hair in New Romantic style but sharper. The accessible, aspirational end of New Romanticism.","garments":["Sharp Italian suit jacket","Open-necked white shirt","Dark sunglasses","New Romantic styled hair","Expensive watch"],"habitat":"1980s music nights, Duran Duran fan events, New Romantic contexts.","context":"Duran Duran positioned themselves as the glamorous, aspirational end of New Romanticism. Their music videos (filmed in Sri Lanka, Antigua, Paris) made global glamour seem achievable for British teenagers.","rarity":"Extinct","see_also":["New Romantic","Blitz Kids Aesthetic","Wall Street Aesthetic"],"colors":["#D4AF37 Rio Gold","#1B4F72 Mediterranean Blue","#FAF8F5 White Shirt","#8B7355 Italian Tan"],"media":["Rio (Duran Duran, 1982) — music","Hungry Like the Wolf (video, 1982) — music video","Sing Blue Silver documentary — documentary"]},"Goth Early":{"summary":"The first wave of Gothic subculture emerging from post-punk — Siouxsie, Bauhaus the band, and the birth of a permanent aesthetic subculture.","era":"c.1979–1983, Britain","mood":"Proto-darkly atmospheric, post-punk serious","visual":"All black. Crimped or teased hair. Siouxsie Sioux spider-web eye makeup. Fishnets. Band T-shirts. Pointed boots. The aesthetic before it had a name — growing out of post-punk's darkness.","garments":["All-black clothing","Crimped teased hair","Spider-web eye makeup","Fishnet stockings","Pointed ankle boots"],"habitat":"Early Gothic history, Siouxsie and the Banshees fan contexts.","context":"The Goth aesthetic emerged from post-punk before it had a name. The Batcave club in London from 1982 gave it a gathering point. Siouxsie Sioux, Bauhaus (the band), and The Cure were creating the visual vocabulary from 1979.","rarity":"Rare","see_also":["Trad Goth","Batcave Aesthetic","Post-Punk Fashion"],"colors":["#1A1A1A Goth Black","#8B0000 Blood Red","#C0C0C0 Bone White","#2C2C2C Velvet"],"media":["The Hunger (1983) — film","Near Dark (1987) — film","Joy Division: Control (2007) — film"]},"Benetton Aesthetic":{"summary":"The deliberately multiracial, politically provocative advertising aesthetic of 1980s–90s Benetton — United Colors and fashion as activist statement.","era":"c.1982–2000, Italy/global","mood":"Provocatively multiracial, advertising-political","visual":"Primary and vivid colours. Simple knitwear. The visual diversity of the advertising campaigns. Clean simple shapes in bold rainbow. The political used to sell the commercial.","garments":["Vivid primary colour knit","Simple sweater","Bold solid colour","Mixed pattern basics","Graphic bright accessories"],"habitat":"Fashion history, advertising ethics debate, 1980s–90s commercial aesthetics.","context":"Benetton under art director Oliviero Toscani produced some of the most controversial advertising in commercial history — AIDS patients, war imagery, prison executions — all to sell knitwear.","rarity":"Extinct","see_also":["Ralph Lauren Lifestyle Aesthetic","Nike Aesthetic","Normcore"],"colors":["#FF0000 Benetton Red","#0000FF Benetton Blue","#FFFF00 Benetton Yellow","#00AA00 Benetton Green"],"media":["Benetton advertising archives (1984–2000)","Colors magazine — print"]},"Dynasty Aesthetic":{"summary":"The shoulder-padded, jewelled excess of the American prime-time soap Dynasty — Joan Collins's Alexis Carrington as the definitive 1980s villainess.","era":"c.1981–1989, American television","mood":"Villainess-magnificent, shoulder-maximised","visual":"Enormous shoulder pads. Beaded evening gowns. Power suits with extreme shoulders. Jewels. Joan Collins as Alexis. Dynasty was the highest-rated show in America in 1984–85.","garments":["Enormous shouldered power suit","Beaded evening gown","Oversized jewellery","Extreme shoulder pad jacket","Statement collar"],"habitat":"1980s themed events, Dynasty fan culture, TV fashion history.","context":"Dynasty's fashion, designed by Nolan Miller, was deliberate excess — each female character needed a more spectacular wardrobe than the last. 25 million Americans watched per episode at its peak.","rarity":"Extinct","see_also":["Joan Collins Aesthetic","Dallas Aesthetic","Power Dressing"],"colors":["#D4AF37 Dynasty Gold","#8B0000 Dynasty Crimson","#C0C0C0 Silver Sequin","#1A1A1A Power Black"],"media":["Dynasty (TV, 1981–89) — TV","Dallas (TV, 1978–91) — TV"]},"Joan Collins Aesthetic":{"summary":"The maximally glamorous, shoulder-padded, jewelled look of Joan Collins as Alexis Carrington — 1980s villainess as permanent fashion icon.","era":"c.1981–present","mood":"Magnificently villainous, unrepentantly maximalist","visual":"The largest possible shoulder pads. Sequinned everything. Furs. Enormous jewellery. Perfectly set hair. Full dramatic makeup. The aesthetic of a woman who enters every room as an event.","garments":["Maximum shoulder pad suit jacket","Sequined evening gown","Enormous statement jewellery","Full dramatic makeup","Perfect set hair"],"habitat":"Dynasty fan culture, 1980s fashion references, camp maximalism.","context":"Joan Collins has maintained her aesthetic consistently since the 1980s — she is one of the few celebrities whose personal style has never deviated. Alexis Carrington became genuinely her aesthetic, not just a role.","rarity":"Niche","see_also":["Dynasty Aesthetic","Power Dressing","Camp Aesthetic"],"colors":["#D4AF37 Alexis Gold","#8B0000 Power Red","#C0C0C0 Silver","#1A1A1A Villain Black"],"media":["Dynasty (TV, 1981–89) — TV","Joan Collins: The First Lady of Dynasty — documentary"]},"Wall Street Aesthetic":{"summary":"The power-suited, red-braced dress of 1980s financial culture — Gordon Gekko's greed-is-good wardrobe made fashion.","era":"c.1984–1990, New York","mood":"Power-defined, status-aggressive, greed-coded","visual":"The Armani suit. Red or yellow braces (suspenders). White spread-collar shirt. Bold striped tie. Slicked-back hair. MBA-branded briefcase. Gold Rolex. Expensive shoes.","garments":["Armani double-breasted suit","Red braces (suspenders)","White spread-collar shirt","Bold striped tie","Gold Rolex watch"],"habitat":"Wall Street cultural references, Gordon Gekko cosplay, 1980s finance history.","context":"Oliver Stone's Wall Street (1987) codified the aesthetic of 1980s financial culture. Michael Douglas's Gordon Gekko became one of cinema's most imitated looks. The 'greed is good' speech is the most quoted in fashion-adjacent business culture.","rarity":"Extinct","see_also":["Finance Bro Aesthetic","Power Dressing","Tech Mogul Aesthetic"],"colors":["#8B7355 Armani Tan","#1B4F72 Power Blue","#D4AF37 Gold Rolex","#FAF8F5 Spread Collar White"],"media":["Wall Street (1987) — film","American Psycho (2000) — film","Bonfire of the Vanities (1990) — film"]},"Dallas Aesthetic":{"summary":"The shoulder-padded, big-hair, Texan excess of TV drama Dallas — oil money, cowboy hats, and J.R. Ewing's grin.","era":"c.1978–1991, American television","mood":"Texan-excessive, big-haired, oilfield wealthy","visual":"Big hair — the Texas beehive or power curls. Shoulder pads. Western-influenced details — belt buckles, pointed boots even in formal suits. Bold colours. Everything bigger than in New York or London.","garments":["Big Texas-styled hair","Shoulder-padded power suit","Western-detail belt buckle","Pointed cowboy boots with suit","Bold colour dress"],"habitat":"Dallas fan culture, Texas heritage events, 1980s TV references.","context":"Dallas was one of the most-watched shows in American television history. 76 million Americans watched the 'Who shot J.R.?' resolution in 1980 — the largest American TV audience ever. It exported aspirational Texan excess worldwide.","rarity":"Extinct","see_also":["Dynasty Aesthetic","Wall Street Aesthetic","Nashville Aesthetic"],"colors":["#D4AF37 Texas Gold","#8B0000 Oil Red","#8B7355 Cowboy Brown","#1B4F72 Power Blue"],"media":["Dallas (TV, 1978–91) — TV","Giant (1956) — film","Urban Cowboy (1980) — film"]},"Miami Vice Aesthetic":{"summary":"The pastel suit-over-T-shirt, no-socks masculine look that directly changed global men's fashion in the mid-1980s.","era":"c.1984–1989","mood":"Sun-bleached, deliberately casual-elegant","visual":"Pastel suit (pink, aqua, grey) over white or pastel T-shirt. No socks with loafers. Slight stubble. Hair loosely styled. Aviator sunglasses. The look of Crockett and Tubbs.","garments":["Pastel suit jacket","Matching pastel trousers","White T-shirt beneath","Loafers with no socks","Aviator sunglasses"],"habitat":"Miami Vice fan culture, 1980s fashion history, 'no socks with loafers' origin story.","context":"Miami Vice (1984–89) directly changed men's fashion worldwide — within six months of its premiere, menswear manufacturers were producing pastel suits and T-shirts as sets. One of the most documented cases of television directly driving fashion trends.","rarity":"Niche","see_also":["Wall Street Aesthetic","Dynasty Aesthetic","Power Dressing"],"colors":["#87CEEB Aqua","#F5C6CB Pastel Pink","#E8D5B0 Cream","#1A1A1A Black"],"media":["Miami Vice (TV, 1984–89) — TV","Miami Vice (2006 film) — film"]},"Early Hip-Hop Fashion":{"summary":"The foundational visual culture of hip-hop's first generation — Adidas, Kangol, fat laces, and the South Bronx expressing itself through style.","era":"c.1973–1984, South Bronx, New York","mood":"Foundationally expressive, street-born, brand-claiming","visual":"Adidas shell toes with fat laces (untied). Kangol bucket hat. Run-DMC track suit. Cazal glasses. Denim jacket. Gold chain. The aesthetic of expressing individuality and community on limited resources.","garments":["Adidas shell toes with fat laces","Kangol hat","Track suit","Gold chain","Cazal glasses"],"habitat":"Hip-hop history, Bronx cultural heritage, Old School Hip-Hop events.","context":"Hip-hop fashion began as community expression — taking expensive sportswear brands and making them a cultural vocabulary. Run-DMC's 'My Adidas' (1986) formalised the relationship between hip-hop and sportswear brands.","rarity":"Extinct","see_also":["Old School Hip-Hop","B-Boy / B-Girl Aesthetic","Streetwear Culture"],"colors":["#1A1A1A Shell Toe Black","#FAF8F5 Adidas White","#D4AF37 Gold Chain","#8B0000 Kangol Red"],"media":["Wild Style (1983) — film","Beat Street (1984) — film","Style Wars (1983) — documentary"]},"Madonna Aesthetic":{"summary":"The continuously reinventing fashion performance of Madonna — from Boy Toy to Sex to Vogue, the most influential single fashion performance in pop history.","era":"c.1983–present","mood":"Perpetually reinventing, culture-provoking","visual":"1980s phase: lace gloves, layered crucifixes, tulle skirts, rubber bracelets, Boy Toy belt. Bleached blonde. Mixed Catholic iconography with underwear as outerwear. Every young woman copying within six months.","garments":["Lace fingerless gloves","Layered crucifix necklaces","Rubber bracelets stack","Tulle miniskirt","Boy Toy belt"],"habitat":"Pop history, Material Girl themed events, 1980s fashion history.","context":"Madonna's fashion influence in 1983–89 was unprecedented — market researchers measured 'the Madonna effect' in real time as trends spread to teenagers globally within months. She and Michael Jackson were the first global pop culture brands.","rarity":"Niche","see_also":["Pop Star Aesthetic","Vogue Fashion","Power Dressing"],"colors":["#1A1A1A Lace Black","#D4AF37 Crucifix Gold","#FAF8F5 Corset White","#8B0000 Boy Toy Red"],"media":["Madonna: Truth or Dare (1991) — documentary","Desperately Seeking Susan (1985) — film","Material Girl video (1985) — music video"]},"Acid Wash Era":{"summary":"The stone-washed, bleach-treated denim aesthetic of mid-1980s fashion — the most identifiable fabric treatment of the decade.","era":"c.1985–1990, global","mood":"Casually bleached, denim-distressed","visual":"Acid-washed denim jacket. Matching jeans. High waist. The pale, mottled, bleach-pattern treatment applied to denim. Oversized jacket. Stone-washed lighter wash alternative.","garments":["Acid-washed denim jacket","Matching acid-wash jeans","High-waisted fit","Pastel T-shirt beneath","White trainers"],"habitat":"1980s fashion history, retro denim collecting, vintage markets.","context":"Acid wash was created by washing denim with pumice stones soaked in chlorine bleach — accidentally discovered in Italy. It became dominant fashion in 1985–89 before disappearing almost entirely, only to be revived in 2010s vintage culture.","rarity":"Niche","see_also":["Grunge Aesthetic","Vintage Americana","Y2K"],"colors":["#8B7355 Bleached Denim","#C0C0C0 Washed Grey","#FAF8F5 Stone Wash","#D4AF37 Brass"],"media":["Back to School (1986) — film","Fast Times at Ridgemont High (1982) — film"]},"Bon Chic Bon Genre":{"summary":"The socially precise, understated chic of the Parisian upper bourgeoisie — the BCBG aesthetic of Saint-Germain and the 16th arrondissement.","era":"c.1970s–present, Paris","mood":"Precisely correct, understated bourgeois","visual":"Conservative, quality clothing in muted or classic colours. Hermès scarf. Simple navy or camel. Ballet flats. Pearl earrings. Burberry or navy blazer. The look of someone who doesn't need to try.","garments":["Quality navy or camel coat","Hermès silk scarf","Simple pearl earrings","Ballet flats","Minimal quality bag"],"habitat":"Parisian social culture, French old money contexts.","context":"BCBG was codified in Thierry Mantoux's 1985 book 'Le BCBG: Le Guide du Bon Chic Bon Genre.' It describes the specific social aesthetic of the French upper bourgeoisie — quality, restraint, and the precise communication of social standing.","rarity":"Niche","see_also":["Old Money","Quiet Luxury","French Girl Style"],"colors":["#1B4F72 BCBG Navy","#8B7355 Camel","#FAF8F5 White","#D4AF37 Hermès Gold"],"media":["Le BCBG: Le Guide du Bon Chic Bon Genre, Thierry Mantoux (1985) — book"]},"BCBG Aesthetic":{"summary":"The American preppy equivalent of Parisian BCBG — the specific social uniform of the educated Eastern Seaboard class.","era":"c.1980s–present, East Coast USA","mood":"Precisely preppy, socially legible","visual":"Polo shirt. Khakis. Boat shoes. Quality blazer. Simple pearl or gold jewellery. Hair neat and correct. The look that says Yale or Georgetown without naming it.","garments":["Polo shirt","Khaki chinos","Boat shoes or loafers","Navy blazer","Simple gold earrings"],"habitat":"East Coast academic circles, preppy fashion history.","context":"The American BCBG aesthetic shares the French original's social logic: dress communicates membership in a class that doesn't need to declare itself.","rarity":"Niche","see_also":["Preppy","Old Money","Ivy League"],"colors":["#1B4F72 Ivy Navy","#8B7355 Khaki","#D4AF37 Gold Button","#FAF8F5 Oxford White"],"media":["The Official Preppy Handbook, Lisa Birnbach (1980) — book","Metropolitan (1990) — film"]},"Parisian Bourgeois":{"summary":"The specific dress of the French middle class — not BCBG aristocratic but the solid, quality dress of teachers, civil servants, and the republic's backbone.","era":"c.1950s–present, France","mood":"Solidly republican, quality-valuing","visual":"Good coat over simple dress or trousers. Practical sensible shoes. Nothing showy. Good quality but not luxury. Conservative, long-lasting, unsexy, and deeply correct.","garments":["Good-quality coat","Simple dress or trousers","Practical leather shoes","Unshowy bag","Natural makeup"],"habitat":"French social history, la vie quotidienne française.","context":"The French bourgeois aesthetic is the unseen foundation of French fashion. It values quality, correctness, and longevity over trend.","rarity":"Niche","see_also":["BCBG Aesthetic","French Girl Style","Quiet Luxury"],"colors":["#1B4F72 Republican Blue","#5B5B5B Bourgeois Grey","#8B7355 Sensible Brown","#FAF8F5 Correct White"],"media":["À bout de souffle (1960) — film","Jules and Jim (1962) — film"]},"French Conservative Chic":{"summary":"The discreetly tailored dress of right-leaning French politics and society — the visual language of the French establishment.","era":"c.1970s–present, France","mood":"Discreetly establishment, correctly tailored","visual":"Tailored suit or quality dress. Conservative colours — navy, camel, beige, grey. Silk scarf. Limited jewellery. Very correct shoes. The aesthetic of political wives and the Académie française.","garments":["Conservative tailored suit","Silk or wool dress","Navy or beige","Silk scarf","Conservative court shoes"],"habitat":"French political history, establishment conservative culture.","context":"French conservative chic is distinct from BCBG by its specifically political overtones — the visual language of the establishment right, from Giscard d'Estaing's presidency through Macroniste centrism.","rarity":"Niche","see_also":["BCBG Aesthetic","Parisian Bourgeois","Power Dressing"],"colors":["#1B4F72 Conservative Navy","#8B7355 Camel","#5B5B5B Establishment Grey","#FAF8F5 Correct White"],"media":["La Promesse de l'Aube — film","French political archive footage"]},"Naomi Campbell Aesthetic":{"summary":"The physical command and cultural authority of Naomi Campbell — striding as declaration, Black supermodel centrality to the 1990s runway.","era":"c.1988–present","mood":"Supremely powerful, stride-defining","visual":"The strut is as much the aesthetic as the clothes. Strong shoulder. Fitted. Minimum effort, maximum impact. Black excellence on the world stage.","garments":["Strong-shoulder tailored dress","Fitted minimal gown","High-heel command walk","Fierce minimal makeup","Statement piece jewellery"],"habitat":"Fashion history, 1990s supermodel culture, Black fashion excellence.","context":"Naomi Campbell's disputes with designers who refused to use Black models changed industry practices. She is one of the most significant figures in fashion history.","rarity":"Niche","see_also":["Old Hollywood Glamour","Power Dressing","Black Girl Magic Fashion"],"colors":["#1A1A1A Power Black","#D4AF37 Gold","#FAF8F5 White","#C0C0C0 Catwalk Silver"],"media":["Unzipped (1995) — documentary","The September Issue (2009) — documentary","Supermodel documentary series"]},"Catwalk Aesthetic":{"summary":"The specific visual vocabulary of the 1990s fashion show — the supermodel era, the Linda/Naomi/Christy trinity, and the runway as cultural event.","era":"c.1990–2000, global fashion weeks","mood":"Supremely professional, runway-specific","visual":"The supermodel's fashion show look. Strong makeup. Hair in show-specific set. Clothes that walk, not just hang. The confidence of someone who walks for a living.","garments":["Show-specific professional makeup","Designer dress as worn on runway","Professional model stride","Show hair set","Model-specific confidence"],"habitat":"Fashion week contexts, supermodel history.","context":"The early 1990s 'golden age of the supermodel' was driven by Versace paying enormous fees to create supermodels as cultural celebrities. Linda Evangelista's quote 'I don't get out of bed for less than $10,000' remains definitive.","rarity":"Niche","see_also":["Naomi Campbell Aesthetic","Kate Moss Aesthetic","Fashion Week Street Style"],"colors":["#1A1A1A Runway Black","#FAF8F5 White","#D4AF37 Gold","#C0C0C0 Silver"],"media":["Unzipped (1995) — documentary","The September Issue (2009) — documentary","Robert Altman's Prêt-à-Porter (1994) — film"]},"Kate Moss Aesthetic":{"summary":"The waif who replaced the supermodel — 30 years of effortless British cool across Calvin Klein, Galliano, and Dior.","era":"c.1990–present","mood":"Effortlessly cool, slightly undone, British","visual":"The slip dress. Vintage-mix approach. Bohemian layers. Skinny jeans with rock T-shirt. The ability to make anything look like it's supposed to look that way. Nothing too precious.","garments":["Slip dress","Vintage rock T-shirt","Skinny jeans","Ankle boots","Effortlessly undone hair"],"habitat":"British fashion culture, Kate Moss tribute events.","context":"Kate Moss's 1993 Calvin Klein Obsession campaign replaced the athletic supermodel with a waif. She has since transitioned from model to brand. Her aesthetic has been continuously imitated for over 30 years.","rarity":"Common","see_also":["Grunge Aesthetic","Indie Sleaze","Slip Dress Era"],"colors":["#8B7355 Vintage Brown","#1A1A1A Rock Black","#FAF8F5 Slip White","#5B5B5B Grunge Grey"],"media":["Calvin Klein Obsession campaign (1993) — advertising","Absolutely Fabulous (TV series) — TV"]},"Calvin Klein Aesthetic":{"summary":"The minimalist American luxury of Calvin Klein — CK One, white cotton, and the American ideal of clean sex appeal.","era":"c.1969–present","mood":"Minimally sexual, American-clean","visual":"White or off-white. Simple cuts. Excellent denim. White cotton underwear as outerwear. Clean, minimal, aspirational. The specific American minimalism of someone who needs no decoration.","garments":["White cotton T-shirt","Classic blue denim","White briefs as statement piece","Minimal white dress","Clean leather belt"],"habitat":"American fashion history, minimalist fashion, denim culture.","context":"Calvin Klein redefined American fashion in the 1970s with minimalist luxury and in the 1980s with jeans advertising banned in several countries. CK One (1994) was the first gender-neutral fragrance to achieve mass market success.","rarity":"Common","see_also":["Kate Moss Aesthetic","Slip Dress Era","Minimalist Design Aesthetic"],"colors":["#FAF8F5 CK White","#1A1A1A CK Black","#8B7355 Denim Wash","#E8D5B0 Minimal Ivory"],"media":["CK One campaign (1994) — advertising","American Psycho (2000) — film","The September Issue (2009) — documentary"]},"Slip Dress Era":{"summary":"The 1990s slip dress — bias-cut silk worn as outerwear, layered over T-shirts or alone, the anti-structure statement of the decade.","era":"c.1993–1999","mood":"Effortlessly underdressed, silk-simple","visual":"Bias-cut silk or satin slip. Thin spaghetti straps. Lace hem. Worn alone or layered over T-shirt or under cardigan. The look of having grabbed something from the lingerie drawer and made it work.","garments":["Bias-cut silk slip dress","Thin spaghetti straps","Lace-trimmed hem","Worn over T-shirt option","Flat strappy sandals"],"habitat":"1990s fashion revival, minimalist fashion.","context":"The slip dress was the definitive early 1990s anti-structure statement — rejection of 1980s power dressing through apparent underdressing. Kate Moss wearing a slip dress over a T-shirt was the definitive early-90s image.","rarity":"Common","see_also":["Kate Moss Aesthetic","Calvin Klein Aesthetic","Grunge Aesthetic"],"colors":["#C0C0C0 Silver Bias","#FAF8F5 Ivory Silk","#F5C6CB Blush","#D4AF37 Champagne"],"media":["Four Weddings and a Funeral (1994) — film","Clueless (1995) — film","Friends (TV series) — TV"]},"Rachel Green Aesthetic":{"summary":"Jennifer Aniston as Rachel Green in Friends — the mini skirt, the layered looks, and one of the most-replicated hairstyles in television history.","era":"c.1994–2004","mood":"Approachably aspirational, 90s perfect","visual":"Mini skirts in plaid or solid. Layered pieces. Tight ribbed tank tops. Fitted blazer. The Rachel haircut: layered face-frame with highlights. Slip-on loafers.","garments":["Plaid mini skirt","Ribbed fitted tank top","Fitted blazer","Slip-on loafers","The Rachel haircut"],"habitat":"Friends fans, 1990s fashion revival, The Rachel haircut cultural history.","context":"The Rachel haircut is widely considered the most replicated hairstyle in American history — at its peak, 11 million women reportedly had variations of it.","rarity":"Niche","see_also":["Kate Moss Aesthetic","Slip Dress Era","Y2K"],"colors":["#F5C6CB Rachel Pink","#FAF8F5 White","#8B7355 Natural","#D4AF37 Gold"],"media":["Friends (TV, 1994–2004) — TV"]},"Heroin Chic":{"summary":"The controversial 1990s aesthetic of studied pallor and underfed waif beauty — the fashion industry's most criticised moment.","era":"c.1993–1997","mood":"Controversially waif-thin, pallid, studied","visual":"Pale, almost translucent skin. Prominent collar bones. Dark under-eye circles. Unwashed-looking hair. Very minimal clothes. President Clinton specifically criticised it in 1997. Contextual note required.","garments":["Slip dress on thin frame","Dark under-eye styling","Pallid complexion","Minimal loose clothing","Flat shoes or bare feet"],"habitat":"Fashion history, 1990s aesthetic study. Sensitive: this aesthetic contributed to the normalisation of underweight bodies in fashion.","context":"Heroin Chic emerged from 1990s photography and Calvin Klein campaigns. Clinton criticised it in 1997 after photographer Davide Sorrenti's death. It represented a fashion industry normalisation of extremely underweight bodies.","rarity":"Extinct","see_also":["Kate Moss Aesthetic","Slip Dress Era","Calvin Klein Aesthetic"],"colors":["#FAF8F5 Pallid White","#8B7355 Unwashed Denim","#5B5B5B Dark Circle Grey","#E8D5B0 Wan Ivory"],"media":["Calvin Klein campaigns (1993–96) — advertising","Trainspotting (1996) — film (contextual reference)"]},"TLC Aesthetic":{"summary":"The Left Eye, T-Boz, and Chilli look — baggy clothes, condom eye patches, and one of the most visually distinctive acts of the 1990s.","era":"c.1992–1999","mood":"Playfully subversive, comfy-cool, politically charged","visual":"Baggy denim and cargo trousers. Bright colours layered. Oversized T-shirts. Left Eye's condom eye patch (AIDS awareness). Caps and snapbacks. Air Force 1s or Timberlands.","garments":["Baggy cargo trousers","Oversized T-shirt","Bright layered colours","Snapback cap","Air Force 1s"],"habitat":"TLC fan culture, 1990s R&B history, Left Eye tributes.","context":"TLC were the best-selling American girl group of all time. Left Eye's condom eye patch was simultaneously fashion statement and AIDS awareness advocacy.","rarity":"Extinct","see_also":["Old School Hip-Hop","Baddie Aesthetic","Grunge Girl"],"colors":["#FF6B6B TLC Red","#4A7C59 Baggy Green","#D4AF37 Gold Chain","#1B4F72 Hip-Hop Blue"],"media":["CrazySexyCool (TLC, 1994) — music","Waterfalls (video, 1995) — music video"]},"Club Kid Aesthetic":{"summary":"The Manhattan club night fantasy of Michael Alig's Limelight era — the most extreme personal styling that has ever been called fashion.","era":"c.1988–1996, New York","mood":"Competitively extreme, self-invented","visual":"Themes and concepts carried into dress. Bodies painted. Objects worn as accessories. The deliberate goal of being the most extreme person in the room. Amanda Lepore. RuPaul early career.","garments":["Concept-as-costume","Full body paint","Object-as-accessory","Theme-carried styling","Maximum extreme anything"],"habitat":"New York nightlife history, Limelight Club cultural history, drag adjacent culture.","context":"The Club Kids were part of the Limelight, Tunnel, and Palladium club scene in the late 1980s–90s. It ended catastrophically when promoter Michael Alig murdered his roommate Andre Melendez in 1996.","rarity":"Extinct","see_also":["Camp Aesthetic","Drag Queen Aesthetic","E-Culture"],"colors":["#D4AF37 Concept Gold","#8B0000 Extreme Red","#C185A0 Drag Rose","#1A1A1A Manhattan Black"],"media":["Party Monster (2003) — film","Club Kids documentary — documentary"]},"Rave Fashion 1990s":{"summary":"The neon, PVC, and baggy aesthetic of British and American rave culture — fluorescent, sweaty, spiritual, and PLUR.","era":"c.1988–1997, UK and USA","mood":"Neon-spiritual, dance-functional, PLUR","visual":"Neon colours. Baggy trousers and hooded tops for movement. PVC elements. Kandi bracelets. Smiley face. Glow accessories. Whistles. The aesthetic is designed for dancing for 8 hours.","garments":["Neon baggy trousers","Hooded sweatshirt","Kandi bead bracelets","Smiley face T-shirt","Glow sticks"],"habitat":"Rave history, Acid House culture, UK club history.","context":"UK rave culture produced the Acid House summer of 1988 and the Second Summer of Love. The fashion was functional — baggy for dancing, kandi for community.","rarity":"Niche","see_also":["Electronic & Club Culture","UK Rave Aesthetic","EDM Festival Aesthetic"],"colors":["#FF6B6B Neon Pink","#39FF14 Neon Green","#00BFFF Electric Blue","#FFFF00 Acid Yellow"],"media":["Human Traffic (1999) — film","24 Hour Party People (2002) — film","Go (1999) — film"]},"Y2K":{"summary":"The turn-of-millennium fashion aesthetic — low-rise jeans, chrome accessories, and the last gasp of pre-internet physical fashion culture.","era":"c.1997–2004; revival 2019–present","mood":"Millennial-nostalgic, chrome-futurist","visual":"Low-rise jeans with visible underwear waistband. Crop top or shrunken T-shirt. Platform flip flops or chunky trainers. Butterfly clips and frosted lipgloss. Tiny handbag. Chrome or metallic accessories. Rhinestones.","garments":["Low-rise jeans","Crop or shrunken top","Platform flip flops","Butterfly hair clips","Rhinestone embellishment"],"habitat":"TikTok, Instagram revival communities, Depop vintage, early 2000s themed events.","context":"Y2K fashion is currently in its second revival cycle. It represents the last era of fashion before smartphones — it exists in blurry film photography and CD jewel cases. Its revival is driven by Gen Z nostalgia for an era they didn't live through.","rarity":"Common","see_also":["Britney Aesthetic","Paris Hilton Aesthetic","Juicy Couture Aesthetic"],"colors":["#C0C0C0 Chrome","#FF6B6B Y2K Pink","#87CEEB Baby Blue","#D4AF37 Metallic Gold"],"media":["Clueless (1995) — film","Mean Girls (2004) — film","Legally Blonde (2001) — film"]},"Y2K Pop Princess":{"summary":"The specific feminine ideal of turn-of-millennium pop — Britney, Christina, Destiny's Child, and the maximally shiny dress of TRL culture.","era":"c.1998–2005","mood":"Maximally shiny, pop-perfect, TRL-era","visual":"Everything sparkles. Very low-rise trousers. Crop top with rhinestones. Platform trainers. Hair crimped or highlighted. The TRL aesthetic — designed to be seen on television and from the back of an arena.","garments":["Rhinestone-embellished crop top","Very low-rise trousers","Platform trainers","Crimped or highlighted hair","Tiny sparkly bag"],"habitat":"Pop nostalgia events, Y2K themed parties.","context":"TRL (Total Request Live on MTV, 1998–2008) directly drove fashion trends in real time. Artists would wear something and teens would immediately seek it out. The connection between pop star fashion and audience dress was at its most direct.","rarity":"Common","see_also":["Y2K","Britney Aesthetic","Christina Aguilera Aesthetic"],"colors":["#FF6B6B Pop Pink","#C0C0C0 Chrome","#D4AF37 Rhinestone Gold","#87CEEB Baby Blue"],"media":["...Baby One More Time (video, 1998) — music video","Legally Blonde (2001) — film","Mean Girls (2004) — film"]},"Britney Aesthetic":{"summary":"Britney Spears's visual identity — from the schoolgirl look to the snake performance to the shaved head, the most documented fashion journey of the 2000s.","era":"c.1998–present","mood":"Pop-icon defining, cultural-touchstone sharp","visual":"Baby Tee and plaid skirt from the original video. Low-rise jeans with visible underwear. Rhinestones. Blonde hair extensions. The red latex catsuit. Platform trainers. The shaved head as fashion anti-statement.","garments":["Baby tee and plaid school skirt","Low-rise jeans","Rhinestone embellishment","Blonde extensions","Red latex catsuit"],"habitat":"Britney fan communities, Y2K revival, pop history.","context":"Britney Spears's Baby One More Time (1998) schoolgirl video was one of the most influential single fashion moments in pop history — that combination of baby tee and plaid skirt was immediately replicated worldwide.","rarity":"Common","see_also":["Y2K Pop Princess","Christina Aguilera Aesthetic","Y2K"],"colors":["#FF6B6B Britney Pink","#C0C0C0 Chrome Silver","#FAF8F5 White","#D4AF37 Rhinestone Gold"],"media":["...Baby One More Time (1998 video) — music video","Crossroads (2002) — film","Oops!... I Did It Again (video, 2000) — music video"]},"Christina Aguilera Aesthetic":{"summary":"Christina Aguilera's specific early 2000s look — the Dirrty era, vinyl chaps, and the maximally provocative pop aesthetic.","era":"c.1999–2007","mood":"Maximally provocative, heavily stylised","visual":"Vinyl or leather hot pants. Braided or crimped blonde hair. Extreme eye makeup. Bandeau tops. Low-rise everything. The Dirrty aesthetic — deliberately confrontational.","garments":["Vinyl or leather hot pants","Bandeau top","Braided crimped hair","Extreme eye makeup","Low-rise everything"],"habitat":"Y2K revival, pop history, 2000s nostalgia events.","context":"Christina Aguilera's Dirrty period (2002) was a deliberate confrontation with the virginal pop princess image — vinyl chaps, dark eye, provocative choreography. It was controversial and influential simultaneously.","rarity":"Niche","see_also":["Britney Aesthetic","Y2K Pop Princess","Y2K"],"colors":["#1A1A1A Dirrty Black","#D4AF37 Vinyl Gold","#8B0000 Dirrty Red","#C0C0C0 Chrome"],"media":["Dirrty (video, 2002) — music video","Beautiful (video, 2002) — music video"]},"Early 2000s Pop":{"summary":"The general visual aesthetic of early 2000s mainstream pop culture — the height of teen pop before social media fragmented taste.","era":"c.1999–2006","mood":"Pre-social media pop perfect","visual":"Shiny everything. Low-rise. Crop. Teen pop aesthetics from Total Request Live. Butterfly clips. Frosted lipgloss. Baby tees. The last moment before social media fragmented pop culture into niches.","garments":["Baby tee","Butterfly clips","Frosted lipgloss","Low-rise jeans","Platform trainers or flip flops"],"habitat":"Early 2000s nostalgia, Y2K revival culture.","context":"Early 2000s pop represents the last era of truly unified youth pop culture — before social media, everyone in a high school watched TRL and heard the same songs. The aesthetic was one shared vocabulary.","rarity":"Common","see_also":["Y2K Pop Princess","Britney Aesthetic","Y2K"],"colors":["#FF6B6B Pop Pink","#87CEEB TRL Blue","#C0C0C0 Chrome","#D4AF37 Rhinestone"],"media":["TRL (MTV, 1998–2008) — TV","Clueless (1995) — film","Mean Girls (2004) — film"]},"Von Dutch Era":{"summary":"The trucker hat and rhinestone-logo aesthetic of 2003–2004 — the most specific and briefly intense micro-trend of the early 2000s.","era":"c.2003–2006","mood":"Extremely specific, briefly intense","visual":"Von Dutch trucker hat. Low-rise jeans. Visible underwear waistband. Baby tee with logo. Paris Hilton and Nicole Richie as the style references. The entire trend lasted approximately 18 months at its peak.","garments":["Von Dutch trucker hat","Low-rise jeans","Baby tee with logo","Visible underwear band","Oversized sunglasses"],"habitat":"2000s nostalgia, Y2K revival, early 2000s pop culture.","context":"Von Dutch was originally a vintage Americana brand repurposed as a celebrity accessory. Its 18-month window of absolute dominance and then complete abandonment makes it one of the purest examples of a micro-trend in fashion history.","rarity":"Niche","see_also":["Paris Hilton Aesthetic","Y2K","Juicy Couture Aesthetic"],"colors":["#8B0000 Von Dutch Red","#D4AF37 Logo Gold","#FAF8F5 White","#1B4F72 Trucker Blue"],"media":["The Simple Life (TV, 2003–07) — TV","Von Dutch documentary — documentary"]},"Early 2000s Logomania":{"summary":"The brand-logo obsession of the early 2000s — LV monogram, Gucci double-G, and luxury logos as streetwear.","era":"c.1999–2007","mood":"Brand-proud, luxuriously logoised","visual":"Louis Vuitton monogram everywhere. Gucci double-G. Fendi baguette. Dior saddle bag. Matching logo sets. The logo as the point — not concealed but displayed as the primary message.","garments":["LV monogram bag","Gucci double-G piece","Logo-printed cap","Matching logo set","Luxury brand sunglasses"],"habitat":"2000s luxury revival, early 2000s fashion history.","context":"The early 2000s logomania was the maximalist luxury expression of the 1990s wealth boom — visible luxury logos were a statement of arrival. It was directly followed by the Quiet Luxury backlash.","rarity":"Niche","see_also":["Y2K","Hypebeast Aesthetic","Quiet Luxury"],"colors":["#D4AF37 LV Gold","#8B0000 Gucci Red","#1A1A1A Logo Black","#8B7355 Monogram Brown"],"media":["The Devil Wears Prada (2006) — film","Sex and the City (TV series) — TV"]},"Velour Tracksuit Era":{"summary":"The Juicy Couture velour tracksuit as status symbol — Paris Hilton, rhinestones on the butt, and the most photographed casual wear of the early 2000s.","era":"c.2001–2007","mood":"Casually status-signalling, velour-soft","visual":"Velour tracksuit in pink, baby blue, or cream. Rhinestone embellishment on jacket and on seat of trousers. Matching set essential. UGG boots. Large sunglasses. Small dog in bag.","garments":["Velour tracksuit top","Velour tracksuit bottoms","UGG boots","Oversized sunglasses","Rhinestone embellishment"],"habitat":"Y2K revival, early 2000s nostalgia, Juicy Couture brand history.","context":"Juicy Couture's velour tracksuit became the defining status casual wear of the early 2000s — worn by everyone from Paris Hilton to Jennifer Lopez. The brand sold for over $200 a set when tracksuits had previously cost $30.","rarity":"Niche","see_also":["Juicy Couture Aesthetic","Paris Hilton Aesthetic","Y2K"],"colors":["#F5C6CB Juicy Pink","#87CEEB Baby Blue","#E8D5B0 Cream","#C185A0 Velour Mauve"],"media":["The Simple Life (TV, 2003–07) — TV","Mean Girls (2004) — film"]},"Juicy Couture Aesthetic":{"summary":"The velour, rhinestone, and aspirational comfort of Juicy Couture at its peak — the brand that made a tracksuit a status symbol.","era":"c.1997–2010; revival 2020s","mood":"Aspirationally casual, velour-luxurious","visual":"Everything in velour or terry cloth. Rhinestones. Matching sets essential. 'Juicy' embroidered on the seat. The paradox of casual dress as conspicuous consumption at its most legible.","garments":["Velour tracksuit set","Rhinestone logo detail","Terry cloth hoodie","UGG boots companion piece","Small charm bracelet"],"habitat":"Y2K revival communities, early 2000s nostalgia events.","context":"Juicy Couture was founded 1997 and reached its cultural peak 2001–07. At its height it was worn by nearly every celebrity. It collapsed with the recession and the shift to 'quiet' luxury. Its revival in the 2020s via Y2K nostalgia is complete.","rarity":"Niche","see_also":["Velour Tracksuit Era","Paris Hilton Aesthetic","Y2K"],"colors":["#F5C6CB Velour Pink","#87CEEB Velour Blue","#E8D5B0 Velour Cream","#D4AF37 Rhinestone Gold"],"media":["The Simple Life (TV) — TV","Legally Blonde (2001) — film"]},"Paris Hilton Aesthetic":{"summary":"The specific early 2000s look of Paris Hilton — the tiny dog, the Von Dutch hat, the pink velour, and fame as a full-time aesthetic performance.","era":"c.2001–2009","mood":"Maximally visible, celebrity-performing","visual":"Pink as the dominant colour. Tiny handbag. Tiny dog. Von Dutch hat. Velour tracksuit. Short party dresses. Oversized sunglasses. Blonde hair extensions. The Simple Life television documentary aesthetic.","garments":["Von Dutch trucker hat","Pink velour tracksuit","Tiny designer handbag","Oversized sunglasses","Short party dress"],"habitat":"Y2K revival, reality TV nostalgia, 2000s pop culture study.","context":"Paris Hilton pioneered the celebrity-as-brand model before social media made it systematic. She was famous for being famous — and built a perfume empire on it. Her aesthetic was instantly legible and globally imitated.","rarity":"Niche","see_also":["Juicy Couture Aesthetic","Y2K Pop Princess","Reality TV Aesthetic"],"colors":["#F5C6CB Paris Pink","#D4AF37 Gold","#FAF8F5 White","#C0C0C0 Chrome"],"media":["The Simple Life (TV, 2003–07) — TV","House of Wax (2005) — film"]},"Early Emo Aesthetic":{"summary":"The sad, black-fringed, studded-belt dress of the emo pre-scene — before Scene, before MySpace, in small venues.","era":"c.1999–2004","mood":"Emotionally raw, black-fringed, earnestly sad","visual":"Black everything. Long side fringe over one eye. Studded belt. Band T-shirt (Taking Back Sunday, Thursday). Tight jeans. Converse. Eyeliner for all genders. The sincerity that Scene would later ironise.","garments":["Black skinny jeans","Band T-shirt","Studded belt","Side fringe over one eye","Black Converse"],"habitat":"Early emo history, Taking Back Sunday and Thursday fan contexts, pre-MySpace music.","context":"Early emo was a small, earnest subculture before it became a mass aesthetic. The transition from sincere post-hardcore to MySpace-era Scene is one of the most documented subculture commercialisations of the 2000s.","rarity":"Rare","see_also":["Emo Aesthetic","Scene Aesthetic","Post-Punk Fashion"],"colors":["#1A1A1A Emo Black","#8B0000 Emo Red","#FAF8F5 Band Tee White","#5B5B5B Emo Grey"],"media":["Taking Back Sunday: Tell All Your Friends (2002) — music","Saves the Day discography — music","The Perks of Being a Wallflower — novel"]},"MySpace Era Fashion":{"summary":"The glam, edited, heavily filtered self-presentation of MySpace profile culture — the first generation to curate their own visual identity online.","era":"c.2004–2009","mood":"Self-curated, digitally performative, early internet","visual":"Everything photographed from above (the 'MySpace angle'). Scene hair. Heavy eye makeup. Band tees. Tight jeans. The look was designed for a single photograph more than for daily life.","garments":["Scene hair with extensions","Heavy eye makeup","Band T-shirt","Tight jeans","Fishnet layering"],"habitat":"MySpace revival nostalgia, internet culture history.","context":"MySpace was the first mass platform for digital self-curation and the origin of the influencer aesthetic — the carefully constructed profile photograph as public self-presentation. The aesthetic it produced was its own genre.","rarity":"Extinct","see_also":["Scene Aesthetic","Emo Aesthetic","Y2K"],"colors":["#1A1A1A MySpace Black","#8B0000 Scene Red","#C185A0 Profile Pink","#D4AF37 Glam Gold"],"media":["MySpace archive photographs","Almost Famous (2000) — film"]},"Bratz Aesthetic":{"summary":"The hyper-stylised, ultra-fashionable doll aesthetic of the early 2000s — the alternative to Barbie that looked actually fashionable.","era":"c.2001–2008; revival 2020s","mood":"Hyper-stylised, overtly fashionable, doll-perfect","visual":"Heavy eye makeup. Large eyes. Full lips. Very high-fashion clothing. Platform shoes or boots. The look that was considered inappropriate for children at the time — and became a fashion reference for adults two decades later.","garments":["Heavy platform boots","Bold eye makeup","Cropped bold-print top","Mini skirt","Dramatic hair"],"habitat":"Y2K revival, Bratz doll fan communities, 2020s fashion revival.","context":"The Bratz doll was the most fashion-forward toy of the early 2000s — it was criticised at the time for being too adult. Its aesthetic was so specific and cohesive that it became a genuine fashion reference in the 2020s revival.","rarity":"Niche","see_also":["Y2K Pop Princess","Y2K","E-Girl"],"colors":["#FF6B6B Bratz Pink","#C185A0 Doll Rose","#D4AF37 Bratz Gold","#1A1A1A Platform Black"],"media":["Bratz (animated series, 2005–07) — animation","Bratz: The Movie (2007) — film"]},"Indie Sleaze Precursor":{"summary":"The early 2000s indie rock aesthetic before it was named — American Apparel, Vice magazine, and the art school downtown scene.","era":"c.2001–2006, New York, London","mood":"Casually transgressive, downtown cool","visual":"Vintage-mix. American Apparel basics. Artfully underdressed. Slightly too-short dress over tights. Oversized sunglasses. The look of someone who went to art school and wants you to know it.","garments":["American Apparel basic","Vintage-mix layering","Slightly too-short dress over tights","Oversized sunglasses","Artfully dishevelled hair"],"habitat":"Pre-Indie Sleaze downtown culture, American Apparel heritage, Vice magazine cultural history.","context":"Indie Sleaze as a named aesthetic is retrospective — it wasn't called that in 2001. The Precursor is the period before it coalesced into a recognisable aesthetic with its own identity.","rarity":"Rare","see_also":["Indie Sleaze","Kate Moss Aesthetic","Hipster"],"colors":["#8B7355 American Apparel Natural","#1A1A1A Downtown Black","#C1440E Lo-Fi Orange","#5B5B5B Art School Grey"],"media":["Vice Magazine archives (2001–06)","Shortbus (2006) — film"]},"Grunge Aesthetic":{"summary":"The Pacific Northwest rock scene's indifferent, layered dress — flannel, ripped denim, and the anti-fashion that became fashion.","era":"c.1987–1994, Seattle; revival perpetual","mood":"Deliberately indifferent, flannel-layered","visual":"Flannel shirt over band T-shirt, sometimes tied at waist. Ripped jeans. Doc Martens. Unwashed hair. The look of someone who genuinely doesn't care — which required enormous effort to imitate.","garments":["Flannel shirt","Ripped worn jeans","Doc Martens boots","Band T-shirt","Deliberately undone hair"],"habitat":"Music venues, thrift stores, Pacific Northwest culture.","context":"Marc Jacobs's 1992 grunge collection got him fired from Perry Ellis. The aesthetic was a genuine subculture before it was a fashion. Kurt Cobain's death in 1994 coincided with its mainstream peak.","rarity":"Common","see_also":["Grunge Girl","Post-Punk Fashion","Kate Moss Aesthetic"],"colors":["#8B7355 Flannel Brown","#1A1A1A Grunge Black","#8B0000 Plaid Red","#5B5B5B Washed Grey"],"media":["Singles (1992) — film","Nirvana: Live at Reading (1992) — concert film","Reality Bites (1994) — film"]},"Riot Grrrl Fashion":{"summary":"The DIY feminist punk dress of Bikini Kill — baby doll dresses over band tees, marker on skin, and rage made wearable.","era":"c.1991–1997, Pacific Northwest","mood":"Confrontationally feminist, DIY-raw","visual":"Baby doll dress or slip over band T-shirt. Doc Martens. Knee-high socks. Marker writing on skin reclaiming slurs. Barrettes and glitter mixed with torn fishnets. Deliberate mix of femme and punk.","garments":["Baby doll dress over band T-shirt","Doc Martens boots","Knee-high socks","Marker writing on skin","Barrettes and torn fishnets"],"habitat":"Feminist music history, riot grrrl zine culture, Olympia Washington heritage.","context":"Riot Grrrl was simultaneously a feminist political movement and an aesthetic — the mix of femme dress with punk aggression was a deliberate statement about femininity and power. Kathleen Hanna was its visual and musical centre.","rarity":"Rare","see_also":["Grunge Aesthetic","Punk Lineage","Women's Liberation Fashion"],"colors":["#FF6B6B Angry Pink","#1A1A1A Black","#FAF8F5 DIY White","#8B0000 Rebel Red"],"media":["The Punk Singer (2013) — documentary","Girls to the Front, Sara Marcus (2010) — book"]},"WASP Aesthetic":{"summary":"The understated, quality-driven dress of the White Anglo-Saxon Protestant establishment — Brooks Brothers, madras, and class expressed through restraint.","era":"c.1950s–present, Eastern USA","mood":"Quietly establishment, unremarkably correct","visual":"Navy blazer. Madras shorts. Button-down Oxford cloth shirt. Penny loafers. Khakis. The look communicates old money by its total refusal to communicate anything at all.","garments":["Navy blazer","Madras shorts or trousers","Oxford cloth button-down","Penny loafers","Khakis"],"habitat":"Ivy League campuses, country clubs, Eastern Seaboard establishment culture.","context":"The WASP aesthetic is the original American quiet luxury — its power lies in its refusal to perform wealth. So deeply coded it is invisible to outsiders and legible only to insiders.","rarity":"Niche","see_also":["New England Preppy","Old Money","Ivy League"],"colors":["#1B4F72 WASP Navy","#8B7355 Khaki","#FAF8F5 White","#D4AF37 Brass Button"],"media":["Metropolitan (1990) — film","The Official Preppy Handbook (1980) — book","Whit Stillman's films"]},"New England Preppy":{"summary":"The coastal, athletic, quality-fixated dress of New England prep school culture — seersucker, repp ties, and the Preppy Handbook made real.","era":"c.1940s–present, New England","mood":"Sporty, quality-conscious, unironic","visual":"Seersucker suits in summer. Repp striped ties. Boat shoes. Rugby shirts. The colours of the sea and sky. Nantucket reds. Lisa Birnbach's 1980 Preppy Handbook is the canonical text.","garments":["Seersucker suit","Repp striped tie","Boat shoes","Rugby shirt","Chino trousers"],"habitat":"New England campuses, yacht clubs, Nantucket, Maine coastal towns.","context":"The Preppy Handbook (1980) sold 1.3 million copies in its first year, both documenting and commercialising the aesthetic. Ralph Lauren built his entire brand on aspiring to it from the outside.","rarity":"Niche","see_also":["WASP Aesthetic","Ivy League","Preppy"],"colors":["#1B4F72 Navy","#8B7355 Seersucker Tan","#8B0000 Prep Red","#FAF8F5 White"],"media":["Dead Poets Society (1989) — film","The Official Preppy Handbook (1980) — book","Metropolitan (1990) — film"]},"Ivy League":{"summary":"The sartorial identity of America's most selective universities — tweed, grey flannel, and the rumpled quality of someone too intellectually busy for vanity.","era":"c.1950s–present, US universities","mood":"Intellectually casual, establishment collegiate","visual":"Grey flannel trousers. Harris Tweed jacket. Button-down shirt. Club tie. A slightly rumpled quality that signals intellectual priority over appearance. Different from deliberate prep in being accidentally rather than deliberately correct.","garments":["Grey flannel trousers","Harris Tweed jacket","Club tie","Button-down Oxford cloth shirt","Plain leather belt"],"habitat":"Harvard, Yale, Princeton campuses, American academic culture.","context":"Take Ivy (1965), a Japanese photobook of American university dress, influenced Japanese menswear for decades. The Japanese appreciation of Ivy style is often more systematic than the original American practitioners.","rarity":"Niche","see_also":["WASP Aesthetic","New England Preppy","Dark Academia"],"colors":["#1B4F72 Yale Blue","#8B0000 Harvard Red","#8B7355 Princeton Stone","#D4AF37 Brass"],"media":["Dead Poets Society (1989) — film","A Beautiful Mind (2001) — film","The Social Network (2010) — film"]},"Nantucket Aesthetic":{"summary":"The specific maritime luxury of Nantucket island — Nantucket reds that fade correctly, lightship baskets, and old money at the seaside.","era":"c.1950s–present, Nantucket, Massachusetts","mood":"Maritime old money, faded-correctly","visual":"Nantucket reds (salmon-red trousers that must be faded to the correct degree — you cannot buy the right colour new). Navy blue. White. Lightship basket handbag. The aesthetic of families who have had a cottage there for four generations.","garments":["Nantucket red trousers","White button-down shirt","Navy blazer","Lightship basket bag","Whale or nautical print"],"habitat":"Nantucket island, Nantucket Reds retail, New England heritage, coastal old money.","context":"Nantucket reds (made by Murray's Toggery) are designed to fade to the correct salmon-red over time. This built-in time requirement is the perfect class barrier — new money cannot buy the correct colour.","rarity":"Rare","see_also":["New England Preppy","Cape Cod Style","Old Money"],"colors":["#87CEEB Harbour Blue","#FAF8F5 White","#D4AF37 Basket Gold","#8B7355 Weathered Tan"],"media":["Jaws (1975) — film","Moby Dick (various) — film"]},"Cape Cod Style":{"summary":"The relaxed, salt-washed dress of Cape Cod summers — linen, nautical stripes, and the relaxed confidence of Massachusetts coastal life.","era":"c.1950s–present, Cape Cod","mood":"Salt-washed, relaxed nautical","visual":"Linen in white and navy. Breton stripe top. Canvas tote. Espadrilles or boat shoes. Sunbleached hair. The look of someone just in from the beach who is somehow still perfectly dressed.","garments":["White linen shirt","Breton stripe top","Canvas tote bag","Espadrilles","Boat shoes"],"habitat":"Cape Cod towns, New England coastal communities, Francophile American culture.","context":"Cape Cod style shares DNA with French Riviera coastal aesthetics. The Breton stripe top arrived in America via French sailors and became a New England staple.","rarity":"Niche","see_also":["Nantucket Aesthetic","French Girl Style","New England Preppy"],"colors":["#87CEEB Cape Blue","#FAF8F5 White Shingle","#8B7355 Weathered Wood","#4A7C59 Salt Marsh"],"media":["Jaws (1975) — film","The Witches of Eastwick (1987) — film"]},"Fishermancore":{"summary":"The practical waterproof dress of commercial fishing reinterpreted as fashion — oilskin, rubber boots, and the aesthetic of the North Sea.","era":"c.2010s–present","mood":"Salt-weathered, functionally noble","visual":"Yellow oilskin jacket. Thick Aran or Guernsey sweater. Rubber sea boots. Waterproof trousers. The authentic version worn by working fishermen, adopted by coastal fashion communities.","garments":["Yellow oilskin jacket","Thick Aran or Guernsey sweater","Rubber sea boots","Waterproof trousers","Fisherman's cap"],"habitat":"Coastal towns, Gorpcore adjacent fashion, fishing heritage communities.","context":"The Guernsey and Aran sweaters are traditional working garments — the Aran's complex cables were originally used to identify drowned fishermen by their clan pattern.","rarity":"Niche","see_also":["Gorpcore","Coastal Grandmother","Heritage Core"],"colors":["#1B4F72 Fisherman Navy","#FAF8F5 Ecru","#8B7355 Natural Rope","#5B5B5B Wet Rock"],"media":["The Perfect Storm (2000) — film","Captains Courageous (1937) — film"]},"Southern Belle Aesthetic":{"summary":"The antebellum and post-Civil War romantic dress of the American South — hoop skirts, parasols, and the highly problematic mythology of Southern femininity.","era":"c.1840–1870; revival in Southern culture","mood":"Romantically mythologised, historically complicated","visual":"Full hoop skirt in white or pale colour. Parasol. Wide-brimmed hat with ribbons. White gloves. The aesthetic of Gone with the Wind — deliberately glamourised and detached from the slave economy that funded it.","garments":["Full hoop skirt","Parasol","Wide-brimmed ribbon hat","White gloves","Fitted corseted bodice"],"habitat":"Southern heritage events. SENSITIVE: This aesthetic is inseparable from the plantation economy and slavery and cannot be contextualised without that history.","context":"The Southern Belle aesthetic romanticises a society built on slavery. Its continued use in plantation tourism and heritage events is contested by those who see it as celebrating the Confederacy.","rarity":"Niche","see_also":["Antebellum Aesthetic","Southern Gothic","Crinoline Aesthetic"],"colors":["#FAF8F5 Magnolia White","#F5C6CB Blush Pink","#D4AF37 Bourbon Gold","#4A7C59 Plantation Green"],"media":["Gone with the Wind (1939) — film","Steel Magnolias (1989) — film","Midnight in the Garden of Good and Evil (1997) — film"]},"Antebellum Aesthetic":{"summary":"The dress of the pre-Civil War American South — romanticised in Southern mythology, inseparable from the plantation slavery that funded it.","era":"c.1830–1865, American South","mood":"Mythologically romanticised, inseparable from slavery","visual":"Full crinoline skirt. Fitted bodice. Parasol. White cotton gloves. The look romanticised in Gone with the Wind (1939). The reality includes the enslaved people who made and maintained these garments.","garments":["Full crinoline dress","Fitted corseted bodice","Lace parasol","White cotton gloves","Bonnet with ribbons"],"habitat":"Southern heritage contexts. SENSITIVE: This aesthetic is inseparable from American chattel slavery and must be contextualised as such.","context":"The antebellum aesthetic cannot be understood without its economic foundation — enslaved labour. Plantation weddings and heritage events that celebrate this aesthetic without that context are broadly criticised as ahistorical.","rarity":"Rare","see_also":["Southern Belle Aesthetic","Southern Gothic","Crinoline Aesthetic"],"colors":["#FAF8F5 White Columned","#F5C6CB Plantation Pink","#D4AF37 Gold","#4A7C59 Lawn Green"],"media":["Gone with the Wind (1939) — film","Beloved (1998) — film","12 Years a Slave (2013) — film"]},"Southern Gothic":{"summary":"The dark, humid, decaying dress aesthetic of the American South's Gothic literary tradition — Blanche DuBois, faded glamour, and beauty in ruin.","era":"c.1930s–present, American South","mood":"Darkly decaying, heat-humid, Southern-strange","visual":"White linen slowly wilting in heat. Faded parasol. Tattered lace trim. The aesthetic of Blanche DuBois — faded glamour, inappropriate finery, the past refusing to die.","garments":["Wilting white linen dress","Faded parasol","Tattered lace trim","Perspiration-stained silk","Rocking chair porch aesthetic"],"habitat":"Southern Gothic literature contexts, Tennessee Williams productions, Gothic communities.","context":"Southern Gothic is a literary genre before it is a fashion aesthetic. A Streetcar Named Desire's Blanche DuBois is its perfect fashion embodiment — the decay is the point.","rarity":"Niche","see_also":["Southern Belle Aesthetic","Gothic Lolita","Grandmacore"],"colors":["#5B3A29 Decay Brown","#4A7C59 Moss Green","#8B0000 Gothic Red","#8B7355 Faded Magnolia"],"media":["True Blood (TV series) — TV","The Beguiled (2017) — film","True Grit (2010) — film"]},"Western / Cowboy Core":{"summary":"The authentic and fashion-revived dress of the American West — Stetson, boots, denim, and the cowboy as the defining American mythological figure.","era":"c.1860s–present; revival 2022–present","mood":"Mythologically American, frontier-proud","visual":"Stetson or wide-brimmed hat. Western boots with pointed toe. Denim jeans. Pearl-snap Western shirt. Bolo tie. Fringe. Large belt buckle. Equally at home at an actual ranch and a Beyoncé music video.","garments":["Stetson wide-brimmed hat","Western boots","Pearl-snap Western shirt","Denim jeans","Large belt buckle"],"habitat":"Rodeos, country music festivals, Texas culture, Beyoncé Cowboy Carter fan contexts.","context":"Beyoncé's Cowboy Carter (2024) brought the Western aesthetic to a global audience while centring Black cowboy history — a deliberate reclamation of a tradition that mainstream Western mythology has systematically erased.","rarity":"Common","see_also":["Rodeo Aesthetic","Nashville Aesthetic","Coastal Cowgirl"],"colors":["#8B7355 Saddle Brown","#1B4F72 Denim Blue","#D4AF37 Buckle Gold","#C1440E Western Red"],"media":["Unforgiven (1992) — film","Brokeback Mountain (2005) — film","Yellowstone (TV series) — TV"]},"Rodeo Aesthetic":{"summary":"The competition and celebration dress of the American rodeo — rhinestones, Wranglers, and the specific dress culture of Western competition.","era":"c.1920s–present, American West","mood":"Competitively sparkled, competition-ready","visual":"Wrangler jeans. Rhinestone-encrusted Western shirt. Cowboy hat. Western boots. The specific aesthetic of someone who competes on horseback and dresses accordingly — practical and spectacular simultaneously.","garments":["Wrangler jeans","Rhinestone Western shirt","Cowboy hat","Pointed-toe Western boots","Rodeo queen sash"],"habitat":"Rodeo events, country music festivals, Western wear communities.","context":"Wrangler jeans are cut specifically for riding. Rhinestones are traditional rodeo wear because they catch the arena lights. The rodeo queen pageant aesthetic is maximalist Western.","rarity":"Niche","see_also":["Western / Cowboy Core","Nashville Aesthetic","Coastal Cowgirl"],"colors":["#D4AF37 Rodeo Gold","#8B0000 Rodeo Red","#8B7355 Saddle Brown","#FAF8F5 Rodeo White"],"media":["Urban Cowboy (1980) — film","8 Seconds (1994) — film","Yellowstone (TV series) — TV"]},"Saloon Girl Aesthetic":{"summary":"The theatrical costuming of the Wild West saloon — feathers, short skirts, and the vintage burlesque-adjacent look of frontier entertainment.","era":"c.1860s origin; perpetual Halloween revival","mood":"Theatrical frontier-femme","visual":"Short saloon skirt. Feather boa or feathers in hair. Corset or fitted bodice. Fishnet or lace-top stockings. High-heeled boots. Heavy stage makeup.","garments":["Short ruffled saloon skirt","Feather boa","Corseted fitted bodice","Fishnet stockings","Heeled ankle boots"],"habitat":"Halloween, Wild West themed events, burlesque adjacent communities.","context":"The Saloon Girl is more myth than historical reality — working women in Western saloons dressed far more practically. The theatrical version is a costume construction from dime novels and Hollywood Westerns.","rarity":"Niche","see_also":["Western / Cowboy Core","Vintage Burlesque Aesthetic","Halloween Costume Aesthetic"],"colors":["#D4AF37 Saloon Gold","#8B0000 Crimson","#1A1A1A Black","#F5C6CB Feather Pink"],"media":["Unforgiven (1992) — film","Deadwood (TV series) — TV","Once Upon a Time in the West (1968) — film"]},"Frontier Workwear Aesthetic":{"summary":"The practical, hardwearing dress of the American frontier — Levi's, work boots, and the heritage of functional clothing that became global fashion.","era":"c.1850–1900; heritage revival perpetual","mood":"Durably functional, American-hardworking","visual":"Levi Strauss denim jeans with rivets (invented 1873). Work boots. Flannel or chambray work shirt. Suspenders. Bandana. The aesthetic that became Americana and then global casual.","garments":["Levi's denim jeans","Chambray work shirt","Suspenders","Work boots","Red bandana"],"habitat":"Heritage workwear communities, selvedge denim culture, Americana enthusiasts.","context":"The Levi's 501 jean was invented in 1873 for California gold miners and became the most influential garment in American fashion history. Frontier workwear is the foundation of global casual dress.","rarity":"Niche","see_also":["Vintage Americana","Heritage Core","Union Workwear Aesthetic"],"colors":["#8B7355 Canvas Brown","#4A7C59 Frontier Green","#5B3A29 Leather","#FAF8F5 Linen White"],"media":["Little House on the Prairie (TV series) — TV","The Revenant (2015) — film","True Grit (2010) — film"]},"Nashville Aesthetic":{"summary":"The rhinestone-studded, boots-and-Stetson dress of country music's capital — Nudie suits, Opry glamour, and the specific glam of country stardom.","era":"c.1940s–present, Nashville","mood":"Country-glamorous, rhinestone-proud","visual":"Nudie suit: rhinestone-embroidered Western suit jacket. Stetson. Cowboy boots. Fringe. The glamour of the Grand Ole Opry mixed with genuine ranch practicality.","garments":["Nudie-style rhinestone suit","Stetson hat","Cowboy boots","Fringe jacket","Statement belt buckle"],"habitat":"Nashville, Grand Ole Opry events, country music festivals.","context":"The Nudie suit (by Ukrainian immigrant Nudie Cohn) is the definitive Nashville garment — rhinestone-encrusted Western suits worn by Hank Williams, Elvis, and generations of country stars.","rarity":"Niche","see_also":["Western / Cowboy Core","Rodeo Aesthetic","Country Girl Aesthetic"],"colors":["#D4AF37 Nashville Gold","#8B0000 Country Red","#8B7355 Denim Brown","#FAF8F5 White Hat"],"media":["Nashville (2014 film) — film","Coal Miner's Daughter (1980) — film","Nashville (TV series) — TV"]},"Southwestern Aesthetic":{"summary":"The turquoise, silver, and adobe-warm dress of the American Southwest — Native American jewellery influence, Georgia O'Keeffe, and desert colour.","era":"c.1920s–present, American Southwest","mood":"Desert-warm, turquoise-accented","visual":"Turquoise and silver jewellery in chunky statement pieces. Earth tones: terracotta, ochre, sage green. Linen or cotton in desert colours. Concho belt. The palette of adobe, red rock, and the New Mexico sky.","garments":["Turquoise and silver statement jewellery","Earth-tone linen dress","Concho belt","Moccasin or leather sandals","Fringed suede"],"habitat":"Santa Fe, Taos, New Mexico art communities. SENSITIVE: Must distinguish between fashion adoption and appropriation of specific Native American tribal jewellery traditions.","context":"The Southwestern aesthetic draws heavily on Native American jewellery traditions — Navajo, Hopi, and Zuni silverwork. The distinction between respectful appreciation and appropriation requires careful navigation.","rarity":"Niche","see_also":["Desert Southwest Style","Western Chic","Boho Feminine"],"colors":["#C1440E Adobe Red","#D4AF37 Turquoise Gold","#8B7355 Desert Tan","#2C5530 Sage Green"],"media":["Thelma & Louise (1991) — film","No Country for Old Men (2007) — film","Breaking Bad (TV series) — TV"]},"Desert Southwest Style":{"summary":"The contemporary slow fashion interpretation of Southwest aesthetics — natural fibres, earth tones, and desert minimalism.","era":"c.2010s–present","mood":"Dusty-warm, naturally minimalist","visual":"Natural linen in terracotta, sand, and sage. Minimal silhouettes. Handmade leather sandals. Simple silver jewellery. The palette of the high desert at dusk. Clean lines with warm tones.","garments":["Natural linen dress or trousers","Simple silver jewellery","Handmade leather sandals","Terracotta or sage palette","Minimal structured bag"],"habitat":"Santa Fe lifestyle blogs, Southwestern independent brands, desert travel content.","context":"Desert Southwest Style emerged from the 2010s natural materials and slow fashion movement interpreted through the Southwest's specific landscape. It differs from the more maximalist Southwestern Aesthetic by its restraint.","rarity":"Niche","see_also":["Southwestern Aesthetic","Western Chic","Slow Fashion Aesthetic"],"colors":["#C1440E Desert Adobe","#D4AF37 Ochre","#4A7C59 Sage","#8B7355 Canyon Tan"],"media":["Georgia O'Keeffe documentary — documentary","Thelma & Louise (1991) — film"]},"Vintage Americana":{"summary":"The nostalgic, heritage-celebrating dress of mid-century American culture — diners, drive-ins, and the open road romanticised.","era":"c.1990s–present","mood":"Nostalgically American, highway-romantic","visual":"Levi's jeans. White T-shirt. Leather jacket. Poodle skirt. Saddle shoes. The aesthetics of diners and drive-ins as nostalgic fantasy.","garments":["Levi's 501 jeans","White cotton T-shirt","Leather jacket","Saddle shoes","Poodle skirt in revival contexts"],"habitat":"American diners, vintage car shows, Route 66 communities, Americana music contexts.","context":"Vintage Americana is nostalgia for a specific version of America — the mid-century white suburban optimism of the 1950s. Its revival is always in tension with the racial politics of that era.","rarity":"Niche","see_also":["Heritage Core","Rockabilly","Western / Cowboy Core"],"colors":["#8B0000 American Red","#1B4F72 American Blue","#FAF8F5 American White","#D4AF37 Old Gold"],"media":["Grease (1978) — film","American Graffiti (1973) — film","Stand by Me (1986) — film"]},"Rugged Americana":{"summary":"The outdoor, workwear-adjacent dress of rural American life — Carhartt, Red Wing boots, and the aesthetic of working the land.","era":"c.1900s–present; fashion revival 2010s","mood":"Durably authentic, land-working","visual":"Carhartt work jacket or coveralls. Red Wing or Wolverine work boots. Flannel shirt. Selvedge denim. The authentic version worn by people who actually work outdoors.","garments":["Carhartt work jacket","Red Wing work boots","Heavy flannel shirt","Selvedge denim jeans","Wool work socks"],"habitat":"Working communities, workwear fashion revival, Americana enthusiasts.","context":"Carhartt became a fashion brand despite and because of its authenticity. The gap between original Carhartt customer (construction worker) and fashion customer (urban creative) is one of fashion's great class translations.","rarity":"Niche","see_also":["Frontier Workwear Aesthetic","Heritage Core","Gorpcore"],"colors":["#8B7355 Worn Denim","#5B3A29 Leather Brown","#C1440E Flannel Red","#D4AF37 Brass"],"media":["Into the Wild (2007) — film","The Revenant (2015) — film","Lonesome Dove (TV) — TV"]},"Heritage Core":{"summary":"The appreciation of American and European traditional workwear and heritage brands — selvedge denim, Japanese reproductions, and the authenticity of wear.","era":"c.2008–present","mood":"Authentically heritage-obsessed","visual":"Selvedge denim on shuttle looms. Red Wing or Alden boots. Japanese craftsmen reproducing American workwear with obsessive accuracy. The specific appreciation of manufacturing process and material quality.","garments":["Selvedge denim jeans","Red Wing or Alden boots","Cone Mills flannel","Raw denim jacket","Vintage or reproduction work shirt"],"habitat":"Selvedge denim forums, heritage brands (Red Wing, Filson, Pendleton), workwear communities.","context":"Heritage Core emerged from Japanese appreciation of American workwear — Japanese craftsmen reproduced American heritage garments with greater fidelity than American manufacturers. The most authentic American heritage wear comes from Japan.","rarity":"Niche","see_also":["Rugged Americana","Frontier Workwear Aesthetic","Vintage Americana"],"colors":["#8B7355 Heritage Tan","#C1440E Heritage Red","#1B4F72 Heritage Blue","#5B3A29 Waxed Brown"],"media":["The Crown (TV series) — TV","Downton Abbey (TV series) — TV","Brideshead Revisited — TV"]},"Western Chic":{"summary":"The fashion-forward, elevated interpretation of Western aesthetics — cowboy boots with tailored suits, Stetson as runway accessory.","era":"c.2000s–present","mood":"Elevated Western, fashion-forward","visual":"Cowboy boots with a tailored suit. Stetson as runway accessory. Fringe on a blazer. The Western vocabulary borrowed by high fashion and elevated without losing its reference.","garments":["Cowboy boots with tailored trousers","Stetson as fashion accessory","Fringe blazer","Western belt with designer dress","Bolo tie with formal shirt"],"habitat":"Fashion weeks, high-end Western wear retailers, editorial fashion.","context":"Saint Laurent under Hedi Slimane was Western Chic's most influential iteration. It requires knowing the reference well enough to abstract it.","rarity":"Niche","see_also":["Western / Cowboy Core","Nashville Aesthetic","Rodeo Aesthetic"],"colors":["#D4AF37 Western Gold","#8B7355 Suede","#C1440E Terracotta","#FAF8F5 White"],"media":["Yellowstone (TV series) — TV","Urban Cowboy (1980) — film"]},"Coastal Cowgirl":{"summary":"The 2022 TikTok fusion of coastal aesthetic and Western cowgirl — linen, cowboy boots, beach waves, and the specific aesthetic of a viral moment.","era":"c.2022–present","mood":"Coastal-Western fusion, TikTok-born","visual":"Linen shorts or skirt. Cowboy boots. Bandana. Flowy blouse. Beach waves. The fusion of two existing aesthetics into a new TikTok-named category that immediately became a dominant trend.","garments":["Linen shorts or skirt","Cowboy boots","Bandana","Flowy beach blouse","Beach-wave hair"],"habitat":"TikTok, Instagram, summer 2022 fashion moment.","context":"Coastal Cowgirl was named as a TikTok aesthetic in summer 2022 and demonstrates how social media can name and crystallise a trend that has been forming organically.","rarity":"Common","see_also":["Western / Cowboy Core","Coastal Grandmother","Y2K"],"colors":["#87CEEB Ocean Blue","#D4AF37 Golden Hat","#8B7355 Sandy Tan","#FAF8F5 White Denim"],"media":["TikTok aesthetic trend (2022) — social media","Outer Banks (TV series) — TV"]},"Inherited Wardrobe Aesthetic":{"summary":"The specific look of wearing clothes genuinely passed down through generations — not thrifted, but actually grandmother's coat, actually grandfather's watch.","era":"c.2010s–present","mood":"Genuinely inherited, temporally layered","visual":"A specific quality of wear that cannot be faked. The right patina. The slightly wrong fit. Grandmother's brooch on a modern dress. The coat that is actually from 1967.","garments":["Genuinely inherited coat or jacket","Family brooch or jewellery","Vintage leather bag with real patina","Actually-old watch","Slightly wrong-fit vintage piece"],"habitat":"Fashion history communities, vintage enthusiasts who distinguish authentic inheritance from thrift.","context":"The Inherited Wardrobe Aesthetic is distinguished from vintage buying by provenance — these are objects with personal history. The emotional value and aesthetic value are inseparable.","rarity":"Rare","see_also":["Vintage Mix","Grandmacore","Old Money"],"colors":["#8B7355 Time-Worn Tan","#5B5B5B Faded Grey","#D4AF37 Patina Gold","#8B4513 Leather Age"],"media":["Gosford Park (2001) — film","The Grand Budapest Hotel (2014) — film"]},"Vintage Glamour":{"summary":"The specific glamour of genuinely vintage formal dress — the 1950s gown worn to a modern event, the real crystal brooch, the actual satin.","era":"c.1990s–present","mood":"Genuinely glamorous, temporally displaced","visual":"Real vintage 1940s–1960s formal dress. Genuine crystal or costume jewellery from the era. The right shoes. The correct silhouette. Worn by someone who took three hours to put it together correctly.","garments":["Genuine 1950s silk evening gown","Period-correct crystal jewellery","Vintage satin gloves","Period-correct shoes","Carefully dressed vintage-appropriate hair"],"habitat":"Vintage events, formal occasions for vintage enthusiasts, jazz clubs.","context":"Vintage Glamour requires knowledge — wearing a 1950s gown correctly means understanding the silhouette and the foundations required. The community distinguishes between vintage glamour (knowledge-based) and vintage costume (surface-level).","rarity":"Niche","see_also":["Vintage Collector Aesthetic","Vintage Mix","Old Hollywood Glamour"],"colors":["#D4AF37 Glamour Gold","#C0C0C0 Vintage Silver","#8B0000 Deep Red","#1A1A1A Black"],"media":["Midnight in Paris (2011) — film","Bullets over Broadway (1994) — film"]},"Vintage Collector Aesthetic":{"summary":"The dress of the serious vintage collector — both the knowledge it represents and the look of someone who wears what they collect.","era":"c.1980s–present","mood":"Knowledgeably specific, era-fluent","visual":"Often single-era focused — a 1940s collector dresses in the 1940s. The pieces are genuine. The knowledge is worn as much as the clothes. Period-correct accessories and foundations complete the look.","garments":["Genuine single-era pieces","Era-specific silhouette","Period-correct accessories","Vintage foundation garments","Era-appropriate footwear"],"habitat":"Vintage fairs, vintage dealer communities, specialist vintage events.","context":"The serious vintage collector can identify a piece's decade, likely origin, and manufacturing details at a glance. The aesthetic is simultaneously personal expression and walking reference library.","rarity":"Rare","see_also":["Vintage Glamour","Archival Fashion Aesthetic","Dead Stock Aesthetic"],"colors":["#8B7355 Archive Brown","#D4AF37 Patina Gold","#5B5B5B Aged Silver","#C1440E Vintage Red"],"media":["The Eye Has to Travel (Diana Vreeland documentary) — documentary"]},"Archival Fashion Aesthetic":{"summary":"The wearing of archived or archival-quality pieces — garments understood as historically significant fashion documents.","era":"c.2000s–present","mood":"Historically significant, document-wearing","visual":"Martin Margiela archive pieces. Early Raf Simons. Pieces that are fashion history themselves. The wearer understands what they have and wears it with that knowledge.","garments":["Archival designer piece","Historically significant garment","Document-quality fashion piece","Collector-context wearing","Mixed with contemporary reference"],"habitat":"Fashion history communities, archive-focused vintage dealers, fashion journalism contexts.","context":"Genuine archive pieces from Margiela, early McQueen, and Raf Simons command museum prices. The community that wears archive is distinct from general vintage by its fashion-historical knowledge.","rarity":"Rare","see_also":["Vintage Collector Aesthetic","Dead Stock Aesthetic","Haute Couture Spectacle"],"colors":["#1A1A1A Archive Black","#FAF8F5 Archive White","#D4AF37 Gold","#5B5B5B Aged Silver"],"media":["Westwood: Punk, Icon, Activist (2018) — documentary","The September Issue (2009) — documentary"]},"Dead Stock Aesthetic":{"summary":"The specific pleasure of unworn vintage — new old stock, original tags, and the temporally suspended quality of clothing that never got worn.","era":"c.2010s–present","mood":"Temporally suspended, pristinely original","visual":"Never-worn vintage with original tags. The specific quality of fabric that has been stored rather than worn. The paradox of wearing something preserved for decades that has never been touched.","garments":["Never-worn vintage with original tags","Dead stock fabric garment","Original packaging elements","Pristine unworn vintage","Period-correct new old stock"],"habitat":"Vintage collector communities, Depop high-end vintage, dead stock specialist dealers.","context":"Dead stock carries the weight of all the years it waited. The community values the preservation as much as the wearing — these are objects that survived.","rarity":"Rare","see_also":["Vintage Collector Aesthetic","Archival Fashion Aesthetic","Inherited Wardrobe Aesthetic"],"colors":["#8B7355 NOS Tan","#FAF8F5 Unworn White","#D4AF37 Original Gold","#5B5B5B Warehouse Grey"],"media":["The True Cost (2015) — documentary","Dazed & Confused (1993) — film"]},"Museum Shop Aesthetic":{"summary":"The specific look of the museum gift shop-adjacent fashion enthusiast — art print scarves, reproduction jewellery, and cultural institution aesthetics.","era":"c.2010s–present","mood":"Culturally literate, institution-adjacent","visual":"Museum-reproduction jewellery. Art print scarves. Cultural institution tote bags. The aesthetic of someone who visits museums frequently and shops the gift shop with knowledge.","garments":["Art print scarf or dress","Museum-reproduction jewellery","Cultural institution tote bag","Art book as accessory","Architectural museum membership badge"],"habitat":"Museum gift shops, cultural institution events, art-literate fashion communities.","context":"Museum shop fashion exists at the intersection of cultural appreciation and fashion. The Van Gogh dress and the Mona Lisa tote are both fashion items and cultural statements.","rarity":"Niche","see_also":["Vintage Mix","Art Hoe","Dark Academia"],"colors":["#FAF8F5 Museum White","#1B4F72 Museum Blue","#D4AF37 Exhibition Gold","#8B7355 Archive Tan"],"media":["The Grand Budapest Hotel (2014) — film","Night at the Museum (2006) — film"]},"Retro Chic":{"summary":"The knowing, stylish invocation of past decade aesthetics — not costume, not pure vintage, but the confident translation of historical reference into contemporary dress.","era":"c.1980s–present","mood":"Knowingly retro, stylishly historical","visual":"A specific decade's silhouette in contemporary fabric. The 1970s blouse in 2024 material. The 1980s shoulder in a modern cut. The difference between costume and retro chic is always knowledge and contemporary translation.","garments":["Decade-specific silhouette in modern fabric","Historical reference as styling element","Retro pattern in contemporary context","Era-informed silhouette","Confident historical mix"],"habitat":"Fashion-literate communities, editorial fashion contexts.","context":"Retro Chic requires fashion knowledge to execute — the difference between it and costume is whether the wearer understands what they are referencing and why. Marc Jacobs is its great practitioner.","rarity":"Niche","see_also":["Vintage Mix","Grandmacore","Archival Fashion Aesthetic"],"colors":["#D4AF37 Retro Gold","#8B0000 Retro Red","#4A7C59 Retro Green","#C0C0C0 Chrome"],"media":["Midnight in Paris (2011) — film","The Artist (2011) — film"]},"Thrift Store Chic":{"summary":"The art of finding fashion at the thrift store — the democratic, sustainable alternative to retail fashion, and a genuine skill.","era":"c.1990s–present","mood":"Democratically fashionable, sustainably skilled","visual":"Genuinely thrifted pieces mixed and styled with intention. The thrift find that looks expensive. The mix that reads as collected rather than random. Requires an eye and time.","garments":["Thrifted blazer","Mixed-decade thrift pieces","Thrift-found dress","Inexpensive but styled accessories","Intentional thrift mix"],"habitat":"Thrift stores, Goodwill, charity shops, Depop, sustainable fashion communities.","context":"Thrift store chic requires time (middle-class) but not money (working-class accessible). The gentrification of thrift stores — fashion-aware shoppers outcompeting those who thrift from necessity — is a documented social problem.","rarity":"Common","see_also":["Vintage Mix","Charity Shop Aesthetic","Sustainable Fashion Aesthetic"],"colors":["#8B7355 Thrift Brown","#C1440E Thrift Red","#4A7C59 Thrift Green","#5B5B5B Thrift Grey"],"media":["Reality Bites (1994) — film","Empire Records (1995) — film","Macklemore: Thrift Shop (2012) — music"]},"Charity Shop Aesthetic":{"summary":"The British equivalent of thrift store chic — Oxfam, Age UK, and the specific pleasure of finding something extraordinary in a charity shop.","era":"c.1990s–present, Britain","mood":"Charitably found, British-specific","visual":"The British charity shop find. Oxfam's fashion-specific locations. The unexpected cashmere in the Sue Ryder. A specific British relationship with second-hand dress.","garments":["Oxfam charity shop find","Unexpected cashmere or silk","Mixed-provenance vintage mix","Charity shop styled outfit","British estate sale piece"],"habitat":"British charity shops, Oxfam boutiques, British sustainable fashion communities.","context":"British charity shopping has its own culture distinct from American thrift — the network of Oxfam boutiques creates a curated tier above the standard charity shop.","rarity":"Common","see_also":["Thrift Store Chic","Vintage Mix","British Heritage Fashion"],"colors":["#8B7355 Charity Tan","#D4AF37 Found Gold","#4A7C59 Green","#C1440E Red"],"media":["Absolutely Fabulous (TV series) — TV","Bridget Jones's Diary (2001) — film"]},"Vintage Mix":{"summary":"The art of mixing vintage pieces with contemporary dress — not single-era, but the skilled blending of eras into coherent modern styling.","era":"c.2000s–present","mood":"Era-fluent, temporally mixed","visual":"Vintage blazer over contemporary basics. 1990s jeans with current trainers. The skill is in the mix — not costume, not pure vintage, but a confident blend that reads as personal style.","garments":["Vintage blazer over contemporary basics","1990s jeans with current trainers","Mixed-era outfit","Vintage accessory with modern dress","Thrifted and new combined"],"habitat":"Fashion-aware communities everywhere, Instagram, vintage and contemporary mix styling.","context":"Vintage mix became the dominant mode of fashion-forward dress in the 2010s–20s — the rejection of head-to-toe current season in favour of personal curation. Kate Moss and Alexa Chung were its canonical practitioners.","rarity":"Common","see_also":["Thrift Store Chic","Vintage Collector Aesthetic","Retro Chic"],"colors":["#C1440E Mixed Red","#4A7C59 Mixed Green","#D4AF37 Mixed Gold","#8B7355 Mixed Brown"],"media":["Pretty in Pink (1986) — film","Reality Bites (1994) — film"]},"Grandmacore":{"summary":"The warm, slightly fussy, lovably dated dress of the fashion-forward grandma aesthetic — floral chintz, candy jewellery, and the reclamation of nan's wardrobe.","era":"c.2019–present","mood":"Warmly dated, lovably fussy","visual":"Floral chintz or brocade. Clip-on pearl or candy jewellery. Lace collar or trim. Midi or maxi length. House slippers elevated to outerwear. The specific warmth of the grandmother's sitting room.","garments":["Floral chintz or brocade dress","Clip-on pearl earrings","Lace collar or trim","Midi or maxi length","Comfortable elevated footwear"],"habitat":"TikTok, Instagram, Depop vintage, cosy aesthetic communities.","context":"Grandmacore emerged from the 2019–2020 internet reclamation of overlooked aesthetics. It reclaims the wardrobe of the unfashionably-dressed grandmother as a tender aesthetic document.","rarity":"Common","see_also":["Grandpacore / Eclectic Grandpa","Cottagecore","Vintage Mix"],"colors":["#F5C6CB Rose Pink","#4A7C59 Sage Green","#D4AF37 Floral Gold","#E8D5B0 Cream"],"media":["The Notebook (2004) — film","Babe (1995) — film","Chocolat (2000) — film"]},"Grandpacore / Eclectic Grandpa":{"summary":"The warm, slightly eccentric dress of the fashion-forward grandfather — the cardigan, the flat cap, and comfortable shoes elevated to style.","era":"c.2019–present","mood":"Eccentrically comfortable, wearably wise","visual":"The good cardigan. The flat cap. Corduroy trousers. The comfortable shoe that has graduated from embarrassment to fashion. Glasses that are either genuinely old or designed to look it.","garments":["Good wool cardigan","Flat cap","Corduroy trousers","Comfortable elevated shoes","Round or square vintage glasses"],"habitat":"TikTok, Instagram, menswear fashion-forward communities.","context":"Harry Styles wearing grandpa cardigans helped this aesthetic, but its deeper roots are in the menswear community's appreciation of heritage knitwear and the reclamation of embarrassing dad dress as style statement.","rarity":"Common","see_also":["Grandmacore","Cottagecore","Vintage Mix"],"colors":["#8B7355 Cardigan Brown","#5B5B5B Flannel Grey","#D4AF37 Warm Gold","#4A7C59 Muted Green"],"media":["The Darjeeling Limited (2007) — film","About Schmidt (2002) — film"]},"Pin-Up General":{"summary":"The glamorised vintage femininity of pin-up culture — curled hair, pencil skirts, seamed stockings, and the 1940s–50s ideal filtered through burlesque revival.","era":"c.1940s origin; 2000s–present revival","mood":"Vintage-glamorous, deliberately sexy","visual":"Victory rolls or curled hair. Red lips. Pencil or wiggle dress. Seamed stockings with visible seam. Platform heels or peep-toes. Polka dots and gingham. The 1940s ideal made deliberately theatrical.","garments":["Victory roll hair","Red lip","Pencil or wiggle dress","Seamed stockings","Platform peep-toe heels"],"habitat":"Rockabilly communities, pin-up photography, burlesque events, vintage beauty culture.","context":"Pin-up culture's revival in the 2000s coincided with the burlesque revival and the rockabilly scene. It represents a specific version of vintage female sexuality — glamorised, stylised, and retro.","rarity":"Niche","see_also":["Victory Roll Aesthetic","Rockabilly","Vintage Burlesque Aesthetic"],"colors":["#8B0000 Pin-Up Red","#FAF8F5 White","#1B4F72 Navy","#D4AF37 Vintage Gold"],"media":["Chicago (2002) — film","Grease (1978) — film","Alberto Vargas artwork — art"]},"Retro Tech Aesthetic":{"summary":"The warm nostalgia for obsolete technology in fashion — cassette tape prints, Polaroid motifs, and the aesthetics of analogue media.","era":"c.2010s–present","mood":"Nostalgically analogue, tech-vintage","visual":"Cassette tape prints. Polaroid camera motifs. Floppy disk embroidery. The warm grain of analogue photography as design inspiration. The aesthetics of technology before it became invisible.","garments":["Cassette tape print top","Polaroid motif accessory","Floppy disk embroidery","Analogue photography-grain print","Lo-fi tech motif"],"habitat":"Y2K adjacent communities, analogue photography enthusiasts, lo-fi aesthetic communities.","context":"Retro Tech Aesthetic emerged from the same nostalgic impulse as Y2K — the longing for a more tactile, visible, and understandable technology. The cassette tape is both fashion item and memorial to a lost media ecology.","rarity":"Niche","see_also":["Y2K","Vaporwave","Cottagecore"],"colors":["#87CEEB Computer Blue","#FAF8F5 Screen White","#D4AF37 Circuit Gold","#5B5B5B Metal Grey"],"media":["Tron (1982) — film","WarGames (1983) — film","Halt and Catch Fire (TV series) — TV"]},"Mod Aesthetic":{"summary":"The sharp-suited, scooter-riding youth movement of early 1960s Britain — Italian tailoring, R&B imports, and working-class aspiration expressed through immaculate style.","era":"c.1958–1966, London; revival perpetual","mood":"Sharply aspirational, scooter-riding, detail-obsessed","visual":"Slim-fit Italian or British suit in grey, navy, or tonic (two-tone) fabric. Fred Perry polo. Desert boots or Chelsea boots. Fishtail parka over suit for scooter riding. Hair short and neat. Women in shift dresses and Mary Quant-adjacent modernism.","garments":["Slim-fit tonic suit","Fred Perry polo shirt","Desert boots","Fishtail parka","Button-down Ben Sherman shirt"],"habitat":"Northern soul nights, scooter rallies, Mod revival communities, Quadrophenia screenings.","context":"Mod was the first British subculture to define itself primarily through fashion — every detail obsessively considered. The rivalry with rockers culminated in the 1964 Brighton beach clashes. Pete Townshend and The Who were its musical architects.","rarity":"Niche","see_also":["Carnaby Street","Mod Revival","Neo-Mod"],"colors":["#1B4F72 Mod Navy","#C0C0C0 Tonic Silver","#8B0000 Target Red","#FAF8F5 White"],"media":["Quadrophenia (1979) — film","Absolute Beginners (1986) — film","This Is England (2006) — film"]},"Mod Girl":{"summary":"The feminine side of Mod culture — geometric shift dresses, go-go boots, Vidal Sassoon cuts, and the women who dressed as sharply as the boys.","era":"c.1962–1966, London","mood":"Geometrically sharp, youthfully modern","visual":"Short shift dress in bold geometric print. Vidal Sassoon five-point bob. White or coloured tights. Low-heeled Mary Janes or go-go boots. Minimal jewellery. Eye makeup heavy, lips pale — the eye is everything.","garments":["Geometric shift dress","Sassoon-cut bob","White tights","Low-heeled Mary Janes","False eyelashes"],"habitat":"Mod girl nights, 1960s fashion events, Northern soul dance floors.","context":"Mod girls were as fashion-obsessed as the boys — Cathy McGowan on Ready Steady Go! was the visual reference. The geometric shift replaced hourglass femininity with a modern, angular ideal.","rarity":"Rare","see_also":["Carnaby Street","Twiggy Aesthetic","Go-Go Girl"],"colors":["#1A1A1A Mod Black","#FAF8F5 White Tights","#FF6B6B Op Art Pink","#D4AF37 Gold"],"media":["Ready Steady Go! (TV, 1963–66) — TV","Blow-Up (1966) — film"]},"Neo-Mod":{"summary":"The contemporary interpretation of Mod style — slim tailoring and target logos updated with modern fabrics and a broader gender inclusivity.","era":"c.2000s–present","mood":"Sharply contemporary, Mod-informed","visual":"Slim-fit suit in modern fabrics. Fred Perry polo as staple. Desert boots or Chelsea boots. Fishtail parka. The Mod vocabulary translated to contemporary silhouettes — less rigid than vintage Mod, but the details remain.","garments":["Modern slim-fit suit","Fred Perry polo","Chelsea boots","Harrington jacket","Slim dark denim"],"habitat":"Mod communities, indie music scenes, Paul Weller fan contexts.","context":"Neo-Mod draws on the original 1960s Mod aesthetic and its 1979 revival simultaneously. Paul Weller's transition from The Jam through Style Council to solo career tracks its evolution.","rarity":"Niche","see_also":["Mod Aesthetic","Mod Revival","Britpop Aesthetic"],"colors":["#1B4F72 Navy","#FAF8F5 White","#8B0000 Target Red","#8B7355 Desert Boot"],"media":["Paul Weller live performances — music","This Is England (2006) — film"]},"Britpop Aesthetic":{"summary":"The laddish, Union Jack-waving, retro-British look of mid-1990s guitar music — Oasis parkas, Blur art school, and the battle for British identity.","era":"c.1993–1997, Britain","mood":"Laddishly patriotic, retro-British, guitar-era","visual":"Oasis camp: working-class casual — parka, trainers, bucket hat, sunglasses indoors. Blur camp: art-school dandy — Fred Perry, Adidas Gazelles, graphic tees. Both camps: Union Jack imagery, British heritage references, deliberate anti-American posture.","garments":["Parka jacket","Bucket hat","Adidas Gazelles","Fred Perry polo","Band T-shirt"],"habitat":"1990s music nostalgia nights, British guitar music revival events, football casual adjacent culture.","context":"Britpop was the most commercially successful British guitar movement since punk. Oasis vs Blur was a genuine cultural event in 1995 — their chart battle was front-page news. The aesthetics of the two camps encoded a class divide.","rarity":"Niche","see_also":["Oasis Aesthetic","Blur Aesthetic","Casuals Aesthetic"],"colors":["#1B4F72 Union Blue","#8B0000 Union Red","#FAF8F5 White","#8B7355 Parka Khaki"],"media":["Trainspotting (1996) — film","Live Forever (2003) — documentary","Oasis: Supersonic (2016) — documentary"]},"Oasis Aesthetic":{"summary":"The specific Gallagher brothers' look — parka, sunglasses indoors, working-class Manchester casual elevated to stadium rock uniform.","era":"c.1994–2009; revival 2024–present","mood":"Defiantly working-class, parka-armoured","visual":"Oversized parka. Round sunglasses worn indoors and at night. Casual trainers. Polo shirt or plain T-shirt. Bucket hat. The studied casualness of someone too cool to dress up, too proud to dress down.","garments":["Oversized parka","Round Lennon sunglasses","Bucket hat","Adidas trainers","Polo shirt"],"habitat":"Oasis fan communities, Mancunian cultural events, Liam Gallagher solo tour audiences.","context":"The Gallagher brothers' style was deliberately anti-fashion — working-class Manchester casual scaled to stadium level. Liam's parka and sunglasses became as iconic as any designer outfit in 1990s British culture.","rarity":"Niche","see_also":["Britpop Aesthetic","Casuals Aesthetic","Mod Revival"],"colors":["#8B7355 Parka Khaki","#1A1A1A Sunglasses Black","#FAF8F5 White Tee","#1B4F72 Denim Blue"],"media":["Oasis: Supersonic (2016) — documentary","Live Forever (2003) — documentary"]},"Blur Aesthetic":{"summary":"The art-school, Essex-meets-Goldsmiths look of Damon Albarn and co. — Fred Perry, Adidas, and the studied casual of the educated working class.","era":"c.1993–1999, London","mood":"Art-school casual, wittily British","visual":"Fred Perry polo. Adidas Gazelles. Slim-fit jeans or chinos. Graphic T-shirts with ironic references. Hair deliberately messy. The look of someone from art school pretending to be from a council estate.","garments":["Fred Perry polo shirt","Adidas Gazelle trainers","Slim chinos","Graphic or vintage tee","Harrington jacket"],"habitat":"Britpop nostalgia events, art school music scenes, Gorillaz cultural contexts.","context":"Blur's aesthetic was the art-school counterpoint to Oasis's working-class authenticity. Graham Coxon's deliberately mismatched style and Damon Albarn's studied casual became the template for indie-educated British cool.","rarity":"Rare","see_also":["Britpop Aesthetic","Oasis Aesthetic","Indie Rock Aesthetic"],"colors":["#1B4F72 Fred Perry Navy","#FAF8F5 White","#D4AF37 Gazelle Gold","#4A7C59 Parklife Green"],"media":["Live Forever (2003) — documentary","Blur: New World Towers (2015) — documentary"]},"Casuals Aesthetic":{"summary":"The designer sportswear dress of British football terrace culture — Sergio Tacchini, Stone Island, and the most label-conscious subculture in British history.","era":"c.1979–present, Britain","mood":"Label-obsessed, terrace-sharp, deliberately anonymous","visual":"European designer sportswear: Sergio Tacchini, Fila, Ellesse, Lacoste, Stone Island. No club colours — the point is anonymity from police. Pristine trainers. The specific knowledge of which labels are currently correct.","garments":["Stone Island jacket","Sergio Tacchini tracksuit top","Adidas Samba trainers","Lacoste polo","CP Company goggle jacket"],"habitat":"Football terraces, casual culture communities, British sportswear fashion.","context":"The Casuals emerged in the late 1970s when Liverpool FC fans travelling to European away matches discovered continental sportswear brands. The movement spread nationwide. Stone Island's compass badge became the defining symbol.","rarity":"Niche","see_also":["Terrace Fashion","Blokecore","Mod Revival"],"colors":["#1B4F72 Stone Island Navy","#4A7C59 CP Company Green","#FAF8F5 Trainer White","#D4AF37 Badge Gold"],"media":["The Firm (2009) — film","ID (1995) — film","Awaydays (2009) — film"]},"Terrace Fashion":{"summary":"The broader dress culture of British football terraces — from skinhead boots to Casual sportswear, fashion as tribal identity on the stands.","era":"c.1960s–present, Britain","mood":"Tribally coded, regionally specific","visual":"Regionally variable — each city and era has its own variation. Scarves in club colours. Stone Island for the Casuals. Dr. Martens for the old school. The terrace as fashion laboratory where trends originate and spread.","garments":["Club scarf","Stone Island jacket","Regional trainer preference","Parka or cagoule","Team-adjacent colour palette"],"habitat":"Football grounds, match-day culture, British working-class fashion.","context":"British terrace fashion has generated more fashion trends than any other sporting context — from skinhead to casual to blokecore. Each generation reinvents the terrace wardrobe while maintaining tribal loyalty.","rarity":"Niche","see_also":["Casuals Aesthetic","Blokecore","Skinhead"],"colors":["#1B4F72 Stadium Blue","#8B0000 Terrace Red","#FAF8F5 White","#4A7C59 Pitch Green"],"media":["Green Street (2005) — film","The Firm (2009) — film"]},"Blokecore":{"summary":"The TikTok-era revival of football shirt styling as fashion — vintage jerseys over basics, terrace casual meets streetwear.","era":"c.2022–present","mood":"Casually nostalgic, football-fashion fusion","visual":"Vintage or retro football shirt worn over a long-sleeve tee or under a jacket. Baggy trousers or wide-leg jeans. Trainers. The football shirt treated as a fashion piece rather than match-day uniform.","garments":["Vintage football jersey","Wide-leg trousers","Classic trainers","Simple layering tee","Crossbody bag"],"habitat":"TikTok, Instagram, vintage football shirt resale market, streetwear communities.","context":"Blokecore emerged as a named TikTok aesthetic in 2022, crystallising a trend that had been building in streetwear — the football shirt as fashion item. Vintage shirts from 1990s European leagues command high resale prices.","rarity":"Common","see_also":["Casuals Aesthetic","Blokette","Terrace Fashion"],"colors":["#8B0000 Jersey Red","#1B4F72 Jersey Blue","#FAF8F5 White","#D4AF37 Badge Gold"],"media":["TikTok #blokecore (2022–) — social media"]},"Blokette":{"summary":"The feminine interpretation of Blokecore — football shirts styled with mini skirts, heels, or tailored pieces, reclaiming terrace culture for women.","era":"c.2023–present","mood":"Femininely terrace, football-fashion reclaimed","visual":"Vintage football shirt cropped or knotted, worn with a mini skirt or tailored trousers. Heeled boots or chunky trainers. Hair down. The deliberate feminisation of a traditionally masculine garment.","garments":["Cropped vintage football shirt","Mini skirt or tailored trousers","Heeled boots","Crossbody bag","Layered jewellery"],"habitat":"TikTok, Instagram, women's football culture, vintage sportswear communities.","context":"Blokette emerged alongside the growth of women's football and the broader feminisation of traditionally male subcultures. It explicitly claims space in football culture for women who dress femininely.","rarity":"Common","see_also":["Blokecore","Casuals Aesthetic","Downtown Girl"],"colors":["#8B0000 Jersey Red","#F5C6CB Feminine Pink","#1B4F72 Jersey Blue","#D4AF37 Gold"],"media":["TikTok #blokette (2023–) — social media"]},"Chav Aesthetic":{"summary":"The controversial British class-coded aesthetic of early 2000s tabloid culture — Burberry check, tracksuits, and the demonisation of working-class style.","era":"c.2003–2008; revival 2020s","mood":"Class-contested, tabloid-demonised, reclaimed","visual":"Full tracksuit in branded sportswear. Burberry check (until the brand withdrew it from accessibility). Large gold hoop earrings. Hair scraped back in a high ponytail. White trainers. The aesthetic was simultaneously authentic working-class dress and a middle-class caricature.","garments":["Branded tracksuit","Large gold hoop earrings","Scraped-back high ponytail","White trainers","Burberry check accessory"],"habitat":"British class discourse, fashion reclamation communities. NOTE: 'Chav' is a contested and class-prejudiced term.","context":"The 'chav' panic of the early 2000s was a middle-class moral panic about working-class aesthetics. Owen Jones's 'Chavs: The Demonization of the Working Class' (2011) analysed how the term pathologised poverty.","rarity":"Niche","see_also":["Council Estate Fashion","Ned Aesthetic","Casuals Aesthetic"],"colors":["#D4AF37 Gold Hoop","#8B7355 Burberry Tan","#1A1A1A Tracksuit Black","#FAF8F5 Trainer White"],"media":["Vicky Pollard / Little Britain (2003) — TV","Chavs, Owen Jones (2011) — book","Misfits (TV series) — TV"]},"Council Estate Fashion":{"summary":"The authentic daily dress of British social housing communities — practical, brand-aware, and distinct from the caricatured 'chav' label.","era":"c.1980s–present, Britain","mood":"Practically authentic, community-rooted","visual":"Clean practical sportswear. Specific trainer knowledge. Puffer jacket or parka. Tracksuit bottoms for comfort. The aesthetic is practical and brand-aware without being the caricature — real people dressing for real lives.","garments":["Clean puffer jacket","Practical trainers","Tracksuit bottoms","Hoodie","Crossbody bag"],"habitat":"British social housing communities, working-class fashion.","context":"Council Estate Fashion is the authentic dress of a community, distinct from middle-class caricatures of it. The style is practical, brand-conscious, and communally shared.","rarity":"Common","see_also":["Chav Aesthetic","Casuals Aesthetic","Ned Aesthetic"],"colors":["#1A1A1A Puffer Black","#FAF8F5 Trainer White","#5B5B5B Tracksuit Grey","#1B4F72 Navy"],"media":["Top Boy (TV series) — TV","This Is England (2006) — film"]},"Ned Aesthetic":{"summary":"The Scottish equivalent of the English 'chav' — Buckfast, Berghaus, and the specific working-class youth aesthetic of Glasgow and central Scotland.","era":"c.2000s–present, Scotland","mood":"Glaswegian-specific, Berghaus-branded","visual":"Berghaus jacket (the specific Scottish brand preference). Tracksuit bottoms tucked into socks. Baseball cap. White trainers. The regional specificity matters — a Ned is specifically Scottish, not English.","garments":["Berghaus jacket","Tracksuit bottoms tucked into socks","Baseball cap","White trainers","Branded hoodie"],"habitat":"Scottish working-class communities, Glasgow and central Scotland.","context":"Ned culture is specifically Scottish — the word may derive from 'Non-Educated Delinquent' though this etymology is contested. Like 'chav', it is a class-prejudiced term that pathologises working-class aesthetics.","rarity":"Niche","see_also":["Chav Aesthetic","Council Estate Fashion","Casuals Aesthetic"],"colors":["#1B4F72 Berghaus Blue","#1A1A1A Black","#FAF8F5 White Trainer","#4A7C59 Berghaus Green"],"media":["Neds (2010) — film","Trainspotting (1996) — film"]},"Woody Guthrie Aesthetic":{"summary":"The dust bowl troubadour look — work shirt, worn boots, and the guitar as the only accessory that matters.","era":"c.1930s–1967","mood":"Dustily radical, working-class poetic","visual":"Work shirt in chambray or flannel. Worn jeans or work trousers. Battered boots. Acoustic guitar. The 'This Machine Kills Fascists' sticker on the guitar as the only decoration. No embellishment — the music is the point.","garments":["Chambray work shirt","Worn work trousers","Battered leather boots","Simple leather belt","Acoustic guitar"],"habitat":"American folk music heritage, protest music contexts, Dust Bowl history.","context":"Woody Guthrie dressed like a working man because he was one. His aesthetic became the template for every protest singer who followed — the deliberate absence of stage costume as political statement.","rarity":"Extinct","see_also":["Pete Seeger Aesthetic","Bob Dylan Aesthetic","Frontier Workwear Aesthetic"],"colors":["#8B7355 Dust Bowl Tan","#5B3A29 Boot Brown","#4A7C59 Work Green","#FAF8F5 Cotton White"],"media":["Bound for Glory (1976) — film","This Machine Kills Fascists (documentary) — documentary"]},"Pete Seeger Aesthetic":{"summary":"The gentle, principled folk singer look — flannel shirt, banjo, and decades of showing up for every cause in the same honest clothes.","era":"c.1940s–2014","mood":"Gently principled, lifelong consistent","visual":"Simple flannel or checked shirt. Work trousers or jeans. Plain leather belt. Banjo. The look of someone who has dressed the same way for 60 years because the clothes aren't the point.","garments":["Flannel checked shirt","Simple work trousers","Plain leather belt","Banjo","Work boots or simple shoes"],"habitat":"Folk music festivals, protest movements, American folk heritage.","context":"Pete Seeger's aesthetic was his ethic — no stage costume, no performance dress. He wore the same kind of clothes to sing for presidents and for striking workers.","rarity":"Extinct","see_also":["Woody Guthrie Aesthetic","Joan Baez Aesthetic","Bob Dylan Aesthetic"],"colors":["#C1440E Flannel Red","#8B7355 Work Tan","#4A7C59 Forest Green","#FAF8F5 Cotton White"],"media":["Pete Seeger: The Power of Song (2007) — documentary"]},"Joan Baez Aesthetic":{"summary":"The dark-haired, barefoot, crystalline-voiced folk protest look — simple natural fabrics, long straight hair, and moral clarity made visible.","era":"c.1959–present","mood":"Morally crystalline, naturally beautiful","visual":"Long straight dark hair, centre-parted. Simple blouse or dress in natural fabrics. Bare feet or simple sandals. No makeup or minimal. Acoustic guitar. The aesthetic of someone whose beauty is incidental to their purpose.","garments":["Simple cotton or linen blouse","Long natural-fabric skirt","Simple sandals or bare feet","Centre-parted long straight hair","Acoustic guitar"],"habitat":"Folk music festivals, civil rights and protest contexts, Joan Baez Institute.","context":"Joan Baez's beauty and her voice made her the visual icon of the 1960s protest movement. Her simplicity was deliberate — no stage costume, no fashionable concession. She marched with King in the same dress she sang in.","rarity":"Rare","see_also":["Bob Dylan Aesthetic","Woody Guthrie Aesthetic","Earth Mother Aesthetic"],"colors":["#FAF8F5 Natural White","#8B7355 Folk Brown","#1A1A1A Hair Black","#4A7C59 Protest Green"],"media":["Joan Baez: How Sweet the Sound (2009) — documentary","Festival (1967) — documentary"]},"Bob Dylan Aesthetic":{"summary":"The most documented personal style evolution in American music — from folk troubadour to electric dandy to country squire to never-ending tour veteran.","era":"c.1961–present","mood":"Perpetually shape-shifting, deliberately illegible","visual":"Folk era: work shirt, jeans, harmonica rack, wild curly hair. Electric era: Ray-Ban Wayfarers, polka-dot shirt, Cuban heels, leather jacket. Rolling Thunder era: whiteface, flowers, gypsy scarves. Each phase fully committed.","garments":["Wild curly hair","Ray-Ban Wayfarers","Leather jacket","Work shirt and jeans","Harmonica rack"],"habitat":"Dylan fan communities, folk-to-rock cultural history, Never Ending Tour audiences.","context":"Dylan's 1965 switch from acoustic folk to electric rock was expressed as much through fashion as sound. The leather jacket and sunglasses replaced the work shirt overnight. Fashion was part of the betrayal narrative.","rarity":"Niche","see_also":["Woody Guthrie Aesthetic","Joan Baez Aesthetic","Bowie Aesthetic"],"colors":["#1A1A1A Electric Black","#8B7355 Folk Brown","#D4AF37 Gold","#5B3A29 Leather"],"media":["No Direction Home (2005) — documentary","Don't Look Back (1967) — documentary","I'm Not There (2007) — film"]},"Bluegrass Aesthetic":{"summary":"The Appalachian roots music dress — Western hats, bolo ties, embroidered shirts, and the mountain string band tradition.","era":"c.1940s–present, Appalachia","mood":"Mountain-rooted, string-band traditional","visual":"Cowboy hat or fedora. Embroidered Western shirt. Bolo tie. Good boots. The look ranges from formal Grand Ole Opry presentation to informal front-porch picking. The instrument — banjo, fiddle, mandolin — is part of the aesthetic.","garments":["Cowboy hat or fedora","Embroidered Western shirt","Bolo tie","Good leather boots","String instrument"],"habitat":"Bluegrass festivals, Appalachian music communities, Grand Ole Opry.","context":"Bluegrass was codified by Bill Monroe in the 1940s. Its dress is rooted in Appalachian working-class tradition — the formal version for the stage, the informal version for the porch. Both are authentic.","rarity":"Niche","see_also":["Classic Country Aesthetic","Nudie Suit Aesthetic","Americana Music Fashion"],"colors":["#8B7355 Mountain Tan","#4A7C59 Appalachian Green","#D4AF37 String Gold","#FAF8F5 Shirt White"],"media":["O Brother, Where Art Thou? (2000) — film","High Lonesome (1994) — documentary"]},"Classic Country Aesthetic":{"summary":"The rhinestone-and-denim dress of country music's golden age — Hank Williams's suit, Patsy Cline's gown, and the Opry as fashion stage.","era":"c.1940s–1975, Nashville","mood":"Opry-formal, rhinestone-proud","visual":"Men: Western suit with embroidery or rhinestones, Stetson, good boots. Women: full-skirted gown or fitted Western dress, elaborate hair. The Grand Ole Opry demanded formal dress — you dressed up to perform.","garments":["Western suit with embroidery","Stetson hat","Rhinestone-trimmed dress","Good cowboy boots","Bolo or Western tie"],"habitat":"Grand Ole Opry, country music heritage events, Nashville.","context":"Classic Country dress was formal by working-class standards — performing at the Opry was an honour that demanded your best. Hank Williams's white suit and Patsy Cline's gowns set standards that persist.","rarity":"Niche","see_also":["Nashville Aesthetic","Nudie Suit Aesthetic","Dolly Parton Aesthetic"],"colors":["#D4AF37 Rhinestone Gold","#FAF8F5 Hank White","#8B0000 Country Red","#8B7355 Denim Brown"],"media":["Coal Miner's Daughter (1980) — film","Walk the Line (2005) — film","I Saw the Light (2015) — film"]},"Nudie Suit Aesthetic":{"summary":"The spectacular rhinestone-embroidered Western suits created by Nudie Cohn — wearable art for country music royalty.","era":"c.1947–1984; legacy perpetual","mood":"Spectacularly embroidered, handmade-magnificent","visual":"Hand-embroidered Western suit with rhinestones in elaborate pictorial designs — cacti, horseshoes, musical notes, roses. Matching embroidered boots. Each suit unique and handmade. The most labour-intensive garments in American popular music.","garments":["Rhinestone-embroidered Western jacket","Matching embroidered trousers","Embroidered cowboy boots","Western hat","Bolo tie or string tie"],"habitat":"Country music history, Nashville, Western wear museums, Gram Parsons fan contexts.","context":"Nudie Cohn (born Nuta Kotlyarenko in Kyiv) created suits for Hank Williams, Elvis, and Gram Parsons. Gram Parsons's marijuana-leaf Nudie suit is one of rock's most famous garments.","rarity":"Rare","see_also":["Nashville Aesthetic","Classic Country Aesthetic","Western / Cowboy Core"],"colors":["#D4AF37 Rhinestone Gold","#8B0000 Embroidery Red","#FAF8F5 Base White","#C0C0C0 Silver Thread"],"media":["Rhinestone Cowboy documentary — documentary","Gram Parsons: Fallen Angel (2004) — documentary"]},"Dolly Parton Aesthetic":{"summary":"The self-created, maximally glamorous look of Dolly Parton — wigs, rhinestones, and the most self-aware personal brand in country music.","era":"c.1967–present","mood":"Maximally self-created, joyfully artificial","visual":"Enormous blonde wig. Full makeup at all times. Rhinestones and sequins. Tight-fitting clothing. Platform or high heels. Acrylic nails. The deliberate construction of an image she has openly described as inspired by 'the town tramp.'","garments":["Enormous blonde wig","Rhinestone-encrusted outfit","Platform heels","Full stage makeup","Acrylic nails"],"habitat":"Dollywood, country music events, Dolly Parton fan culture worldwide.","context":"Dolly Parton has said 'It costs a lot of money to look this cheap.' Her aesthetic is the most self-aware in country music — simultaneously genuine and performed, working-class and glamorous, comic and deeply sincere.","rarity":"Niche","see_also":["Nashville Aesthetic","Classic Country Aesthetic","Camp Aesthetic"],"colors":["#D4AF37 Dolly Gold","#FAF8F5 Blonde White","#F5C6CB Dolly Pink","#C0C0C0 Rhinestone Silver"],"media":["9 to 5 (1980) — film","Dolly Parton: Here I Am (2019) — documentary"]},"Outlaw Country":{"summary":"The anti-Nashville establishment dress of 1970s outlaw country — long hair, denim, and the deliberate rejection of rhinestone Opry formality.","era":"c.1972–1985, Austin/Nashville","mood":"Anti-establishment, denim-authentic","visual":"Long hair and beards. Denim and leather instead of rhinestone suits. Black as dominant colour. Bandanas. The deliberate rejection of Nashville formality — Willie Nelson, Waylon Jennings, and Kris Kristofferson dressed like rock musicians, not Opry performers.","garments":["Denim jacket","Black T-shirt or Western shirt","Long hair and beard","Bandana","Worn leather boots"],"habitat":"Austin music scene, outlaw country revival communities, Willie Nelson fan events.","context":"Outlaw Country was a deliberate rejection of the Nashville establishment — its dress was part of its politics. Willie Nelson's braids and bandana became as iconic as any rhinestone suit.","rarity":"Niche","see_also":["Classic Country Aesthetic","Nashville Aesthetic","Western / Cowboy Core"],"colors":["#1A1A1A Outlaw Black","#8B7355 Worn Denim","#5B3A29 Leather Brown","#8B0000 Bandana Red"],"media":["Outlaw Country documentary — documentary","Heartworn Highways (1976) — documentary"]},"Americana Music Fashion":{"summary":"The contemporary roots music dress — heritage workwear, vintage boots, and the aesthetic of musicians who sound old and dress accordingly.","era":"c.2000s–present","mood":"Heritage-informed, authentically worn","visual":"Vintage or heritage workwear. Good boots well worn. Flannel or chambray. Facial hair. The aesthetic of someone who listens to vinyl, drinks bourbon, and values things that get better with age.","garments":["Heritage flannel shirt","Worn leather boots","Selvedge or vintage denim","Leather belt","Felt hat"],"habitat":"Americana music festivals, roots music communities, independent record store culture.","context":"Americana as a musical genre consolidated in the 2000s, and its fashion followed — a mix of heritage workwear, vintage country, and indie rock sensibility. The aesthetic signals authenticity and historical awareness.","rarity":"Niche","see_also":["Heritage Core","Outlaw Country","Alt-Country Aesthetic"],"colors":["#8B7355 Worn Tan","#5B3A29 Leather Brown","#C1440E Flannel Red","#4A7C59 Forest Green"],"media":["Inside Llewyn Davis (2013) — film","Once (2007) — film"]},"Modern Folk Aesthetic":{"summary":"The gentle, handmade-adjacent dress of the contemporary folk music revival — knit beanies, natural fibres, and the aesthetic of sincerity.","era":"c.2007–present","mood":"Gently sincere, handmade-adjacent","visual":"Natural fibres in muted earth tones. Knit beanie or soft hat. Simple layering. The look of someone who might also make pottery, keep bees, or live in a converted barn. Bon Iver in a cabin as origin myth.","garments":["Knit beanie","Natural fibre sweater","Simple layered shirts","Worn denim or corduroy","Simple leather boots"],"habitat":"Folk festivals, independent music venues, Cottagecore-adjacent communities.","context":"The modern folk revival that began with Bon Iver, Fleet Foxes, and Iron & Wine created an aesthetic of deliberate simplicity and handmade sensibility that feeds directly into Cottagecore.","rarity":"Common","see_also":["Indie Folk","Cottagecore","Earth Mother Aesthetic"],"colors":["#8B7355 Cabin Brown","#4A7C59 Forest Green","#E8D5B0 Natural Cream","#5B5B5B Wool Grey"],"media":["Bon Iver: For Emma, Forever Ago (2007) — music","Fleet Foxes documentary — documentary"]},"Indie Folk":{"summary":"The aesthetic intersection of indie rock and folk music — vintage dresses, acoustic instruments, and the Mumford & Sons-to-Phoebe Bridgers pipeline.","era":"c.2006–present","mood":"Vintage-gentle, acoustically independent","visual":"Vintage-mix dress or shirt. Simple accessories. Muted colours with occasional floral. The look ranges from Mumford & Sons waistcoat-folk to Phoebe Bridgers skeleton suit — the genre is wider than it first appears.","garments":["Vintage floral dress","Simple waistcoat","Worn leather shoes","Knit cardigan","Simple acoustic guitar"],"habitat":"Indie music festivals, independent venues, folk-adjacent music communities.","context":"Indie Folk sits at the crossover between folk's sincerity and indie rock's self-awareness. Its aesthetic borrows from both — vintage folk simplicity with indie ironic distance.","rarity":"Common","see_also":["Modern Folk Aesthetic","Indie Rock Aesthetic","Cottagecore"],"colors":["#8B7355 Vintage Tan","#4A7C59 Meadow Green","#F5C6CB Floral Pink","#E8D5B0 Natural Linen"],"media":["Inside Llewyn Davis (2013) — film","Once (2007) — film"]},"New Folk Fashion":{"summary":"The contemporary folk-inspired wardrobe that draws on heritage craft — hand-knits, natural dyes, and the slow fashion ethos of the folk revival.","era":"c.2015–present","mood":"Craft-conscious, naturally dyed","visual":"Hand-knitted or hand-dyed garments. Natural fibres — wool, linen, cotton. Muted earthy palette. Simple shapes. The aesthetic of someone who could plausibly have made what they are wearing.","garments":["Hand-knit sweater","Natural-dye linen dress","Simple wool trousers","Handmade leather accessories","Muted woven scarf"],"habitat":"Maker communities, slow fashion circles, craft fair culture.","context":"New Folk Fashion draws on the folk music revival and the maker movement simultaneously — it values process and material as much as appearance. It is inseparable from the slow fashion movement.","rarity":"Niche","see_also":["Modern Folk Aesthetic","Slow Living Aesthetic","Sustainable Fashion Aesthetic"],"colors":["#8B7355 Natural Wool","#4A7C59 Plant Dye Green","#C1440E Madder Red","#E8D5B0 Undyed Linen"],"media":["Making magazine","Selvedge magazine"]},"Alt-Country Aesthetic":{"summary":"The punk-meets-honky-tonk dress of alternative country — vintage Western with indie edge, Uncle Tupelo's flannel meeting Lucinda Williams's boots.","era":"c.1990–present","mood":"Punk-country fusion, authentically worn","visual":"Vintage Western shirt with punk or indie edge. Worn cowboy boots. Denim. The look of someone who loves Hank Williams and The Replacements equally. Less polished than Nashville, less grungy than indie rock.","garments":["Vintage Western shirt","Worn cowboy boots","Denim jeans","Leather belt with simple buckle","Felt or straw hat"],"habitat":"Alt-country music venues, Americana festival culture, Bloodshot Records communities.","context":"Alt-Country emerged in the 1990s as punk musicians discovered country roots. Uncle Tupelo, Wilco, and Lucinda Williams defined its aesthetic — the Western shirt worn with punk sincerity rather than Nashville polish.","rarity":"Niche","see_also":["Outlaw Country","Americana Music Fashion","Indie Rock Aesthetic"],"colors":["#8B7355 Honky Tonk Brown","#8B0000 Western Red","#1B4F72 Denim Blue","#D4AF37 Buckle Gold"],"media":["I Am Trying to Break Your Heart (2002) — documentary","Heartworn Highways (1976) — documentary"]},"New York Dolls Aesthetic":{"summary":"The lipstick-and-platform proto-punk look of the New York Dolls — glam meets street, the missing link between the Rolling Stones and the Sex Pistols.","era":"c.1971–1977, New York","mood":"Gloriously trashy, proto-punk glamorous","visual":"Lipstick and mascara on men. Platform boots. Tight trousers. Ripped or torn shirts. Leopard print. The look of someone who raided their girlfriend's makeup bag and a thrift store simultaneously.","garments":["Platform boots","Tight satin or leather trousers","Lipstick and heavy eyeliner","Leopard print anything","Ripped vintage shirt"],"habitat":"Proto-punk history, Mercer Arts Center legacy, New York rock heritage.","context":"The New York Dolls invented the aesthetic vocabulary that punk would codify. Malcolm McLaren managed them briefly before returning to London to create the Sex Pistols — he literally brought the look across the Atlantic.","rarity":"Extinct","see_also":["UK Punk Aesthetic","Glam Rock","CBGB Aesthetic"],"colors":["#8B0000 Lipstick Red","#1A1A1A Punk Black","#D4AF37 Leopard Gold","#C185A0 Mascara Rose"],"media":["New York Dolls: All Dolled Up (2005) — documentary","Trash (New York Dolls, 1973) — music"]},"UK Punk Aesthetic":{"summary":"The safety-pinned, ripped, confrontational dress of British punk 1976–78 — Vivienne Westwood's SEX shop, DIY as ideology, and fashion as weapon.","era":"c.1976–1979, London","mood":"Confrontationally DIY, deliberately offensive","visual":"Safety pins through fabric and sometimes skin. Ripped clothing held together with pins and tape. Bondage trousers from Westwood's shop. Band T-shirts altered with markers and bleach. Mohawk or spiked hair. Doc Martens.","garments":["Safety-pinned ripped T-shirt","Bondage trousers","Doc Martens boots","Leather jacket with studs","Mohawk or spiked hair"],"habitat":"Punk heritage, 1976–77 London punk history, DIY music communities.","context":"British punk fashion was inseparable from its politics — dressing offensively was the point. Vivienne Westwood and Malcolm McLaren's SEX shop at 430 King's Road was the fashion laboratory.","rarity":"Niche","see_also":["Sex Pistols Aesthetic","Vivienne Westwood Punk","DIY Punk"],"colors":["#1A1A1A Punk Black","#8B0000 Anarchy Red","#FAF8F5 Bleached White","#C0C0C0 Safety Pin Silver"],"media":["The Filth and the Fury (2000) — documentary","Jubilee (1978) — film","Punk Britannia (BBC, 2012) — documentary"]},"Sex Pistols Aesthetic":{"summary":"The specific Pistols look — McLaren/Westwood creations, bondage gear, swastikas-as-provocation, and the most photographed punk band in history.","era":"c.1975–1978, London","mood":"Maximum provocation, designed confrontation","visual":"Bondage trousers and straps from SEX shop. Ripped shirts with provocative slogans. Safety pins. Spiky hair. The Cambridge Rapist mask. Swastikas worn as provocation. Every element designed to offend.","garments":["SEX shop bondage trousers","Ripped slogan T-shirt","Safety pins as decoration","Spiked or messy hair","Leather and chain accessories"],"habitat":"Punk history, Sex Pistols cultural legacy, Westwood heritage.","context":"The Sex Pistols were a fashion project as much as a band — McLaren conceived them as walking advertisements for his shop. The swastika use was intended as provocation, not endorsement, but remains deeply contested.","rarity":"Rare","see_also":["UK Punk Aesthetic","Vivienne Westwood Punk","Sid Vicious Aesthetic"],"colors":["#1A1A1A Pistols Black","#8B0000 Anarchy Red","#FAF8F5 White","#D4AF37 Safety Pin Gold"],"media":["The Great Rock 'n' Roll Swindle (1980) — film","The Filth and the Fury (2000) — documentary","Pistol (TV series, 2022) — TV"]},"Vivienne Westwood Punk":{"summary":"Westwood's specific punk design vocabulary — bondage straps, tartan, provocative slogans, and the transformation of subcultural dress into high fashion.","era":"c.1974–1981, London","mood":"Intellectually provocative, fashion-as-confrontation","visual":"Bondage trousers with straps connecting the legs. Tartan in punk context. Provocative slogan T-shirts. Safety pins as design elements. The specific Westwood cut — always technically excellent even when deliberately torn.","garments":["Bondage trousers","Tartan punk pieces","Provocative slogan tee","Leather and chain harness","Platform boots"],"habitat":"Westwood retrospectives, punk fashion history, V&A costume collections.","context":"Westwood's genius was making punk fashion technically sophisticated — her bondage trousers are complex pattern-cutting. She transformed subcultural dress into collectible fashion, eventually becoming a Dame of the British Empire.","rarity":"Rare","see_also":["UK Punk Aesthetic","Sex Pistols Aesthetic","Vivienne Westwood Aesthetic"],"colors":["#1A1A1A Punk Black","#8B0000 Westwood Red","#2E5A8B Tartan Blue","#D4AF37 Buckle Gold"],"media":["Westwood: Punk, Icon, Activist (2018) — documentary","Pistol (TV series, 2022) — TV"]},"Sid Vicious Aesthetic":{"summary":"The specific destroyed, chain-draped look of Sid Vicious — the padlock necklace, the blood, and the aesthetic of self-destruction as style.","era":"c.1977–1979, London/New York","mood":"Self-destructively iconic, tragically wasted","visual":"Padlock on chain around neck. Bare chest with scrawled writing. Ripped jeans. Leather jacket. The sunken-cheeked, destroyed look of someone not performing danger but living it.","garments":["Padlock chain necklace","Ripped and destroyed jeans","Leather jacket","Bare chest","Combat or biker boots"],"habitat":"Punk history, cautionary aesthetic. NOTE: Sid Vicious died at 21 from heroin overdose — this aesthetic is inseparable from addiction and tragedy.","context":"Sid Vicious became punk's most photographed figure precisely because his self-destruction was real. The padlock necklace has been continuously referenced in fashion. His death underscored punk's romantic-destructive mythology.","rarity":"Extinct","see_also":["Sex Pistols Aesthetic","UK Punk Aesthetic","Heroin Chic"],"colors":["#1A1A1A Destroyed Black","#C0C0C0 Padlock Silver","#8B0000 Blood Red","#5B5B5B Wasted Grey"],"media":["Sid and Nancy (1986) — film","The Filth and the Fury (2000) — documentary"]},"CBGB Aesthetic":{"summary":"The specific look of New York's CBGB club scene — Ramones leather, Blondie's mix, Television's art-school cool, all on the Bowery.","era":"c.1974–1979, New York","mood":"Downtown raw, Bowery-specific","visual":"Leather jackets (Ramones). Ripped jeans. Band T-shirts. Converse or boots. The look varies by band — Ramones were uniform, Blondie was eclectic, Television was art-school — but the Bowery location unified them.","garments":["Leather motorcycle jacket","Ripped or worn jeans","Band T-shirt","Converse sneakers","Simple dark clothing"],"habitat":"CBGB legacy, New York punk history, Bowery cultural heritage.","context":"CBGB (Country, BlueGrass, and Blues) became punk's home accidentally. The club's filthy bathroom and cramped stage created an aesthetic of deliberate squalor that New York punk embraced.","rarity":"Extinct","see_also":["Ramones Aesthetic","Patti Smith Aesthetic","New York Punk"],"colors":["#1A1A1A Bowery Black","#8B7355 Leather Brown","#FAF8F5 T-shirt White","#5B5B5B Concrete Grey"],"media":["CBGB (2013) — film","Blank Generation (1980) — film","End of the Century: The Story of the Ramones (2003) — documentary"]},"New York Punk":{"summary":"The broader New York punk aesthetic beyond CBGB — art school meets street, intellect meets aggression, downtown Manhattan as creative laboratory.","era":"c.1974–1980, Lower Manhattan","mood":"Intellectually aggressive, downtown-authentic","visual":"More art-school influenced than UK punk. Less safety pins, more studied cool. Dark sunglasses. Leather jacket. Simple dark clothing. The downtown New York aesthetic of people who read Rimbaud and played three chords.","garments":["Leather jacket","Dark sunglasses","Simple dark T-shirt or blouse","Slim dark jeans","Boots or Converse"],"habitat":"Lower East Side heritage, downtown New York cultural history.","context":"New York punk was more intellectual than its UK counterpart — Television's Tom Verlaine named himself after a French poet. The aesthetic was cool rather than confrontational, art-school rather than working-class.","rarity":"Rare","see_also":["CBGB Aesthetic","Patti Smith Aesthetic","No Wave Aesthetic"],"colors":["#1A1A1A Downtown Black","#5B5B5B NYC Grey","#8B7355 Leather","#FAF8F5 White Tee"],"media":["Punk: Attitude (2005) — documentary","CBGB (2013) — film"]},"Ramones Aesthetic":{"summary":"The uniform simplicity of the Ramones — leather jacket, ripped jeans, Converse, and the most consistent band uniform in rock history.","era":"c.1974–1996","mood":"Uniformly simple, deliberately identical","visual":"Black leather motorcycle jacket. Ripped blue jeans. White T-shirt. Converse sneakers. Bowl-cut hair. All four members dressed identically — the Ramones were the first band to make the uniform the aesthetic.","garments":["Black leather motorcycle jacket","Ripped blue jeans","White T-shirt","Converse sneakers","Bowl-cut hair"],"habitat":"Punk communities worldwide, Ramones fan culture.","context":"The Ramones' uniform was both democratic (identical) and iconic (immediately recognisable). They wore the same outfit for 22 years. The leather jacket became the single most referenced garment in punk history.","rarity":"Niche","see_also":["CBGB Aesthetic","UK Punk Aesthetic","Pop Punk Aesthetic"],"colors":["#1A1A1A Leather Black","#4A7C59 Denim Blue","#FAF8F5 T-shirt White","#C0C0C0 Rivet Silver"],"media":["End of the Century (2003) — documentary","Rock 'n' Roll High School (1979) — film"]},"Patti Smith Aesthetic":{"summary":"The poet-punk look of Patti Smith — men's white shirt, Keith Richards hair, and the most literary personal style in rock history.","era":"c.1975–present","mood":"Poetically androgynous, literarily punk","visual":"Men's white button-down shirt, slightly too big. Skinny dark trousers. Messy Keith Richards-influenced hair. No makeup. Simple jewellery — a ribbon, a pin. The look of someone who just wrote a poem and is about to play a gig.","garments":["Oversized white men's shirt","Skinny dark trousers","Messy uncombed hair","Simple ribbon or pin","Worn leather jacket"],"habitat":"Literary punk communities, Patti Smith fan culture, poetry-meets-music spaces.","context":"Patti Smith's look has been remarkably consistent for 50 years — the white shirt, the androgyny, the poet's indifference to fashion that is itself a powerful fashion statement. Robert Mapplethorpe's photographs of her defined the aesthetic.","rarity":"Niche","see_also":["New York Punk","CBGB Aesthetic","Androgynous Fashion"],"colors":["#FAF8F5 White Shirt","#1A1A1A Poet Black","#8B7355 Worn Leather","#5B5B5B Ash Grey"],"media":["Just Kids, Patti Smith (2010) — memoir","Patti Smith: Dream of Life (2008) — documentary"]},"Crass Aesthetic":{"summary":"The stark, black-and-white, stencilled aesthetic of anarcho-punk — Crass's visual propaganda system applied to dress.","era":"c.1977–1984, Essex","mood":"Starkly political, visually propagandist","visual":"All black military surplus. Crass symbol stencilled on clothing. Black-and-white palette only. No colour — colour is frivolous. Military boots. The aesthetic of someone who lives in a commune and means it.","garments":["Black military surplus clothing","Stencilled Crass symbol","Combat boots","Black-and-white only palette","DIY patches and stencils"],"habitat":"Anarcho-punk communities, Crass fan culture, peace punk heritage.","context":"Crass created a complete visual system — logo, typography, packaging, dress — that was as coherent as any corporate identity but entirely DIY. They lived communally at Dial House in Essex and practiced what they preached.","rarity":"Rare","see_also":["Anarcho-Punk","DIY Punk","UK Punk Aesthetic"],"colors":["#1A1A1A Crass Black","#FAF8F5 Stencil White","#5B5B5B Military Grey","#2C2C2C Surplus"],"media":["The Crasstafari documentary — documentary","There Is No Authority But Yourself (2006) — documentary"]},"Anarcho-Punk":{"summary":"The political punk aesthetic beyond the Sex Pistols — all black, DIY patches, peace symbols, and punk as lived political practice.","era":"c.1978–present","mood":"Politically committed, DIY-principled","visual":"All black with patches and stencils. Anti-war symbols. DIY everything. Combat boots. The aesthetic signals genuine political commitment — not fashion punk but lifestyle anarchism.","garments":["Black clothing with DIY patches","Combat boots","Peace and anarchy symbols","Stencilled slogans","Black hoodie or jacket"],"habitat":"Anarchist communities, squatter culture, political punk scenes.","context":"Anarcho-punk distinguishes itself from fashion punk by being lived — the aesthetic is inseparable from the politics. Crass, Conflict, and Subhumans defined its visual vocabulary.","rarity":"Niche","see_also":["Crass Aesthetic","DIY Punk","Activist Dress"],"colors":["#1A1A1A Anarchy Black","#FAF8F5 Patch White","#8B0000 Circle-A Red","#5B5B5B Military"],"media":["Punk: Attitude (2005) — documentary"]},"DIY Punk":{"summary":"The handmade, self-produced, zine-culture aesthetic of punk — everything made by hand, distributed by hand, worn by hand.","era":"c.1977–present","mood":"Handmade-principled, self-produced","visual":"Hand-sewn patches. Hand-stencilled T-shirts. Zines as accessories. Hand-altered thrift store finds. The aesthetic of someone who refuses to buy anything they could make themselves.","garments":["Hand-sewn patch jacket","Hand-stencilled T-shirt","Altered thrift finds","DIY screen-printed fabric","Zine in pocket"],"habitat":"DIY punk shows, zine fairs, independent record stores, house show circuits.","context":"DIY punk is punk's purest ideology applied to fashion — if you can make it yourself, you should. The battle jacket (denim vest covered in hand-sewn patches) is its canonical garment.","rarity":"Niche","see_also":["Anarcho-Punk","Crass Aesthetic","Hardcore Punk"],"colors":["#1A1A1A DIY Black","#FAF8F5 Stencil White","#8B0000 Ink Red","#4A7C59 Thrift Green"],"media":["American Hardcore (2006) — documentary"]},"Joy Division Aesthetic":{"summary":"The grey, sparse, Factory Records look of Joy Division — the most minimal and devastating aesthetic in post-punk history.","era":"c.1978–1980, Manchester","mood":"Devastatingly minimal, grey-industrial","visual":"Grey. Simple dark shirt or polo. Overcoat. The most minimal possible presentation. Peter Saville's Factory Records sleeve design as the visual counterpart — Closer's marble tomb, Unknown Pleasures' radio pulsar. Ian Curtis's dance as visual aesthetic.","garments":["Simple dark shirt","Grey overcoat","Dark trousers","Plain shoes","Minimal presentation"],"habitat":"Factory Records heritage, post-punk communities, Manchester music history.","context":"Joy Division's aesthetic was the negation of punk's visual noise — total reduction to essentials. Peter Saville's sleeve designs for Factory Records created a visual language as influential as the music. Ian Curtis died at 23.","rarity":"Rare","see_also":["Post-Punk Fashion","Gang of Four Aesthetic","Goth Early"],"colors":["#5B5B5B Joy Division Grey","#1A1A1A Factory Black","#FAF8F5 Pulsar White","#2C2C2C Overcoat"],"media":["Control (2007) — film","Joy Division (2007) — documentary","24 Hour Party People (2002) — film"]},"Gang of Four Aesthetic":{"summary":"The angular, anti-fashion dress of Gang of Four — Marxist politics expressed through deliberately functional clothing.","era":"c.1977–1984, Leeds","mood":"Angularly political, anti-decorative","visual":"Functional clothing without decoration. Button-down shirts. Straight trousers. The deliberate rejection of punk's visual codes as much as rock's. The aesthetic of four Leeds University students who read Situationist theory.","garments":["Plain button-down shirt","Straight dark trousers","Simple shoes","No decoration or embellishment","Functional anti-fashion"],"habitat":"Post-punk history, Marxist music communities.","context":"Gang of Four dressed with deliberate anti-style — their Marxist politics extended to rejecting the commodity spectacle of punk fashion. The plainness was the statement.","rarity":"Extinct","see_also":["Joy Division Aesthetic","Post-Punk Fashion","No Wave Aesthetic"],"colors":["#5B5B5B Function Grey","#1A1A1A Anti-Fashion Black","#FAF8F5 Shirt White","#8B7355 Utility Brown"],"media":["Punk: Attitude (2005) — documentary"]},"No Wave Aesthetic":{"summary":"The abrasive, art-school-extreme dress of late 1970s downtown Manhattan — noise, film, and fashion as confrontation beyond punk.","era":"c.1977–1982, Lower Manhattan","mood":"Aggressively arty, beyond-punk confrontational","visual":"Art school extreme. Black as default. Deliberate visual aggression. The aesthetic of people making noise music, Super-8 films, and performance art simultaneously. Lydia Lunch, James Chance, DNA.","garments":["All black","Art-school extreme styling","Deliberately confrontational presentation","Minimal or maximal — never moderate","Thrift and performance mixed"],"habitat":"No Wave music history, downtown Manhattan art history.","context":"No Wave rejected punk as too conventional and rock as too commercial. Brian Eno's 1978 compilation 'No New York' documented its four key bands. The aesthetic was deliberately unpleasant.","rarity":"Extinct","see_also":["New York Punk","Downtown 1980 Aesthetic","New York No Wave"],"colors":["#1A1A1A No Wave Black","#FAF8F5 Film White","#5B5B5B Noise Grey","#8B0000 Aggression Red"],"media":["No Wave documentary — documentary","Downtown 81 (2000) — film"]},"New York No Wave":{"summary":"The visual culture of the broader No Wave scene — Basquiat, Debbie Harry, and the intersection of punk, art, and fashion on the Lower East Side.","era":"c.1978–1983, Lower East Side","mood":"Cross-disciplinary downtown, art-punk fused","visual":"Basquiat's crown and paint-splattered suit. Debbie Harry in No Wave context. The mix of visual art and music that made every participant a multimedia artist. Thrift store finds elevated by context.","garments":["Paint-splattered clothing","Thrift store found pieces","Mixed art and music references","Deliberately cross-disciplinary styling","Simple black with art accents"],"habitat":"Lower East Side art history, Basquiat cultural contexts.","context":"New York No Wave dissolved the boundaries between music, visual art, film, and fashion. Everyone did everything — Basquiat painted and played music, Debbie Harry sang and acted. The aesthetic was cross-disciplinary by definition.","rarity":"Extinct","see_also":["No Wave Aesthetic","Downtown 1980 Aesthetic","CBGB Aesthetic"],"colors":["#1A1A1A Downtown Black","#D4AF37 Crown Gold","#8B0000 Paint Red","#FAF8F5 Canvas White"],"media":["Downtown 81 (2000) — film","Basquiat (1996) — film"]},"Downtown 1980 Aesthetic":{"summary":"The specific look of early 1980s downtown Manhattan — where punk met art met fashion met clubbing in the East Village and Tribeca.","era":"c.1980–1985, Lower Manhattan","mood":"Post-punk downtown, club-art fused","visual":"Black as base. Oversized vintage coat. Art jewellery. The look of someone who goes from gallery to club to studio without changing. Basquiat in an Armani suit with bare feet as the defining image.","garments":["Oversized vintage coat","All-black base layer","Art jewellery","Mixed high and low fashion","Gallery-to-club transition pieces"],"habitat":"1980s New York art history, East Village heritage, club culture.","context":"Downtown 1980 was the moment when underground culture and mainstream fashion first intersected in New York — before the East Village was gentrified, before SoHo was expensive.","rarity":"Extinct","see_also":["New York No Wave","Club Kid Aesthetic","Basquiat"],"colors":["#1A1A1A Downtown Black","#D4AF37 Art Gold","#5B5B5B Loft Grey","#8B0000 East Village Red"],"media":["Basquiat (1996) — film","Downtown 81 (2000) — film","Wild Style (1983) — film"]},"Hardcore Punk":{"summary":"The stripped-down, uniform aggression of American hardcore punk — shaved heads, band tees, cargo shorts, and the mosh pit as fashion context.","era":"c.1980–present","mood":"Aggressively stripped-down, mosh-pit functional","visual":"Shaved head or very short hair. Band T-shirt. Cargo shorts or jeans. Sneakers or boots. No embellishment. The aesthetic is functional for the mosh pit — nothing that can be grabbed or torn off.","garments":["Hardcore band T-shirt","Cargo shorts or jeans","Shaved or close-cropped hair","Sneakers or boots","Simple dark hoodie"],"habitat":"Hardcore shows, DIY venues, straight edge communities.","context":"Hardcore stripped punk back to essentials — faster, shorter, more aggressive, and dressed accordingly. Black Flag, Minor Threat, and Bad Brains defined distinct regional variations.","rarity":"Niche","see_also":["DIY Punk","Straight Edge Aesthetic","DC Hardcore"],"colors":["#1A1A1A Hardcore Black","#FAF8F5 Band Tee White","#5B5B5B Cargo Grey","#8B0000 Aggression Red"],"media":["American Hardcore (2006) — documentary","The Decline of Western Civilization (1981) — documentary"]},"Straight Edge Aesthetic":{"summary":"The X-marked, clean-living hardcore punk aesthetic — no drugs, no alcohol, no smoking, marked by the iconic X on the hand.","era":"c.1981–present","mood":"Militantly clean, X-marked","visual":"Black X marked on back of each hand (origin: under-18 marker at DC clubs). Band T-shirt. Athletic build (many straight edge adherents are physically active). Clean, un-intoxicated presentation.","garments":["X marked on hands","Straight edge band T-shirt","Simple dark clothing","Athletic build aesthetic","No intoxication markers"],"habitat":"Straight edge communities, hardcore punk shows, vegan and activist spaces.","context":"Minor Threat's Ian MacKaye coined 'straight edge' in 1981. The X marker was originally used at DC clubs to identify underage attendees who couldn't drink. Straight edge reclaimed it as a badge of abstinence.","rarity":"Niche","see_also":["Hardcore Punk","DC Hardcore","DIY Punk"],"colors":["#1A1A1A Edge Black","#FAF8F5 X White","#5B5B5B Clean Grey","#4A7C59 Vegan Green"],"media":["Edge: Perspectives on Drug Free Culture (2009) — documentary"]},"DC Hardcore":{"summary":"The specific look of Washington DC's hardcore punk scene — Dischord Records, cargo shorts, and the most ideological punk scene in America.","era":"c.1980–1990, Washington DC","mood":"Ideologically rigorous, Dischord-principled","visual":"Plain clothes without fashion signifiers. Cargo shorts. Simple T-shirt. Sneakers. The deliberate absence of style as style. Ian MacKaye's Dischord Records released everything at fair price with no merchandising excess.","garments":["Plain T-shirt","Cargo shorts","Simple sneakers","No brand signifiers","Functional basic clothing"],"habitat":"Dischord Records heritage, DC punk history, political punk communities.","context":"DC Hardcore was the most ideologically coherent punk scene — Dischord's pricing policy, the straight edge ethic, and Fugazi's refusal to sell merchandise above cost created a complete alternative economic aesthetic.","rarity":"Rare","see_also":["Straight Edge Aesthetic","Hardcore Punk","DIY Punk"],"colors":["#1A1A1A DC Black","#FAF8F5 White Tee","#5B5B5B Plain Grey","#8B7355 Cargo Tan"],"media":["Salad Days: A Decade of Punk in Washington DC (2014) — documentary"]},"Oi Aesthetic":{"summary":"The working-class street punk look of Oi! music — Doc Martens, braces, and the deliberately proletarian punk rejection of art-school pretension.","era":"c.1979–1985, Britain","mood":"Working-class defiant, street-level","visual":"Doc Martens boots. Braces (suspenders) over T-shirt. Shaved or very short hair. Ben Sherman or Fred Perry. Flight jacket or Harrington. The look of someone who works Monday and gigs Friday.","garments":["Doc Martens boots","Braces over T-shirt","Shaved or short hair","Fred Perry or Ben Sherman","Flight jacket"],"habitat":"Oi! punk communities, working-class punk heritage.","context":"Oi! was explicitly working-class punk — it rejected both art-school punk and mainstream commercialisation. Its aesthetic overlapped with skinhead, creating ongoing confusion and controversy about political associations.","rarity":"Rare","see_also":["Skinhead","Street Punk","UK Punk Aesthetic"],"colors":["#1A1A1A Boot Black","#8B0000 Braces Red","#FAF8F5 Fred Perry White","#4A7C59 Flight Jacket Green"],"media":["This Is England (2006) — film"]},"Sham 69 Aesthetic":{"summary":"The terrace-punk crossover look of Sham 69 — football casual meets punk, Hersham Boys pride, and the most working-class band in punk.","era":"c.1977–1980, Hersham/London","mood":"Terrace-punk, working-class proud","visual":"Football casual meets punk. Boots and braces. Short hair. Band T-shirt. The look of someone who went to the match and the gig in the same clothes.","garments":["Boots and braces","Short-cropped hair","Simple punk T-shirt","Denim jacket","Football terrace casual elements"],"habitat":"Oi! heritage, working-class punk history.","context":"Sham 69 bridged football terrace culture and punk in a way that was both genuine and problematic — their gigs attracted National Front supporters that the band actively opposed.","rarity":"Extinct","see_also":["Oi Aesthetic","UK Punk Aesthetic","Terrace Fashion"],"colors":["#1A1A1A Black","#8B0000 Red","#FAF8F5 White","#1B4F72 Denim Blue"],"media":["This Is England (2006) — film"]},"Street Punk":{"summary":"The studded, mohawked, crust-adjacent punk aesthetic — the most visually extreme form of punk, living on the street or looking like it.","era":"c.1980–present","mood":"Visually extreme, street-living","visual":"Tall coloured mohawk. Studded leather jacket with extensive metalwork. Painted-back denim jacket. Tartan trousers or bondage pants. Tall boots with many buckles. The most visually recognisable form of punk.","garments":["Tall coloured mohawk","Studded leather jacket","Tartan bondage trousers","Tall buckled boots","Painted denim jacket"],"habitat":"Street punk communities, crust punk scenes, punk festivals.","context":"Street Punk is punk's most visible form — the mohawk and studded jacket are now the universal visual shorthand for 'punk.' The irony is that the most recognisable version is also the most commodified.","rarity":"Niche","see_also":["UK Punk Aesthetic","Oi Aesthetic","DIY Punk"],"colors":["#1A1A1A Stud Black","#8B0000 Mohawk Red","#C0C0C0 Metal Silver","#4A7C59 Tartan Green"],"media":["Punk: Attitude (2005) — documentary","SLC Punk! (1998) — film"]},"Skinhead":{"summary":"The working-class, Jamaican-music-influenced subculture of late 1960s Britain — Doc Martens, braces, and a look whose political meaning has been permanently contested.","era":"c.1967–present, Britain","mood":"Working-class sharp, politically contested","visual":"Shaved or very short head. Doc Martens boots (colour and lacing patterns signalled subgroups). Braces. Ben Sherman button-down. Sta-Prest trousers. Harrington jacket or Crombie overcoat.","garments":["Doc Martens boots","Braces over shirt","Ben Sherman button-down","Sta-Prest trousers","Harrington or Crombie coat"],"habitat":"SHARP (Skinheads Against Racial Prejudice) communities, reggae and ska scenes. SENSITIVE: The original skinhead movement was multiracial, rooted in Jamaican music culture. Far-right groups later appropriated the aesthetic, creating permanent political ambiguity.","context":"Original 1969 skinheads were working-class multicultural youth influenced by Jamaican rude boy culture. The National Front's appropriation of the look in the late 1970s permanently politicised it. SHARP exists specifically to reclaim the original anti-racist meaning.","rarity":"Niche","see_also":["Oi Aesthetic","Mod Aesthetic","Casuals Aesthetic"],"colors":["#1A1A1A Boot Black","#8B0000 Braces Red","#FAF8F5 Ben Sherman White","#5B3A29 Crombie Brown"],"media":["This Is England (2006) — film","Romper Stomper (1992) — film","American History X (1998) — film"]},"Riot Grrrl":{"summary":"The feminist punk movement and its DIY dress — zine culture, marker-on-skin activism, and the reclamation of girlhood as political act.","era":"c.1991–1997, Pacific Northwest","mood":"Fiercely feminist, DIY-activist","visual":"Baby doll dresses. Combat boots. Marker writing on arms reclaiming slurs. Barrettes and glitter mixed with punk aggression. Zines as fashion accessories. The deliberate mixing of femme and punk codes.","garments":["Baby doll dress","Combat boots","Marker-written skin","Band T-shirt","Barrettes with punk elements"],"habitat":"Feminist punk communities, zine culture, Olympia and Portland music scenes.","context":"Riot Grrrl was a political movement that used fashion as activism — writing 'SLUT' on your arm in marker was both reclamation and confrontation. Kathleen Hanna, Tobi Vail, and Allison Wolfe were its architects.","rarity":"Rare","see_also":["Bikini Kill Aesthetic","Kinderwhore","DIY Punk"],"colors":["#FF6B6B Riot Pink","#1A1A1A Punk Black","#FAF8F5 Zine White","#8B0000 Marker Red"],"media":["The Punk Singer (2013) — documentary","Don't Need You (2006) — documentary"]},"Bikini Kill Aesthetic":{"summary":"The specific Kathleen Hanna look — crop top with marker slogans, mini skirt, combat boots, and the most confrontational feminist presence in punk history.","era":"c.1990–1997, Olympia/DC","mood":"Confrontationally feminist, physically present","visual":"Crop top with hand-written slogans. Mini skirt or shorts. Combat boots. Marker writing on stomach or arms. Hair in messy ponytail or braids. The look of someone who will get in your face and not back down.","garments":["Slogan crop top","Mini skirt","Combat boots","Marker-written skin","Messy hair"],"habitat":"Riot Grrrl communities, feminist punk heritage.","context":"Kathleen Hanna's stage presence was as physical as any hardcore frontman — she dressed to confront, not to perform. The crop top with hand-written slogans became Riot Grrrl's most replicated image.","rarity":"Rare","see_also":["Riot Grrrl","Sleater-Kinney Aesthetic","Kinderwhore"],"colors":["#FF6B6B Bikini Kill Pink","#1A1A1A Black","#FAF8F5 White","#8B0000 Marker Red"],"media":["The Punk Singer (2013) — documentary"]},"Sleater-Kinney Aesthetic":{"summary":"The slightly more polished, guitar-forward feminist punk look — Carrie Brownstein's vintage-mix and Corin Tucker's powerful physicality.","era":"c.1994–present, Portland","mood":"Guitar-forward feminist, vintage-sharp","visual":"Vintage-mix styling with punk edge. Good jeans and boots. Slightly more polished than pure Riot Grrrl. The aesthetic evolved with the band — from DIY punk to Portlandia's knowing irony and back.","garments":["Vintage-mix top","Good jeans","Boots","Simple layering","Guitar-ready practicality"],"habitat":"Portland music scene, feminist rock communities.","context":"Sleater-Kinney evolved the Riot Grrrl aesthetic into something more sonically sophisticated and visually polished. Carrie Brownstein's later work on Portlandia gave her aesthetic a knowing, ironic dimension.","rarity":"Niche","see_also":["Riot Grrrl","Bikini Kill Aesthetic","Indie Rock Aesthetic"],"colors":["#8B0000 Guitar Red","#1A1A1A Punk Black","#8B7355 Vintage Brown","#FAF8F5 White"],"media":["Portlandia (TV series) — TV"]},"Kinderwhore":{"summary":"The deliberately provocative baby-doll-dress-over-combat-boots look — innocence and aggression combined as feminist statement.","era":"c.1991–1996","mood":"Provocatively innocent, aggression-in-lace","visual":"Baby doll or vintage dress in floral or lace. Smeared lipstick and raccoon eye makeup. Combat boots or Mary Janes. Torn tights. The deliberate juxtaposition of girlish innocence with punk aggression.","garments":["Baby doll or vintage dress","Smeared red lipstick","Raccoon eye makeup","Combat boots","Torn tights or fishnets"],"habitat":"Riot Grrrl-adjacent communities, 1990s alternative rock culture.","context":"Kinderwhore was a feminist fashion strategy — performing exaggerated femininity and childishness to confront male gaze assumptions. Courtney Love was its most visible practitioner.","rarity":"Rare","see_also":["Courtney Love Aesthetic","Riot Grrrl","Grunge Girl"],"colors":["#F5C6CB Baby Pink","#8B0000 Smeared Red","#1A1A1A Combat Black","#FAF8F5 Lace White"],"media":["Hole: Live Through This (1994) — music"]},"Courtney Love Aesthetic":{"summary":"The specific destroyed glamour of Courtney Love — smeared lipstick, torn vintage silk, tiaras in unwashed hair, and beauty as battleground.","era":"c.1991–present","mood":"Destructively glamorous, beauty-as-combat","visual":"Vintage slip or silk dress, deliberately torn. Smeared bright red lipstick. Raccoon eyeliner. Tiara or headband in messy bleached hair. The deliberate destruction of femininity as feminist statement.","garments":["Torn vintage silk dress","Smeared bright lipstick","Tiara in messy hair","Baby doll elements","Platform or combat boots"],"habitat":"Grunge and Riot Grrrl-adjacent culture, alternative rock history.","context":"Courtney Love's aesthetic was a deliberate confrontation — she took the prettiest possible garments and destroyed them. The smeared lipstick and torn vintage silk became one of the 1990s' most influential personal styles.","rarity":"Niche","see_also":["Kinderwhore","Grunge Girl","Riot Grrrl"],"colors":["#8B0000 Smeared Red","#F5C6CB Torn Pink","#1A1A1A Grunge Black","#D4AF37 Tiara Gold"],"media":["Hole: Live Through This (1994) — music","Kurt & Courtney (1998) — documentary"]},"Pop Punk Aesthetic":{"summary":"The accessible, skate-influenced, colourful punk of the late 1990s–2000s — Dickies shorts, band tees, Vans, and punk made radio-friendly.","era":"c.1994–present","mood":"Accessibly rebellious, skate-punk fun","visual":"Dickies or cargo shorts. Band T-shirt. Vans or Converse. Studded belt. Skate-influenced accessories. Hair spiked or dyed with cheap drugstore colour. The look of someone whose rebellion is fun rather than dangerous.","garments":["Dickies shorts","Band T-shirt","Vans sneakers","Studded belt","Spiked or dyed hair"],"habitat":"Warped Tour communities, pop punk revival shows, skate parks.","context":"Pop Punk made punk accessible to suburban teenagers — Blink-182, Green Day, and Sum 41 dressed in a way that was rebellious enough to feel transgressive but safe enough for MTV.","rarity":"Common","see_also":["Blink-182 Aesthetic","Green Day Aesthetic","Skater Aesthetic"],"colors":["#1A1A1A Punk Black","#FF6B6B Pop Pink","#8B7355 Dickies Tan","#FAF8F5 Band Tee White"],"media":["American Pie (1999) — film"]},"Blink-182 Aesthetic":{"summary":"The specific casual SoCal punk look of Blink-182 — boardshorts, no shirt, toilet humour, and punk as beach party.","era":"c.1997–2005; reunion 2022–present","mood":"SoCal casual, irreverently fun","visual":"Boardshorts or Dickies. Often shirtless. Vans. Trucker hats. Tattoos (Travis Barker as tattoo icon). Casual SoCal beach-punk crossover.","garments":["Boardshorts or Dickies","Band or plain T-shirt","Vans shoes","Trucker hat","Visible tattoos"],"habitat":"SoCal punk culture, Warped Tour nostalgia, pop punk revival shows.","context":"Blink-182 made punk a beach sport. Travis Barker's extensive tattoo coverage became as influential as the music — he is one of the most tattooed celebrities in popular culture.","rarity":"Common","see_also":["Pop Punk Aesthetic","Green Day Aesthetic","Skater Aesthetic"],"colors":["#1B4F72 SoCal Blue","#FAF8F5 White Tee","#1A1A1A Tattoo Black","#8B7355 Sand Tan"],"media":["Blink-182 music videos — music video"]},"Green Day Aesthetic":{"summary":"The eyeliner-and-skinny-tie punk of Green Day — evolving from Berkeley pop punk to American Idiot's politicised punk opera.","era":"c.1990–present","mood":"Evolving punk, eyeliner-coded","visual":"Early: simple T-shirt and jeans punk. American Idiot era: eyeliner, skinny red tie, black suit jacket, political imagery. The aesthetic evolved from casual Berkeley punk to theatrical political punk.","garments":["Skinny black tie","Black suit jacket","Eyeliner","Band or slogan T-shirt","Converse sneakers"],"habitat":"Pop punk communities, Green Day fan culture, political punk contexts.","context":"Green Day's aesthetic evolution mirrors punk's journey from subculture to mainstream — Billie Joe Armstrong's eyeliner and skinny tie during the American Idiot era created a distinct visual language for politicised pop punk.","rarity":"Common","see_also":["Pop Punk Aesthetic","Blink-182 Aesthetic","Emo Aesthetic"],"colors":["#1A1A1A Punk Black","#8B0000 American Idiot Red","#FAF8F5 White Shirt","#4A7C59 Green Day Green"],"media":["American Idiot (musical) — theatre","Bullet in a Bible (2005) — concert film"]},"Pop Punk Revival":{"summary":"The 2020s return of pop punk aesthetics — Machine Gun Kelly, Olivia Rodrigo, and a new generation discovering studded belts and eyeliner.","era":"c.2020–present","mood":"Nostalgically rebellious, TikTok-mediated","visual":"Updated pop punk: studded belts, band tees (vintage or reproduction), coloured hair, platform boots. Mixed with contemporary elements — more gender-fluid, more colourful, more social-media aware than the original.","garments":["Studded belt","Vintage or repro band tee","Platform boots","Coloured or streaked hair","Plaid or tartan elements"],"habitat":"TikTok, pop punk revival concerts, Warped Tour nostalgia events.","context":"The pop punk revival was driven by TikTok nostalgia and artists like Machine Gun Kelly, Olivia Rodrigo, and Willow Smith. It reads the original through a 2020s lens — more diverse and gender-inclusive.","rarity":"Common","see_also":["Pop Punk Aesthetic","Olivia Rodrigo Aesthetic","Emo Revival"],"colors":["#1A1A1A Punk Black","#FF6B6B Revival Pink","#C185A0 Dyed Hair","#D4AF37 Stud Gold"],"media":["Olivia Rodrigo: GUTS (2023) — music"]},"Olivia Rodrigo Aesthetic":{"summary":"The Y2K-meets-pop-punk look of Olivia Rodrigo — butterfly clips, vintage band tees, and heartbreak as a generation's fashion mood board.","era":"c.2021–present","mood":"Heartbreak-coded, Y2K-punk fusion","visual":"Vintage or vintage-inspired band tees. Plaid mini skirt. Platform boots or Mary Janes. Butterfly clips. Smudged eyeliner. The look bridges Y2K nostalgia and pop punk revival with a Gen Z sensibility.","garments":["Vintage band T-shirt","Plaid mini skirt","Platform Mary Janes","Butterfly clips","Smudged eyeliner"],"habitat":"TikTok, Gen Z fashion communities, GUTS tour audiences.","context":"Olivia Rodrigo became the face of the pop punk revival for Gen Z — her aesthetic mixes Y2K nostalgia with 2000s pop punk and 1990s grunge in a way that feels both referential and original.","rarity":"Common","see_also":["Pop Punk Revival","Y2K","Emo Revival"],"colors":["#C185A0 Rodrigo Purple","#FF6B6B Heartbreak Pink","#1A1A1A Punk Black","#FAF8F5 White"],"media":["Olivia Rodrigo: driving home 2 u (2022) — documentary","GUTS World Tour (2024) — concert"]},"Proto-Goth Aesthetic":{"summary":"The dark, literary pre-Goth look of the late 1970s — before the subculture had a name, when Siouxsie, Bauhaus, and The Cure were inventing darkness.","era":"c.1978–1982, Britain","mood":"Pre-named darkness, post-punk-to-Goth transitional","visual":"All black with occasional deep purple or burgundy. Backcombed or crimped hair. Dramatic eye makeup — Egyptian or spider-web inspired. Fishnets. Pointed boots. The look before it had rules.","garments":["All-black outfit","Backcombed dramatic hair","Egyptian-inspired eye makeup","Pointed ankle boots","Fishnet stockings"],"habitat":"Early Goth history, post-punk-to-Goth transition, Batcave club precursors.","context":"Proto-Goth existed before the word 'Goth' was applied to the subculture. Siouxsie Sioux, Peter Murphy, and Robert Smith were independently developing a dark aesthetic from post-punk's grey into something more theatrical.","rarity":"Extinct","see_also":["Trad Goth","Batcave Aesthetic","Post-Punk Fashion"],"colors":["#1A1A1A Pre-Goth Black","#5B5B5B Post-Punk Grey","#4B0082 Deep Purple","#C0C0C0 Silver"],"media":["The Hunger (1983) — film","Near Dark (1987) — film"]},"Trad Goth":{"summary":"The codified, original Goth subculture look — Siouxsie-inspired makeup, all black, pointed boots, and the purist form of Gothic dress.","era":"c.1982–present","mood":"Purist dark, subculturally codified","visual":"All black. Backcombed or teased hair in elaborate forms. Siouxsie-inspired spider-web or Egyptian eye makeup. Pointed winklepicker boots. Fishnet. Velvet. Lace. Silver jewellery with ankh or bat motifs.","garments":["All-black clothing with velvet or lace","Pointed winklepicker boots","Elaborate dark eye makeup","Fishnet stockings or gloves","Silver ankh or bat jewellery"],"habitat":"Goth clubs, Goth festivals (Wave-Gotik-Treffen, Whitby Goth Weekend), purist Goth communities.","context":"Trad Goth is the purist form — adherents maintain the original 1980s aesthetic without incorporating later developments like cyber or pastel goth. The Batcave club and Siouxsie are its founding references.","rarity":"Niche","see_also":["Batcave Aesthetic","Siouxsie Aesthetic","Romantic Goth"],"colors":["#1A1A1A Goth Black","#4B0082 Deep Purple","#C0C0C0 Silver","#8B0000 Blood Red"],"media":["The Crow (1994) — film","Bram Stoker's Dracula (1992) — film"]},"Batcave Aesthetic":{"summary":"The specific look of London's Batcave club (1982–85) — the birthplace of Goth as a named subculture, where the dress code was darkness and originality.","era":"c.1982–1985, London","mood":"Club-born, theatrically dark","visual":"Maximum theatrical darkness. Each person competing for the most elaborate dark look. Backcombed hair reaching extraordinary heights. White and black face makeup. Theatrical costume elements. The Batcave was the Blitz club's dark twin.","garments":["Extreme backcombed hair","White face with black eye makeup","Theatrical dark costume","Fishnet everything","Pointed boots with extreme height"],"habitat":"Batcave club legacy, early Goth history, Goth purist communities.","context":"The Batcave at 69 Dean Street, Soho, ran from 1982–85 and gave Goth its first dedicated space. Specimen, Alien Sex Fiend, and early Siouxsie performances defined its visual vocabulary.","rarity":"Extinct","see_also":["Trad Goth","Proto-Goth Aesthetic","Siouxsie Aesthetic"],"colors":["#1A1A1A Batcave Black","#FAF8F5 Face White","#4B0082 Purple","#8B0000 Crimson"],"media":["Goth: A History (2004) — documentary"]},"Siouxsie Aesthetic":{"summary":"The specific makeup and styling of Siouxsie Sioux — the spider-web eye, the Egyptian liner, and the most imitated face in Goth history.","era":"c.1978–present","mood":"Iconically dark, Egyptian-geometric","visual":"Extreme geometric black eye makeup extending past the eye in Egyptian or spider-web patterns. Backcombed jet-black hair in dramatic volume. Pale face. Dark lips. PVC or leather. The single most imitated look in Goth.","garments":["Extreme geometric eye makeup","Backcombed jet-black hair","PVC or leather bodice","Fishnet arms or legs","Silver tribal jewellery"],"habitat":"Goth communities worldwide, Siouxsie and the Banshees fan culture.","context":"Siouxsie Sioux's makeup was her signature — constantly evolving but always geometrically precise. She drew from Weimar cabaret, ancient Egypt, and punk simultaneously. Every Goth makeup tutorial begins with Siouxsie.","rarity":"Niche","see_also":["Trad Goth","Batcave Aesthetic","Deathrock"],"colors":["#1A1A1A Siouxsie Black","#FAF8F5 Face White","#8B0000 Lip Red","#C0C0C0 Silver"],"media":["Nocturne (Siouxsie, 1983) — concert film"]},"Deathrock":{"summary":"The American West Coast variant of Goth — horror punk meets dark post-punk, with a rawer, more DIY sensibility than British Goth.","era":"c.1979–present, Los Angeles","mood":"Horror-raw, DIY-dark","visual":"Teased and spiked hair (less polished than British Goth). Horror-influenced makeup — skull, zombie, or cadaverous. Ripped fishnets. DIY aesthetic. Black with horror-film colour accents. Shredded fabric.","garments":["Teased spiked hair","Horror makeup — skull or cadaverous","Ripped and shredded black fabric","DIY patches and studs","Combat or pointed boots"],"habitat":"Deathrock communities, LA dark punk scene, horror-punk crossover.","context":"Deathrock emerged parallel to British Goth but from a different source — LA punk rather than British post-punk. Christian Death, 45 Grave, and TSOL were its architects. It retains a rawer, more punk-adjacent energy.","rarity":"Niche","see_also":["Christian Death Aesthetic","Horror Punk Goth","Trad Goth"],"colors":["#1A1A1A Deathrock Black","#FAF8F5 Corpse White","#4A7C59 Zombie Green","#8B0000 Horror Red"],"media":["Return of the Living Dead (1985) — film"]},"Christian Death Aesthetic":{"summary":"The specific sacrilegious, glamourously dark look of Christian Death — crosses inverted, veils worn, and blasphemy as visual vocabulary.","era":"c.1979–present, Los Angeles","mood":"Sacrilegiously beautiful, deathrock-glamorous","visual":"Rozz Williams's signature: pale face, dark eyes, crucifix imagery inverted, veil and funeral elements. More glamorous than standard deathrock. Religious iconography subverted. Black lace and funeral wear repurposed.","garments":["Inverted crucifix","Black lace veil","Funeral-wear elements","Pale dramatic face","Religious iconography subverted"],"habitat":"Deathrock communities, Christian Death fan culture.","context":"Christian Death's Rozz Williams made sacrilege beautiful — inverted religious imagery worn as fashion was simultaneously provocative and aesthetically considered. His suicide in 1998 added genuine tragedy to the mythology.","rarity":"Rare","see_also":["Deathrock","Romantic Goth","Gothic Aristocrat"],"colors":["#1A1A1A Funeral Black","#FAF8F5 Corpse White","#8B0000 Blood","#D4AF37 Crucifix Gold"],"media":["Only Theatre of Pain (Christian Death, 1982) — music"]},"Horror Punk Goth":{"summary":"The Misfits-adjacent, B-movie-horror-meets-punk aesthetic — skull imagery, devilock hair, and monster movies made wearable.","era":"c.1977–present","mood":"B-movie horrific, punk-campy","visual":"Misfits devilock hairstyle (long front, shaved sides). Skull and horror imagery. Black and white palette. B-movie monster references. Crimson Skull logo. The intersection of 1950s horror camp and 1970s punk aggression.","garments":["Misfits devilock hair","Skull-motif T-shirt or jacket","Black leather jacket","Horror-print patches","Combat boots"],"habitat":"Horror punk communities, Misfits fan culture, psychobilly crossover.","context":"Horror Punk connects 1950s B-movie aesthetics with punk energy. The Misfits' Crimson Ghost logo is one of the most recognisable images in punk — worn by people who may never have heard the music.","rarity":"Niche","see_also":["Deathrock","Street Punk","Psychobilly"],"colors":["#1A1A1A Horror Black","#FAF8F5 Skull White","#8B0000 Crimson Ghost Red","#4A7C59 Monster Green"],"media":["Night of the Living Dead (1968) — film"]},"Gothic Aristocrat":{"summary":"The refined, historical, aristocratic expression of Goth — velvet frock coats, lace cravats, and the vampire as fashion ideal.","era":"c.1990s–present","mood":"Vampirically refined, aristocratically dark","visual":"Velvet frock coat or tailcoat. Lace cravat or jabot. Silver-topped cane. Top hat or wide-brimmed hat. The aesthetic of the Vampire Lestat — aristocratic, elegant, eternally nocturnal.","garments":["Velvet frock coat","Lace cravat or jabot","Silver-topped walking cane","Top hat or wide-brimmed hat","Brocade waistcoat"],"habitat":"Goth balls and formal events, vampire-themed gatherings, Goth festivals.","context":"Gothic Aristocrat draws on Victorian and 18th-century dress reimagined through a Goth lens. Anne Rice's vampire novels and the Vampire: The Masquerade RPG codified the aesthetic.","rarity":"Niche","see_also":["Romantic Goth","Victorian Gothic","Vampire Aristocrat Aesthetic"],"colors":["#1A1A1A Velvet Black","#4B0082 Aristocrat Purple","#D4AF37 Silver-Gold","#8B0000 Blood Crimson"],"media":["Interview with the Vampire (1994) — film","Bram Stoker's Dracula (1992) — film"]},"Cemetery Aesthetic":{"summary":"The specific visual culture of cemetery-as-fashion-space — headstone photography, mourning dress, and the graveyard as Goth pilgrimage site.","era":"c.1990s–present","mood":"Sepulchrally romantic, graveyard-dwelling","visual":"All black mourning-adjacent dress. Long flowing skirts or coats. Victorian mourning references. The cemetery as backdrop and spiritual space. Crosses and memento mori jewellery.","garments":["Long flowing black dress or coat","Mourning-adjacent jewellery","Cross or ankh pendant","Victorian-inspired hat or veil","Heavy leather boots"],"habitat":"Famous cemeteries (Père Lachaise, Highgate, Abney Park), Goth photography, taphophile communities.","context":"Cemetery Goth is both aesthetic and practice — many Goths genuinely find peace in cemeteries. Père Lachaise (Jim Morrison, Oscar Wilde) and Highgate (Karl Marx) are pilgrimage sites.","rarity":"Niche","see_also":["Victorian Gothic","Mourning Dress Aesthetic","Gothic Aristocrat"],"colors":["#1A1A1A Headstone Black","#5B5B5B Granite Grey","#4A7C59 Moss Green","#8B7355 Weathered Stone"],"media":["The Crow (1994) — film"]},"Romantic Goth":{"summary":"The softer, more literary, lace-and-velvet expression of Goth — Byron and Shelley reimagined in the darkwave era.","era":"c.1990s–present","mood":"Darkly poetic, lace-draped","visual":"Lace and velvet in deep black, burgundy, or midnight blue. Flowing sleeves. Corset over dress. Long skirts. Silver or cameo jewellery. The aesthetic of someone who reads Keats by candlelight.","garments":["Lace-trimmed velvet dress","Corset over blouse","Long flowing skirt","Cameo brooch","Silver ring set"],"habitat":"Gothic romantic literature communities, Goth festivals, darkwave events.","context":"Romantic Goth draws more from literature than music — Byron, Shelley, the Brontës, and Poe as style references. It is softer and more feminine than Trad Goth and emphasises beauty over confrontation.","rarity":"Niche","see_also":["Gothic Aristocrat","Trad Goth","Victorian Gothic"],"colors":["#1A1A1A Romantic Black","#4B0082 Midnight Purple","#8B0000 Burgundy","#C0C0C0 Lace Silver"],"media":["Wuthering Heights (various) — film","Crimson Peak (2015) — film"]},"Gothic Lolita":{"summary":"The Japanese crossover of Gothic fashion and Lolita subculture — dark frills, crosses, and doll-like precision in black and white.","era":"c.1990s–present, Japan/global","mood":"Darkly doll-like, precisely frilled","visual":"Black and white colour scheme. Knee-length bell-shaped skirt with petticoat. Lace headdress. Cross or rosary accessories. Platform Mary Janes. The aesthetic combines Japanese Lolita construction with Gothic visual codes.","garments":["Black bell-shaped Lolita skirt","White lace blouse with black trim","Lace headdress","Cross or rosary pendant","Platform Mary Janes"],"habitat":"Japanese fashion communities, Harajuku, global Lolita communities, Goth-Lolita crossover events.","context":"Gothic Lolita emerged from the intersection of Japanese Lolita fashion and Western Goth subculture. Mana (of Malice Mizer) founded the brand Moi-même-Moitié which codified the aesthetic. It has a rigorous community with strict dress codes.","rarity":"Niche","see_also":["Japanese Lolita","Sweet Lolita","Trad Goth"],"colors":["#1A1A1A Gothic Black","#FAF8F5 Lolita White","#8B0000 Cross Red","#C0C0C0 Lace Silver"],"media":["Kamikaze Girls (2004) — film","Gothic & Lolita Bible (magazine) — print"]},"Dark Romantic":{"summary":"The contemporary intersection of dark aesthetics and romantic femininity — Gothic elements softened with florals, wine tones, and candlelit warmth.","era":"c.2015–present","mood":"Darkly warm, romantically Gothic","visual":"Dark floral prints. Wine and burgundy with black. Velvet textures. Lace details. Candlelit atmosphere. The aesthetic of someone who reads dark romance novels and decorates their home in dried flowers and vintage candelabras.","garments":["Dark floral midi dress","Velvet blazer or cardigan","Lace-trimmed blouse","Wine or burgundy accessories","Vintage-style jewellery"],"habitat":"Dark romance book communities, Pinterest, Gothic-adjacent fashion.","context":"Dark Romantic softens Gothic severity with warmth — it draws on the same literary sources but interprets them through a contemporary romantic lens. It is the aesthetic of the dark romance publishing boom.","rarity":"Common","see_also":["Romantic Goth","Victorian Gothic","Whimsigoth"],"colors":["#4B0082 Wine Purple","#8B0000 Burgundy","#1A1A1A Gothic Black","#D4AF37 Candlelight Gold"],"media":["Crimson Peak (2015) — film","Rebecca (2020) — film"]},"Cyber Goth":{"summary":"The neon-and-PVC fusion of Goth and rave culture — goggles, platform boots, UV-reactive fabric, and dancing under blacklight.","era":"c.1999–2015","mood":"Neon-dark, rave-Gothic fused","visual":"Neon-coloured synthetic hair extensions (falls) in green, pink, or blue. Cybernetic goggles. PVC clothing. Platform boots with extreme height. UV-reactive elements. Industrial-style gas masks as accessories.","garments":["Neon synthetic hair falls","Cybernetic goggles","PVC outfit","Extreme platform boots","UV-reactive accessories"],"habitat":"Cyber Goth communities, industrial club nights, Goth festivals.","context":"Cyber Goth fused Goth's darkness with rave culture's neon optimism — the goggles and platforms were as much rave accessory as Gothic statement. The subculture peaked in the early 2000s and is now largely nostalgic.","rarity":"Rare","see_also":["Industrial Goth","Neon Goth","Trad Goth"],"colors":["#1A1A1A Cyber Black","#39FF14 Neon Green","#FF6B6B Neon Pink","#00BFFF Electric Blue"],"media":["The Matrix (1999) — film"]},"Industrial Goth":{"summary":"The hard, machine-aesthetic fusion of Goth and industrial music — steel, leather, and the body as machine.","era":"c.1988–present","mood":"Machine-hard, leather-industrial","visual":"Black leather and metal hardware. Industrial-style harnesses and straps. Steel-toed boots. The body presented as machine-like — hard, angular, functional. Music by Nine Inch Nails, Ministry, KMFDM.","garments":["Black leather pants or skirt","Industrial harness or straps","Steel-toed boots","Metal hardware accessories","PVC or rubber elements"],"habitat":"Industrial club nights, EBM events, Goth-industrial crossover scenes.","context":"Industrial Goth draws from industrial music's machine aesthetics and S&M-influenced leather culture. It is harder and more aggressive than Romantic Goth — the body as weapon rather than poem.","rarity":"Niche","see_also":["EBM Fashion","Cyber Goth","Trad Goth"],"colors":["#1A1A1A Industrial Black","#C0C0C0 Steel Silver","#5B5B5B Machine Grey","#8B0000 Blood Red"],"media":["Nine Inch Nails: Closer (video, 1994) — music video"]},"Neon Goth":{"summary":"The colour-accented variant of Goth — all black but with vivid neon pops in hair, accessories, or makeup.","era":"c.2000s–present","mood":"Dark with neon accents, Goth-club friendly","visual":"Primarily black with vivid neon accents — hair streaks, UV necklaces, neon eyeliner, coloured contacts. Platform boots. The neon is always an accent, never the dominant colour.","garments":["All-black base outfit","Neon-coloured hair streak","UV-reactive jewellery","Neon eyeliner","Platform boots"],"habitat":"Goth clubs with blacklight, alternative nightlife, festival Goth.","context":"Neon Goth bridges the gap between traditional Goth purism and Cyber Goth's full neon — it maintains the black foundation while adding selective colour as accent.","rarity":"Niche","see_also":["Cyber Goth","Trad Goth","Industrial Goth"],"colors":["#1A1A1A Goth Black","#39FF14 Neon Green","#FF6B6B Neon Pink","#00BFFF Electric Blue"],"media":["The Matrix Resurrections (2021) — film"]},"Mallgoth":{"summary":"The accessible, Hot Topic-adjacent Goth look of the early 2000s — band tees, chain wallets, and Goth as mall-available commodity.","era":"c.1998–2008","mood":"Accessibly dark, Hot Topic-adjacent","visual":"Hot Topic purchased Goth-adjacent clothing. Band T-shirts (The Cure, Marilyn Manson, Evanescence). Chain wallet. Tripp pants. Wristbands. Black nail polish. The entry-level Goth experience.","garments":["Band T-shirt","Tripp NYC pants","Chain wallet","Studded wristbands","Black nail polish"],"habitat":"Shopping malls, Hot Topic stores, early 2000s alternative youth culture.","context":"Mallgoth is viewed with both derision (by Goth purists) and affection (by those who grew up in it). Hot Topic made dark fashion accessible to suburban teenagers who had no local Goth scene.","rarity":"Niche","see_also":["Hot Topic Aesthetic","Nu Goth","Trad Goth"],"colors":["#1A1A1A Mall Black","#8B0000 Band Red","#C0C0C0 Chain Silver","#5B5B5B Grey"],"media":["South Park Goth kids episodes — TV"]},"Hot Topic Aesthetic":{"summary":"The commercial, licensed, alternative-culture retail aesthetic — where Goth, punk, and fandom converge in a mall store.","era":"c.1989–present","mood":"Commercially alternative, fandom-adjacent","visual":"Licensed band merchandise. Pop culture references on clothing. Enamel pins. Studded accessories. The aesthetic of alternative culture as retail category.","garments":["Licensed band T-shirt","Pop culture reference tee","Enamel pin collection","Studded belt","Alternative-branded accessories"],"habitat":"Hot Topic stores, mall alternative culture.","context":"Hot Topic democratised alternative fashion — making it available to teenagers in every American mall. The tension between accessibility and authenticity is permanent.","rarity":"Common","see_also":["Mallgoth","Pop Punk Aesthetic","Fandom Core"],"colors":["#1A1A1A Store Black","#8B0000 Red","#FF6B6B Pink","#D4AF37 Pin Gold"],"media":["Wayne's World (1992) — film"]},"Nu Goth":{"summary":"The 2010s Tumblr-era evolution of Goth — minimalist black, occult symbols, and the Alexander McQueen-influenced fashion Goth.","era":"c.2011–present","mood":"Fashion-Goth minimalist, Tumblr-occult","visual":"Minimalist all-black. Alexander McQueen or Rick Owens aesthetic influence. Occult symbols as jewellery — crescent moons, pentagrams, crystals. Wide-brimmed hat. The fashion-world Goth rather than the subculture Goth.","garments":["All-black minimalist outfit","Wide-brimmed black hat","Occult symbol jewellery","Platform or chunky boots","Structured black coat"],"habitat":"Fashion-forward Goth communities, Tumblr aesthetic culture, designer Goth.","context":"Nu Goth emerged from Tumblr aesthetics and high fashion simultaneously — Alexander McQueen's dark romanticism and Rick Owens's monochrome architecture filtered through internet culture.","rarity":"Common","see_also":["Witch House Aesthetic","Tumblr Goth","Health Goth"],"colors":["#1A1A1A Nu Black","#2C2C2C Fashion Dark","#C0C0C0 Silver Moon","#5B5B5B Occult Grey"],"media":["American Horror Story (TV series) — TV"]},"Witch House Aesthetic":{"summary":"The murky, occult electronic music aesthetic — inverted crosses, pitched-down vocals, and darkness as internet subgenre.","era":"c.2009–2014","mood":"Murkily occult, internet-born dark","visual":"Inverted crosses and triangles. Grainy, low-resolution photography. Dark, desaturated colour palette. Occult symbols. The aesthetic of music too dark for dance floors, consumed through headphones and Tumblr.","garments":["Occult symbol accessories","Dark oversized clothing","All-black with grey","Low-key dark presentation","No bright colours"],"habitat":"Witch House music communities, Tumblr dark aesthetic.","context":"Witch House was a brief but influential micro-genre combining chopped-and-screwed hip-hop with occult imagery and Goth sensibility. Its aesthetic influenced Nu Goth and Dark Internet aesthetics.","rarity":"Rare","see_also":["Nu Goth","Tumblr Goth","Dark & Eerie Internet"],"colors":["#1A1A1A Witch Black","#2C2C2C Murky Dark","#5B5B5B Fog Grey","#4B0082 Occult Purple"],"media":["Crystal Castles discography — music"]},"Tumblr Goth":{"summary":"The Tumblr-era soft dark aesthetic — occult imagery meets millennial internet culture, darkness filtered through digital curation.","era":"c.2011–2018","mood":"Digitally curated darkness, soft-occult","visual":"All black with soft textures. Chokers. Platform boots. Dark lipstick. Occult-themed jewellery. The Tumblr dashboard as curatorial space for dark aesthetics. Less aggressive than Trad Goth, more fashion-aware.","garments":["Black velvet choker","Platform boots","Dark matte lipstick","All-black soft-textured outfit","Moon or crystal pendant"],"habitat":"Tumblr archives, internet Goth communities, Instagram dark aesthetic.","context":"Tumblr Goth was Goth filtered through the internet's curation logic — mood boards of dark images, black clothing as lifestyle aesthetic, occult imagery as decoration rather than belief system.","rarity":"Common","see_also":["Nu Goth","Pastel Goth","Soft Goth"],"colors":["#1A1A1A Tumblr Black","#2C2C2C Velvet Dark","#C0C0C0 Moon Silver","#4B0082 Purple"],"media":["American Horror Story (TV series) — TV"]},"Pastel Goth":{"summary":"The fusion of Goth and pastel kawaii — lavender hair, crosses on pink, and the deliberate collision of cute and creepy.","era":"c.2012–present","mood":"Cute-creepy, pastel-dark fused","visual":"Pastel purple, pink, or blue hair. Black clothing mixed with pastel accents. Inverted crosses in pastel colours. Platform shoes. Creepy-cute accessories — eyeball rings, skeleton in pink. The aesthetic of deliberately corrupted innocence.","garments":["Pastel-coloured hair","Black outfit with pastel accents","Pastel inverted cross accessory","Creepy-cute jewellery","Platform shoes"],"habitat":"Tumblr, Instagram, kawaii-Goth crossover communities.","context":"Pastel Goth was born on Tumblr around 2012 as a deliberate collision of two aesthetics — Japanese kawaii cute and Western Goth darkness. The result was one of the internet's most successful aesthetic fusions.","rarity":"Common","see_also":["Soft Goth","Nu Goth","Fairy Kei"],"colors":["#C185A0 Pastel Purple","#F5C6CB Pastel Pink","#1A1A1A Goth Black","#B0C4DE Pastel Blue"],"media":["Melanie Martinez: Cry Baby (2015) — music"]},"Soft Goth":{"summary":"The toned-down, wearable-everyday version of Goth — dark but not dramatic, accessible but still identifiably dark.","era":"c.2015–present","mood":"Wearably dark, everyday Goth","visual":"All black but without extreme makeup or accessories. Simple dark clothing in good quality. Dark nails. Simple silver jewellery. The Goth who works in an office but makes it clear where their heart lies.","garments":["Simple all-black outfit","Dark nail polish","Silver minimal jewellery","Quality black basics","Subtle dark lipstick"],"habitat":"Everyday alternative fashion, office-compatible dark dressing.","context":"Soft Goth acknowledges that most people can't wear full Trad Goth to work — it provides an aesthetically coherent, wearable-everyday dark palette that still signals subcultural identity.","rarity":"Common","see_also":["Nu Goth","Tumblr Goth","Trad Goth"],"colors":["#1A1A1A Soft Black","#2C2C2C Dark Grey","#C0C0C0 Silver","#5B5B5B Charcoal"],"media":["Wednesday (TV series, 2022) — TV"]},"Nu Goth Pastel":{"summary":"The specific intersection of Nu Goth minimalism and pastel accents — fashion-forward darkness with calculated colour intrusions.","era":"c.2013–present","mood":"Fashion-minimalist with pastel shock","visual":"Primarily black minimalist Nu Goth base. Single pastel accent — hair, bag, shoes, or jewellery. The pastel is always unexpected and deliberate against the black field.","garments":["All-black Nu Goth base","Single pastel accent piece","Structured black coat","Platform boots","Minimal occult jewellery"],"habitat":"Fashion Goth communities, Tumblr-to-Instagram aesthetic migration.","context":"Nu Goth Pastel is a precise fusion — it takes Nu Goth's fashion-forward minimalism and adds a single pastel element for visual tension. Less cute than Pastel Goth, more calculated.","rarity":"Niche","see_also":["Nu Goth","Pastel Goth","Soft Goth"],"colors":["#1A1A1A Nu Black","#C185A0 Pastel Accent","#F5C6CB Soft Pink","#B0C4DE Ice Blue"],"media":["Wednesday (TV series, 2022) — TV"]},"Health Goth":{"summary":"The intersection of Goth aesthetics and athletic wear — black Nike, gym culture in darkness, and the body as dark machine.","era":"c.2013–2018","mood":"Athletically dark, gym-Gothic","visual":"All-black sportswear: black Nike, black leggings, black running shoes. The gym-going Goth. Dark athletic aesthetic. Mesh panels. Compression fabric. The body maintained as a dark machine.","garments":["All-black sportswear","Black running shoes","Black mesh panel top","Dark compression leggings","Minimal dark accessories"],"habitat":"Dark athletic communities, Health Goth tumblr, internet micro-aesthetic.","context":"Health Goth was coined in 2013 as a Tumblr aesthetic and quickly became both a genuine fashion category and a meme. Nike and Adidas both released all-black collections that fed the trend.","rarity":"Niche","see_also":["Athletic Goth","Dark Sportswear","Nu Goth"],"colors":["#1A1A1A Sport Black","#2C2C2C Mesh Dark","#5B5B5B Athletic Grey","#C0C0C0 Swoosh Silver"],"media":["Health Goth Tumblr (2013) — social media"]},"Athletic Goth":{"summary":"The broader intersection of athletic wear and dark aesthetics — beyond Health Goth's meme origin into a genuine daily-wear aesthetic.","era":"c.2015–present","mood":"Functionally dark, sport-Gothic everyday","visual":"Technical athletic fabrics in all black. Trainers with dark outfits. The practical fusion of active lifestyle and Gothic sensibility for people who genuinely work out and genuinely love black.","garments":["Black technical leggings","Dark athletic top","Black trainers","Dark water bottle","Minimal dark accessories"],"habitat":"Alternative fitness communities, dark running clubs.","context":"Athletic Goth moved beyond Health Goth's Tumblr origins into genuine daily wear — the practical need for activewear that doesn't compromise a dark aesthetic.","rarity":"Niche","see_also":["Health Goth","Dark Sportswear","Gorpcore"],"colors":["#1A1A1A Athletic Black","#2C2C2C Dark Tech","#5B5B5B Breathable Grey","#1B4F72 Midnight Blue"],"media":["Nike all-black collections — fashion"]},"Dark Sportswear":{"summary":"All-black sportswear as aesthetic category — the normalisation of head-to-toe black athletic wear as a daily uniform.","era":"c.2015–present","mood":"Monochromatically athletic, dark-normative","visual":"All-black leggings, trainers, hoodie, cap. The uniform of the modern dark wardrobe meets athleisure. Functional and monochrome. Works for gym, errands, and casual socialising.","garments":["Black leggings","Black hoodie","Black trainers","Black cap","Black crossbody bag"],"habitat":"Urban everyday wear, dark athleisure communities.","context":"Dark Sportswear is the mainstreaming of Health Goth — all-black athletic wear became so common it ceased to be subcultural and became simply a wardrobe category.","rarity":"Common","see_also":["Health Goth","Athletic Goth","Athleisure"],"colors":["#1A1A1A Black","#2C2C2C Charcoal","#5B5B5B Dark Grey","#1B4F72 Navy"],"media":["Nike, Adidas, Lululemon all-black ranges — fashion"]},"Mallgoth Revival":{"summary":"The nostalgic 2020s return of early 2000s Mallgoth — Tripp pants, chain wallets, and Hot Topic childhood repackaged as TikTok nostalgia.","era":"c.2020–present","mood":"Nostalgically dark, 2000s-coded","visual":"Tripp pants or wide-leg chains. Band tees (vintage or reproduction). Studded accessories. The specific early 2000s dark aesthetic revived through TikTok nostalgia by people who were children during its original run.","garments":["Tripp NYC pants revival","Vintage band T-shirt","Chain accessories","Studded belt","Platform boots"],"habitat":"TikTok, Depop vintage, alternative Y2K nostalgia.","context":"Mallgoth Revival is part of the broader Y2K nostalgia cycle — Gen Z discovering early 2000s alternative fashion with the same reverence millennials had for 1970s punk.","rarity":"Common","see_also":["Mallgoth","Hot Topic Aesthetic","Y2K Revival"],"colors":["#1A1A1A Revival Black","#8B0000 Red","#C0C0C0 Chain Silver","#5B5B5B Grey"],"media":["TikTok #mallgoth — social media"]},"Nostalgic Goth":{"summary":"The retrospective, archive-minded Goth who dresses from a specific past era of the subculture — 1980s purist, 1990s romantic, or early 2000s cyber.","era":"c.2015–present","mood":"Archive-minded, era-specific","visual":"Depends on chosen era — could be 1982 Batcave precise or 1996 Romantic Goth. The key is deliberate historical specificity within Goth's own timeline.","garments":["Era-specific Goth clothing","Period-correct accessories","Vintage or reproduction pieces","Subcultural historical knowledge worn","Era-appropriate boots"],"habitat":"Goth purist communities, subculture history appreciation.","context":"Goth has existed long enough to have its own nostalgia cycles — each generation of Goths looks back to a previous golden age. The subculture is now multi-generational.","rarity":"Niche","see_also":["Trad Goth","Mallgoth Revival","Batcave Aesthetic"],"colors":["#1A1A1A Archive Black","#4B0082 Era Purple","#C0C0C0 Silver","#8B0000 Blood Red"],"media":["Goth documentary series — documentary"]},"McBling Goth":{"summary":"The fusion of mid-2000s McBling bling culture and Goth — dark glamour, rhinestones on black, and Goth-goes-maximalist.","era":"c.2003–2008; revival 2020s","mood":"Darkly blinged, Goth-maximalist","visual":"All-black base with rhinestone, crystal, or metallic embellishment. Dark glamour — the intersection of 2000s bling culture with Gothic darkness. Studded and crystal-encrusted accessories.","garments":["Black outfit with rhinestone embellishment","Crystal-encrusted accessories","Dark metallic fabric","Platform boots with metal hardware","Statement dark jewellery"],"habitat":"Y2K-Goth crossover communities, dark maximalist fashion.","context":"McBling Goth is a retroactive label for the 2000s moment when Goth embraced bling culture's maximalism — rhinestones and crystals in all-black created a distinct sub-aesthetic.","rarity":"Niche","see_also":["Mallgoth","Nu Goth","Cyber Goth"],"colors":["#1A1A1A Bling Black","#D4AF37 Crystal Gold","#C0C0C0 Rhinestone Silver","#8B0000 Dark Red"],"media":["Evanescence: Fallen (2003) — music"]},"Goth Punk":{"summary":"The direct crossover of Goth and punk — studs meet velvet, mohawks meet eyeliner, darkness and aggression combined.","era":"c.1982–present","mood":"Aggressively dark, punk-Gothic hybrid","visual":"Punk elements (studs, spikes, leather) combined with Goth elements (black velvet, dramatic makeup, pointed boots). The hybrid is more aggressive than Romantic Goth and more theatrical than street punk.","garments":["Studded leather jacket","Dark dramatic makeup","Pointed or platform boots","Spiked accessories","Black velvet with punk hardware"],"habitat":"Goth-punk crossover scenes, Deathrock-adjacent communities.","context":"Goth Punk sits at the intersection of punk's aggression and Goth's theatricality — it maintains punk's DIY energy while embracing Goth's darker aesthetic vocabulary.","rarity":"Niche","see_also":["Deathrock","Trad Goth","Street Punk"],"colors":["#1A1A1A Punk-Goth Black","#C0C0C0 Stud Silver","#8B0000 Punk Red","#4B0082 Goth Purple"],"media":["The Crow (1994) — film"]},"Gothic Hardcore":{"summary":"The intersection of hardcore punk energy and Gothic aesthetics — dark, aggressive, and physically intense.","era":"c.1990s–present","mood":"Physically intense, dark-hardcore","visual":"Hardcore's stripped-down functionality in all black. Band tees from dark hardcore bands. Simple aggressive dark presentation. More mosh pit than dance floor.","garments":["Dark hardcore band T-shirt","Black jeans or shorts","Combat boots","Simple dark hoodie","Minimal presentation"],"habitat":"Dark hardcore shows, crossover punk-Goth scenes.","context":"Gothic Hardcore bridges the energy of hardcore punk with Goth's visual darkness — bands like Tragedy and His Hero Is Gone operate in this crossover space.","rarity":"Rare","see_also":["Goth Punk","Hardcore Punk","Deathrock"],"colors":["#1A1A1A Hardcore Black","#5B5B5B Dark Grey","#8B0000 Blood","#2C2C2C Charcoal"],"media":["American Hardcore (2006) — documentary"]},"Ethereal Goth":{"summary":"The dreamy, gossamer, Cocteau Twins-influenced expression of Goth — floating fabrics, pale ethereal beauty, and darkness as transcendence.","era":"c.1985–present","mood":"Dreamily transcendent, gossamer-dark","visual":"Pale floating fabrics in black, white, or deep blue. Hair long and flowing. Minimal or ethereal makeup — pale skin, soft dark eyes. The look of someone who has stepped out of a Pre-Raphaelite painting into a darkwave club.","garments":["Flowing pale or dark fabric dress","Long loose hair","Ethereal soft makeup","Simple silver jewellery","Soft leather or flat shoes"],"habitat":"Ethereal wave communities, Cocteau Twins fan culture, dreampop events.","context":"Ethereal Goth is Goth's most beautiful variant — influenced by the Cocteau Twins, Dead Can Dance, and the ethereal wave subgenre. It emphasises transcendence and beauty over confrontation.","rarity":"Niche","see_also":["Angelic Goth","Romantic Goth","Ethereal Feminine"],"colors":["#B0C4DE Ethereal Blue","#FAF8F5 Ghost White","#1A1A1A Dark Base","#C185A0 Mist Rose"],"media":["Cocteau Twins: Heaven or Las Vegas (1990) — music"]},"Angelic Goth":{"summary":"The celestial, white-and-silver variant of Goth — wings, halos, and angelic imagery in Gothic context.","era":"c.2010s–present","mood":"Celestially dark, angelic-Gothic","visual":"White or silver instead of black. Wing-shaped accessories. Halo references. Pearl and crystal rather than silver and iron. The aesthetic of the fallen angel or the Gothic divine.","garments":["White or silver gown or dress","Wing-shaped accessories","Pearl and crystal jewellery","Ethereal pale makeup","Platform or heeled boots in white"],"habitat":"Gothic angel communities, Celestial Goth aesthetics, alternative angel fashion.","context":"Angelic Goth inverts Goth's typical palette — using white and silver where black would be expected. It draws on fallen angel mythology and the overlap between the sacred and the dark.","rarity":"Niche","see_also":["Ethereal Goth","Angelcore","Dark Angel Aesthetic"],"colors":["#FAF8F5 Angelic White","#C0C0C0 Silver","#B0C4DE Ice Blue","#D4AF37 Halo Gold"],"media":["Constantine (2005) — film"]},"Whimsigoth":{"summary":"The TikTok-era fusion of whimsy and Goth — Stevie Nicks meets celestial witch, dark but not aggressive, mystical but wearable.","era":"c.2022–present","mood":"Mystically whimsical, dark-but-gentle","visual":"Flowing dark fabrics — velvet, lace, chiffon in black and deep jewel tones. Celestial motifs — moons, stars. Crystal jewellery. Wide-brimmed hat. Layered necklaces. The aesthetic of a friendly neighbourhood witch.","garments":["Flowing velvet or lace dress","Wide-brimmed hat","Celestial-motif jewellery","Crystal pendant","Layered dark necklaces"],"habitat":"TikTok, Instagram, witchy aesthetic communities.","context":"Whimsigoth was named on TikTok in 2022 as a softer, more accessible alternative to traditional Goth — it combines Stevie Nicks witchy femininity with celestial imagery and modern dark fashion.","rarity":"Common","see_also":["Stevie Nicks Aesthetic","Witchcore","Dark Romantic"],"colors":["#1A1A1A Dark Base","#4B0082 Jewel Purple","#D4AF37 Celestial Gold","#C0C0C0 Moon Silver"],"media":["Practical Magic (1998) — film","TikTok #whimsigoth — social media"]},"Gothic Princess":{"summary":"The dark fairytale princess aesthetic — tiaras on black velvet, Gothic gowns with princess silhouettes, and darkness as royal birthright.","era":"c.2015–present","mood":"Darkly regal, princess-Gothic","visual":"Gothic ball gown or princess-line dress in black. Tiara or crown. Dark gemstone jewellery. Lace gloves. The aesthetic of the dark fairy tale — Sleeping Beauty's Maleficent rather than Aurora.","garments":["Black gothic ball gown","Dark tiara or crown","Black lace gloves","Dark gemstone jewellery","Platform or heeled boots"],"habitat":"Gothic princess communities, dark fairy tale fashion, Goth prom aesthetics.","context":"Gothic Princess merges the princess archetype with Gothic darkness — it appeals to those who loved fairy tales but always preferred the villain's wardrobe.","rarity":"Niche","see_also":["Dark Royale Goth","Princesscore","Villaincore"],"colors":["#1A1A1A Royal Black","#4B0082 Crown Purple","#D4AF37 Tiara Gold","#8B0000 Gemstone Red"],"media":["Maleficent (2014) — film","Sleeping Beauty (1959) — animation"]},"Dark Royale Goth":{"summary":"The regal, maximalist dark aesthetic — Goth as aristocratic power, velvet thrones, and dark crowns worn without irony.","era":"c.2018–present","mood":"Regally dark, crown-wearing","visual":"Rich velvet in black and deep jewel tones. Ornate gold or silver crown or circlet. Statement jewellery. Structured gowns or tailored dark suits. The aesthetic of dark royalty — power expressed through darkness.","garments":["Rich velvet gown or suit","Ornate crown or circlet","Statement dark jewellery","Structured dark tailoring","Platform or heeled boots"],"habitat":"Dark royalty aesthetic communities, Gothic formal events.","context":"Dark Royale Goth reclaims royalty imagery for Gothic communities — the crown worn without irony, the velvet throne as genuine aesthetic aspiration rather than costume.","rarity":"Niche","see_also":["Gothic Princess","Gothic Aristocrat","Royalcore"],"colors":["#1A1A1A Royale Black","#D4AF37 Crown Gold","#4B0082 Regal Purple","#8B0000 Blood Ruby"],"media":["The Favourite (2018) — film"]},"Visual Kei":{"summary":"The spectacular, gender-bending Japanese rock aesthetic — elaborate hair, dramatic makeup, and the most visually ambitious live music culture in the world.","era":"c.1980s–present, Japan","mood":"Spectacularly gender-fluid, theatrically elaborate","visual":"Elaborate sculpted and coloured hair in gravity-defying forms. Dramatic face makeup. Elaborate costumes mixing Gothic, glam, punk, and fantasy elements. Platform boots. Each band member with a distinct visual identity.","garments":["Gravity-defying coloured hair","Elaborate dramatic face makeup","Mixed Gothic-glam-punk costume","Platform boots","Individually distinct visual identity"],"habitat":"Japanese rock venues, Visual Kei festivals, global J-rock fan communities.","context":"Visual Kei (meaning 'visual style') was pioneered by X Japan in the 1980s. It is one of the world's most elaborate live music visual cultures — each performance is a costume event. It crosses into Gothic Lolita and Harajuku fashion.","rarity":"Niche","see_also":["Gothic Lolita","Harajuku Street","Glam Rock"],"colors":["#1A1A1A Visual Black","#8B0000 Dramatic Red","#D4AF37 Stage Gold","#C185A0 Hair Pink"],"media":["We Are X (2016) — documentary","Malice Mizer performances — music"]},"Throbbing Gristle Aesthetic":{"summary":"The confrontational anti-aesthetic of industrial music's founders — camouflage, military surplus, and the deliberate weaponisation of boredom.","era":"c.1975–1981, London","mood":"Confrontationally anti-aesthetic, militarily surplus","visual":"Military surplus clothing. Camouflage. Plain functional clothing without any concession to fashion. The deliberate visual equivalent of their music — uncomfortable, functional, and aggressively ordinary.","garments":["Military surplus jacket","Camouflage trousers","Plain functional clothing","No concession to fashion","Combat boots"],"habitat":"Industrial music history, ICA and art gallery contexts.","context":"Throbbing Gristle invented industrial music and its anti-aesthetic simultaneously. Genesis P-Orridge later evolved into a radical body modification practice. The early TG look was deliberately ordinary as provocation.","rarity":"Extinct","see_also":["Industrial Aesthetic","EBM Fashion","Post-Punk Fashion"],"colors":["#5B5B5B Military Grey","#4A7C59 Camo Green","#8B7355 Surplus Brown","#1A1A1A Black"],"media":["Industrial Soundtrack for the Urban Decay (2017) — documentary"]},"Industrial Aesthetic":{"summary":"The broader visual culture of industrial music — machine aesthetics, protective clothing, and the factory as fashion reference.","era":"c.1976–present","mood":"Machine-functional, factory-referenced","visual":"Protective clothing references — goggles, gas masks, heavy boots. Black leather and rubber. Metal hardware. The aesthetic draws from factories, power stations, and military installations rather than nightclubs.","garments":["Protective goggles or gas mask","Heavy leather or rubber","Metal hardware accessories","Steel-toed boots","Functional dark workwear"],"habitat":"Industrial music venues, EBM clubs, dark electronic communities.","context":"Industrial aesthetic takes its visual cues from the same sources as its sound — factories, machines, and systems of control. The look is deliberately dehumanising, which is the point.","rarity":"Niche","see_also":["EBM Fashion","Industrial Goth","Throbbing Gristle Aesthetic"],"colors":["#1A1A1A Machine Black","#C0C0C0 Steel","#5B5B5B Industrial Grey","#8B7355 Rust"],"media":["Nine Inch Nails: Broken (1992) — music"]},"Einstürzende Neubauten Aesthetic":{"summary":"The Berlin rubble-punk industrial look — literal building materials as instruments, construction site as stage, and post-war urban decay as fashion.","era":"c.1980–present, Berlin","mood":"Rubble-architectural, urban-decayed","visual":"Construction and demolition references. Hard hats and industrial protection. Plain dark clothing covered in dust. The look of someone who makes music with power tools and jackhammers.","garments":["Construction-referenced clothing","Industrial protection elements","Dust-covered dark basics","Heavy work boots","Plain utilitarian layers"],"habitat":"Berlin industrial music history, Neubauten fan communities.","context":"Einstürzende Neubauten (literally 'collapsing new buildings') dressed from the rubble of Berlin's post-war landscape. Their aesthetic is inseparable from their instruments — shopping trolleys, metal pipes, and concrete.","rarity":"Rare","see_also":["Industrial Aesthetic","Throbbing Gristle Aesthetic","Berlin Techno Fashion"],"colors":["#5B5B5B Concrete Grey","#8B7355 Rubble Brown","#1A1A1A Dust Black","#C0C0C0 Metal"],"media":["Einstürzende Neubauten documentary — documentary"]},"Nine Inch Nails Aesthetic":{"summary":"The Trent Reznor industrial-rock look — sweat-soaked black, broken machines, and controlled destruction as performance aesthetic.","era":"c.1989–present","mood":"Controlled destruction, sweat-black industrial","visual":"All black. Simple T-shirt and trousers destroyed during performance. Sweat-soaked. The look of controlled physical exhaustion. Early: more elaborate (Closer video). Later: stripped to essentials — black shirt, black trousers.","garments":["Black T-shirt","Black trousers","Performance-destroyed clothing","Simple black boots","Minimal presentation"],"habitat":"NIN fan culture, industrial rock communities.","context":"Trent Reznor's aesthetic evolved from the theatrical darkness of the Downward Spiral era to a stripped minimalism. The NIN logo (designed by Gary Talpas) is as recognisable as any fashion brand logo.","rarity":"Niche","see_also":["Industrial Aesthetic","Industrial Goth","Grunge"],"colors":["#1A1A1A NIN Black","#5B5B5B Sweat Grey","#8B0000 Broken Red","#2C2C2C Dark"],"media":["Nine Inch Nails: Closure (1997) — video"]},"EBM Fashion":{"summary":"The Electronic Body Music dress code — black combat boots, black tank top, military-adjacent minimalism, and dancing like a soldier.","era":"c.1981–present, Belgium/Germany","mood":"Militarily minimal, body-rhythmic","visual":"Black tank top or sleeveless shirt. Black combat or military boots. Black trousers — often cargo. Short cropped hair. Physically fit presentation. The aesthetic of someone who treats dancing as military exercise.","garments":["Black tank top","Black combat boots","Black cargo trousers","Short cropped hair","Minimal accessories"],"habitat":"EBM clubs, dark electronic events, European industrial festivals.","context":"EBM (from Belgian bands like Front 242 and Nitzer Ebb) created a distinct visual code — harder and more military than Goth, less theatrical than industrial. The dancing is physical and machine-like.","rarity":"Niche","see_also":["Industrial Aesthetic","Dark Electro Fashion","Industrial Goth"],"colors":["#1A1A1A EBM Black","#5B5B5B Combat Grey","#4A7C59 Military Green","#C0C0C0 Steel"],"media":["Front 242 performances — music"]},"Dark Electro Fashion":{"summary":"The darker, more aggressive variant of EBM dress — gas masks, cyber elements, and the dance floor as dystopian space.","era":"c.1990s–present","mood":"Dystopically aggressive, club-dark","visual":"Gas mask or respirator as accessory. Black with neon accents. Cyber elements — goggles, LED accessories. More aggressive and darker than standard EBM. The dance floor as post-apocalyptic landscape.","garments":["Gas mask or respirator","Black with neon cyber accents","LED accessories","Heavy platform boots","Cyber-industrial goggles"],"habitat":"Dark electro clubs, Cyber Goth-adjacent events, European industrial festivals.","context":"Dark Electro pushed EBM into more extreme visual territory — the gas mask as dance floor accessory, neon as accent against total black, and the club as dystopian simulation.","rarity":"Rare","see_also":["EBM Fashion","Cyber Goth","Industrial Goth"],"colors":["#1A1A1A Dark Black","#39FF14 Neon Green","#C0C0C0 Metal","#5B5B5B Smoke Grey"],"media":["Matrix-era dark electronic events — cultural"]},"Aggrotech Aesthetic":{"summary":"The most aggressive form of dark electronic fashion — extreme industrial-cyber hybrid, all black with harsh neon, and fury as dance style.","era":"c.2000s–present","mood":"Maximum aggression, harsh-neon dark","visual":"Extreme platform boots. Gas mask or half-mask. Black with vivid neon UV-reactive accents. Aggressive stance. The most extreme version of the industrial-dark-electronic fashion spectrum.","garments":["Extreme platform boots","Gas mask or half-mask","UV-reactive neon accents","Black PVC or leather","Industrial harness"],"habitat":"Aggrotech events, extreme dark electronic clubs.","context":"Aggrotech is the most extreme end of the dark electronic spectrum — musically harsh, visually aggressive, and physically intense on the dance floor.","rarity":"Rare","see_also":["Dark Electro Fashion","EBM Fashion","Cyber Goth"],"colors":["#1A1A1A Aggro Black","#39FF14 Harsh Green","#FF6B6B Neon Red","#C0C0C0 Steel"],"media":["Aggrotech festival footage — cultural"]},"Power Electronics Fashion":{"summary":"The extreme noise music's anti-aesthetic — deliberately provocative, militaristic, and designed to make audiences uncomfortable.","era":"c.1980–present","mood":"Deliberately provocative, anti-audience","visual":"Military surplus. Camouflage. Sometimes deliberately provocative imagery. The visual is designed to be as uncomfortable as the sound — ear-splitting noise accompanied by confrontational visuals.","garments":["Military surplus clothing","Camouflage","Deliberately plain presentation","Combat boots","Confrontational imagery"],"habitat":"Noise music communities, extreme underground art. NOTE: Some power electronics artists use deliberately offensive imagery as provocation — this is contested within the community.","context":"Power Electronics fashion follows from Throbbing Gristle's confrontational anti-aesthetic but pushes it further. The community is small and the boundary between confrontation and endorsement is permanently debated.","rarity":"Rare","see_also":["Throbbing Gristle Aesthetic","Industrial Aesthetic","Noise"],"colors":["#5B5B5B Military Grey","#4A7C59 Camo Green","#1A1A1A Black","#8B7355 Surplus"],"media":["Industrial Soundtrack for the Urban Decay (2017) — documentary"]},"Darkwave Aesthetic":{"summary":"The melancholic, synth-driven dark music fashion — softer than industrial, darker than synthpop, and more beautiful than either.","era":"c.1982–present","mood":"Melancholically beautiful, synth-dark","visual":"All black but softer than industrial — velvet, flowing fabrics, romantic rather than aggressive. Dark eyeliner. Long hair for all genders. The aesthetic of someone who listens to Clan of Xymox and reads poetry simultaneously.","garments":["Soft black velvet or flowing fabric","Dark eyeliner","Long flowing hair","Silver jewellery","Pointed or elegant boots"],"habitat":"Darkwave communities, Cold Cave and Drab Majesty fan contexts, Gothic romantic events.","context":"Darkwave sits between Goth and synthpop — musically melodic but dark, visually romantic but not aggressive. It has experienced a significant revival since the mid-2010s with bands like Drab Majesty and Cold Cave.","rarity":"Niche","see_also":["Ethereal Goth","Romantic Goth","Post-Punk Fashion"],"colors":["#1A1A1A Darkwave Black","#4B0082 Synth Purple","#C0C0C0 Silver","#2C2C2C Velvet Dark"],"media":["Darkwave documentary — documentary"]},"Cocteau Twins Aesthetic":{"summary":"The specific ethereal, dreamy look of the Cocteau Twins — Elizabeth Fraser's otherworldly presence and the visual equivalent of shoegaze.","era":"c.1982–1997, Scotland","mood":"Otherworldly, dream-dissolving","visual":"Elizabeth Fraser in flowing, slightly oversized, soft clothing. Long hair. Minimal makeup except for soft eyes. The look of someone who exists slightly outside normal reality. Robin Guthrie in simple dark clothing.","garments":["Flowing soft oversized top","Simple dark clothing","Long natural hair","Minimal soft eye makeup","Simple shoes"],"habitat":"Cocteau Twins fan culture, ethereal wave communities, 4AD label heritage.","context":"The Cocteau Twins' visual presentation was as otherworldly as their music — Elizabeth Fraser's voice and her ethereal presence were inseparable. The 4AD label's sleeve design (by Vaughan Oliver) completed the visual world.","rarity":"Rare","see_also":["Ethereal Goth","Shoegaze Aesthetic","Dream Pop Fashion"],"colors":["#B0C4DE Dream Blue","#C185A0 Ethereal Rose","#FAF8F5 Ghost White","#4B0082 Deep Purple"],"media":["Cocteau Twins: Heaven or Las Vegas (1990) — music"]},"Ethereal Wave Fashion":{"summary":"The visual culture of ethereal wave music — pale flowing fabrics, medieval references, and beauty as the primary Gothic value.","era":"c.1984–present","mood":"Beautifully pale, medievally flowing","visual":"Pale fabrics flowing and layered. Medieval or Pre-Raphaelite references. Long loose hair. Minimal or soft makeup. The emphasis on beauty and transcendence rather than darkness and confrontation.","garments":["Pale flowing layered fabrics","Medieval-referenced styling","Long loose natural hair","Soft ethereal makeup","Simple soft shoes"],"habitat":"Ethereal wave communities, Dead Can Dance fan culture, Goth beautiful wing.","context":"Ethereal Wave fashion represents Goth's most beautiful expression — where the subculture meets Pre-Raphaelite painting and medieval troubadour music. Dead Can Dance and Cocteau Twins are its musical architects.","rarity":"Niche","see_also":["Cocteau Twins Aesthetic","Ethereal Goth","Dead Can Dance Aesthetic"],"colors":["#FAF8F5 Ethereal White","#B0C4DE Pale Blue","#C185A0 Soft Rose","#E8D5B0 Linen"],"media":["Dead Can Dance: Into the Labyrinth (1993) — music"]},"Dead Can Dance Aesthetic":{"summary":"The world-music-meets-medieval darkness of Dead Can Dance — Lisa Gerrard's robes, Brendan Perry's monastic severity, and the ritual as performance.","era":"c.1981–present, Australia/Europe","mood":"Ritually medieval, world-music dark","visual":"Lisa Gerrard in flowing ceremonial robes suggesting Byzantine, Middle Eastern, and medieval European traditions simultaneously. Brendan Perry in monastic dark simplicity. The performance as ritual rather than concert.","garments":["Ceremonial flowing robes","Medieval-world-music fusion garments","Monastic dark simplicity","Ritual jewellery","Simple dark shoes"],"habitat":"Dead Can Dance fan communities, world-music Goth crossover, ritual performance.","context":"Dead Can Dance created a unique aesthetic — drawing on Byzantine, Moorish, Celtic, and Middle Eastern visual traditions simultaneously. Lisa Gerrard's stage presence is genuinely ritualistic rather than theatrical.","rarity":"Rare","see_also":["Ethereal Wave Fashion","Cocteau Twins Aesthetic","Byzantine Empress"],"colors":["#8B0000 Ritual Red","#D4AF37 Byzantine Gold","#1A1A1A Monastic Black","#4B0082 Liturgical Purple"],"media":["Dead Can Dance: Toward the Within (1994) — concert film"]},"Neoclassical Dark":{"summary":"The orchestral-dark aesthetic — dark suits, classical music references, and the intersection of Goth sensibility with classical composition.","era":"c.1990s–present","mood":"Orchestrally dark, classically severe","visual":"Dark formal clothing — suits, long coats, classical concert dress. The aesthetic of someone who attends both Goth festivals and classical concerts. Minimal, severe, and compositionally precise.","garments":["Dark formal suit or long coat","Classical concert-appropriate dark dress","Minimal severe presentation","Quality dark fabrics","Simple elegant shoes"],"habitat":"Neoclassical dark communities, dark ambient events, classical-Goth crossover.","context":"Neoclassical Dark bridges Goth subculture and classical music — artists like Dead Can Dance, Sophia, and Current 93 draw from both traditions. The aesthetic reflects this dual heritage.","rarity":"Rare","see_also":["Dead Can Dance Aesthetic","Gothic Aristocrat","Classical Musician Aesthetic"],"colors":["#1A1A1A Concert Black","#2C2C2C Formal Dark","#D4AF37 Gold","#5B5B5B Score Grey"],"media":["Dead Can Dance: Toward the Within (1994) — concert film"]},"Metalhead Aesthetic":{"summary":"The universal heavy metal uniform — band T-shirt, jeans, long hair, and the battle vest covered in patches as identity document.","era":"c.1970–present","mood":"Loudly loyal, battle-vested","visual":"Band T-shirt (loyalty demonstrated by choice). Blue or black jeans. Long hair for all genders. The battle vest: a denim or leather vest covered in patches from bands seen live. Combat boots or sneakers.","garments":["Band T-shirt","Battle vest with patches","Blue or black jeans","Long hair","Combat boots or sneakers"],"habitat":"Metal concerts, festivals (Wacken, Download, Hellfest), metal communities worldwide.","context":"The metalhead uniform is one of the most consistent in music history — band tee, jeans, long hair has been the standard since the 1970s. The battle vest is an ongoing autobiographical garment documenting live attendance.","rarity":"Common","see_also":["NWOBHM Aesthetic","Black Metal Aesthetic","Glam Metal"],"colors":["#1A1A1A Metal Black","#FAF8F5 Band Tee White","#8B7355 Denim","#C0C0C0 Patch Silver"],"media":["Metal: A Headbanger's Journey (2005) — documentary","This Is Spinal Tap (1984) — film"]},"NWOBHM Aesthetic":{"summary":"The denim-and-leather look of the New Wave of British Heavy Metal — Iron Maiden, Saxon, and the working-class British metal uniform.","era":"c.1979–1984, Britain","mood":"Working-class metal, denim-leather proud","visual":"Denim jacket with patches. Leather jacket. Band T-shirt. Tight jeans. White high-top trainers or boots. Long hair. The working-class British metalhead — from the factory to the gig.","garments":["Denim jacket with patches","Leather jacket","Iron Maiden or Saxon T-shirt","Tight blue jeans","White high-top trainers"],"habitat":"NWOBHM heritage events, Iron Maiden fan communities, British metal history.","context":"NWOBHM was explicitly working-class British — bands from Sheffield, Birmingham, and Newcastle who dressed like their audience. Iron Maiden's Eddie mascot is one of the most recognisable images in rock.","rarity":"Niche","see_also":["Metalhead Aesthetic","Biker Metal","Glam Metal"],"colors":["#1A1A1A Iron Black","#1B4F72 Denim Blue","#8B0000 Eddie Red","#C0C0C0 Metal Silver"],"media":["Metal: A Headbanger's Journey (2005) — documentary"]},"Biker Metal":{"summary":"The leather-and-chains crossover of motorcycle culture and heavy metal — Judas Priest's leather daddy transformation of metal dress.","era":"c.1978–present","mood":"Leather-heavy, motorcycle-coded","visual":"Full black leather — jacket, trousers, boots. Chains. Studs. The aesthetic of the motorcycle gang applied to the metal stage. Rob Halford of Judas Priest codified the look (while simultaneously smuggling gay leather culture into mainstream metal).","garments":["Full black leather jacket","Leather trousers","Chain accessories","Studded belt and cuffs","Heavy leather boots"],"habitat":"Metal communities, motorcycle culture, leather fashion.","context":"Rob Halford brought gay leather bar aesthetics into metal and nobody noticed for decades. His 1978 transformation of Judas Priest's look from denim to full leather permanently changed metal's visual vocabulary.","rarity":"Niche","see_also":["Metalhead Aesthetic","NWOBHM Aesthetic","Leather Daddy Aesthetic"],"colors":["#1A1A1A Leather Black","#C0C0C0 Chain Silver","#8B0000 Metal Red","#5B3A29 Hide Brown"],"media":["Metal: A Headbanger's Journey (2005) — documentary"]},"Glam Metal":{"summary":"The hairspray-and-spandex excess of 1980s Sunset Strip metal — Mötley Crüe, Poison, and more makeup than your girlfriend.","era":"c.1981–1991, Los Angeles","mood":"Excessively glamorous, Sunset Strip hedonistic","visual":"Enormous teased hair requiring industrial hairspray. Full face makeup — eyeliner, lipstick, blush. Spandex. Leather. Leopard print. Bandanas. The deliberate feminisation of masculine rock performance.","garments":["Enormous teased hair","Full face makeup","Spandex trousers","Leopard print anything","Bandana and leather"],"habitat":"Sunset Strip heritage, 1980s metal nostalgia events, hair metal communities.","context":"Glam Metal was simultaneously the most commercially successful and most critically derided form of 1980s rock. Grunge killed it in 1991. Its deliberate gender play was rarely acknowledged at the time.","rarity":"Niche","see_also":["Hair Metal","Glam Rock","Metalhead Aesthetic"],"colors":["#D4AF37 Hairspray Gold","#FF6B6B Neon Pink","#1A1A1A Leather Black","#C185A0 Lipstick"],"media":["The Dirt (2019) — film","Decline of Western Civilization Part II: The Metal Years (1988) — documentary"]},"Hair Metal":{"summary":"The specific big-hair variant of Glam Metal — Bon Jovi, Whitesnake, and the stadium-rock intersection of metal and pop.","era":"c.1983–1991","mood":"Stadium-accessible, big-hair pop-metal","visual":"Big hair — permed, teased, and sprayed. More pop-accessible than extreme Glam Metal. Denim and leather. Band T-shirts. The look was slightly less extreme than Mötley Crüe — accessible enough for arena audiences.","garments":["Big permed and teased hair","Denim jacket","Band T-shirt","Leather trousers or jeans","Bandana"],"habitat":"1980s rock nostalgia, hair metal revival events.","context":"Hair Metal was the commercial peak of 1980s rock — Bon Jovi and Def Leppard sold millions. The hair was the defining feature and its sudden irrelevance when grunge arrived was one of pop culture's most dramatic aesthetic shifts.","rarity":"Niche","see_also":["Glam Metal","Metalhead Aesthetic","Arena Rock Fashion"],"colors":["#D4AF37 Hair Gold","#1B4F72 Denim Blue","#1A1A1A Leather Black","#8B0000 Rock Red"],"media":["Rock of Ages (2012) — film"]},"Black Metal Aesthetic":{"summary":"The corpse-painted, spiked, deliberately anti-commercial extreme metal aesthetic — Norwegian forests, church burnings, and the most controversial look in music history.","era":"c.1984–present, Scandinavia","mood":"Misanthropically extreme, corpse-painted","visual":"Corpse paint — black and white face paint suggesting death. Spiked leather gauntlets and armour. Bullet belts. Band logos deliberately illegible. Forest and winter imagery. The aesthetic of complete rejection of human society.","garments":["Corpse paint face","Spiked leather gauntlets","Bullet belt","Band T-shirt with illegible logo","Black leather and spikes"],"habitat":"Black metal communities, extreme metal festivals. NOTE: Norwegian Black Metal's history includes arson and murder — the aesthetic cannot be separated from this context.","context":"Black Metal's visual aesthetic was deliberately anti-commercial — illegible logos, lo-fi production, and corpse paint rejected metal's mainstream commercialisation. The Norwegian scene's criminal history (church burnings, murder) makes this one of the most contested aesthetics in music.","rarity":"Niche","see_also":["Corpse Paint","Norwegian Black Metal","Death Metal Aesthetic"],"colors":["#1A1A1A Black","#FAF8F5 Corpse White","#C0C0C0 Bullet Silver","#4A7C59 Forest Green"],"media":["Lords of Chaos (2018) — film","Until the Light Takes Us (2008) — documentary"]},"Corpse Paint":{"summary":"The black-and-white face paint of black metal — death made visible, theatrical but deadly serious, and one of music's most recognisable visual codes.","era":"c.1984–present","mood":"Death-visible, theatrically serious","visual":"White face base (suggesting death or corpse pallor). Black around eyes (skull-like hollows). Sometimes black mouth area. Each musician develops a distinctive paint pattern. Applied with varying degrees of care — from precise to deliberately rough.","garments":["White corpse face paint","Black eye and mouth paint","Distinctive personal pattern","Applied over black clothing","Part of complete black metal presentation"],"habitat":"Black metal performances, extreme metal culture.","context":"Corpse paint's origins include KISS, King Diamond, and Celtic Frost, but Norwegian black metal made it specifically ideological — the paint was not theatre, it was identity. Each musician's pattern becomes recognisable.","rarity":"Niche","see_also":["Black Metal Aesthetic","Norwegian Black Metal","Death Metal Aesthetic"],"colors":["#FAF8F5 Death White","#1A1A1A Hollow Black","#5B5B5B Smudge Grey","#8B0000 Blood"],"media":["Lords of Chaos (2018) — film"]},"Norwegian Black Metal":{"summary":"The specific aesthetic of the Norwegian black metal scene — church burnings, Burzum, Mayhem, and the most extreme intersection of music and criminal ideology.","era":"c.1990–1997, Norway","mood":"Extremely misanthropic, historically violent","visual":"Corpse paint in the Norwegian tradition. Forest photography. Snow and ice. Medieval weapon references. Church imagery (burning). The aesthetic is inseparable from actual arson and murder within the scene.","garments":["Norwegian-style corpse paint","Spiked accessories","Forest-and-winter clothing","Medieval weapon-inspired accessories","All-black leather and spikes"],"habitat":"Norwegian black metal heritage. SENSITIVE: This scene's history includes arson of historic churches and the murder of Mayhem's Euronymous by Burzum's Varg Vikernes.","context":"The Norwegian Black Metal scene produced extraordinary music and extraordinary violence. Between 1992–96, multiple historic churches were burned and guitarist Euronymous was murdered. The aesthetic cannot be separated from this history.","rarity":"Rare","see_also":["Black Metal Aesthetic","Corpse Paint","Death Metal Aesthetic"],"colors":["#1A1A1A Norway Black","#FAF8F5 Snow White","#4A7C59 Forest Green","#8B0000 Blood Red"],"media":["Lords of Chaos (2018) — film","Until the Light Takes Us (2008) — documentary"]},"Folk Metal Aesthetic":{"summary":"The medieval-fantasy-meets-metal look — braided hair, drinking horns, and Norse or Celtic imagery applied to heavy metal performance.","era":"c.1990s–present","mood":"Medievally festive, folk-metal celebratory","visual":"Medieval-inspired elements — braided hair, fur trim, leather armour references. Viking or Celtic motifs. Drinking horns as accessories. The intersection of historical reenactment and metal performance.","garments":["Braided hair","Fur-trimmed vest or cloak","Leather armour-style elements","Viking or Celtic motif jewellery","Heavy boots"],"habitat":"Folk metal festivals, medieval metal events, Viking-metal communities.","context":"Folk Metal combines metal's aggression with folk music's celebration — bands like Korpiklaani, Finntroll, and Ensiferum dress in medieval-folk costume for performances, blurring the line between concert and reenactment.","rarity":"Niche","see_also":["Black Metal Aesthetic","Viking Aesthetic","Medieval Knight Dress"],"colors":["#8B7355 Leather Brown","#4A7C59 Forest Green","#D4AF37 Mead Gold","#1A1A1A Metal Black"],"media":["Folk metal festival footage — music"]},"Death Metal Aesthetic":{"summary":"The brutal, un-glamorous, deliberately ugly aesthetic of death metal — gore imagery, illegible logos, and the rejection of all visual pretension.","era":"c.1985–present","mood":"Brutally un-glamorous, gore-referenced","visual":"Band T-shirt with deliberately gruesome artwork. Jeans or cargo shorts. Long hair. No makeup, no theatricality. The deliberate rejection of glam metal's vanity. The music is the point, not the look.","garments":["Death metal band T-shirt","Simple jeans or cargo shorts","Long unkempt hair","Simple sneakers or boots","No theatrical elements"],"habitat":"Death metal shows, extreme metal festivals.","context":"Death Metal's visual aesthetic is anti-aesthetic — a deliberate rejection of Glam Metal's vanity. The band logos are often deliberately illegible, and the album art deliberately gruesome, as tests of commitment.","rarity":"Niche","see_also":["Black Metal Aesthetic","Metalhead Aesthetic","Doom Metal"],"colors":["#1A1A1A Death Black","#8B0000 Gore Red","#5B5B5B Grey","#FAF8F5 Logo White"],"media":["Death by Metal (2016) — documentary"]},"Doom Metal":{"summary":"The slow, heavy, occult-tinged aesthetic of doom metal — Black Sabbath worship, stoner imagery, and the weight of the riff made visible.","era":"c.1970s–present","mood":"Slowly heavy, occult-tinged","visual":"Black Sabbath as origin point. Occult or psychedelic imagery. Long hair. Jeans and band tee as standard. Less extreme than death or black metal visually. The stoner end tends toward tie-dye and 1970s nostalgia.","garments":["Black Sabbath or doom band T-shirt","Jeans","Long hair","Occult or psychedelic accessories","Simple boots"],"habitat":"Doom metal communities, stoner rock scenes, occult rock events.","context":"Doom Metal is the slowest, heaviest form of metal — its visual aesthetic matches the pace. Less theatrical than black metal, less brutal than death metal, more occult than thrash. It is the closest to metal's original Sabbath-worship roots.","rarity":"Niche","see_also":["Metalhead Aesthetic","Death Metal Aesthetic","Occultcore"],"colors":["#1A1A1A Doom Black","#4B0082 Occult Purple","#4A7C59 Stoner Green","#8B7355 Earth Brown"],"media":["Metal: A Headbanger's Journey (2005) — documentary"]},"Funeral Doom":{"summary":"The glacially slow, grief-saturated extreme of doom metal — minimal visual presentation, mourning-adjacent, and the slowest music in existence.","era":"c.1990s–present","mood":"Glacially grieving, mourning-adjacent","visual":"Minimal and mournful. Simple black clothing. Long hair. No stage performance — just slow, heavy, grief. The most minimal visual presentation in extreme metal.","garments":["Simple all-black clothing","Long unkempt hair","Minimal presentation","No theatrical elements","Heavy boots"],"habitat":"Funeral doom communities, extreme underground metal.","context":"Funeral Doom is the extreme of slow and heavy — songs can last 20+ minutes, tempos approach stasis. The visual aesthetic matches: minimal, mournful, and utterly without performance artifice.","rarity":"Rare","see_also":["Doom Metal","Death Metal Aesthetic","Black Metal Aesthetic"],"colors":["#1A1A1A Funeral Black","#5B5B5B Grief Grey","#2C2C2C Mourning","#8B7355 Earth"],"media":["Extreme metal documentary — documentary"]},"Alternative Metal":{"summary":"The 1990s crossover of metal and alternative rock — Tool's art-prog, Faith No More's eclectic energy, and metal made for people who also read books.","era":"c.1989–present","mood":"Intellectually heavy, genre-crossing","visual":"Less uniform than traditional metal. Varied between bands — Tool's austere intellectualism, Faith No More's eclectic maximalism, Deftones' shoegaze-influenced softness. Generally: dark, simple, less committed to metal's traditional codes.","garments":["Simple dark clothing","Band T-shirt from varied genres","Less committed to metal uniform","Jeans or dark trousers","Simple shoes or boots"],"habitat":"Alternative metal communities, Tool fan culture, genre-crossing rock scenes.","context":"Alternative Metal broke metal's visual uniformity — bands dressed from multiple reference points (art, punk, goth, grunge) rather than metal's established codes. The audience followed.","rarity":"Common","see_also":["Metalhead Aesthetic","Grunge","Nu Metal Aesthetic"],"colors":["#1A1A1A Alt Black","#5B5B5B Dark Grey","#1B4F72 Dark Blue","#8B7355 Earthy Brown"],"media":["Tool live performances — music"]},"Grunge Metal":{"summary":"The flannel-and-feedback intersection of grunge and metal — Alice in Chains, Soundgarden, and the Seattle sound's heavier edge.","era":"c.1990–1996, Seattle","mood":"Heavily grunge, flannel-and-feedback","visual":"Standard grunge uniform (flannel, ripped jeans, Doc Martens) but with longer hair and heavier presentation. Alice in Chains and Soundgarden were heavier than Nirvana — their audience dressed slightly more metal-adjacent.","garments":["Flannel shirt","Ripped jeans","Long hair","Band T-shirt","Heavy boots"],"habitat":"Seattle music heritage, grunge-metal crossover communities.","context":"Grunge Metal sits at the intersection of Seattle grunge and heavy metal — bands like Alice in Chains and Soundgarden were heavier than Nirvana but shared the same flannel-and-denim visual vocabulary.","rarity":"Niche","see_also":["Grunge","Alternative Metal","Metalhead Aesthetic"],"colors":["#8B7355 Flannel Brown","#1A1A1A Black","#1B4F72 Denim Blue","#8B0000 Dark Red"],"media":["Singles (1992) — film"]},"Nu Metal Aesthetic":{"summary":"The baggy, aggressive, late-1990s fusion of metal, hip-hop, and industrial — JNCOs, red caps, and angst as fashion category.","era":"c.1996–2004","mood":"Aggressively baggy, angst-coded","visual":"Extremely baggy JNCO jeans or cargo trousers. Red or black backwards cap. Band tee or Adidas tracksuit top. Goatee or facial hair. Dreadlocks for some. The aggressive fusion of metal, hip-hop, and skate aesthetics.","garments":["Extremely baggy JNCO jeans","Backwards red cap","Band or branded T-shirt","Adidas or Puma trainers","Goatee or soul patch"],"habitat":"Nu Metal nostalgia communities, late 1990s alternative culture.","context":"Nu Metal fused metal, hip-hop, and industrial — Korn, Limp Bizkit, Linkin Park, and Slipknot each had distinct visual identities within the broader aesthetic. JNCO jeans were the canonical garment.","rarity":"Niche","see_also":["Korn Aesthetic","Limp Bizkit Era","Metalhead Aesthetic"],"colors":["#1A1A1A Nu Black","#8B0000 Cap Red","#5B5B5B JNCO Grey","#D4AF37 Chain Gold"],"media":["Woodstock '99 documentary — documentary"]},"Korn Aesthetic":{"summary":"The specific Adidas-tracksuit, dreadlocked look of Korn — the band that launched Nu Metal's visual identity.","era":"c.1994–2003","mood":"Adidas-tracked, dreadlocked, suburban-angry","visual":"Adidas tracksuit (Jonathan Davis sponsorship). Dreadlocks. Baggy everything. The microphone stand made from an HR Giger spine. Kilt worn by Davis in later years. The aesthetic of suburban Californian angst.","garments":["Adidas tracksuit","Dreadlocked hair","Extremely baggy trousers","Band merchandise","Simple trainers"],"habitat":"Nu Metal history, Korn fan communities.","context":"Korn's 1994 debut established Nu Metal's visual language — the Adidas tracksuit, the dreadlocks, the baggy silhouette. Jonathan Davis's adoption of kilts later added a surprising element.","rarity":"Niche","see_also":["Nu Metal Aesthetic","Limp Bizkit Era","Alternative Metal"],"colors":["#1A1A1A Korn Black","#FAF8F5 Adidas White","#5B5B5B Dreadlock Grey","#8B0000 Logo Red"],"media":["Who Then Now? (Korn, 2002) — documentary"]},"Limp Bizkit Era":{"summary":"The red-cap, cargo-short, aggressively fratty aesthetic of Limp Bizkit — Nu Metal at its most commercially extreme and culturally contested.","era":"c.1997–2003","mood":"Aggressively fratty, red-cap coded","visual":"Backwards red New York Yankees cap (Fred Durst signature). Baggy cargo shorts. Oversized band tee or sports jersey. Goatee. The aesthetic of aggression crossed with frat-boy casualness.","garments":["Backwards red Yankees cap","Baggy cargo shorts","Oversized T-shirt or jersey","Goatee facial hair","Chunky trainers"],"habitat":"Late 1990s nostalgia, Woodstock '99 cultural discussion.","context":"Limp Bizkit was Nu Metal's most polarising act — commercially enormous (Woodstock '99) and critically savaged. Fred Durst's red cap became one of the most mocked fashion items of the era.","rarity":"Extinct","see_also":["Nu Metal Aesthetic","Korn Aesthetic","Pop Punk Aesthetic"],"colors":["#8B0000 Durst Red","#1A1A1A Black","#FAF8F5 White","#5B5B5B Cargo Grey"],"media":["Woodstock '99 documentary — documentary"]},"Post-Metal Aesthetic":{"summary":"The atmospheric, art-leaning end of heavy music — Isis, Neurosis, and the aesthetics of volume as meditation.","era":"c.1990s–present","mood":"Atmospherically heavy, art-metal contemplative","visual":"Simple, dark, understated. Less metal-coded than traditional heavy music. Art prints and design-focused merchandise. The aesthetic of musicians who list Swans and Godspeed alongside Black Sabbath as influences.","garments":["Simple dark clothing","Design-focused band merchandise","Understated presentation","Dark jeans or trousers","Simple boots or sneakers"],"habitat":"Post-metal and atmospheric heavy music communities, art-leaning metal scenes.","context":"Post-Metal's visual aesthetic reflects its music — atmospheric, patient, and more art-world-adjacent than traditional metal. Band merchandise tends toward design quality rather than genre signifiers.","rarity":"Niche","see_also":["Alternative Metal","Doom Metal","Shoegaze Aesthetic"],"colors":["#1A1A1A Atmospheric Black","#5B5B5B Grey","#2C2C2C Dark","#8B7355 Earth"],"media":["Isis: Oceanic live performances — music"]},"Old School Hip-Hop":{"summary":"The foundational visual culture of hip-hop's first decade — Adidas shell toes, Kangol hats, fat gold chains, and the South Bronx inventing a global aesthetic.","era":"c.1973–1986, South Bronx/New York","mood":"Foundationally expressive, Bronx-born","visual":"Adidas shell toe sneakers with fat laces. Kangol bucket hat. Track suit. Leather bomber jacket. Fat gold chain. Cazal glasses. Name belt buckle. The visual language of community and identity created from limited resources.","garments":["Adidas shell toe sneakers","Kangol bucket hat","Track suit","Fat gold rope chain","Cazal glasses"],"habitat":"Hip-hop history, South Bronx heritage, old school block party culture.","context":"Old School Hip-Hop fashion was invented by Black and Latino youth in the South Bronx who turned sportswear brands into cultural vocabulary. Every element — the sneaker, the chain, the hat — carried community meaning before it carried commercial value.","rarity":"Extinct","see_also":["B-Boy / B-Girl Aesthetic","Run-DMC Aesthetic","Early Streetwear"],"colors":["#1A1A1A Shell Toe Black","#FAF8F5 Adidas White","#D4AF37 Gold Chain","#8B0000 Kangol Red"],"media":["Wild Style (1983) — film","Style Wars (1983) — documentary","Beat Street (1984) — film"]},"B-Boy / B-Girl Aesthetic":{"summary":"The functional, athletic dress of breakdancing culture — tracksuits, headbands, and clothing that lets you spin on your head.","era":"c.1975–present","mood":"Athletically functional, dance-ready","visual":"Track suit for movement. Headband or bandana. Clean sneakers. The clothing must allow spinning, flipping, and floor work. Cardboard on the ground. Boombox nearby. The aesthetic is functional first — you dance in it.","garments":["Track suit","Headband or bandana","Clean sneakers","Windbreaker","Wristbands"],"habitat":"Breakdancing communities, hip-hop dance battles, street dance culture.","context":"B-boy and B-girl fashion is determined by function — you need to move freely, spin on surfaces, and look fresh doing it. The track suit became hip-hop's foundational garment because it worked for dancing.","rarity":"Niche","see_also":["Old School Hip-Hop","Run-DMC Aesthetic","Streetwear Culture"],"colors":["#8B0000 Adidas Red","#FAF8F5 White","#1A1A1A Black","#D4AF37 Gold"],"media":["Wild Style (1983) — film","Flashdance (1983) — film","Beat Street (1984) — film"]},"Run-DMC Aesthetic":{"summary":"The Adidas-without-laces, black-hat, gold-chain uniform of Run-DMC — the first hip-hop act to make fashion an explicit part of their artistic identity.","era":"c.1983–1993","mood":"Uniformly iconic, brand-defining","visual":"Black fedora hat. Adidas Superstar sneakers without laces. Black leather jacket. Gold rope chain. The look was a deliberate uniform — all three members dressed identically. The first hip-hop Adidas endorsement deal followed.","garments":["Adidas Superstar without laces","Black fedora hat","Black leather jacket","Gold rope chain","Adidas track suit"],"habitat":"Hip-hop history, Run-DMC fan culture, Adidas heritage.","context":"Run-DMC's 'My Adidas' (1986) led to the first hip-hop sneaker endorsement deal — Adidas paid $1.6 million after seeing 40,000 fans hold up their Adidas at a Madison Square Garden concert. Fashion and music merged permanently.","rarity":"Extinct","see_also":["Old School Hip-Hop","Kangol Era","Golden Age Hip-Hop"],"colors":["#1A1A1A Hat Black","#FAF8F5 Adidas White","#D4AF37 Chain Gold","#8B0000 Stripe Red"],"media":["Tougher Than Leather (1988) — film","King of Rock music video — music video"]},"Kangol Era":{"summary":"The specific Kangol hat period of hip-hop — LL Cool J's bucket hat, the Beastie Boys' berets, and the British hat brand that became hip-hop royalty.","era":"c.1984–1993","mood":"Hat-defined, Kangol-crowned","visual":"Kangol bucket hat or beret worn at a specific angle. Each rapper had their own Kangol style — LL Cool J's bucket, Slick Rick's beret, Grandmaster Flash's fedora variation. The hat defined the era.","garments":["Kangol bucket hat","Kangol beret","Track suit","Gold chain","Clean sneakers"],"habitat":"Old school hip-hop heritage, Kangol brand history.","context":"Kangol was a British hat brand adopted by hip-hop without any marketing strategy — the culture chose the brand. LL Cool J's bucket hat became one of the most recognisable accessories in hip-hop history.","rarity":"Extinct","see_also":["Old School Hip-Hop","Run-DMC Aesthetic","Golden Age Hip-Hop"],"colors":["#8B0000 Kangol Red","#1A1A1A Hat Black","#FAF8F5 White","#D4AF37 Gold"],"media":["LL Cool J music videos — music video"]},"Golden Age Hip-Hop":{"summary":"The 1987–1996 zenith of hip-hop creativity and its fashion — from Afrocentric kente to gangsta denim, the most diverse visual era in the genre's history.","era":"c.1987–1996","mood":"Creatively diverse, culturally assertive","visual":"Enormous diversity: Afrocentric kente cloth and medallions (Public Enemy, X Clan). Baggy jeans and Timberlands (East Coast). Dickies and flannel (West Coast). The Golden Age had no single look — it had many, all simultaneously.","garments":["Afrocentric medallion and kente","Baggy jeans","Timberland boots","Starter jacket","Cross Colours clothing"],"habitat":"Hip-hop history, Golden Age appreciation communities.","context":"The Golden Age produced hip-hop's most creatively diverse fashion moment — Afrocentrism, gangsta realism, bohemian jazz-rap, and Native Tongues positivity all coexisted. Cross Colours, Karl Kani, and FUBU emerged as hip-hop's own brands.","rarity":"Extinct","see_also":["Tupac Aesthetic","Biggie Aesthetic","Bling Era Aesthetic"],"colors":["#D4AF37 Medallion Gold","#8B0000 Afrocentric Red","#4A7C59 Cross Colours Green","#1A1A1A Black"],"media":["Hip-Hop Evolution (TV series) — documentary"]},"Tupac Aesthetic":{"summary":"The bandana, bare-chest, tattoo-mapped look of Tupac Shakur — thug life as visual manifesto, vulnerability and hardness in the same frame.","era":"c.1991–1996","mood":"Vulnerably hard, tattoo-mapped","visual":"Bandana tied on shaved head. Bare chest revealing tattoos — THUG LIFE across the stomach, Nefertiti on the chest. Baggy jeans. Timberland boots. Nose stud. The look of someone simultaneously tough and exposed.","garments":["Bandana on shaved head","Bare chest with visible tattoos","Baggy jeans","Timberland boots","Simple jewellery and nose stud"],"habitat":"Tupac fan culture, West Coast hip-hop heritage.","context":"Tupac's aesthetic was autobiographical — THUG LIFE tattooed on his body was both identity and manifesto. His vulnerability (the poetry, the tears) existed alongside the hardness (the bandana, the bare chest). His murder at 25 froze the aesthetic permanently.","rarity":"Niche","see_also":["Golden Age Hip-Hop","Biggie Aesthetic","Trap Aesthetic"],"colors":["#8B0000 Bandana Red","#1A1A1A Tattoo Black","#8B7355 Timberland Tan","#D4AF37 Gold"],"media":["Poetic Justice (1993) — film","Tupac: Resurrection (2003) — documentary","All Eyez on Me (2017) — film"]},"Biggie Aesthetic":{"summary":"The Coogi sweaters, Versace shades, and Brooklyn swagger of the Notorious B.I.G. — luxury as aspiration, the king of New York dressed accordingly.","era":"c.1993–1997","mood":"Luxuriously aspirational, Brooklyn-royal","visual":"Coogi sweater (the multicoloured Australian knit). Versace sunglasses. Kangol hat. Jesus piece chain. The Biggie look was aspirational luxury — the clothing of someone who had escaped poverty and was celebrating.","garments":["Coogi sweater","Versace sunglasses","Kangol hat","Jesus piece gold chain","Leather jacket"],"habitat":"East Coast hip-hop heritage, Brooklyn cultural history, Biggie fan culture.","context":"Biggie's fashion represented the aspiration at the heart of hip-hop — the Coogi sweater and Versace shades were markers of success emerging from Bedford-Stuyvesant poverty. His murder at 24 froze the aesthetic alongside Tupac's.","rarity":"Niche","see_also":["Golden Age Hip-Hop","Tupac Aesthetic","Bling Era Aesthetic"],"colors":["#D4AF37 Coogi Gold","#8B0000 Versace Red","#1A1A1A Brooklyn Black","#C0C0C0 Jesus Piece Silver"],"media":["Notorious (2009) — film","Biggie: I Got a Story to Tell (2021) — documentary"]},"Aaliyah Aesthetic":{"summary":"The tomboy-feminine, baggy-meets-sleek look of Aaliyah — crop top and baggy trousers, sunglasses, and effortless cool that defined late-1990s R&B.","era":"c.1994–2001","mood":"Effortlessly androgynous, tomboy-sleek","visual":"Crop top with baggy low-rise trousers. Dark sunglasses (signature). Hair swept over one eye. Leather or sleek fabrics. The specific combination of masculine bagginess and feminine body-consciousness that Aaliyah uniquely owned.","garments":["Crop top","Baggy low-rise trousers","Dark sunglasses","Hair swept over one eye","Leather or sleek top"],"habitat":"Late 1990s R&B heritage, Aaliyah fan communities.","context":"Aaliyah's style was the definitive tomboy-feminine of the late 1990s — she combined masculine silhouettes with body-conscious elements in a way that influenced a generation. Her death at 22 in a plane crash froze one of music's most promising aesthetic evolutions.","rarity":"Niche","see_also":["TLC Aesthetic","Neo-Soul Aesthetic","Y2K"],"colors":["#1A1A1A Aaliyah Black","#C0C0C0 Silver","#8B0000 Dark Red","#FAF8F5 White Crop"],"media":["Romeo Must Die (2000) — film","Queen of the Damned (2002) — film"]},"Neo-Soul Aesthetic":{"summary":"The natural, Afrocentric, spiritually conscious look of late-1990s neo-soul — headwraps, natural hair, and beauty as cultural statement.","era":"c.1994–present","mood":"Naturally conscious, Afrocentrically spiritual","visual":"Natural Afro or locs. Headwrap in African print. Earth-tone flowing garments. Cowrie shell jewellery. Natural face — no or minimal makeup. The aesthetic signals cultural consciousness and natural beauty as political choice.","garments":["Natural hair or locs","African print headwrap","Earth-tone flowing garments","Cowrie shell jewellery","Natural face minimal makeup"],"habitat":"Neo-soul music communities, natural hair movement, Afrocentric fashion.","context":"Neo-soul fashion was a deliberate return to natural aesthetics after the bling era's commercialism — Erykah Badu, Lauryn Hill, and D'Angelo made natural hair and Afrocentric dress a mainstream aesthetic choice.","rarity":"Niche","see_also":["Erykah Badu Aesthetic","Lauryn Hill Aesthetic","Afrocentric"],"colors":["#8B7355 Earth Brown","#D4AF37 Cowrie Gold","#4A7C59 Consciousness Green","#C1440E Ochre"],"media":["Brown Sugar (2002) — film"]},"Erykah Badu Aesthetic":{"summary":"The towering headwrap, natural beauty, and Afro-bohemian mysticism of Erykah Badu — the most visually distinctive artist in neo-soul history.","era":"c.1997–present","mood":"Mystically Afro-bohemian, headwrap-towering","visual":"Towering headwrap in elaborate forms. Natural makeup with dramatic lip colour. Flowing Afrocentric garments. Enormous sunglasses. The look evolves constantly but the headwrap and natural aesthetic remain constant.","garments":["Towering elaborate headwrap","Flowing Afrocentric garments","Dramatic lip colour","Enormous sunglasses","Natural or statement jewellery"],"habitat":"Erykah Badu fan culture, neo-soul communities, Afro-bohemian fashion.","context":"Erykah Badu's headwrap became as iconic as any garment in 1990s music. Her aesthetic combines Afrocentrism, spirituality, and bohemian creativity into something entirely her own — consistently evolving but instantly recognisable.","rarity":"Niche","see_also":["Neo-Soul Aesthetic","Lauryn Hill Aesthetic","Afrofuturism"],"colors":["#D4AF37 Headwrap Gold","#8B7355 Earth Brown","#4A7C59 Natural Green","#8B0000 Lip Red"],"media":["Erykah Badu: Live (1997) — concert film"]},"Lauryn Hill Aesthetic":{"summary":"The natural locs, army fatigue, and quiet power of Lauryn Hill — Fugees-era tomboy to Miseducation-era goddess, one of music's most powerful style evolutions.","era":"c.1996–present","mood":"Quietly powerful, naturally regal","visual":"Fugees era: locs, army fatigue jacket, jeans, sneakers — tomboy casual. Miseducation era: natural hair crown, earth-tone flowing dress, African jewellery — goddess transformation. Both equally iconic.","garments":["Natural locs or hair crown","Army fatigue jacket (Fugees era)","Earth-tone flowing dress (Miseducation era)","African jewellery","Simple sneakers or sandals"],"habitat":"Lauryn Hill fan communities, neo-soul heritage.","context":"Lauryn Hill's transition from Fugees-era tomboy to Miseducation-era natural queen was one of the most striking visual transformations in 1990s music. The Miseducation of Lauryn Hill remains the best-selling hip-hop album by a woman.","rarity":"Niche","see_also":["Neo-Soul Aesthetic","Erykah Badu Aesthetic","Natural Hair Aesthetic"],"colors":["#8B7355 Army Fatigue","#D4AF37 Crown Gold","#4A7C59 Earth Green","#1A1A1A Natural Black"],"media":["The Miseducation of Lauryn Hill (1998) — music"]},"Bling Era Aesthetic":{"summary":"The maximalist, diamond-encrusted, luxury-brand-draped era of early 2000s hip-hop — Roc-A-Fella, Bad Boy, and excess as aspiration.","era":"c.1998–2006","mood":"Maximally blinged, luxury-excess","visual":"Diamond-encrusted chains and watches. Fur coats. Designer labels worn head to toe — Gucci, Versace, Louis Vuitton. Champagne as accessory. The aesthetic of newly enormous hip-hop wealth displayed without restraint.","garments":["Diamond-encrusted chain","Fur coat","Head-to-toe designer","Luxury watch","Champagne bottle"],"habitat":"Early 2000s hip-hop culture, Roc-A-Fella and Bad Boy heritage.","context":"The Bling Era was hip-hop celebrating its economic power — Jay-Z, P. Diddy, and 50 Cent dressed in luxury brands as explicit wealth display. The diamond chain became the era's defining accessory.","rarity":"Niche","see_also":["Hip-Hop Luxury","Designer Streetwear","Logomania"],"colors":["#D4AF37 Bling Gold","#C0C0C0 Diamond Silver","#1A1A1A Fur Black","#8B0000 Versace Red"],"media":["Get Rich or Die Tryin' (2005) — film"]},"Early 2000s Hip-Hop":{"summary":"The broader visual culture of hip-hop in the early 2000s — Timbs, du-rags, white tees, and the era between Golden Age authenticity and full luxury excess.","era":"c.2000–2006","mood":"Transitionally excessive, Timb-booted","visual":"Oversized white T-shirt (the tall tee). Timberland boots. Du-rag or fitted cap. Baggy jeans. Simple gold chain. The everyday look of hip-hop between the Golden Age and the luxury era.","garments":["Oversized white T-shirt","Timberland boots","Du-rag or fitted cap","Baggy jeans","Gold chain"],"habitat":"Early 2000s hip-hop culture, urban fashion communities.","context":"The early 2000s hip-hop look was the everyday counterpart to the Bling Era's excess — Timberlands and white tees were the uniform of the street while the videos showed diamonds and fur.","rarity":"Niche","see_also":["Bling Era Aesthetic","Golden Age Hip-Hop","Trap Aesthetic"],"colors":["#FAF8F5 White Tee","#8B7355 Timberland Tan","#1A1A1A Du-rag Black","#D4AF37 Chain Gold"],"media":["8 Mile (2002) — film"]},"Lil Kim Aesthetic":{"summary":"The maximally provocative, luxury-draped femininity of Lil' Kim — wigs, pasties, fur, and the most confrontationally sexual presentation in hip-hop history.","era":"c.1996–present","mood":"Maximally provocative, luxury-sexual","visual":"Coloured wigs in every shade. Deliberately provocative outfits — the purple pastie and fur from the 1999 VMAs. Full designer luxury. Extreme makeup. The deliberate weaponisation of female sexuality in a male-dominated genre.","garments":["Coloured statement wig","Provocative designer outfit","Full fur","Extreme makeup","Platform heels"],"habitat":"Lil Kim fan culture, hip-hop femininity history, maximalist fashion.","context":"Lil' Kim's aesthetic was deliberately confrontational — she made female sexual display a power move in hip-hop's male-dominated visual space. Her influence on Nicki Minaj, Cardi B, and Megan Thee Stallion is direct and acknowledged.","rarity":"Niche","see_also":["Bling Era Aesthetic","Baddie Aesthetic","Hip-Hop Luxury"],"colors":["#C185A0 Kim Pink","#D4AF37 Luxury Gold","#4B0082 Wig Purple","#1A1A1A Fur Black"],"media":["Lil' Kim: Hardcore (1996) — music","VH1 Hip Hop Honors — TV"]},"Early Streetwear":{"summary":"The foundational brands and culture of streetwear before it became luxury — Stüssy, Supreme's first decade, and skate-meets-hip-hop on the sidewalk.","era":"c.1984–2000","mood":"Street-born, brand-community fused","visual":"Stüssy logo tees and caps. Early Supreme box logo. Skate-influenced silhouettes crossed with hip-hop bagginess. Limited-edition drops before the concept was mainstream. The aesthetic of community-built brand culture.","garments":["Stüssy logo T-shirt","Early Supreme box logo","Baggy jeans or cargo","Skate shoes","Snapback cap"],"habitat":"Original streetwear communities, Stüssy and Supreme heritage, skate-hip-hop crossover.","context":"Streetwear emerged from the intersection of surf, skate, and hip-hop cultures in 1980s California and New York. Stüssy (1980) and Supreme (1994) built brand loyalty through scarcity and community before the luxury industry adopted the model.","rarity":"Niche","see_also":["FUBU Era","Streetwear Culture","Designer Streetwear"],"colors":["#1A1A1A Street Black","#FAF8F5 Logo White","#8B0000 Supreme Red","#8B7355 Stüssy Tan"],"media":["Fresh Dressed (2015) — documentary"]},"FUBU Era":{"summary":"The For Us By Us moment — Black-owned hip-hop fashion brands creating their own industry instead of borrowing from European luxury.","era":"c.1992–2003","mood":"Self-made, community-owned","visual":"FUBU logo prominently displayed. Karl Kani jeans. Cross Colours bright positivity. The aesthetic of Black entrepreneurship in fashion — brands made by and for the hip-hop community.","garments":["FUBU logo jersey or jacket","Karl Kani jeans","Cross Colours bright pieces","Branded cap","Community-brand sneakers"],"habitat":"Hip-hop fashion history, Black-owned fashion brand heritage.","context":"FUBU (For Us, By Us), Karl Kani, Cross Colours, and Walker Wear represented hip-hop creating its own fashion industry. Daymond John built FUBU from scratch in Hollis, Queens — the same neighbourhood as Run-DMC.","rarity":"Extinct","see_also":["Early Streetwear","Rocawear Aesthetic","Golden Age Hip-Hop"],"colors":["#1B4F72 FUBU Blue","#D4AF37 Logo Gold","#8B0000 Brand Red","#FAF8F5 White"],"media":["Fresh Dressed (2015) — documentary"]},"Rocawear Aesthetic":{"summary":"Jay-Z's fashion brand and its visual identity — the rapper-as-mogul aesthetic, Roc-A-Fella diamond hand, and hip-hop as corporate enterprise.","era":"c.1999–2007","mood":"Mogul-aspirational, Roc-branded","visual":"Rocawear logo pieces — jerseys, jackets, jeans. The Roc diamond hand sign as brand gesture. Slightly more refined than FUBU's streetwear — pointing toward the luxury pivot that Jay-Z would later make with his personal style.","garments":["Rocawear branded jacket","Logo jersey","Roc diamond hand sign","Fitted cap","Clean sneakers"],"habitat":"Jay-Z fan culture, early 2000s hip-hop fashion, rapper-brand history.","context":"Rocawear was Jay-Z's entry into fashion entrepreneurship — it generated over $700 million in revenue before he sold it. It represented hip-hop's transition from wearing luxury brands to owning fashion brands.","rarity":"Extinct","see_also":["FUBU Era","Bling Era Aesthetic","Designer Streetwear"],"colors":["#1A1A1A Roc Black","#D4AF37 Diamond Gold","#FAF8F5 White","#1B4F72 Navy"],"media":["Fade to Black (2004) — documentary"]},"Crunk Aesthetic":{"summary":"The Southern hip-hop party dress of the crunk era — grillz, oversized chains, and the specific visual energy of Lil Jon and the Dirty South.","era":"c.2002–2007, Atlanta/Memphis","mood":"Party-aggressive, Southern-loud","visual":"Grillz (decorative dental caps). Oversized chains. Fitted cap. Oversized white tee. The specific Southern hip-hop aesthetic of Lil Jon's 'YEAH!' era — loud, party-ready, and unsubtle.","garments":["Grillz dental caps","Oversized chain","Fitted cap","Oversized white T-shirt","Baggy jeans"],"habitat":"Southern hip-hop culture, crunk era nostalgia, Atlanta music heritage.","context":"Crunk was Southern hip-hop's party mode — Lil Jon, Three 6 Mafia, and the Memphis-Atlanta axis created a specific visual energy. Grillz crossed from regional Southern culture to global trend via Nelly's 2005 single.","rarity":"Extinct","see_also":["Trap Aesthetic","Atlanta Style","Bling Era Aesthetic"],"colors":["#D4AF37 Grillz Gold","#C0C0C0 Chain Silver","#FAF8F5 White Tee","#1A1A1A Black"],"media":["Hustle & Flow (2005) — film"]},"Trap Aesthetic":{"summary":"The lean-era, face-tattooed, designer-draped look of trap music — Gucci Mane to Future to Young Thug, Atlanta's gift to global fashion.","era":"c.2010–present, Atlanta","mood":"Lean-coded, designer-draped, Atlanta-futuristic","visual":"Face tattoos. Designer everything — Gucci, Balenciaga, Off-White. Skinny jeans replacing baggy. Coloured dreadlocks. Lean culture references. Young Thug's gender-fluid fashion as the aesthetic's most radical expression.","garments":["Face tattoos","Designer brand head-to-toe","Skinny jeans","Coloured dreadlocks","Designer sunglasses"],"habitat":"Atlanta hip-hop culture, trap music communities, global streetwear.","context":"Trap fashion represents hip-hop's most radical aesthetic shift — from baggy to skinny, from gold chains to face tattoos, from masculine uniformity to Young Thug's gender-fluid fashion revolution.","rarity":"Common","see_also":["Atlanta Style","Designer Streetwear","Hip-Hop Luxury"],"colors":["#1A1A1A Trap Black","#D4AF37 Designer Gold","#8B0000 Lean Red","#4B0082 Codeine Purple"],"media":["Atlanta (TV series) — TV"]},"Atlanta Style":{"summary":"The specific fashion culture of Atlanta's hip-hop scene — from Outkast's eccentricity to trap's designer excess, the most fashion-forward city in American music.","era":"c.1994–present, Atlanta","mood":"Eclectically fashion-forward, Southern creative","visual":"Enormous range — Outkast's eclectic maximalism, T.I.'s sharp tailoring, Young Thug's gender fluidity, Future's designer darkness. Atlanta allows more fashion risk than New York or LA.","garments":["Eclectic designer mix","Bold colour choices","Risk-taking silhouettes","Statement accessories","Gender-fluid elements"],"habitat":"Atlanta music and fashion scenes, Southern hip-hop culture.","context":"Atlanta has been hip-hop's most fashion-forward city since Outkast declared 'the South got somethin' to say' in 1995. André 3000's increasingly eccentric fashion and Young Thug's gender-fluid dressing pushed hip-hop's visual boundaries.","rarity":"Niche","see_also":["Trap Aesthetic","Designer Streetwear","Afrofuturism"],"colors":["#D4AF37 Atlanta Gold","#4B0082 Outkast Purple","#8B0000 Southern Red","#1A1A1A Night Black"],"media":["Atlanta (TV series) — TV","Outkast: The Way You Move (video) — music video"]},"Migos Aesthetic":{"summary":"The specific Versace-obsessed, chain-heavy, coordinated crew look of Migos — the trio as fashion unit.","era":"c.2013–2023","mood":"Versace-obsessed, trio-coordinated","visual":"Versace prominently featured — the 2013 viral single 'Versace' was a literal fashion statement. Heavy chains. Designer sunglasses. Coordinated but not identical outfits. Offset's Met Gala appearances as the trio's fashion ambassador.","garments":["Versace prominently worn","Heavy designer chains","Coordinated trio outfits","Designer sunglasses","Statement rings and watches"],"habitat":"Migos fan culture, Atlanta trap fashion.","context":"Migos made 'Versace' both a song title and a lifestyle brand. Offset's marriage to Cardi B created hip-hop's most fashion-forward couple. The trio's visual coordination was as considered as their musical chemistry.","rarity":"Niche","see_also":["Trap Aesthetic","Atlanta Style","Designer Streetwear"],"colors":["#D4AF37 Versace Gold","#1A1A1A Migos Black","#8B0000 Designer Red","#C0C0C0 Chain Silver"],"media":["Migos: Culture music videos — music video"]},"Hip-Hop Luxury":{"summary":"The mature intersection of hip-hop and haute couture — Jay-Z at the Met Gala, A$AP Rocky at Dior, and hip-hop as fashion establishment.","era":"c.2010–present","mood":"Establishment-luxury, hip-hop-elevated","visual":"Haute couture and runway pieces worn by hip-hop artists. Custom designer pieces. Front-row fashion week attendance. The transition from wearing luxury brands to collaborating with them — Kanye at Balenciaga, Pharrell at Louis Vuitton.","garments":["Haute couture pieces","Custom designer collaborations","Fashion week front row attire","Bespoke tailoring","Statement luxury accessories"],"habitat":"Met Gala, fashion weeks, hip-hop-luxury crossover events.","context":"Hip-Hop Luxury represents the genre's full arrival in the fashion establishment — from being excluded from luxury stores to running them. Pharrell's appointment as Louis Vuitton men's creative director in 2023 completed the journey.","rarity":"Niche","see_also":["Designer Streetwear","Virgil Abloh Aesthetic","Bling Era Aesthetic"],"colors":["#D4AF37 Couture Gold","#1A1A1A Formal Black","#FAF8F5 Runway White","#8B0000 LV Red"],"media":["Fresh Dressed (2015) — documentary"]},"Designer Streetwear":{"summary":"The fusion of luxury fashion houses and streetwear culture — Off-White, Fear of God, and the permanent merger of high and low fashion.","era":"c.2013–present","mood":"High-low fused, luxury-street merged","visual":"Luxury brand logos on streetwear silhouettes. Hoodies and sneakers at runway prices. The Off-White diagonal stripe. Fear of God's oversized essentials. Supreme x Louis Vuitton as the defining collaboration.","garments":["Off-White diagonal stripe piece","Fear of God oversized hoodie","Luxury sneakers","Supreme x luxury brand collaboration","Designer streetwear logo"],"habitat":"Streetwear communities, designer resale markets, fashion-forward urban culture.","context":"Designer Streetwear erased the boundary between luxury and street fashion permanently. The Supreme x Louis Vuitton collaboration (2017) was the symbolic merger. Virgil Abloh at Louis Vuitton institutionalised it.","rarity":"Common","see_also":["Virgil Abloh Aesthetic","Hip-Hop Luxury","Hypebeast Aesthetic"],"colors":["#1A1A1A Street Black","#FAF8F5 Off-White","#D4AF37 Designer Gold","#8B0000 Supreme Red"],"media":["The Gospel According to Virgil — documentary"]},"Virgil Abloh Aesthetic":{"summary":"The specific design language of Virgil Abloh — quotation marks, industrial belts, and the Ghanaian-American polymath who bridged Kanye and Louis Vuitton.","era":"c.2012–2021","mood":"Conceptually street, quotation-marked","visual":"The Off-White quotation marks: \"SHOELACES\" on laces, \"BELT\" on belts. Industrial yellow belt. Deconstructed luxury. The Nike x Off-White sneaker collaborations as grail items. Every element labelled and questioned.","garments":["Off-White quotation mark piece","Industrial yellow belt","Nike x Off-White sneaker","Deconstructed luxury garment","Labelled and questioned design"],"habitat":"Virgil Abloh legacy, Off-White and Louis Vuitton heritage, designer streetwear.","context":"Virgil Abloh's death at 41 from cancer in 2021 ended one of fashion's most transformative careers. He was the first Black American artistic director at Louis Vuitton. His 'everything in quotation marks' design philosophy questioned luxury's self-seriousness.","rarity":"Niche","see_also":["Designer Streetwear","Hip-Hop Luxury","Kanye West"],"colors":["#1A1A1A Off-Black","#FAF8F5 Off-White","#D4AF37 Industrial Yellow","#8B0000 LV Red"],"media":["Virgil Abloh: Figures of Speech exhibition — exhibition"]},"Drill Aesthetic":{"summary":"The ski masks, puffer jackets, and dark anonymity of drill music — Chicago to London to Brooklyn, the aesthetic of music too dangerous for faces.","era":"c.2012–present, Chicago/London/Brooklyn","mood":"Anonymously dark, puffer-armoured","visual":"Ski mask or balaclava covering face. Black puffer jacket. Dark tracksuit. Designer belts and accessories as contrast. The anonymity is functional — many drill artists cannot show their faces due to legal or safety concerns.","garments":["Ski mask or balaclava","Black puffer jacket","Dark tracksuit","Designer belt","Dark trainers"],"habitat":"Drill music communities, Chicago/London/Brooklyn drill scenes.","context":"Drill fashion's anonymity is not aesthetic choice but necessity — many artists face legal restrictions on public appearances. The ski mask became both practical protection and genre signifier.","rarity":"Common","see_also":["Trap Aesthetic","Council Estate Fashion","Streetwear Culture"],"colors":["#1A1A1A Drill Black","#2C2C2C Puffer Dark","#D4AF37 Belt Gold","#5B5B5B Mask Grey"],"media":["Top Boy (TV series) — TV","Blue Story (2019) — film"]},"Afrobeats Fashion":{"summary":"The colourful, luxury-mixed, globally confident dress of the Afrobeats music scene — Wizkid, Burna Boy, and West African fashion on the world stage.","era":"c.2015–present, Nigeria/Ghana/global","mood":"Globally confident, colourfully luxurious","visual":"African print mixed with luxury brands. Bold colours. Designer pieces with traditional references. The aesthetic of a globally successful music scene that is equally comfortable in Lagos and London.","garments":["African print mixed with designer","Bold colourful pieces","Luxury accessories","Traditional-contemporary fusion","Statement jewellery"],"habitat":"Afrobeats music events, Nigerian and Ghanaian fashion scenes, global diaspora.","context":"Afrobeats fashion represents a new confidence — West African artists dressing in a way that acknowledges both traditional heritage and global luxury culture. Burna Boy's fashion-forward approach has made him a style icon beyond music.","rarity":"Common","see_also":["Ankara / African Print Fashion","Nigerian Street Fashion","Designer Streetwear"],"colors":["#D4AF37 Gold","#4A7C59 Ankara Green","#8B0000 Bold Red","#FAF8F5 White"],"media":["Afrobeats: The Backstory (documentary) — documentary"]},"Baddie Aesthetic":{"summary":"The Instagram-era feminine maximalism of the Baddie — contoured makeup, bodycon silhouettes, and confidence as the primary garment.","era":"c.2015–present","mood":"Confidently maximalist, Instagram-contoured","visual":"Full contour and highlight makeup. Bodycon dress or matching set. Long nails. Long hair (often extensions or wigs). Heels or designer sneakers. The aesthetic of someone whose Instagram grid is professionally curated.","garments":["Bodycon dress or matching set","Full contour makeup","Long styled hair or wig","Long nails","Heels or designer sneakers"],"habitat":"Instagram, TikTok, club and brunch culture, urban feminine fashion.","context":"The Baddie aesthetic emerged from Black and Latina beauty culture on Instagram, drawing on hip-hop femininity, Kardashian influence, and makeup artistry. It centres confidence and self-presentation as primary values.","rarity":"Common","see_also":["Brunch Aesthetic","Black Girl Magic Fashion","Instagram Baddie"],"colors":["#1A1A1A Baddie Black","#F5C6CB Nude Pink","#D4AF37 Gold","#8B0000 Bold Red"],"media":["Instagram #baddie — social media"]},"Brunch Aesthetic":{"summary":"The polished, going-out-for-Sunday-brunch look — somewhere between casual and dressed up, designed for both food photos and group selfies.","era":"c.2015–present","mood":"Polished-casual, photo-ready","visual":"Somewhere between dressed up and casual. Heeled mule or strappy sandal. Matching set or smart dress. Hair done. Nails done. Sunglasses. The outfit designed for the specific social occasion of brunch — photographable but relaxed.","garments":["Matching set or smart casual dress","Heeled mule or sandal","Structured handbag","Sunglasses","Styled hair and nails"],"habitat":"Brunch culture, Sunday social events, Instagram lifestyle content.","context":"Brunch Aesthetic codifies the specific dressing challenge of Sunday brunch — too dressed up is try-hard, too casual is disrespectful to the occasion. The result is a precisely calibrated middle ground.","rarity":"Common","see_also":["Baddie Aesthetic","Going Out Aesthetic","Clean Girl"],"colors":["#F5C6CB Brunch Pink","#FAF8F5 White","#D4AF37 Mimosa Gold","#87CEEB Sunday Blue"],"media":["Instagram #brunch — social media"]},"Black Girl Magic Fashion":{"summary":"The celebratory, culturally affirming fashion expression of Black femininity — natural hair, bold colour, and style as joyful resistance.","era":"c.2013–present","mood":"Joyfully affirming, culturally celebratory","visual":"Natural hair in all its forms celebrated. Bold colour and print. African-inspired and diasporic references. The aesthetic centres Black women's beauty in all its diversity — from natural hair to wigs, from minimalist to maximalist.","garments":["Natural hair celebrated in all forms","Bold colour choices","African-inspired prints and accessories","Statement jewellery","Culturally affirming wardrobe"],"habitat":"Black Girl Magic communities, natural hair movement, Black fashion culture.","context":"Black Girl Magic (coined by CaShawn Thompson in 2013) became a cultural movement celebrating Black women's beauty, achievement, and style. The fashion expression ranges from Afrocentric to minimalist — the unifying element is celebration.","rarity":"Common","see_also":["Baddie Aesthetic","Natural Hair Aesthetic","Afrofuturism"],"colors":["#D4AF37 Magic Gold","#4A7C59 Ankara Green","#8B0000 Bold Red","#4B0082 Royal Purple"],"media":["Black Girls Rock! (BET) — TV"]},"Shoegaze Aesthetic":{"summary":"The noise-beautiful, hair-curtain, effects-pedal-obsessed look of shoegaze — staring at your shoes while making transcendent sound.","era":"c.1988–1993; revival 2010s–present","mood":"Dreamily loud, hair-curtained","visual":"Long hair falling over face (the shoe-gazing posture of looking at effects pedals). Oversized vintage band tee or sweater. Jeans. Simple shoes. The deliberate rejection of frontman performance — beauty through apparent indifference.","garments":["Long hair over face","Oversized vintage sweater","Simple jeans","Basic sneakers or boots","Layered simple clothing"],"habitat":"Shoegaze revival communities, indie music venues, My Bloody Valentine fan culture.","context":"Shoegaze got its name from the NME mocking bands who stared at their pedals rather than performing. The aesthetic of looking down became the genre's defining visual — anti-performance as performance.","rarity":"Niche","see_also":["Dream Pop Fashion","My Bloody Valentine Aesthetic","Indie Rock Aesthetic"],"colors":["#5B5B5B Fuzz Grey","#8B7355 Vintage Tan","#B0C4DE Reverb Blue","#C185A0 Noise Rose"],"media":["Lost in Translation (2003) — film"]},"Dream Pop Fashion":{"summary":"The soft, hazy, slightly psychedelic dress of dream pop — Beach House ethereal, pastel washes, and the aesthetic of music that sounds like memory.","era":"c.1985–present","mood":"Hazily ethereal, memory-soft","visual":"Soft, slightly oversized clothing in muted tones. Flowing dresses or simple separates. Hair natural and loose. The look of someone slightly out of focus — dreamy, soft, and present without being sharp.","garments":["Flowing soft dress","Oversized vintage sweater","Natural loose hair","Simple flat shoes","Muted-tone layering"],"habitat":"Dream pop communities, Beach House and Slowdive fan cultures, ethereal music events.","context":"Dream Pop's aesthetic mirrors its sound — soft, layered, slightly blurred. It shares DNA with shoegaze visually but is gentler and more deliberately beautiful rather than noise-aggressive.","rarity":"Niche","see_also":["Shoegaze Aesthetic","Ethereal Goth","Indie Rock Aesthetic"],"colors":["#B0C4DE Dream Blue","#C185A0 Haze Rose","#E8D5B0 Memory Cream","#5B5B5B Soft Grey"],"media":["Beach House: Depression Cherry (2015) — music"]},"My Bloody Valentine Aesthetic":{"summary":"The specific noise-beautiful anti-presentation of My Bloody Valentine — Kevin Shields' wall of sound made into a wall of anti-fashion.","era":"c.1988–present","mood":"Anti-presentational, noise-beautiful","visual":"Kevin Shields: oversized T-shirt, jeans, sneakers, looking at guitar. Bilinda Butcher: simple dress, long hair, quiet presence. The most self-effacing presentation of a band making the most overwhelming sound in rock.","garments":["Oversized plain T-shirt","Simple jeans","Basic sneakers","Long natural hair","Absolutely minimal presentation"],"habitat":"My Bloody Valentine fan culture, shoegaze heritage.","context":"MBV's visual anti-aesthetic was the perfect complement to their music — the most extreme sound in indie rock made by people who looked like they'd wandered in from a library. The contrast was the point.","rarity":"Rare","see_also":["Shoegaze Aesthetic","Dream Pop Fashion","Post-Punk Fashion"],"colors":["#C185A0 Loveless Pink","#5B5B5B Noise Grey","#FAF8F5 White Tee","#8B7355 Quiet Brown"],"media":["My Bloody Valentine: Loveless (1991) — music"]},"Slowcore Aesthetic":{"summary":"The whisper-quiet, deeply introverted dress of slowcore music — the aesthetic of sadness slowed to a crawl.","era":"c.1990–present","mood":"Whisper-introverted, glacially sad","visual":"Simple, dark, quiet. Nothing attention-seeking. The aesthetic of someone who plays music so quiet the audience has to lean in. Low-key dark clothing, simple shoes, no performance gesture.","garments":["Simple dark clothing","Quiet unassuming layers","Basic shoes","No performance gesture","Natural unkempt hair"],"habitat":"Slowcore music communities, Low and Codeine fan cultures.","context":"Slowcore bands like Low, Codeine, and Red House Painters dressed as quietly as they played — the visual equivalent of music that whispers rather than shouts.","rarity":"Rare","see_also":["Shoegaze Aesthetic","Dream Pop Fashion","Indie Rock Aesthetic"],"colors":["#5B5B5B Whisper Grey","#1A1A1A Dark","#8B7355 Quiet Brown","#2C2C2C Hush"],"media":["Low: I Could Live in Hope (1994) — music"]},"Grunge":{"summary":"The Pacific Northwest flannel-and-denim anti-fashion that became the defining look of early 1990s alternative rock.","era":"c.1987–1994, Seattle; revival perpetual","mood":"Deliberately indifferent, thrift-layered","visual":"Flannel shirt — open, tied at waist, or layered. Ripped and faded jeans. Doc Martens or Converse. Band T-shirt. Unwashed or uncombed hair. Thrift store clothing worn with genuine indifference to appearance.","garments":["Flannel shirt","Ripped faded jeans","Doc Martens boots","Band T-shirt","Thrift store layers"],"habitat":"Pacific Northwest music heritage, thrift stores, grunge revival communities.","context":"Grunge fashion was authentic anti-fashion — Seattle musicians dressed from thrift stores because they were poor, not because they were making a statement. When Marc Jacobs showed grunge on the Perry Ellis runway in 1992, he was fired.","rarity":"Common","see_also":["Nirvana Aesthetic","Kurt Cobain Aesthetic","Grunge Girl"],"colors":["#8B7355 Flannel Brown","#1A1A1A Grunge Black","#8B0000 Plaid Red","#1B4F72 Faded Denim"],"media":["Singles (1992) — film","Reality Bites (1994) — film","Hype! (1996) — documentary"]},"Nirvana Aesthetic":{"summary":"The specific visual language of Nirvana — Kurt's cardigan, the smiley face logo, and the most photographed band of the 1990s.","era":"c.1989–1994, Seattle","mood":"Uncomfortably famous, cardigan-wrapped","visual":"Oversized cardigan (Kurt's signature). Striped long-sleeve shirt. Ripped jeans. Converse One Stars. Hair unwashed and in face. The Nirvana smiley face logo. Sunglasses worn indoors from discomfort, not cool.","garments":["Oversized cardigan","Striped long-sleeve shirt","Ripped jeans","Converse One Stars","Hair in face"],"habitat":"Nirvana fan culture, 1990s alternative heritage, Seattle music history.","context":"Nirvana's look was genuine poverty dressed up as nothing — Kurt Cobain famously wore a thrift-store dress on the cover of The Face. His discomfort with fame was expressed through increasingly dishevelled presentation.","rarity":"Niche","see_also":["Kurt Cobain Aesthetic","Grunge","Grunge Girl"],"colors":["#8B7355 Cardigan Brown","#1A1A1A Black","#FAF8F5 Striped White","#5B5B5B Faded Grey"],"media":["About a Son (2006) — documentary","Montage of Heck (2015) — documentary"]},"Kurt Cobain Aesthetic":{"summary":"The specific personal style of Kurt Cobain — the most influential anti-fashion figure of the 1990s.","era":"c.1991–1994","mood":"Painfully authentic, anti-fame dressed","visual":"Oversized mohair cardigan in olive or brown. Striped shirt. Ripped jeans. Converse. Sunglasses hiding from cameras. The occasional deliberate gender-subversion — wearing a dress on stage or for photo shoots.","garments":["Olive mohair cardigan","Striped T-shirt","Heavily ripped jeans","Converse sneakers","Dress worn for provocation"],"habitat":"Kurt Cobain fan culture, grunge heritage.","context":"Kurt Cobain's fashion influence was entirely accidental — he dressed from thrift stores and discomfort, and millions of teenagers copied him. His wearing of dresses was an explicitly political gesture against homophobia and machismo.","rarity":"Niche","see_also":["Nirvana Aesthetic","Grunge","Courtney Love Aesthetic"],"colors":["#4A7C59 Olive Cardigan","#8B7355 Mohair Brown","#1B4F72 Ripped Denim","#FAF8F5 Stripe White"],"media":["Montage of Heck (2015) — documentary","Last Days (2005) — film"]},"Pearl Jam Aesthetic":{"summary":"The flannel-working-class-earnest look of Pearl Jam — less theatrical than Nirvana, more working-class, and consistently anti-corporate.","era":"c.1990–present, Seattle","mood":"Working-class earnest, anti-corporate","visual":"Flannel or work shirt. Jeans. Work boots or sneakers. Eddie Vedder's long hair tied back or free. The look of someone who works construction and plays arena rock without changing clothes.","garments":["Flannel work shirt","Worn jeans","Work boots","Long hair","Simple working-class layers"],"habitat":"Pearl Jam fan communities, Seattle music heritage.","context":"Pearl Jam's aesthetic was always more working-class than grunge's art-school adjacent acts. Eddie Vedder dressed like a dockworker who happened to sing. Their anti-Ticketmaster stance extended to anti-fashion as principle.","rarity":"Niche","see_also":["Grunge","Nirvana Aesthetic","Rugged Americana"],"colors":["#8B7355 Flannel Brown","#1B4F72 Denim Blue","#5B3A29 Boot Brown","#4A7C59 Work Green"],"media":["Pearl Jam Twenty (2011) — documentary"]},"Grunge Girl":{"summary":"The feminine interpretation of grunge — baby doll dresses over ripped tights, Doc Martens, and the specific 1990s alternative femininity.","era":"c.1991–1996","mood":"Alternatively feminine, doc-booted","visual":"Baby doll or vintage floral dress. Ripped tights or fishnets. Doc Martens. Dark lipstick. Messy hair. The deliberate collision of feminine prettiness with punk roughness. Drew Barrymore circa 1993.","garments":["Baby doll or vintage floral dress","Ripped tights","Doc Martens boots","Dark lipstick","Messy uncombed hair"],"habitat":"1990s alternative culture, grunge revival, vintage dress communities.","context":"Grunge Girl was the feminine expression of grunge — it took vintage prettiness and roughened it with boots and torn tights. It influenced Kinderwhore but was less confrontational, more accessible.","rarity":"Niche","see_also":["Grunge","Hole Aesthetic","Kinderwhore"],"colors":["#C185A0 Floral Rose","#1A1A1A Boot Black","#8B0000 Dark Lip","#8B7355 Vintage Brown"],"media":["Reality Bites (1994) — film","My So-Called Life (TV, 1994) — TV"]},"Hole Aesthetic":{"summary":"The specific band aesthetic of Hole — Courtney Love's destroyed glamour applied to a full band context.","era":"c.1991–1998","mood":"Band-scale destroyed glamour","visual":"Courtney Love's smeared-lipstick baby doll aesthetic as band uniform. Vintage slips. Torn lace. Smeared makeup. Platform shoes. The aesthetic of a band that looked like they'd been fighting and then went straight on stage.","garments":["Vintage slip or baby doll dress","Smeared lipstick","Torn lace elements","Platform shoes","Messy bleached hair"],"habitat":"Hole fan culture, 1990s alternative rock, Courtney Love aesthetic heritage.","context":"Hole's look was Courtney Love's destroyed glamour scaled to a band — all four members dressed in variations of the baby doll/combat boot/smeared makeup vocabulary. Live Through This (1994) was both sonic and visual manifesto.","rarity":"Rare","see_also":["Courtney Love Aesthetic","Kinderwhore","Grunge Girl"],"colors":["#8B0000 Smeared Red","#F5C6CB Torn Pink","#1A1A1A Combat Black","#FAF8F5 Slip White"],"media":["Hole: Live Through This (1994) — music"]},"Grunge Femme":{"summary":"The contemporary, feminine-forward interpretation of grunge — softer than original grunge, more deliberate, and styled for 2020s sensibility.","era":"c.2015–present","mood":"Femininely grunge, styled-casual","visual":"Oversized flannel worn as dress. Fishnet tights. Platform boots. Dark lipstick. The grunge vocabulary applied with contemporary awareness — less accidentally dishevelled, more deliberately styled.","garments":["Oversized flannel as dress","Fishnet tights","Platform boots","Dark matte lipstick","Layered chain necklaces"],"habitat":"Contemporary alternative fashion, grunge revival communities.","context":"Grunge Femme reinterprets 1990s grunge through a contemporary feminine lens — more deliberate and styled than the original, incorporating platform boots and layered jewellery as updates.","rarity":"Common","see_also":["Grunge Girl","Soft Grunge","Alt Girl Aesthetic"],"colors":["#8B0000 Dark Lip","#1A1A1A Boot Black","#8B7355 Flannel Brown","#C0C0C0 Chain Silver"],"media":["Euphoria (TV series) — TV"]},"Grunge Revival":{"summary":"The periodic return of grunge aesthetics to mainstream fashion — flannel, ripped denim, and the 1990s as perpetual nostalgia.","era":"c.2010–present","mood":"Nostalgically grunge, cyclically revived","visual":"Flannel shirts, ripped jeans, combat boots — the core grunge vocabulary reinterpreted for each new generation. Each revival is slightly more polished than the original.","garments":["Flannel shirt","Ripped jeans","Combat boots","Band T-shirt","Layered thrift look"],"habitat":"Mainstream fashion, thrift stores, alternative fashion communities.","context":"Grunge revival cycles roughly every 5–7 years in fashion — each time slightly more stylised, slightly further from the original's genuine poverty-dress. The 2020s revival is the most polished yet.","rarity":"Common","see_also":["Grunge","Soft Grunge","Grunge Femme"],"colors":["#8B7355 Revival Flannel","#1B4F72 Faded Denim","#1A1A1A Black","#5B5B5B Washed Grey"],"media":["Nirvana revival cultural moment — cultural"]},"Runway Grunge":{"summary":"The designer interpretation of grunge aesthetics — Marc Jacobs 1992, Saint Laurent, and the luxury fashion industry's ongoing flirtation with anti-fashion.","era":"c.1992–present","mood":"Luxury anti-fashion, designer-dishevelled","visual":"Grunge elements at luxury prices — cashmere flannel, artfully ripped premium denim, $800 combat boots. The aesthetic of poverty performed with expensive materials.","garments":["Cashmere flannel shirt","Premium ripped denim","Luxury combat boots","Designer band T-shirt","Expensive thrift-adjacent styling"],"habitat":"Fashion runways, luxury retail, designer fashion.","context":"Marc Jacobs' 1992 Perry Ellis grunge collection got him fired but proved prophetic — luxury fashion has continuously returned to grunge's anti-fashion vocabulary ever since. The contradiction is the point.","rarity":"Niche","see_also":["Grunge","Grunge Revival","Anti-Fashion Aesthetic"],"colors":["#8B7355 Luxury Flannel","#1A1A1A Designer Black","#1B4F72 Premium Denim","#D4AF37 Luxury Gold"],"media":["Marc Jacobs: Perry Ellis Spring 1993 — fashion"]},"Grunge Luxe":{"summary":"The contemporary luxury-casual grunge crossover — expensive basics worn with grunge attitude, the rich kid in vintage flannel.","era":"c.2010s–present","mood":"Expensively casual, rich-kid grunge","visual":"High-quality basics in grunge silhouettes. Expensive leather jacket over vintage tee. Premium denim deliberately faded. The aesthetic of someone who has money but wants to look like they don't care.","garments":["Premium leather jacket","Quality vintage-style tee","Premium faded denim","Expensive simple boots","Cashmere beanie"],"habitat":"Luxury casual fashion, high-end vintage mix.","context":"Grunge Luxe is the permanent resolution of grunge's paradox — the anti-fashion aesthetic made into a luxury category. It's what happens when grunge's indifference becomes aspirational.","rarity":"Common","see_also":["Runway Grunge","Grunge Revival","Quiet Luxury"],"colors":["#1A1A1A Premium Black","#8B7355 Quality Brown","#1B4F72 Premium Denim","#5B5B5B Cashmere Grey"],"media":["Saint Laurent campaigns — fashion"]},"Soft Grunge":{"summary":"The Tumblr-era softening of grunge aesthetics — pastel and dark mixed, flower crowns with combat boots, and grunge made pretty.","era":"c.2011–2016","mood":"Pretty-dark, Tumblr-softened","visual":"Grunge elements softened with pastel and feminine touches. Floral dress under flannel. Doc Martens with floral socks. Dark lipstick with soft eye. The Tumblr curation of grunge as mood board rather than lived subculture.","garments":["Flannel over floral dress","Doc Martens with feminine socks","Dark lipstick","Soft grunge layering","Choker necklace"],"habitat":"Tumblr archives, soft grunge revival communities, Instagram alternative fashion.","context":"Soft Grunge was Tumblr's domestication of grunge — taking its visual vocabulary and making it pretty, photogenic, and shareable. The original grunge was never pretty; Soft Grunge always was.","rarity":"Common","see_also":["Pastel Grunge","Tumblr Grunge","Grunge Girl"],"colors":["#C185A0 Soft Rose","#1A1A1A Grunge Black","#B0C4DE Pastel Blue","#8B7355 Flannel"],"media":["Tumblr soft grunge tags (2011–16) — social media"]},"Pastel Grunge":{"summary":"The specific colour variant of Soft Grunge — pastel colours applied to grunge silhouettes, the most photographed Tumblr aesthetic of 2013.","era":"c.2012–2016","mood":"Pastel-dark, candy-grunge","visual":"Pastel pink, lavender, or mint applied to grunge silhouettes. Pastel hair with dark roots. Creepers or platforms in pastel. Soft colours with black accents. The deliberate collision of sweet and tough.","garments":["Pastel-coloured flannel or jacket","Pastel hair with dark roots","Platform creepers","Black accents on pastel base","Choker with pastel outfit"],"habitat":"Tumblr pastel grunge community, Instagram alternative fashion.","context":"Pastel Grunge was Soft Grunge's most photogenic variant — the pastel palette made it instantly shareable and distinctly different from original grunge's brown-and-grey palette.","rarity":"Niche","see_also":["Soft Grunge","Pastel Goth","Tumblr Grunge"],"colors":["#C185A0 Pastel Purple","#F5C6CB Pastel Pink","#B0C4DE Pastel Blue","#1A1A1A Grunge Black"],"media":["Tumblr pastel grunge (2012–16) — social media"]},"Tumblr Grunge":{"summary":"The Tumblr-curated version of grunge — mood boards of cigarettes, coffee, and melancholy layered over band T-shirts and black jeans.","era":"c.2011–2017","mood":"Curated melancholy, dashboard-grunge","visual":"Black skinny jeans. Oversized band tee or sweater. Choker. Doc Martens or Converse. The Tumblr curation added a specific melancholic, photographic quality to grunge that the original never had.","garments":["Black skinny jeans","Oversized band T-shirt","Choker necklace","Doc Martens or Converse","Layered rings and bracelets"],"habitat":"Tumblr archives, internet grunge communities.","context":"Tumblr Grunge was a specific internet aesthetic — grunge filtered through Tumblr's curatorial sensibility. It was more melancholic and photogenic than the original, and explicitly styled rather than genuinely dishevelled.","rarity":"Common","see_also":["Soft Grunge","Pastel Grunge","E-Girl"],"colors":["#1A1A1A Tumblr Black","#5B5B5B Grey","#8B7355 Coffee Brown","#C0C0C0 Silver"],"media":["Tumblr grunge aesthetic (2011–17) — social media"]},"Indie Rock Aesthetic":{"summary":"The early 2000s indie rock look — vintage-mix, thrift store finds, and the specific studied casual of the Pitchfork generation.","era":"c.2001–present","mood":"Studied casual, thrift-curated","visual":"Vintage band or graphic T-shirt. Slim or skinny jeans. Converse or Vans. Layered shirts. The look of someone who reads Pitchfork and shops at vintage stores with a specific knowledge of what they're looking for.","garments":["Vintage graphic T-shirt","Slim jeans","Converse or Vans","Layered shirts","Simple messenger bag"],"habitat":"Indie music venues, independent record stores, Pitchfork-adjacent communities.","context":"Indie Rock Aesthetic is the visual equivalent of the music — drawing from multiple sources (punk, thrift, art school) with a specific knowledge and curation that distinguishes it from mainstream alternative fashion.","rarity":"Common","see_also":["Strokes Aesthetic","Indie Sleaze","Hipster"],"colors":["#1A1A1A Indie Black","#8B7355 Thrift Brown","#1B4F72 Vintage Blue","#FAF8F5 Graphic White"],"media":["Garden State (2004) — film","500 Days of Summer (2009) — film"]},"Strokes Aesthetic":{"summary":"The specific early 2000s Lower East Side cool of The Strokes — leather jackets, skinny ties, and the studied casual that launched a thousand indie bands.","era":"c.2001–2006, New York","mood":"Studied cool, LES effortless","visual":"Leather jacket. Converse. Skinny jeans or dark trousers. Slightly dishevelled hair. The look of someone who spent two hours looking like they spent zero minutes. Julian Casablancas' half-unbuttoned shirts.","garments":["Leather jacket","Converse sneakers","Skinny dark jeans","Half-unbuttoned shirt","Slightly dishevelled hair"],"habitat":"Early 2000s indie rock, Lower East Side heritage, garage rock revival.","context":"The Strokes codified the early 2000s indie look — their Is This It album cover (a woman's hip in a black glove) was as influential as their music. Their effortless cool was, famously, extremely effortful.","rarity":"Niche","see_also":["Indie Rock Aesthetic","Indie Sleaze","New York Punk"],"colors":["#1A1A1A Leather Black","#FAF8F5 Shirt White","#8B7355 Cool Brown","#5B5B5B Downtown Grey"],"media":["The Strokes: Is This It (2001) — music","Meet Me in the Bathroom (2022) — documentary"]},"Indie Sleaze":{"summary":"The messy, party-all-night, art-school-adjacent look of mid-2000s indie culture — American Apparel, Vice magazine, and the Misshapes era.","era":"c.2005–2012; revival 2022–present","mood":"Messily nocturnal, art-party coded","visual":"American Apparel basics. Flash photography. Messy hair. Smudged eyeliner. The look of someone who went out at 11pm and hasn't been home yet. Slightly too-short dress or shorts. Vintage sunglasses at night.","garments":["American Apparel bodysuit or basic","Messy smudged eyeliner","Too-short dress or shorts","Vintage sunglasses at night","Flash-photography-ready outfit"],"habitat":"Late 2000s indie party culture, Misshapes-era New York, Vice magazine heritage.","context":"Indie Sleaze was named retrospectively during its 2022 revival — at the time it was just 'going out.' The aesthetic of flash-lit party photography, American Apparel, and deliberate messiness defined a pre-Instagram moment.","rarity":"Common","see_also":["Strokes Aesthetic","Hipster","Kate Moss Aesthetic"],"colors":["#1A1A1A Night Black","#FF6B6B Flash Pink","#8B7355 American Apparel Tan","#FAF8F5 Flash White"],"media":["Meet Me in the Bathroom (2022) — documentary","Skins (TV series) — TV"]},"Emo Aesthetic":{"summary":"The black-fringe, studded-belt, emotionally transparent dress of emo — My Chemical Romance theatricality to Fall Out Boy accessibility.","era":"c.2001–2009; revival 2020s","mood":"Emotionally transparent, fringe-hidden","visual":"Black side-swept fringe covering one eye. Skinny jeans. Studded belt. Band T-shirt. Converse. Eyeliner for all genders. The visual expression of emotional transparency through dark fashion.","garments":["Black side-swept fringe","Skinny black jeans","Studded belt","Band T-shirt","Eyeliner and dark eye makeup"],"habitat":"Emo communities, My Chemical Romance fan culture, Warped Tour heritage.","context":"Emo fashion was the visual expression of emotional honesty in a genre that made vulnerability its primary value. The black fringe hiding one eye was simultaneously concealment and expression.","rarity":"Common","see_also":["My Chemical Romance Aesthetic","Scene Aesthetic","Pop Punk Aesthetic"],"colors":["#1A1A1A Emo Black","#8B0000 MCR Red","#FAF8F5 Band White","#5B5B5B Liner Grey"],"media":["My Chemical Romance: The Black Parade (2006) — music"]},"Thursday Aesthetic":{"summary":"The earnest, post-hardcore version of emo — less theatrical than MCR, more literary, and dressed in the simple dark clothes of New Brunswick basement shows.","era":"c.1998–2012, New Brunswick NJ","mood":"Earnestly literary, basement-show sincere","visual":"Simple dark clothing. Less theatrical than mainstream emo. Band T-shirt and jeans. The earnest sincerity of the post-hardcore scene before it became commercially coded.","garments":["Simple dark T-shirt","Dark jeans","Basic shoes","Minimal styling","Earnest untheatrical presentation"],"habitat":"Post-hardcore communities, New Brunswick music heritage, Geoff Rickly fan culture.","context":"Thursday represented emo's literary, earnest wing — Geoff Rickly dressed simply and spoke about poetry. Their aesthetic was sincere rather than theatrical, New Brunswick basement rather than MTV stage.","rarity":"Rare","see_also":["Emo Aesthetic","Taking Back Sunday Aesthetic","Hardcore Punk"],"colors":["#1A1A1A Earnest Black","#5B5B5B Simple Grey","#8B7355 Basement Brown","#FAF8F5 White"],"media":["Thursday: Full Collapse (2001) — music"]},"Taking Back Sunday Aesthetic":{"summary":"The Long Island emo-pop look — studded belts, tight shirts, and the specific suburban alternative fashion of the TBS generation.","era":"c.2002–2008","mood":"Suburban-alternative, emo-pop accessible","visual":"Tight ringer T-shirt or band tee. Studded belt. Skinny jeans. Side-swept hair. The accessible, suburban version of emo — less theatrical than MCR, more styled than Thursday.","garments":["Tight ringer T-shirt","Studded belt","Skinny jeans","Side-swept hair","Wristbands"],"habitat":"Emo-pop communities, Long Island music heritage, Warped Tour.","context":"Taking Back Sunday represented emo's suburban-accessible wing — the look could be assembled at Hot Topic and the mall. Their audience dressed like the band because the band dressed like their audience.","rarity":"Niche","see_also":["Emo Aesthetic","Fall Out Boy Aesthetic","Pop Punk Aesthetic"],"colors":["#1A1A1A Emo Black","#FAF8F5 Ringer White","#8B0000 Belt Red","#5B5B5B Grey"],"media":["Taking Back Sunday: Tell All Your Friends (2002) — music"]},"My Chemical Romance Aesthetic":{"summary":"The theatrical, concept-album-driven visual world of My Chemical Romance — from I Brought You My Bullets to The Black Parade, the most visually ambitious emo band.","era":"c.2001–2013; reunion 2019–present","mood":"Theatrically dark, concept-album visual","visual":"Changes by album era: Bullets era — vampire horror. Three Cheers era — blood-stained hospital. Black Parade — military marching band in black. Danger Days — neon desert punk. Each era fully designed with costumes, makeup, and visual narrative.","garments":["Era-specific costume","Black Parade military jacket","Stage makeup","Black and red palette","Concept-driven accessories"],"habitat":"MCR fan culture (the MCRmy), emo heritage, theatrical rock communities.","context":"My Chemical Romance treated each album as a visual world — The Black Parade's military aesthetic was as considered as any fashion collection. Gerard Way's transition from emo to comic book creator (The Umbrella Academy) was a natural evolution.","rarity":"Common","see_also":["Emo Aesthetic","Fall Out Boy Aesthetic","Green Day Aesthetic"],"colors":["#1A1A1A Parade Black","#8B0000 MCR Red","#FAF8F5 Military White","#D4AF37 Brass Button"],"media":["My Chemical Romance: Life on the Murder Scene (2006) — documentary"]},"Fall Out Boy Aesthetic":{"summary":"The accessible, pop-punk-meets-emo look of Fall Out Boy — Pete Wentz's eyeliner, trucker hats, and emo made for arenas.","era":"c.2003–present","mood":"Accessibly emo, arena-scaled","visual":"Pete Wentz: heavy eyeliner, hoodies, skinny jeans, side-swept hair. Patrick Stump: trucker hat and glasses. The most commercially accessible version of emo — dark enough to be alternative, polished enough for MTV.","garments":["Heavy eyeliner","Skinny jeans","Band hoodie","Trucker hat","Clandestine Industries merch"],"habitat":"Pop-punk-emo crossover communities, Warped Tour heritage, FOB fan culture.","context":"Fall Out Boy bridged emo and mainstream pop — Pete Wentz's fashion influence extended beyond music into the founding of Clandestine Industries clothing line. Their aesthetic was the gateway for millions of teenagers into alternative culture.","rarity":"Common","see_also":["Emo Aesthetic","My Chemical Romance Aesthetic","Pop Punk Aesthetic"],"colors":["#1A1A1A Eyeliner Black","#FAF8F5 White","#8B0000 Red Accent","#D4AF37 Gold"],"media":["Fall Out Boy music videos — music video"]},"Emo Revival":{"summary":"The 2010s–2020s return of emo aesthetics and music — genuine new bands and nostalgic cosplay coexisting.","era":"c.2012–present","mood":"Revived-earnest, nostalgically sincere","visual":"Updated emo: skinny jeans, band tees, but with contemporary updates — more gender-fluid, more diverse, more aware of emo's original problems with inclusion.","garments":["Updated skinny jeans","Band T-shirt (new and vintage)","Eyeliner","Modern emo layering","Platform or chunky boots"],"habitat":"Emo revival music communities, When We Were Young festival.","context":"The Emo Revival produced both genuine new music (The World Is a Beautiful Place, American Football reunion) and nostalgic spectacle (When We Were Young festival). The aesthetic updated for inclusion.","rarity":"Common","see_also":["Emo Aesthetic","Modern Emo","Pop Punk Revival"],"colors":["#1A1A1A Revival Black","#8B0000 Red","#FAF8F5 White","#5B5B5B Grey"],"media":["When We Were Young Festival — cultural event"]},"Modern Emo":{"summary":"Contemporary emo fashion stripped of 2000s excess — cleaner, more gender-inclusive, and influenced by indie and shoegaze as much as punk.","era":"c.2015–present","mood":"Cleaned-up emo, indie-influenced","visual":"Dark but less theatrical than 2000s emo. Simple black or dark clothing. Less studded-belt, more quality basics. The fringe may be gone but the emotional transparency remains. Influence from math rock and shoegaze.","garments":["Simple dark quality basics","Band T-shirt (contemporary)","Dark jeans or trousers","Simple boots or sneakers","Minimal dark accessories"],"habitat":"Modern emo communities, indie-emo crossover venues.","context":"Modern Emo reflects the genre's evolution — less visual coding, more musical substance. The look is darker and simpler, influenced by shoegaze and math rock's understated presentations.","rarity":"Niche","see_also":["Emo Revival","Midwest Emo Aesthetic","Shoegaze Aesthetic"],"colors":["#1A1A1A Modern Black","#5B5B5B Clean Grey","#1B4F72 Dark Blue","#8B7355 Indie Brown"],"media":["American Football: LP2 (2016) — music"]},"Midwest Emo Aesthetic":{"summary":"The specific house-show, flannel-and-jeans look of Midwest emo — Cap'n Jazz, American Football, and the most understated wing of emotional music.","era":"c.1993–present, American Midwest","mood":"House-show understated, flannel-earnest","visual":"Flannel shirt. Jeans. Simple sneakers. The most understated possible presentation — these are musicians who play in basements and living rooms. The American Football house (on the album cover) as the defining image.","garments":["Flannel shirt","Simple jeans","Basic sneakers","Plain T-shirt","Glasses"],"habitat":"Midwest emo communities, house show circuits, Champaign-Urbana heritage.","context":"Midwest Emo's aesthetic is defined by its understatement — the American Football house on their debut cover became one of indie music's most recognisable images precisely because it was so ordinary.","rarity":"Niche","see_also":["Modern Emo","Emo Revival","Indie Rock Aesthetic"],"colors":["#8B7355 Flannel Brown","#5B5B5B House Grey","#4A7C59 Midwest Green","#FAF8F5 Plain White"],"media":["American Football: LP1 (1999) — music"]},"Scene Aesthetic":{"summary":"The hyper-coloured, MySpace-era explosion of emo's dark palette — neon extensions, raccoon eyes, and the most visually extreme youth subculture of the 2000s.","era":"c.2005–2012; revival 2020s","mood":"Hyper-coloured, MySpace-maximalist","visual":"Enormous teased hair with neon-coloured extensions. Heavy black eyeliner with coloured accents. Extremely tight skinny jeans. Band T-shirt. Neon accessories — kandi bracelets, bow clips, zebra print. The most visually extreme of the 2000s youth aesthetics.","garments":["Enormous teased hair with extensions","Heavy raccoon eyeliner","Super-skinny jeans","Neon accessories and kandi","Band T-shirt"],"habitat":"Scene revival communities, MySpace heritage, Warped Tour nostalgia.","context":"Scene took emo's dark palette and exploded it into colour — adding neon extensions, zebra print, and kandi bracelets from rave culture. It was designed to photograph well on MySpace profile pictures.","rarity":"Niche","see_also":["Scene Queen","Emo Aesthetic","MySpace Era Fashion"],"colors":["#FF6B6B Neon Pink","#39FF14 Neon Green","#1A1A1A Scene Black","#00BFFF Electric Blue"],"media":["Scene documentary — documentary"]},"Scene Queen":{"summary":"The hyper-visible, self-promoting MySpace Scene girl — enormous hair, extreme makeup, and the first generation of internet micro-celebrities.","era":"c.2006–2011","mood":"Self-promoting, MySpace-famous","visual":"The most extreme version of Scene — hair at maximum volume and colour. Makeup at maximum drama. Thousands of MySpace friends. Self-shot photographs from above ('the MySpace angle'). The first internet micro-celebrities.","garments":["Maximum-volume multicoloured hair","Extreme raccoon eye makeup","Bow accessories","Ultra-tight skinny jeans","Neon kandi and accessories"],"habitat":"MySpace legacy, Scene heritage, internet celebrity history.","context":"Scene Queens were the first generation of internet micro-celebrities — famous on MySpace before Instagram existed. Audrey Kitching, Kiki Kannibal, and others had hundreds of thousands of followers on a pre-influencer platform.","rarity":"Extinct","see_also":["Scene Aesthetic","MySpace Era Fashion","E-Girl"],"colors":["#FF6B6B Queen Pink","#39FF14 Neon Green","#1A1A1A Black","#D4AF37 Gold"],"media":["Scene Queens documentary — documentary"]},"Scene Revival":{"summary":"The 2020s TikTok-driven return of Scene aesthetics — neon hair extensions, raccoon eyes, and 2000s MySpace culture rediscovered.","era":"c.2021–present","mood":"Nostalgically neon, TikTok-revived","visual":"Scene elements updated for 2020s — neon hair clips and extensions, raccoon eyeliner, kandi bracelets. More gender-inclusive than the original. Often mixed with contemporary alt fashion elements.","garments":["Neon hair extensions","Raccoon eyeliner","Kandi bracelets","Skinny jeans or contemporary alt bottom","Band or graphic tee"],"habitat":"TikTok, Scene revival communities, alt fashion.","context":"Scene Revival on TikTok introduced the aesthetic to a generation who were toddlers during its original run. The revival is more inclusive and self-aware than the original.","rarity":"Common","see_also":["Scene Aesthetic","Emo Revival","Mallgoth Revival"],"colors":["#FF6B6B Revival Pink","#39FF14 Revival Green","#1A1A1A Black","#00BFFF Revival Blue"],"media":["TikTok #scenerevival — social media"]},"Y2K Scene":{"summary":"The specific intersection of Y2K revival and Scene aesthetics — combining early 2000s silhouettes with Scene's neon colourway.","era":"c.2022–present","mood":"Y2K-Scene fused, nostalgically neon","visual":"Y2K silhouettes (low-rise, baby tee, platform) in Scene colourways (neon, zebra print, raccoon eyes). The fusion of two early 2000s aesthetics that originally coexisted but are now combined.","garments":["Low-rise jeans with Scene belt","Baby tee with neon graphics","Platform boots","Raccoon eyeliner","Mixed Y2K-Scene accessories"],"habitat":"TikTok Y2K-Scene crossover, alt fashion communities.","context":"Y2K Scene is a TikTok-era fusion — combining two aesthetics that were adjacent in the early 2000s but are now experienced as a single nostalgic moment.","rarity":"Niche","see_also":["Scene Revival","Y2K Revival","Emo Revival"],"colors":["#FF6B6B Neon Pink","#87CEEB Y2K Blue","#1A1A1A Black","#C0C0C0 Chrome"],"media":["TikTok crossover content — social media"]},"Scenecore":{"summary":"The hardened, music-first version of Scene — less about hair and more about the bands, scene kids who actually go to shows.","era":"c.2006–2012","mood":"Music-first Scene, show-going authentic","visual":"Scene elements but more focused on band loyalty than hair architecture. Battle-tested — these scene kids actually attend shows, not just photograph well online. Slightly less extreme presentation.","garments":["Band T-shirt from attended shows","Skinny jeans","Scene-adjacent hair but less extreme","Vans or Converse","Kandi from actual events"],"habitat":"Scene music shows, Warped Tour, post-hardcore venues.","context":"Scenecore distinguishes the music-focused Scene participant from the MySpace-focused Scene Queen — the emphasis is on band attendance and community rather than online photographic presentation.","rarity":"Niche","see_also":["Scene Aesthetic","Emo Aesthetic","Pop Punk Aesthetic"],"colors":["#1A1A1A Band Black","#FF6B6B Scene Pink","#FAF8F5 White","#5B5B5B Venue Grey"],"media":["Warped Tour documentary — documentary"]},"Soft Emo":{"summary":"The gentler, more wearable version of emo fashion — dark but not theatrical, emotionally coded but office-compatible.","era":"c.2015–present","mood":"Gently dark, wearably emotional","visual":"Dark basics with subtle emo coding — a small band pin, dark nail polish, subtle eyeliner. The emo aesthetic toned down for daily wear. Dark but not dramatic.","garments":["Dark quality basics","Subtle eyeliner","Small band pin or enamel pin","Dark nail polish","Simple dark boots or sneakers"],"habitat":"Everyday alternative fashion, office-compatible dark dressing.","context":"Soft Emo is emo grown up — the aesthetic adapted for people who still love the music but work in environments that don't allow full Scene presentation.","rarity":"Common","see_also":["Emo Aesthetic","Soft Goth","Modern Emo"],"colors":["#1A1A1A Soft Black","#5B5B5B Dark Grey","#8B0000 Subtle Red","#2C2C2C Charcoal"],"media":["Contemporary emo fashion — cultural"]},"Pastel Emo":{"summary":"The pastel-coloured variant of emo — pink and lavender replacing black, maintaining the emotional transparency but softening the palette.","era":"c.2015–present","mood":"Pastel-emotional, soft-dark","visual":"Pastel pink, lavender, or baby blue replacing emo's traditional black. Maintaining emo elements — fringe, eyeliner, skinny silhouette — but in soft colours. The emotional content remains; the darkness becomes gentle.","garments":["Pastel-coloured emo outfit","Soft-coloured eyeliner","Pastel hair","Emo silhouette in gentle tones","Soft accessories"],"habitat":"Pastel emo communities, Tumblr-to-Instagram aesthetic migration.","context":"Pastel Emo applies the same logic as Pastel Goth — taking a dark subculture and inverting its palette while maintaining its emotional content and silhouette.","rarity":"Niche","see_also":["Soft Emo","Pastel Goth","Emo Kawaii"],"colors":["#C185A0 Pastel Purple","#F5C6CB Pastel Pink","#B0C4DE Pastel Blue","#E8D5B0 Soft Cream"],"media":["Pastel emo aesthetic — social media"]},"Emo Kawaii":{"summary":"The fusion of emo aesthetics and Japanese kawaii cute — Hello Kitty on a studded belt, tears with heart stickers, sad-cute as a complete system.","era":"c.2015–present","mood":"Sad-cute, emo-kawaii fused","visual":"Emo elements (dark clothing, eyeliner, emotional content) combined with kawaii elements (plushies, pastel accents, cute accessories). Hello Kitty or Sanrio mixed with band merch. Tears as aesthetic element.","garments":["Emo outfit with kawaii accessories","Sanrio-themed accessories","Mixed dark and cute elements","Pastel accents on black base","Cute plushie as accessory"],"habitat":"Emo-kawaii crossover communities, Sanrio-alternative fusion.","context":"Emo Kawaii combines two aesthetics that share an emotional register — both value vulnerability and feeling. The fusion works because both emo and kawaii centre emotional expression.","rarity":"Niche","see_also":["Pastel Emo","Soft Emo","Sanrio Aesthetic"],"colors":["#1A1A1A Emo Black","#F5C6CB Kawaii Pink","#FF6B6B Sanrio Red","#B0C4DE Cute Blue"],"media":["Emo-kawaii crossover content — social media"]},"Garage Band Aesthetic":{"summary":"The simple, un-produced look of the garage band — rehearsal-room fashion, the aesthetic of musicians before they can afford stage clothes.","era":"c.1960s–present","mood":"Unproduced, rehearsal-room authentic","visual":"Whatever you wore to practice. T-shirt and jeans. The look of someone who plays music in a garage and hasn't had time to develop a stage image. Authentically un-styled.","garments":["Plain T-shirt","Jeans","Whatever shoes you own","No styled hair","Instrument as main accessory"],"habitat":"Garage band culture, DIY music communities, rehearsal spaces.","context":"The Garage Band Aesthetic is fashion's degree zero — the look of musicians before image. The Ramones codified it; every band that plays its first gig in the clothes they rehearsed in perpetuates it.","rarity":"Common","see_also":["DIY Band Aesthetic","Indie Rock Aesthetic","Pop Punk Aesthetic"],"colors":["#1A1A1A Basic Black","#FAF8F5 Plain White","#1B4F72 Denim Blue","#5B5B5B Grey"],"media":["Wayne's World (1992) — film","School of Rock (2003) — film"]},"DIY Band Aesthetic":{"summary":"The deliberately handmade, self-produced visual identity of independent bands — screen-printed merch, hand-drawn flyers, and the aesthetic of doing it yourself.","era":"c.1980s–present","mood":"Handmade-independent, self-produced","visual":"Hand-screen-printed T-shirts. Hand-drawn show flyers. DIY album art. The visual identity built from Sharpies, photocopiers, and screen-printing kits rather than graphic design studios.","garments":["Hand-printed band T-shirt","DIY patch jacket","Self-produced merch","Hand-drawn visual identity","Simple practical clothing"],"habitat":"DIY music communities, independent venue circuits, zine culture.","context":"DIY Band Aesthetic is punk's creative economy applied to visual identity — bands who can't afford design studios make their own visual world. The handmade quality becomes the aesthetic value.","rarity":"Niche","see_also":["Garage Band Aesthetic","DIY Punk","Indie Rock Aesthetic"],"colors":["#1A1A1A Screen Print Black","#FAF8F5 Print White","#8B0000 Ink Red","#5B5B5B Photocopy Grey"],"media":["We Jam Econo: The Story of the Minutemen (2005) — documentary"]},"Bedroom Pop Fashion":{"summary":"The lo-fi, home-recorded music aesthetic made dress — the visual culture of artists who record in bedrooms and dress accordingly.","era":"c.2015–present","mood":"Lo-fi domestic, bedroom-recorded","visual":"Comfortable, domestic clothing — oversized sweaters, pyjama-adjacent pieces, soft textures. The look of someone who records in their bedroom and doesn't change clothes to perform. Clairo and Rex Orange County as references.","garments":["Oversized comfortable sweater","Simple soft trousers","Bedroom-comfortable shoes","Natural unstyled hair","Glasses or simple accessories"],"habitat":"Bedroom pop communities, lo-fi music culture, Spotify bedroom pop playlists.","context":"Bedroom Pop fashion reflects its production context — music made at home in comfortable clothes. The aesthetic signals authenticity through domesticity, the opposite of stadium rock performance.","rarity":"Common","see_also":["Lo-Fi Aesthetic","Indie Rock Aesthetic","Soft Emo"],"colors":["#E8D5B0 Bedroom Cream","#5B5B5B Soft Grey","#B0C4DE Gentle Blue","#8B7355 Cozy Brown"],"media":["Clairo: Diary 001 (2018) — music"]},"Emo Nite Aesthetic":{"summary":"The specific dress of Emo Nite club events — nostalgic emo fashion worn out to dedicated emo DJ nights, 2000s revival as weekly ritual.","era":"c.2014–present","mood":"Nostalgically emo, club-night coded","visual":"Revived emo fashion for a night out — band tees, eyeliner, skinny jeans, studded belts. Often mixed with contemporary going-out elements. The specific look of someone dressed for an emo-themed club night.","garments":["Band T-shirt dressed up for going out","Eyeliner","Skinny jeans or dark trousers","Studded belt or chain","Going-out boots or platforms"],"habitat":"Emo Nite LA and global events, emo-themed club nights.","context":"Emo Nite began in LA in 2014 and went global — dedicated club nights playing 2000s emo. The aesthetic is emo fashion revived specifically for nightlife context, often by people who were teenagers during the original era.","rarity":"Common","see_also":["Emo Revival","Scene Revival","Going Out Aesthetic"],"colors":["#1A1A1A Emo Night Black","#8B0000 Red Accent","#FAF8F5 Band Tee White","#C0C0C0 Chain Silver"],"media":["Emo Nite events — cultural"]},"Ballroom Aesthetic":{"summary":"The spectacular, competitive dress of ballroom culture — categories, houses, and fashion as survival art in Black and Latino LGBTQ+ communities.","era":"c.1960s–present, New York/global","mood":"Competitively spectacular, house-proud","visual":"Category-dependent: Realness (passing as a specific social category), Vogue (athletic dance fashion), Face (beauty competition), Runway (modelling walk). Each category demands specific visual excellence. Designer labels central.","garments":["Category-specific presentation","Designer labels as aspirational identity","Competition-grade fashion","House-specific colours or codes","Vogue-ready performance wear"],"habitat":"Ballroom events, house communities, vogueing scenes worldwide.","context":"Ballroom culture created a complete alternative fashion system for Black and Latino LGBTQ+ communities excluded from mainstream fashion. Paris is Burning (1990) documented it; Pose (2018) mainstreamed it. Houses function as chosen families.","rarity":"Niche","see_also":["Vogue Fashion","House Mother Aesthetic","Drag Queen Aesthetic"],"colors":["#D4AF37 Trophy Gold","#8B0000 Category Red","#C0C0C0 Runway Silver","#1A1A1A Night Black"],"media":["Paris Is Burning (1990) — documentary","Pose (TV series, 2018–21) — TV"]},"Vogue Fashion":{"summary":"The athletic, movement-based fashion of vogueing — clothing that allows the five elements (hand performance, catwalk, duckwalk, floor work, spins/dips) while looking flawless.","era":"c.1970s–present","mood":"Athletically flawless, movement-demanding","visual":"Clothing that allows extreme movement while maintaining visual perfection. Tight-fitting or bodysuit bases. Statement pieces that move with the dancer. High heels for femme categories. The body as the primary fashion element.","garments":["Movement-allowing bodysuit","Statement fashion piece","High heels for femme vogue","Designer accessory","Competition-grade presentation"],"habitat":"Vogueing events, ballroom culture, dance competitions.","context":"Madonna's 'Vogue' (1990) brought the dance to mainstream attention; the actual culture is far deeper, more competitive, and more meaningful than a pop single. The five elements of vogue demand specific clothing solutions.","rarity":"Niche","see_also":["Ballroom Aesthetic","House Mother Aesthetic","Drag Queen Aesthetic"],"colors":["#D4AF37 Gold","#C0C0C0 Silver","#1A1A1A Black","#FAF8F5 Spotlight White"],"media":["Paris Is Burning (1990) — documentary","Pose (TV series) — TV"]},"House Mother Aesthetic":{"summary":"The specific authority and elegance of the ballroom House Mother — matriarchal glamour, community leadership, and fashion mentorship as family structure.","era":"c.1970s–present","mood":"Matriarchally elegant, community-leading","visual":"Elegant, authoritative presence. Designer pieces worn with confidence and knowledge. The House Mother dresses both as personal expression and as role model for house children. Less competitive display, more settled authority.","garments":["Elegant authoritative outfit","Signature personal style","Designer pieces worn with knowledge","Statement jewellery","Confident settled presentation"],"habitat":"Ballroom culture, house family structures.","context":"The House Mother in ballroom culture serves as fashion mentor, family elder, and community leader. Their dress communicates authority and experience — they have already won their trophies and now guide others.","rarity":"Rare","see_also":["Ballroom Aesthetic","Vogue Fashion","Drag Queen Aesthetic"],"colors":["#D4AF37 Matriarch Gold","#4B0082 Authority Purple","#1A1A1A Evening Black","#C0C0C0 Silver"],"media":["Pose (TV series) — TV","Paris Is Burning (1990) — documentary"]},"Chicago House Aesthetic":{"summary":"The warehouse-party dress of Chicago house music's origins — functional dance clothing, sweat-ready, and the visual culture of the Warehouse and Music Box.","era":"c.1984–1990, Chicago","mood":"Warehouse-functional, sweat-ready","visual":"Functional dance clothing — loose enough to move, dark enough for the warehouse. Tank tops, loose trousers, sneakers. The aesthetic is determined by dancing for hours in hot warehouses. Frankie Knuckles' Warehouse as the origin space.","garments":["Loose dance-ready tank top","Comfortable dark trousers","Dance sneakers","Simple functional layers","Sweat-ready clothing"],"habitat":"Chicago house music heritage, warehouse dance culture.","context":"Chicago house was born in the Warehouse club where Frankie Knuckles DJed. The fashion was entirely functional — you dressed to dance for eight hours in a hot room. This functionalism became its own aesthetic.","rarity":"Extinct","see_also":["Detroit Techno Aesthetic","UK Rave Aesthetic","Berlin Techno Fashion"],"colors":["#1A1A1A Warehouse Black","#5B5B5B Sweat Grey","#FAF8F5 Tank White","#8B7355 Dance Brown"],"media":["Pump Up the Volume (1990) — documentary"]},"Detroit Techno Aesthetic":{"summary":"The Afrofuturist, machine-influenced dress of Detroit techno's originators — Juan Atkins, Derrick May, and Kevin Saunderson imagining the future from the Motor City.","era":"c.1985–present, Detroit","mood":"Afrofuturistically urban, machine-city coded","visual":"Dark, futuristic, machine-influenced. Black and metallics. The aesthetic of someone imagining the future from a declining industrial city. Less about excess, more about vision. Afrofuturist references.","garments":["Dark futuristic clothing","Metallic accents","Simple geometric shapes","Machine-influenced accessories","Afrofuturist elements"],"habitat":"Detroit techno heritage, Movement festival, Afrofuturist communities.","context":"Detroit Techno was created by three Black men imagining a future from a post-industrial city — the aesthetic reflects that Afrofuturist vision. Juan Atkins named his label 'Metroplex' after Fritz Lang's Metropolis.","rarity":"Rare","see_also":["Chicago House Aesthetic","Berlin Techno Fashion","Afrofuturism"],"colors":["#1A1A1A Machine Black","#C0C0C0 Motor Silver","#1B4F72 Detroit Blue","#D4AF37 Future Gold"],"media":["High Tech Soul (2006) — documentary","God Said Give 'Em Drum Machines (2023) — documentary"]},"UK Rave Aesthetic":{"summary":"The fluorescent, smiley-face, warehouse-party dress of late 1980s British rave culture — the Second Summer of Love made wearable.","era":"c.1988–1992, Britain","mood":"Ecstatically fluorescent, acid-smiley","visual":"Fluorescent colours — yellow, green, pink. Smiley face motif everywhere. Baggy clothes for dancing. Dungarees. Bucket hats. Glow accessories. Whistles. The aesthetic of illegal warehouse parties and motorway service station meet-ups.","garments":["Fluorescent T-shirt or hoodie","Smiley face motif","Baggy dungarees or trousers","Bucket hat","Glow sticks and whistles"],"habitat":"UK rave heritage, acid house history, Second Summer of Love commemorations.","context":"The UK's 1988 acid house explosion produced an aesthetic of deliberate euphoria — fluorescent colours, smiley faces, and baggy clothes for dancing. The Criminal Justice Act 1994 specifically targeted these gatherings.","rarity":"Niche","see_also":["Acid House Fashion","PLUR Aesthetic","Rave Fashion 1990s"],"colors":["#FFFF00 Acid Yellow","#39FF14 Fluorescent Green","#FF6B6B Neon Pink","#1A1A1A Night Black"],"media":["Human Traffic (1999) — film","24 Hour Party People (2002) — film"]},"Acid House Fashion":{"summary":"The specific smiley-face, fluorescent dress of acid house — the visual brand of the most consequential youth movement in British history since punk.","era":"c.1987–1990, Britain","mood":"Smiley-euphoric, chemically influenced","visual":"The smiley face as universal symbol. Fluorescent and neon colours. Bandana or headband. Baggy jeans or dungarees. The visual shorthand for an experience that changed British youth culture permanently.","garments":["Smiley face T-shirt","Fluorescent bandana","Baggy jeans or dungarees","Bucket hat","Neon accessories"],"habitat":"Acid house heritage, Haçienda legacy, British dance music history.","context":"The acid house smiley face became the most reproduced symbol of the era — it appeared on T-shirts, flyers, and pills. The symbol's simplicity made it a perfect viral image before the internet existed.","rarity":"Extinct","see_also":["UK Rave Aesthetic","Second Summer of Love","Haçienda Aesthetic"],"colors":["#FFFF00 Smiley Yellow","#1A1A1A Black","#39FF14 Acid Green","#FF6B6B Fluorescent Pink"],"media":["24 Hour Party People (2002) — film"]},"Second Summer of Love":{"summary":"The 1988–89 British cultural explosion — acid house, warehouse parties, and the brief utopian moment when class, race, and region dissolved on the dance floor.","era":"c.1988–1989, Britain","mood":"Briefly utopian, culturally explosive","visual":"Fluorescent colours against the British grey. Dungarees and smiley faces. The specific visual joy of a cold country having its most euphoric cultural moment. Fields, warehouses, and motorway service stations as fashion venues.","garments":["Smiley face everything","Dungarees","Fluorescent layers","Bandana","Dancing shoes"],"habitat":"1988–89 British cultural memory, acid house heritage.","context":"The Second Summer of Love was Britain's most significant youth culture event since punk — briefly dissolving class and regional barriers on the dance floor. The fashion was as utopian as the rhetoric.","rarity":"Extinct","see_also":["Acid House Fashion","UK Rave Aesthetic","Haçienda Aesthetic"],"colors":["#FFFF00 Summer Yellow","#39FF14 Field Green","#FF6B6B Pink","#87CEEB Sky Blue"],"media":["24 Hour Party People (2002) — film","Beats (2019) — film"]},"Haçienda Aesthetic":{"summary":"The specific look of Manchester's legendary Haçienda nightclub — Factory Records design, Ben Kelly's interior, and Madchester fashion on the dance floor.","era":"c.1982–1997, Manchester","mood":"Factory-designed, Madchester-danced","visual":"Ben Kelly's interior design — hazard stripes, industrial chic. The patrons: Madchester baggy — flared jeans, floppy fringes, bucket hats, loose shirts. Peter Saville's typography on everything. The intersection of dance culture and indie design.","garments":["Baggy flared jeans","Floppy fringe hair","Bucket hat","Loose patterned shirt","Adidas or simple trainers"],"habitat":"Haçienda legacy events, Manchester music heritage, Factory Records culture.","context":"The Haçienda was simultaneously a nightclub, a design statement, and a cultural laboratory. It lost money consistently but produced the Madchester movement and changed British popular culture permanently.","rarity":"Extinct","see_also":["Madchester Fashion","Acid House Fashion","UK Rave Aesthetic"],"colors":["#FFFF00 Hazard Yellow","#1A1A1A Factory Black","#5B5B5B Industrial Grey","#8B0000 Stripe Red"],"media":["24 Hour Party People (2002) — film"]},"Madchester Fashion":{"summary":"The specific baggy, ecstasy-era look of Manchester 1988–92 — Happy Mondays' Shaun Ryder, Stone Roses' floppy fringes, and dance-rock dressed accordingly.","era":"c.1988–1992, Manchester","mood":"Baggily euphoric, Madchester-specific","visual":"Extremely baggy flared jeans (Joe Bloggs brand). Oversized patterned shirts. Floppy fringe haircut. Bucket hat. Adidas trainers. The specific look of Manchester's dance-rock crossover moment.","garments":["Joe Bloggs baggy flared jeans","Oversized patterned shirt","Floppy fringe haircut","Bucket hat","Adidas trainers"],"habitat":"Madchester heritage, Stone Roses and Happy Mondays fan culture.","context":"Madchester fashion was determined by its context — baggy jeans for dancing, loose shirts for sweating, bucket hats for all-night outdoor parties. Joe Bloggs jeans were the canonical garment. The look lasted about four years.","rarity":"Extinct","see_also":["Haçienda Aesthetic","Britpop Aesthetic","UK Rave Aesthetic"],"colors":["#1B4F72 Stone Roses Blue","#FFFF00 Madchester Yellow","#8B7355 Baggy Brown","#FAF8F5 Patterned White"],"media":["24 Hour Party People (2002) — film","Spike Island (2012) — film"]},"PLUR Aesthetic":{"summary":"The Peace Love Unity Respect philosophy of rave culture expressed through kandi bracelets, neon colours, and the visual language of communal euphoria.","era":"c.1990–present","mood":"Communally euphoric, kandi-beaded","visual":"Handmade kandi bead bracelets traded between ravers. Neon colours. Smiley faces. Comfortable dancing clothing. The PLUR handshake (trading kandi) as social ritual. Furry boots and legwarmers at festivals.","garments":["Kandi bead bracelets","Neon clothing","Furry boots or legwarmers","Comfortable dance clothing","PLUR-themed accessories"],"habitat":"Rave communities, EDM festivals, kandi-trading culture.","context":"PLUR originated in the 1990s rave scene as a philosophical framework — Peace, Love, Unity, Respect. The kandi bracelet trade is its material expression, a gift economy operating within commercial festivals.","rarity":"Niche","see_also":["Kandi Aesthetic","UK Rave Aesthetic","EDM Festival Aesthetic"],"colors":["#FF6B6B Neon Pink","#39FF14 Neon Green","#FFFF00 Neon Yellow","#00BFFF Electric Blue"],"media":["Under the Electric Sky (2014) — documentary"]},"Kandi Aesthetic":{"summary":"The specific visual culture of kandi bracelets and beaded accessories in rave culture — handmade, traded, and worn as social memory.","era":"c.1990s–present","mood":"Handmade-social, bead-memoried","visual":"Arms covered in handmade plastic bead bracelets (kandi). Each bracelet commemorates an event, a friendship, or a trade. Neon and pastel colours. Often stacked from wrist to elbow. Perler bead cuffs and necklaces for elaborate versions.","garments":["Multiple kandi bead bracelets","Perler bead cuffs","Neon beaded accessories","Traded friendship bracelets","Full kandi arm coverage"],"habitat":"Rave and EDM festival communities, kandi crafting communities.","context":"Each kandi bracelet tells a story — made for a specific event, traded with a specific person, wearing the memory of a specific night. The arms of a longtime raver are an autobiography in beads.","rarity":"Niche","see_also":["PLUR Aesthetic","EDM Festival Aesthetic","Rave Fashion 1990s"],"colors":["#FF6B6B Bead Pink","#39FF14 Bead Green","#FFFF00 Bead Yellow","#00BFFF Bead Blue"],"media":["Under the Electric Sky (2014) — documentary"]},"Jungle / Drum and Bass Aesthetic":{"summary":"The dark, urban, fast-moving dress of jungle and drum and bass culture — dark clothing, hoodies, and the nocturnal energy of 170 BPM.","era":"c.1991–present, UK","mood":"Nocturnally urban, fast-moving","visual":"Dark colours — black, navy, dark grey. Hoodies. Simple trainers. The aesthetic is urban, nocturnal, and fast. Less neon than rave culture — jungle's darkness is part of its identity. Moschino caps in the early days.","garments":["Dark hoodie","Simple trainers","Dark jeans or tracksuit","Cap or beanie","Minimal dark presentation"],"habitat":"Jungle and DnB communities, UK bass music culture.","context":"Jungle and drum and bass emerged from UK rave culture but took a darker, more urban direction. The fashion followed — less fluorescent, more functional, dressed for dark clubs rather than fields.","rarity":"Niche","see_also":["UK Rave Aesthetic","Berlin Techno Fashion","Drill Aesthetic"],"colors":["#1A1A1A Jungle Black","#1B4F72 Dark Navy","#5B5B5B Urban Grey","#D4AF37 Moschino Gold"],"media":["Jungle Fever (1994) — documentary"]},"Berlin Techno Fashion":{"summary":"The all-black, industrial-minimal dress of Berlin's techno scene — Berghain's door policy as fashion arbiter, and darkness as creative freedom.","era":"c.1989–present, Berlin","mood":"Industrially minimal, Berghain-coded","visual":"All black. Simple, dark, minimal. Leather, PVC, harness elements acceptable. No bright colours. No flashy brands. The aesthetic is deliberately anti-glamorous — the darkness of the club provides creative anonymity.","garments":["All-black clothing","Simple dark T-shirt","Black jeans or trousers","Leather or harness elements","Dark minimal boots"],"habitat":"Berlin techno clubs, Berghain and Tresor legacy, German electronic music culture.","context":"Berlin techno fashion is inseparable from Berghain's infamous door policy — dress too fancy or too tourist and you won't get in. The all-black minimal look signals belonging. The club's darkness is deliberate creative freedom.","rarity":"Niche","see_also":["Berghain Aesthetic","Minimal Techno Fashion","Industrial Goth"],"colors":["#1A1A1A Berghain Black","#2C2C2C Dark","#5B5B5B Concrete Grey","#C0C0C0 Steel"],"media":["Berlin Calling (2008) — film"]},"Berghain Aesthetic":{"summary":"The specific dark, industrial, body-positive dress code of the world's most famous techno club — all black, no phones, and freedom through anonymity.","era":"c.2004–present, Berlin","mood":"Anonymously free, industrially intimate","visual":"All black. Leather. Harness. Simple dark clothing. No bright colours, no flashy logos, no phones (cameras covered at the door). The aesthetic creates a space where appearance is secondary to experience.","garments":["All-black base","Leather or harness elements","Simple dark boots","No bright colours or logos","Body-positive presentation"],"habitat":"Berghain club, Berlin techno culture.","context":"Berghain's dress code and no-phone policy create a space where fashion becomes secondary to experience — the darkness and anonymity allow freedom of expression that visibility would inhibit.","rarity":"Niche","see_also":["Berlin Techno Fashion","Minimal Techno Fashion","Industrial Goth"],"colors":["#1A1A1A Total Black","#2C2C2C Leather Dark","#5B5B5B Industrial Grey","#C0C0C0 Metal"],"media":["Berlin Calling (2008) — film"]},"Minimal Techno Fashion":{"summary":"The stripped-back, anti-decorative dress of minimal techno culture — less is more applied to both sound and wardrobe.","era":"c.2000s–present","mood":"Stripped-back, anti-decorative","visual":"Pure minimalism in dark tones. Simple black T-shirt. Black trousers. Plain dark shoes. No logos, no decoration, no colour. The visual equivalent of Richie Hawtin's stripped-back sound.","garments":["Plain black T-shirt","Simple black trousers","Undecorated dark shoes","No logos or brand display","Minimal accessories"],"habitat":"Minimal techno events, Richie Hawtin and Ricardo Villalobos fan culture.","context":"Minimal Techno fashion applies the genre's philosophy to dress — strip everything back to essentials. The result is one of the most austere fashion aesthetics in any music culture.","rarity":"Niche","see_also":["Berlin Techno Fashion","Berghain Aesthetic","Normcore"],"colors":["#1A1A1A Minimal Black","#2C2C2C Dark","#5B5B5B Grey","#FAF8F5 Rare White"],"media":["Berlin Calling (2008) — film"]},"UK Club Aesthetic":{"summary":"The broader dress culture of British nightclubs — from Fabric to Ministry of Sound, the specific fashion language of going out in Britain.","era":"c.1990s–present, Britain","mood":"Going-out specific, UK-club coded","visual":"Varies by venue and era but generally: dressed up more than Americans, less formally than continental Europeans. Short dresses and heels for women. Smart-casual to smart for men. The UK's specific going-out culture.","garments":["Going-out dress or outfit","Heeled shoes","Smart-casual menswear","Club-appropriate accessories","Queue-waiting outerwear"],"habitat":"British nightclub culture, UK going-out communities.","context":"UK club fashion has its own vocabulary distinct from American or European equivalents — the British relationship with going out, queuing, and dressing up creates specific fashion solutions.","rarity":"Common","see_also":["Going Out Aesthetic","Club Fashion","Berlin Techno Fashion"],"colors":["#1A1A1A Club Black","#D4AF37 Going Out Gold","#8B0000 Club Red","#C0C0C0 Sequin Silver"],"media":["Skins (TV series) — TV","Human Traffic (1999) — film"]},"Raver / Rave Culture":{"summary":"The general visual culture of rave — across all decades and regional variations, the dress of people who dance all night to electronic music.","era":"c.1988–present, global","mood":"Dance-functional, communally euphoric","visual":"Comfortable clothing that allows movement. Bright or neon for visibility. Kandi bracelets. Water bottle as essential accessory. The constant across all rave variations: the clothing must work for dancing for hours.","garments":["Comfortable dance clothing","Neon or bright elements","Comfortable trainers","Kandi or festival accessories","Hydration essentials"],"habitat":"Raves, festivals, electronic music events worldwide.","context":"Rave fashion across all its variations shares one principle: the clothing must serve the dancing. Everything else — neon, kandi, brands — is regional and temporal variation on that functional base.","rarity":"Common","see_also":["UK Rave Aesthetic","PLUR Aesthetic","EDM Festival Aesthetic"],"colors":["#FF6B6B Neon Pink","#39FF14 Neon Green","#FFFF00 Acid Yellow","#1A1A1A Night Black"],"media":["Under the Electric Sky (2014) — documentary"]},"EDM Festival Aesthetic":{"summary":"The commercial, mainstream festival fashion of EDM culture — neon bikini tops, face gems, and Coachella-adjacent festival fashion.","era":"c.2010–present","mood":"Commercially festive, neon-decorated","visual":"Neon bikini or crop top. Face gems and glitter. Flower crown or festival headpiece. High-waisted shorts. Comfortable boots or trainers. The aesthetic of large commercial electronic festivals — Tomorrowland, Ultra, EDC.","garments":["Neon crop top or bikini","Face gems and glitter","Festival headpiece or flower crown","High-waisted shorts","Comfortable festival boots"],"habitat":"EDM festivals (Tomorrowland, Ultra, EDC), commercial electronic music culture.","context":"EDM Festival fashion is the commercial mainstreaming of rave aesthetics — neon and glitter from underground culture packaged for Coachella and Tomorrowland's Instagram-ready audiences.","rarity":"Common","see_also":["Coachella Fashion","PLUR Aesthetic","Raver / Rave Culture"],"colors":["#FF6B6B Festival Pink","#39FF14 Festival Green","#FFFF00 Festival Yellow","#D4AF37 Glitter Gold"],"media":["Under the Electric Sky (2014) — documentary"]},"Coachella Fashion":{"summary":"The Instagram-era festival fashion of Coachella — flower crowns, boho dresses, and the most photographed festival fashion event in the world.","era":"c.2010–present, Indio, California","mood":"Instagram-boho, commercially festive","visual":"Boho dresses and fringe. Flower crowns. Denim shorts. Ankle boots. Flash tattoos. The aesthetic designed as much for Instagram as for music. Coachella is now as much a fashion event as a music festival.","garments":["Boho dress or fringe","Flower crown","Denim shorts","Ankle boots","Flash tattoos and body jewellery"],"habitat":"Coachella festival, festival fashion content, Instagram.","context":"Coachella transformed from a music festival into a fashion event around 2010 — sponsored 'brand houses,' celebrity sightings, and Instagram content became as important as the musical performances.","rarity":"Common","see_also":["EDM Festival Aesthetic","Festival Folk","Boho Feminine"],"colors":["#D4AF37 Desert Gold","#C1440E Terracotta","#87CEEB California Blue","#FAF8F5 White"],"media":["Coachella: 20 Years in the Desert (2020) — documentary"]},"Hyperpop Fashion":{"summary":"The glitched, maximalist, post-internet fashion of hyperpop music — 100 gecs chaos, Charli XCX edge, and the aesthetic of too much at maximum volume.","era":"c.2018–present","mood":"Maximally glitched, post-internet chaotic","visual":"Deliberately overwhelming. Clashing colours. DIY and couture mixed. Gender-fluid. Platform everything. The aesthetic of music that processes pop through a distortion pedal — beautiful and ugly simultaneously.","garments":["Clashing coloured outfit","Platform shoes or boots","Gender-fluid pieces","DIY mixed with designer","Deliberately overwhelming accessories"],"habitat":"Hyperpop communities, PC Music adjacent culture, post-internet fashion.","context":"Hyperpop fashion mirrors its sound — pop processed through distortion until it becomes something new. 100 gecs' chaotic visual presentation and Charli XCX's club-ready futurism are its two poles.","rarity":"Niche","see_also":["PC Music Aesthetic","E-Girl","Cyber Goth"],"colors":["#FF6B6B Glitch Pink","#39FF14 Glitch Green","#00BFFF Glitch Blue","#FFFF00 Glitch Yellow"],"media":["100 gecs music videos — music video"]},"PC Music Aesthetic":{"summary":"The glossy, hyper-manufactured, post-internet pop aesthetic of the PC Music label — SOPHIE, A.G. Cook, and pop perfected into plastic.","era":"c.2013–present, London","mood":"Hyper-glossy, plastic-perfected","visual":"Glossy, hyper-smooth surfaces. Plastic and metallic textures. Hyper-feminine or hyper-processed presentation. The visual equivalent of music that sounds like pop boiled down to its purest, most synthetic elements.","garments":["Glossy synthetic fabric","Metallic or plastic textures","Hyper-feminine or processed presentation","Smooth and perfect surfaces","Futuristic accessories"],"habitat":"PC Music fan culture, SOPHIE legacy, post-internet pop communities.","context":"PC Music and SOPHIE created a visual language of hyper-processed pop — music and fashion both polished until they became deliberately artificial. SOPHIE's death in 2021 was a devastating loss to experimental music and fashion simultaneously.","rarity":"Rare","see_also":["Hyperpop Fashion","E-Girl","Digital Club Wear"],"colors":["#C0C0C0 Chrome Silver","#FF6B6B Plastic Pink","#FAF8F5 Glossy White","#00BFFF Synthetic Blue"],"media":["SOPHIE: Oil of Every Pearl's Un-Insides (2018) — music"]},"Digital Club Wear":{"summary":"The post-internet, avatar-influenced fashion designed for club spaces and digital documentation simultaneously.","era":"c.2018–present","mood":"Avatar-influenced, digitally documented","visual":"Clothing designed to look good both in person and on camera. Reflective and holographic materials. Bold graphic elements. The aesthetic of someone who exists equally in physical clubs and on Instagram.","garments":["Holographic or reflective material","Bold graphic elements","Camera-ready club outfit","Platform shoes","LED or light-reactive elements"],"habitat":"Contemporary club culture, digital fashion communities.","context":"Digital Club Wear reflects the reality that club fashion is now experienced as much through phone cameras as in person — materials and shapes are chosen for their photographic qualities as much as their physical presence.","rarity":"Niche","see_also":["Hyperpop Fashion","PC Music Aesthetic","Cyber Goth"],"colors":["#C0C0C0 Holographic Silver","#FF6B6B Reflective Pink","#00BFFF Digital Blue","#D4AF37 LED Gold"],"media":["Digital fashion communities — social media"]},"Psytrance / Trance Festival Fashion":{"summary":"The fluorescent, fractally patterned, third-eye-opening fashion of psytrance culture — UV-reactive prints, harem pants, and the Goa beach as origin myth.","era":"c.1988–present, Goa/global","mood":"Psychedelically fluorescent, fractally patterned","visual":"UV-reactive prints in fractal or sacred geometry patterns. Harem or fisherman pants. Bare feet. Dreadlocks. Third-eye bindis. The aesthetic of Goa trance culture's spiritual-hedonistic fusion.","garments":["UV-reactive fractal-print clothing","Harem or fisherman pants","Dreadlocks or natural hair","Third-eye bindi","Bare feet or minimal sandals"],"habitat":"Psytrance festivals (Boom, Ozora), Goa trance communities, global psytrance culture.","context":"Psytrance fashion originated in 1980s Goa hippie-traveller culture and evolved into a global festival aesthetic. The UV-reactive prints and sacred geometry motifs create a specific visual world.","rarity":"Niche","see_also":["UK Rave Aesthetic","EDM Festival Aesthetic","Flower Child Early"],"colors":["#39FF14 UV Green","#FF6B6B UV Pink","#00BFFF UV Blue","#FFFF00 UV Yellow"],"media":["Last Hippie Standing (2002) — documentary"]},"Hardstyle / Gabber Aesthetic":{"summary":"The shaved-head, Nike Air Max, hardcore-dancing dress of gabber and hardstyle — Dutch working-class rave culture at maximum BPM.","era":"c.1992–present, Netherlands","mood":"Maximum BPM, working-class rave","visual":"Shaved head or very short hair. Nike Air Max trainers (specifically). Track suit or Australian-style shorts. Gabber-specific merchandise. The aesthetic of dancing at 150+ BPM — functional, minimal, working-class Dutch.","garments":["Nike Air Max trainers","Track suit","Shaved or very short hair","Australian shorts","Gabber merchandise"],"habitat":"Gabber and hardstyle communities, Thunderdome events, Dutch rave culture.","context":"Gabber emerged from Rotterdam's working-class rave scene in the early 1990s. The Nike Air Max became its canonical shoe — the specific model indicated which generation of gabber you belonged to.","rarity":"Niche","see_also":["UK Rave Aesthetic","Raver / Rave Culture","EDM Festival Aesthetic"],"colors":["#1A1A1A Gabber Black","#FAF8F5 Air Max White","#8B0000 Thunderdome Red","#D4AF37 Logo Gold"],"media":["Thunderdome documentary — documentary"]},"Dubstep / EDM Underground":{"summary":"The dark, hooded, bass-heavy dress of underground dubstep and bass music — the club interior as fashion context.","era":"c.2005–present","mood":"Bass-heavy, hood-dark","visual":"Dark hoodie. Simple dark clothing. The aesthetic of someone in a dark room listening to sub-bass frequencies. Less visual than other electronic genres — the sound is the experience, not the look.","garments":["Dark hoodie","Simple dark jeans or tracksuit","Dark trainers","Minimal presentation","Bass-culture merchandise"],"habitat":"Bass music communities, dubstep events, DMZ and Fabric heritage.","context":"Underground dubstep and bass music fashion is deliberately minimal — the dark club and the sub-bass frequencies are the experience. The visual presentation is functional rather than decorative.","rarity":"Niche","see_also":["Jungle / Drum and Bass Aesthetic","Berlin Techno Fashion","UK Club Aesthetic"],"colors":["#1A1A1A Bass Black","#2C2C2C Hood Dark","#5B5B5B Urban Grey","#1B4F72 Deep Blue"],"media":["Dubstep documentary — documentary"]},"Jimi Hendrix Aesthetic":{"summary":"The psychedelic, military-jacket, bandana-wrapped look of Jimi Hendrix — the most visually distinctive guitarist in rock history.","era":"c.1966–1970","mood":"Psychedelically electric, military-repurposed","visual":"Military jacket with elaborate embroidery and decoration. Headband or bandana. Bell-bottom trousers. Rings on every finger. Scarves tied to microphone stand and guitar strap. The Fender Stratocaster as essential visual element.","garments":["Decorated military jacket","Headband or silk scarf","Bell-bottom trousers","Multiple rings","Fender Stratocaster"],"habitat":"Hendrix fan culture, psychedelic rock heritage, Monterey Pop/Woodstock legacy.","context":"Hendrix repurposed military uniforms as psychedelic costume — the Hussar jacket at Monterey Pop (1967) is one of rock's defining images. His style influenced every rock guitarist who followed.","rarity":"Extinct","see_also":["Glam Rock","Bowie Aesthetic","Festival Folk"],"colors":["#4B0082 Purple Haze","#D4AF37 Gold Trim","#8B0000 Experience Red","#1A1A1A Black"],"media":["Monterey Pop (1968) — documentary","Woodstock (1970) — documentary"]},"Rockstar Aesthetic":{"summary":"The general visual vocabulary of rock stardom — leather jackets, stage presence, and the body as instrument of performance.","era":"c.1955–present","mood":"Performatively magnetic, stage-consuming","visual":"Leather jacket as armour. Tight trousers or jeans. Boots with a heel. Hair styled or deliberately unstyled. Sunglasses as shield. The body occupying space with authority. Each era adds its own details but the core vocabulary persists.","garments":["Leather jacket","Tight dark trousers","Heeled boots","Sunglasses","Statement accessories"],"habitat":"Rock concerts, backstage culture, music industry.","context":"The Rockstar Aesthetic is one of fashion's most persistent archetypes — from Elvis through Hendrix, Jagger, Bowie, and beyond. The leather jacket remains its single most consistent element.","rarity":"Common","see_also":["Jimi Hendrix Aesthetic","Glam Rock","Bowie Aesthetic"],"colors":["#1A1A1A Leather Black","#D4AF37 Gold","#8B0000 Stage Red","#C0C0C0 Silver"],"media":["Almost Famous (2000) — film","This Is Spinal Tap (1984) — film"]},"Rolling Stones Aesthetic":{"summary":"The Jagger-swagger, Keith-scarves, endlessly touring look of the Rolling Stones — the longest-running rock fashion evolution in history.","era":"c.1962–present","mood":"Swaggeringly eternal, scarves-and-leather","visual":"Mick Jagger: skin-tight, sequined or coloured, physically commanding the stage. Keith Richards: scarves, skull ring, leather, bandana, the look of someone who has survived everything. Charlie Watts: Savile Row suits. Three distinct aesthetics in one band.","garments":["Jagger's stage-commanding outfit","Richards' scarf and skull ring","Watts' Savile Row suit","Band-member-specific visual identity","Endlessly touring wardrobe"],"habitat":"Rolling Stones fan culture, classic rock heritage.","context":"The Stones have maintained distinct individual aesthetics for 60 years — Jagger's physicality, Richards' outlaw piracy, and Watts' (d.2021) impeccable Savile Row tailoring never converged.","rarity":"Niche","see_also":["Rockstar Aesthetic","Led Zeppelin Aesthetic","Glam Rock"],"colors":["#8B0000 Tongue Red","#1A1A1A Rock Black","#D4AF37 Stage Gold","#C0C0C0 Keith Silver"],"media":["Gimme Shelter (1970) — documentary","Shine a Light (2008) — concert film"]},"Led Zeppelin Aesthetic":{"summary":"The mystical, 1970s-excess, dragon-suited look of Led Zeppelin — Jimmy Page's occult wardrobe, Robert Plant's golden god locks, and stadium rock dressed for Tolkien.","era":"c.1968–1980","mood":"Mystically excessive, golden-god 1970s","visual":"Jimmy Page: dragon suit, occult symbolism, black and silver. Robert Plant: bare chest, golden curls, extremely tight jeans. John Bonham: simple drummer presentation. John Paul Jones: quiet competence. The contrast between members was the visual dynamic.","garments":["Page's dragon-embroidered suit","Plant's bare chest and tight jeans","Occult symbol accessories","Platform boots","Flowing scarves"],"habitat":"Led Zeppelin fan culture, 1970s stadium rock heritage.","context":"Jimmy Page's interest in Aleister Crowley and the occult expressed itself through his wardrobe — the dragon suit, the ZOSO symbol, and specifically commissioned pieces. Plant's golden-god image defined the 1970s rock frontman.","rarity":"Extinct","see_also":["Rockstar Aesthetic","Glam Rock","Jimi Hendrix Aesthetic"],"colors":["#D4AF37 Golden God","#1A1A1A Occult Black","#C0C0C0 Dragon Silver","#8B0000 Zeppelin Red"],"media":["The Song Remains the Same (1976) — concert film","Becoming Led Zeppelin (2021) — documentary"]},"Arena Rock Fashion":{"summary":"The stadium-scaled, visible-from-the-back-row dress of arena rock — everything bigger, brighter, and readable at 50,000 people.","era":"c.1975–present","mood":"Stadium-scaled, back-row visible","visual":"Everything scaled up for visibility. Bold colours. Sequins. Platform boots. Hair at maximum volume. The clothing must read from the nosebleed seats. Stage wear rather than street wear.","garments":["Bold coloured stage wear","Sequined or metallic elements","Platform or heeled boots","Maximum-volume hair","Statement accessories visible from distance"],"habitat":"Arena and stadium concerts, classic rock and pop-rock tours.","context":"Arena Rock fashion is determined by scale — everything must be visible to 50,000 people. This simple constraint drives every design decision toward bold, bright, and big.","rarity":"Niche","see_also":["Rockstar Aesthetic","Glam Metal","Pop Star Aesthetic"],"colors":["#D4AF37 Stage Gold","#C0C0C0 Sequin Silver","#8B0000 Spot Red","#FAF8F5 Spotlight White"],"media":["This Is Spinal Tap (1984) — film"]},"Hair Band Aesthetic":{"summary":"The extreme teased-hair, spandex, glam-metal-pop crossover look — the specific Sunset Strip variation of glam metal at its most accessible.","era":"c.1983–1991, Los Angeles","mood":"Teased-hair maximum, spandex-accessible","visual":"Hair at absolute maximum — teased, sprayed, and defying physics. Spandex in vivid colours. Leather. Bandanas. The accessible, pop-friendly end of glam metal.","garments":["Maximum-teased hair","Vivid spandex","Leather accessories","Bandana","Platform or heeled boots"],"habitat":"Sunset Strip heritage, 1980s hair metal nostalgia.","context":"Hair Bands were glam metal's most commercially accessible form — Bon Jovi and Def Leppard sold tens of millions. The hair was both the aesthetic's defining feature and its eventual downfall when grunge made it irrelevant overnight.","rarity":"Niche","see_also":["Glam Metal","Arena Rock Fashion","Rockstar Aesthetic"],"colors":["#D4AF37 Hair Gold","#FF6B6B Hot Pink","#1A1A1A Leather Black","#C0C0C0 Silver"],"media":["Rock of Ages (2012) — film","The Decline of Western Civilization Part II (1988) — documentary"]},"NME Aesthetic":{"summary":"The British music press-coded look — NME cover stars as fashion references, the specific indie-rock-meets-journalism aesthetic of Camden and Shoreditch.","era":"c.1980s–2010s, Britain","mood":"Music-press coded, indie-journalist adjacent","visual":"Whatever the current NME cover star is wearing — the magazine served as Britain's indie fashion bible. Skinny jeans era, baggy era, leather jacket era — each following NME's current favourite band.","garments":["Current NME-approved band's look","Skinny jeans (post-2004)","Leather jacket","Band T-shirt","Indie-specific trainers"],"habitat":"British indie music culture, NME legacy (now online only).","context":"NME (New Musical Express) was Britain's indie fashion arbiter for decades — its covers set the visual tone for alternative Britain. Its decline to online-only reflects the fragmentation of music-led fashion.","rarity":"Niche","see_also":["Indie Rock Aesthetic","Britpop Aesthetic","Strokes Aesthetic"],"colors":["#1A1A1A Indie Black","#8B0000 NME Red","#FAF8F5 Cover White","#1B4F72 Denim"],"media":["NME magazine covers — print"]},"Downtown Girl":{"summary":"The TikTok-era update of downtown New York cool — dark feminine, espresso-toned, and the aesthetic of someone who shops vintage in the East Village.","era":"c.2021–present","mood":"Dark-feminine downtown, espresso-toned","visual":"Dark colour palette — black, brown, espresso. Vintage-mix. Leather jacket. Dark sunglasses. Low-rise jeans or dark trousers. The contemporary version of New York downtown cool filtered through TikTok.","garments":["Leather jacket","Dark sunglasses","Vintage-mix top","Low-rise dark jeans","Simple boots"],"habitat":"TikTok, Instagram, downtown New York-adjacent fashion communities.","context":"Downtown Girl codifies a specific New York cool that existed informally before TikTok named it — dark, vintage-mix, slightly tough feminine energy. It draws on Strokes-era downtown but updates for 2020s sensibility.","rarity":"Common","see_also":["Strokes Aesthetic","Indie Sleaze","Dark Feminine"],"colors":["#1A1A1A Downtown Black","#5B3A29 Espresso Brown","#8B7355 Vintage Tan","#5B5B5B Dark Grey"],"media":["TikTok #downtowngirl — social media"]},"Bedroom Pop Aesthetic":{"summary":"The lo-fi, home-recorded visual culture of bedroom pop — fairy lights, laptops, and the aesthetic of making music in your room.","era":"c.2015–present","mood":"Domestically lo-fi, fairy-lit","visual":"The bedroom as creative studio and aesthetic space. Fairy lights. Vintage posters. Record player. Comfortable clothing. The Instagram grid of someone who records music at home and aestheticises the domestic space accordingly.","garments":["Comfortable oversized clothing","Soft knit layers","Simple domestic-creative presentation","Natural hair","Minimal accessories"],"habitat":"Bedroom pop communities, lo-fi music culture, creative domestic aesthetics.","context":"The Bedroom Pop Aesthetic extends beyond clothing to environment — the bedroom as simultaneously recording studio, photograph backdrop, and aesthetic statement.","rarity":"Common","see_also":["Bedroom Pop Fashion","Lo-Fi Aesthetic","Indie Rock Aesthetic"],"colors":["#E8D5B0 Fairy Light Warm","#5B5B5B Lo-Fi Grey","#B0C4DE Soft Blue","#8B7355 Record Brown"],"media":["Clairo music videos — music video"]},"Lo-Fi Music Aesthetic":{"summary":"The deliberately low-fidelity, cassette-warm, VHS-grained visual culture of lo-fi music and its associated lifestyle aesthetic.","era":"c.2015–present","mood":"Cassette-warm, VHS-grained","visual":"Lo-fi hip hop 'study beats' anime girl as visual icon. Vintage electronics. Cassette tapes. VHS grain as deliberate visual filter. The aesthetic of deliberately choosing lower quality for warmth and character.","garments":["Oversized comfortable sweater","Headphones as accessory","Vintage-adjacent casual wear","Warm muted colour palette","Simple comfortable shoes"],"habitat":"Lo-fi hip hop YouTube streams, lo-fi aesthetic communities, study culture.","context":"The lo-fi music aesthetic became one of the most widespread visual cultures of the late 2010s through YouTube study streams — the 'lo-fi girl studying' became a globally recognised image.","rarity":"Common","see_also":["Bedroom Pop Aesthetic","Cozycore","Study With Me Aesthetic"],"colors":["#E8D5B0 Cassette Warm","#C185A0 Lo-Fi Pink","#5B5B5B Grain Grey","#8B7355 Vintage Brown"],"media":["Lo-fi hip hop YouTube streams — social media"]},"Z-Boys Aesthetic":{"summary":"The original Dogtown look — ripped Vans, cut-off jeans, and the surf-to-skate transition that invented modern skateboarding culture.","era":"c.1975–1979, Santa Monica/Venice Beach","mood":"Ocean-to-concrete, originally feral","visual":"Cut-off jeans or shorts. Ripped Vans slip-ons. Surf T-shirts. Shaggy sun-bleached hair. The look of kids who surfed in the morning and skated drained swimming pools in the afternoon. Tony Alva and Jay Adams as visual references.","garments":["Cut-off denim shorts","Ripped Vans slip-ons","Surf brand T-shirt","Shaggy sun-bleached hair","Knee pads for pool riding"],"habitat":"Dogtown heritage, Z-Boys cultural legacy, original skateboarding culture.","context":"The Z-Boys (Zephyr competition team) invented modern skateboarding by applying surfing techniques to empty swimming pools during the 1970s drought. Their style was genuine — surf kids adapting to concrete.","rarity":"Extinct","see_also":["Skater Aesthetic","Surf Aesthetic","California Surf"],"colors":["#87CEEB Pacific Blue","#D4AF37 Sunbleach Gold","#1B4F72 Denim Blue","#FAF8F5 Vans White"],"media":["Dogtown and Z-Boys (2001) — documentary","Lords of Dogtown (2005) — film"]},"Skate Punk":{"summary":"The intersection of skateboarding and punk — Thrasher magazine, hardcore on the half-pipe, and skating as punk's athletic expression.","era":"c.1983–present","mood":"Punk-athletic, half-pipe aggressive","visual":"Thrasher magazine T-shirt. Vans or skate shoes. Punk-adjacent clothing — band tees, short hair or mohawk. Skateboard as essential accessory. The aesthetic of someone who listens to Black Flag and skates pools.","garments":["Thrasher T-shirt","Vans skate shoes","Punk band tee","Skate-worn jeans or shorts","Skateboard"],"habitat":"Skate punk communities, Thrasher magazine culture, skate-hardcore crossover.","context":"Skate Punk merged two DIY cultures — skating and punk — through shared venues, shared music, and shared fashion. Thrasher magazine was the visual bible; Black Flag and Suicidal Tendencies provided the soundtrack.","rarity":"Niche","see_also":["Skater Aesthetic","Hardcore Punk","Pop Punk Aesthetic"],"colors":["#1A1A1A Punk Black","#FFFF00 Thrasher Yellow","#8B0000 Red","#FAF8F5 White"],"media":["Dogtown and Z-Boys (2001) — documentary"]},"Skater Aesthetic":{"summary":"The general visual culture of skateboarding — Vans, Thrasher, baggy silhouettes, and the board as identity.","era":"c.1980s–present","mood":"Board-carrying, Vans-wearing","visual":"Vans or Nike SB. Baggy or loose jeans. Thrasher or skate brand T-shirt. Hoodie. Beanie. Skateboard carried or nearby at all times. The clothing must allow skateboarding — nothing restrictive.","garments":["Vans or skate shoes","Baggy jeans","Skate brand T-shirt","Hoodie","Beanie"],"habitat":"Skate parks, skate shops, skateboarding communities worldwide.","context":"Skater fashion is one of the most globally consistent subcultures — Vans, Thrasher, and the baggy silhouette work from Tokyo to São Paulo to London. The skateboard is both transport and identity document.","rarity":"Common","see_also":["Thrasher Aesthetic","Street Skate Fashion","Skate Girl"],"colors":["#1A1A1A Skate Black","#FAF8F5 Vans White","#FFFF00 Thrasher Yellow","#1B4F72 Denim Blue"],"media":["Mid90s (2018) — film","Skate videos"]},"Thrasher Aesthetic":{"summary":"The specific Thrasher magazine visual identity — the flame logo, the 'Skate and Destroy' ethos, and the most recognised skate brand logo in the world.","era":"c.1981–present","mood":"Skate-and-destroy, flame-logoed","visual":"Thrasher magazine flame logo T-shirt. Simple dark or neutral clothing underneath. The logo itself is the statement — wearing Thrasher claims membership in skate culture (and is contested when worn by non-skaters).","garments":["Thrasher flame logo T-shirt","Thrasher hoodie","Simple jeans","Skate shoes","Skateboard"],"habitat":"Skateboarding communities, Thrasher magazine culture.","context":"Thrasher's flame logo became a mainstream fashion item in the 2010s, creating tension with skaters who viewed it as an earned identity — you wear Thrasher because you skate, not because it's fashionable.","rarity":"Common","see_also":["Skater Aesthetic","Skate Punk","Street Skate Fashion"],"colors":["#FFFF00 Flame Yellow","#8B0000 Flame Red","#1A1A1A Black","#FAF8F5 White"],"media":["Thrasher magazine — print"]},"Street Skate Fashion":{"summary":"The urban skateboarding dress that merges skate culture with streetwear — Supreme, Palace, and the skate shop as fashion boutique.","era":"c.2000–present","mood":"Urban-skate, streetwear-fused","visual":"Supreme or Palace branded pieces. Slim or relaxed-fit trousers. Skate shoes or Nike Dunks. The intersection of skateboarding and streetwear culture where the skate shop is also a fashion destination.","garments":["Supreme or Palace piece","Skate shoes or Nike Dunks","Slim or relaxed trousers","Graphic hoodie","Skate-streetwear cap"],"habitat":"Street skating, Supreme and Palace communities, skate-streetwear crossover.","context":"Street Skate Fashion represents skateboarding's full merger with streetwear — Supreme began as a skate shop and became a billion-dollar brand. Palace maintains closer ties to actual skating.","rarity":"Common","see_also":["Skater Aesthetic","Streetwear Culture","Designer Streetwear"],"colors":["#8B0000 Supreme Red","#1A1A1A Black","#FAF8F5 White","#1B4F72 Palace Blue"],"media":["Supreme documentary — documentary"]},"Skate Girl":{"summary":"The feminine expression of skate culture — Vans, oversized skate tees, and women claiming space in a historically male-dominated subculture.","era":"c.2000s–present","mood":"Femininely skate, space-claiming","visual":"Oversized skate T-shirt knotted or tucked. Vans Old Skool. Baggy jeans or skate-cut trousers. Messy hair. The look of a woman who actually skates — functional but styled with feminine awareness.","garments":["Oversized skate tee","Vans Old Skool","Baggy or wide-leg jeans","Messy natural hair","Simple accessories"],"habitat":"Women's skateboarding communities, skate girl culture.","context":"Skate Girl fashion represents women claiming space in skateboarding — historically male-dominated, increasingly inclusive. The aesthetic is functional (you need to move) and deliberately casual.","rarity":"Common","see_also":["Skater Aesthetic","Skater Femme","Tomboy Aesthetic"],"colors":["#1A1A1A Skate Black","#FAF8F5 Vans White","#1B4F72 Denim Blue","#8B7355 Tan"],"media":["Skate Kitchen (2018) — film","Betty (TV series) — TV"]},"Skater Femme":{"summary":"The explicitly feminine-forward version of skate girl fashion — skirts with pads, platforms with grip, and femininity as a deliberate choice in skate culture.","era":"c.2015–present","mood":"Deliberately feminine, skate-capable","visual":"Skirt or dress worn while skating (with safety shorts). Platform Vans or chunky skate shoes. Feminine jewellery. Hair styled. The deliberate choice to be visibly feminine in a traditionally masculine space.","garments":["Skirt or dress for skating","Platform or chunky skate shoes","Feminine jewellery","Styled hair","Safety shorts underneath"],"habitat":"Skater Femme communities, women's skateboarding, TikTok skate content.","context":"Skater Femme makes femininity an active choice rather than a contradiction in skate culture — it refuses the premise that skating requires masculine presentation.","rarity":"Niche","see_also":["Skate Girl","Tomboy Aesthetic","Skater Aesthetic"],"colors":["#F5C6CB Femme Pink","#1A1A1A Skate Black","#FAF8F5 White","#D4AF37 Jewellery Gold"],"media":["Betty (TV series) — TV","Skate Kitchen (2018) — film"]},"Skate Streetwear":{"summary":"The premium, brand-conscious version of skate fashion — where skating meets high-end streetwear and the skate shoe becomes a collector item.","era":"c.2010–present","mood":"Premium skate-street, collector-conscious","visual":"Limited-edition skate shoes (Nike SB Dunks as grails). Premium streetwear brands with skate roots. The aesthetic of someone who collects sneakers and skates — both activities inform the wardrobe.","garments":["Limited-edition Nike SB Dunks","Premium skate brand pieces","Collector sneakers","Quality hoodie or jacket","Skate-premium accessories"],"habitat":"Sneaker collecting, premium skate-streetwear crossover, StockX market.","context":"Skate Streetwear sits where skateboarding's authentic culture meets sneaker collecting's consumer culture — the Nike SB Dunk exists in both worlds simultaneously.","rarity":"Common","see_also":["Street Skate Fashion","Sneakerhead Aesthetic","Designer Streetwear"],"colors":["#1A1A1A Premium Black","#FAF8F5 Dunk White","#8B0000 Nike Red","#D4AF37 Collector Gold"],"media":["Sneaker culture documentaries — documentary"]},"Skate Luxe":{"summary":"The high-fashion interpretation of skateboarding aesthetics — Celine by Hedi Slimane, and the skate vocabulary elevated to runway level.","era":"c.2018–present","mood":"Luxury-skate, runway-elevated","visual":"Skate silhouettes in luxury fabrics. Oversized hoodie in cashmere. Premium denim. Designer skate shoes. The skate vocabulary translated to luxury price points — Hedi Slimane's Celine as the primary reference.","garments":["Cashmere skate hoodie","Premium oversized tee","Luxury denim","Designer skate shoe","Luxury-minimal accessories"],"habitat":"Luxury fashion with skate influence, Celine by Slimane contexts.","context":"Skate Luxe represents skateboarding's complete absorption into luxury fashion — the same silhouettes and vocabulary at 100x the price, stripped of subcultural meaning and filled with aspirational value.","rarity":"Niche","see_also":["Skate Streetwear","Street Skate Fashion","Grunge Luxe"],"colors":["#1A1A1A Luxury Black","#FAF8F5 Premium White","#8B7355 Luxury Tan","#5B5B5B Cashmere Grey"],"media":["Celine by Hedi Slimane campaigns — fashion"]},"Sneakerhead Aesthetic":{"summary":"The collector culture of rare and limited sneakers as fashion identity — the shoe as the centrepiece of the outfit, everything else is secondary.","era":"c.1985–present","mood":"Collector-obsessed, shoe-centred","visual":"The sneaker is the outfit's focal point — everything else is built around it. Clean, simple clothing that doesn't compete with the shoe. The shoe must be pristine (deadstock preferred) or perfectly maintained.","garments":["Rare or limited sneakers","Simple complementary clothing","Clean presentation","Sneaker-matching colour coordination","Minimal distracting accessories"],"habitat":"Sneaker collecting communities, StockX and GOAT markets, sneaker conventions.","context":"Sneakerhead culture creates a fashion system where the shoe is the primary garment — everything else serves it. The market for rare sneakers now operates like fine art, with secondary market prices in thousands.","rarity":"Common","see_also":["Streetwear Culture","Designer Streetwear","Hip-Hop Luxury"],"colors":["#FAF8F5 Clean White","#8B0000 Jordan Red","#1A1A1A Black","#D4AF37 Gold"],"media":["Sneakerheadz (2015) — documentary"]},"Streetwear Culture":{"summary":"The broader visual culture of streetwear — from Stüssy origins to Supreme hype to Off-White luxury, the most commercially successful subculture in fashion history.","era":"c.1984–present, global","mood":"Drop-culture coded, brand-community fused","visual":"Logo-centric graphic pieces. Limited-edition drops creating scarcity. Sneakers as essential. Hoodies, T-shirts, and caps as canvas. The aesthetic ranges from DIY screen-prints to luxury collaborations.","garments":["Logo graphic T-shirt or hoodie","Limited-edition pieces","Sneakers","Branded cap","Streetwear-specific accessories"],"habitat":"Streetwear communities worldwide, drop culture, resale markets.","context":"Streetwear is the most commercially successful subculture in fashion history — it has absorbed luxury fashion, sportswear, and skate culture into a single system driven by limited drops and brand loyalty.","rarity":"Common","see_also":["Early Streetwear","Designer Streetwear","Sneakerhead Aesthetic"],"colors":["#1A1A1A Street Black","#FAF8F5 Logo White","#8B0000 Supreme Red","#D4AF37 Hype Gold"],"media":["Fresh Dressed (2015) — documentary","Complex Sneaker Shopping — web series"]},"Surf Aesthetic":{"summary":"The general visual culture of surfing — boardshorts, rash guards, sun-bleached hair, and the ocean as wardrobe context.","era":"c.1960s–present, global coastlines","mood":"Ocean-dwelling, sun-bleached","visual":"Boardshorts. Rash guard or simple T-shirt. Sun-bleached hair. Tan. Flip flops or barefoot. Wetsuit for cold water. The aesthetic determined by the ocean — everything must dry quickly, resist salt, and allow paddling.","garments":["Boardshorts","Rash guard or simple T-shirt","Sun-bleached hair","Flip flops","Wetsuit for cold water"],"habitat":"Surf breaks worldwide, surf culture communities.","context":"Surf fashion is determined by function — the ocean demands specific clothing solutions. The sun-bleached hair and permanent tan are not styled but earned through hours in salt water.","rarity":"Common","see_also":["California Surf","Surf Luxe","Beach Bum Aesthetic"],"colors":["#87CEEB Pacific Blue","#D4AF37 Sun Gold","#FAF8F5 Foam White","#8B7355 Sand"],"media":["The Endless Summer (1966) — documentary","Blue Crush (2002) — film"]},"California Surf":{"summary":"The specific sun-drenched California surf aesthetic — Malibu to Huntington, the Beach Boys to surf punk, and California as surfing's cultural capital.","era":"c.1960–present, California","mood":"California golden, Pacific-coded","visual":"The iconic California surf look — Hawaiian shirt or branded surf tee. Boardshorts. Huarache sandals or Vans. Sun-bleached blond hair. The specific California light and colour palette.","garments":["Surf brand T-shirt","Classic boardshorts","Vans slip-ons","Sun-bleached hair","Simple sunglasses"],"habitat":"California coastline, Malibu to San Diego, surf culture.","context":"California invented modern surf culture — from the Beach Boys' visual branding to surf brands like Quiksilver and Billabong. The aesthetic is inseparable from California's specific light, colour, and cultural mythology.","rarity":"Common","see_also":["Surf Aesthetic","Beach Bum Aesthetic","Z-Boys Aesthetic"],"colors":["#87CEEB California Blue","#D4AF37 Sun Gold","#FAF8F5 White","#8B0000 Sunset Red"],"media":["The Endless Summer (1966) — documentary","Point Break (1991) — film"]},"Beach Bum Aesthetic":{"summary":"The deliberately unambitious, permanently sun-relaxed look of the beach bum — the person who chose the ocean over the career.","era":"c.1960s–present","mood":"Permanently relaxed, career-free","visual":"Boardshorts that have been worn for years. Faded T-shirt. Flip flops or barefoot. Permanent tan. Hair sun-damaged but free. The look of someone who chose waves over wages.","garments":["Worn boardshorts","Faded T-shirt","Flip flops","Permanent tan","Salt-damaged hair"],"habitat":"Beach towns worldwide, surf culture's relaxed wing.","context":"The Beach Bum represents surfing's anti-ambition — the deliberate choice of ocean time over career advancement. The aesthetic is earned through lifestyle rather than purchased.","rarity":"Common","see_also":["Surf Aesthetic","California Surf","Van Life Aesthetic"],"colors":["#D4AF37 Permanent Tan","#87CEEB Ocean Blue","#8B7355 Faded Fabric","#FAF8F5 Salt White"],"media":["The Big Lebowski (1998) — film","Point Break (1991) — film"]},"Surf Luxe":{"summary":"The elevated, fashion-forward interpretation of surf culture — premium surf brands, luxury beachwear, and surfing as aspirational lifestyle.","era":"c.2010–present","mood":"Premium coastal, luxury surf","visual":"Premium surf brand pieces. Quality linen and cotton. Designer sunglasses. Elevated boardshorts. The surf aesthetic translated to luxury lifestyle — the person who surfs and then has lunch at a beachfront restaurant.","garments":["Premium surf brand pieces","Quality linen shirt","Designer sunglasses","Elevated boardshorts","Premium sandals"],"habitat":"Luxury coastal lifestyle, premium surf brands, upscale beach communities.","context":"Surf Luxe translates surf culture's casual ease to luxury price points — the specific relaxation of the beach maintained at premium quality levels.","rarity":"Niche","see_also":["Surf Aesthetic","Coastal Athletic","Resort Wear"],"colors":["#87CEEB Luxury Blue","#FAF8F5 Linen White","#D4AF37 Sun Gold","#8B7355 Premium Sand"],"media":["Surf lifestyle magazines — print"]},"Modern Surf":{"summary":"Contemporary surf fashion — sustainable materials, technical fabrics, and surfing's evolution from counterculture to mainstream athletic lifestyle.","era":"c.2015–present","mood":"Sustainably contemporary, technically evolved","visual":"Technical surf fabrics. Sustainable or recycled materials. Modern surf brands (Patagonia surf, Finisterre). The aesthetic of contemporary surfing — more technical, more environmentally conscious, less beach-bum.","garments":["Technical surf fabric","Sustainable material wetsuit or rashguard","Modern surf brand pieces","Recycled-material boardshorts","Eco-conscious accessories"],"habitat":"Contemporary surf culture, sustainable surf communities.","context":"Modern Surf reflects surfing's evolution — from counterculture to mainstream sport to environmental movement. The aesthetic incorporates sustainability as a core value.","rarity":"Common","see_also":["Surf Aesthetic","Sustainable Fashion Aesthetic","Gorpcore"],"colors":["#87CEEB Ocean Blue","#4A7C59 Eco Green","#8B7355 Natural","#FAF8F5 Clean White"],"media":["Surf culture documentaries — documentary"]},"Coastal Athletic":{"summary":"The intersection of coastal lifestyle and athletic wear — running on the beach, paddleboarding, and the active ocean lifestyle dressed accordingly.","era":"c.2015–present","mood":"Actively coastal, ocean-athletic","visual":"Athletic wear with coastal influence. Running tights or shorts in ocean-inspired colours. Technical fabrics for salt and sand. The look of someone whose exercise involves the ocean — surfing, paddleboarding, ocean swimming, coastal running.","garments":["Ocean-coloured athletic wear","Technical salt-resistant fabrics","Sport sandals or running shoes","Sun-protective athletic layers","Waterproof watch"],"habitat":"Coastal fitness communities, ocean sports culture.","context":"Coastal Athletic emerged from the intersection of athleisure and surf culture — athletic wear designed for the specific demands of exercising near or in the ocean.","rarity":"Common","see_also":["Surf Aesthetic","Athleisure","Runner's Aesthetic"],"colors":["#87CEEB Ocean Blue","#FAF8F5 Athletic White","#4A7C59 Sea Green","#D4AF37 Sand Gold"],"media":["Coastal fitness content — social media"]},"Suffragette Dress":{"summary":"The politically coded dress of the women's suffrage movement — purple, white, and green as the colours of dignity, purity, and hope.","era":"c.1903–1918, Britain; c.1848–1920, America","mood":"Politically coded, dignifiedly determined","visual":"Ordinary Edwardian dress in suffragette colours: purple (dignity), white (purity), green (hope). WSPU rosettes and badges. Sashes. The clothing was deliberately respectable to counter caricatures of suffragettes as unfeminine.","garments":["Purple, white, and green dress","WSPU rosette or badge","Suffragette sash","Respectable Edwardian outfit","Votes for Women banner"],"habitat":"Suffragette history, women's rights heritage events, feminist fashion history.","context":"Suffragette dress was deliberately respectable — the movement needed to counter the 'unsexed woman' caricature used to dismiss them. Looking dignified while chaining yourself to railings was a calculated strategy.","rarity":"Extinct","see_also":["Edwardian Suffragette","Women's Liberation Fashion","New Woman Aesthetic"],"colors":["#6B2D8B Dignity Purple","#FAF8F5 Purity White","#4A7C59 Hope Green"],"media":["Suffragette (2015) — film"]},"Socialist Realism Fashion":{"summary":"The state-mandated aesthetic of Soviet and communist-bloc dress — functional workers' clothing as ideological statement.","era":"c.1930–1991, Soviet Union and allies","mood":"Ideologically functional, state-mandated","visual":"Functional workers' clothing. Grey, brown, and navy. No fashion excess. The aesthetic of a state that declared fashion bourgeois decadence — everyone dressed the same because inequality was theoretically eliminated.","garments":["Standard issue grey coat","Functional workers' clothing","Simple dress or suit","No luxury elements","State-produced shoes"],"habitat":"Soviet history, communist-bloc fashion studies, Cold War cultural history.","context":"Socialist Realism applied to fashion meant eliminating individual expression through dress — the state produced limited ranges and fashion was officially dismissed as capitalist frivolity. In practice, citizens constantly subverted these restrictions.","rarity":"Extinct","see_also":["Constructivist Fashion","Mao Suit Aesthetic","Normcore"],"colors":["#5B5B5B Soviet Grey","#8B7355 Worker Brown","#1B4F72 Navy","#4A7C59 Military Green"],"media":["Goodbye, Lenin! (2003) — film"]},"Union Workwear Aesthetic":{"summary":"The functional, solidarity-expressing dress of organised labour — denim, work boots, and the deliberate pride of working-class identity.","era":"c.1880s–present","mood":"Solidarity-expressing, working-class proud","visual":"Denim overalls or work jeans. Work boots (union-made when possible). Union badge or pin. Simple work shirt. The clothing of physical labour worn with explicit pride and political identity.","garments":["Denim overalls or work jeans","Union-made work boots","Union badge or pin","Simple work shirt","Hard hat for construction"],"habitat":"Organised labour communities, union heritage events, working-class identity culture.","context":"Union Workwear is functional clothing worn as political identity — the union badge, the insistence on union-made products, and the pride in physical labour clothing all signal solidarity and class consciousness.","rarity":"Niche","see_also":["Frontier Workwear Aesthetic","Heritage Core","Rugged Americana"],"colors":["#1B4F72 Denim Blue","#8B7355 Boot Brown","#D4AF37 Badge Gold","#FAF8F5 Work White"],"media":["Norma Rae (1979) — film","On the Waterfront (1954) — film"]},"Civil Rights Movement Fashion":{"summary":"The deliberately dignified, Sunday-best dress of the American Civil Rights movement — dressing up as resistance, respectability as political weapon.","era":"c.1954–1968, United States","mood":"Dignifiedly resistant, Sunday-best political","visual":"Sunday best: men in suits and ties, women in dresses and hats. Immaculately pressed. The deliberate choice to dress up for protests, sit-ins, and marches — making violence against well-dressed people undeniably visible.","garments":["Men's suit and tie","Women's Sunday dress and hat","Immaculately pressed clothing","Church-quality presentation","Dignity as the primary garment"],"habitat":"Civil Rights history. SENSITIVE: This aesthetic must be contextualised within the violence and courage of the movement — dressing up while being beaten, hosed, and arrested.","context":"The Civil Rights movement's dress code was a calculated strategy — photographs of well-dressed Black Americans being beaten and hosed shamed the nation. The dignity of the clothing made the violence undeniable.","rarity":"Extinct","see_also":["Harlem Renaissance Fashion","Black Girl Magic Fashion","Protest Fashion"],"colors":["#1A1A1A Sunday Black","#FAF8F5 Shirt White","#1B4F72 Suit Navy","#D4AF37 Church Gold"],"media":["Selma (2014) — film","Eyes on the Prize (documentary) — documentary"]},"Black Panther Aesthetic":{"summary":"The black beret, leather jacket, and raised fist of the Black Panther Party — revolutionary Black self-determination expressed through deliberate uniform.","era":"c.1966–1982, United States","mood":"Revolutionarily uniformed, self-determined","visual":"Black leather jacket. Black beret (inspired by Che Guevara). Dark sunglasses. Afro hairstyle. The raised fist as gesture. The aesthetic was a deliberate uniform — signalling organisation, discipline, and resistance.","garments":["Black leather jacket","Black beret","Dark sunglasses","Natural Afro hairstyle","Black trousers and boots"],"habitat":"Black Panther Party heritage, Black liberation history. SENSITIVE: The BPP's history is complex — community programs alongside armed resistance, government persecution alongside internal conflict.","context":"The Black Panther uniform was deliberately militaristic — the beret, the leather jacket, and the organised presentation communicated that this was not a plea for equality but a demand for liberation.","rarity":"Extinct","see_also":["Civil Rights Movement Fashion","Afrofuturism","Revolutionary Fashion"],"colors":["#1A1A1A Panther Black","#5B3A29 Leather Brown","#D4AF37 Gold","#8B0000 Revolution Red"],"media":["Judas and the Black Messiah (2021) — film","The Black Panthers: Vanguard of the Revolution (2015) — documentary"]},"Women's Liberation Fashion":{"summary":"The anti-fashion, consciousness-raising dress of second-wave feminism — rejecting beauty standards as political act.","era":"c.1968–1980, Western world","mood":"Anti-beauty-standard, politically conscious","visual":"Rejection of makeup, bras, high heels, and fashion magazines. Simple functional clothing. The deliberate refusal to perform femininity as consumer capitalism defined it. Jeans and T-shirts as political statement.","garments":["Simple functional clothing","No makeup","No bra (statement)","Jeans and T-shirt","Sensible shoes"],"habitat":"Second-wave feminist history, consciousness-raising groups, women's liberation movement.","context":"The bra-burning myth (no bras were actually burned at the 1968 Miss America protest — they were thrown in a 'freedom trash can') became the iconic image of fashion-as-political-rejection in the women's movement.","rarity":"Extinct","see_also":["Suffragette Dress","Riot Grrrl","Earth Mother Aesthetic"],"colors":["#1B4F72 Denim Blue","#FAF8F5 T-shirt White","#4A7C59 Liberation Green","#8B7355 Earth Brown"],"media":["Mrs. America (TV series) — TV"]},"Anarchist Aesthetic":{"summary":"The deliberately anti-fashion, all-black, circle-A visual vocabulary of anarchist politics — dress as refusal of all systems including fashion.","era":"c.1880s–present","mood":"Systematically refusing, all-black political","visual":"All black. Circle-A symbol. Black flag. Black bandana or mask for protests. Simple functional clothing without brand display. The aesthetic of someone who refuses the fashion system as one more hierarchy to dismantle.","garments":["All-black clothing","Circle-A patch or pin","Black bandana or mask","No brand display","Functional boots"],"habitat":"Anarchist communities, protest movements, anti-capitalist organising.","context":"Anarchist fashion is anti-fashion by principle — the circle-A is worn not as decoration but as identification. All-black dress for protests (the 'black bloc') is simultaneously practical (anonymity) and symbolic (solidarity).","rarity":"Niche","see_also":["Anarcho-Punk","Anti-Fashion Aesthetic","Protest Fashion"],"colors":["#1A1A1A Anarchy Black","#8B0000 Circle-A Red","#FAF8F5 Propaganda White","#5B5B5B Bloc Grey"],"media":["Anarchist documentary — documentary"]},"Revolutionary Fashion":{"summary":"The dress of political revolution across history — from Phrygian caps to raised fists, the visual language of overthrowing power.","era":"c.1789–present, global","mood":"Overthrow-coding, politically symbolic","visual":"Varies by revolution: Phrygian cap (France), black beret (Black Panthers), keffiyeh (Palestinian resistance), yellow vest (gilets jaunes). Each revolution creates its own visual shorthand for solidarity and resistance.","garments":["Revolution-specific headwear","Colour-coded clothing","Solidarity symbol","Practical resistance clothing","Identification markers"],"habitat":"Revolutionary movements, political resistance, protest culture.","context":"Every revolution creates fashion — the French Revolution's cockade, the Black Panthers' beret, the gilets jaunes' yellow vest. Revolutionary dress turns ordinary clothing into political weapon.","rarity":"Niche","see_also":["French Revolutionary Dress","Black Panther Aesthetic","Protest Fashion"],"colors":["#8B0000 Revolution Red","#1A1A1A Black","#FAF8F5 White","#FFFF00 Revolution Yellow"],"media":["Les Misérables (2012) — film"]},"Protest Fashion":{"summary":"The practical, solidarity-signalling dress of protest movements — from suffragettes to BLM, clothing as political tool.","era":"c.1900s–present, global","mood":"Solidarity-signalling, practically resistant","visual":"Colour-coded for solidarity (purple/white/green for suffragettes, pink for the Women's March, black for BLM). Practical for long marches. Statement T-shirts and slogans. The pussy hat (2017 Women's March) as recent example.","garments":["Solidarity colour-coded clothing","Protest slogan T-shirt","Practical march clothing","Movement-specific accessory","Comfortable protest shoes"],"habitat":"Protest movements, solidarity actions, political marches.","context":"Protest fashion serves dual purposes — practical (comfortable for marching, identifiable for safety) and symbolic (colour coding, slogans, unity markers). Each movement develops its own visual vocabulary.","rarity":"Common","see_also":["Suffragette Dress","Revolutionary Fashion","Activist Dress"],"colors":["#8B0000 Solidarity Red","#FF6B6B Pussy Hat Pink","#1A1A1A BLM Black","#4A7C59 Climate Green"],"media":["Protest coverage — news media"]},"Activist Dress":{"summary":"The everyday dress of committed activists — practical, politically aware, and signalling values through sustainable and ethical fashion choices.","era":"c.2000s–present","mood":"Values-signalling, sustainably practical","visual":"Sustainable and ethical clothing choices. Thrifted or secondhand pieces. Slogan tees for causes. Practical for organising work. The aesthetic of someone whose wardrobe reflects their politics daily, not just at protests.","garments":["Ethical or sustainable clothing","Thrifted or secondhand pieces","Cause-supporting slogan tee","Practical organising clothing","Values-aligned accessories"],"habitat":"Activist communities, organising spaces, ethical fashion circles.","context":"Activist Dress extends political consciousness to daily wardrobe choices — who made this, where was it made, does buying it support or contradict my values? Fashion as lived ethics rather than performance.","rarity":"Niche","see_also":["Protest Fashion","Sustainable Fashion Aesthetic","Eco-Activist Fashion"],"colors":["#4A7C59 Ethics Green","#8B7355 Thrift Brown","#1A1A1A Solidarity Black","#FAF8F5 Clean White"],"media":["The True Cost (2015) — documentary"]},"Anti-Fashion Aesthetic":{"summary":"The deliberate rejection of fashion as a system — from Comme des Garçons to normcore, the intellectual position that refusing fashion is itself a fashion statement.","era":"c.1980s–present","mood":"Intellectually refusing, systematically anti","visual":"Depends on the specific anti-fashion position — Comme des Garçons' deconstruction, Margiela's anonymity, normcore's deliberate blandness. What unifies them is the intellectual rejection of fashion's conventional values.","garments":["Deliberately unconventional clothing","Deconstructed or inside-out pieces","Aggressively plain basics","Refusal of trend","Intellectual fashion position"],"habitat":"Fashion theory, avant-garde fashion communities, anti-consumerist circles.","context":"Anti-fashion is fashion's permanent internal critic — every generation produces designers and movements that refuse the system while operating within it. The paradox (refusing fashion is a fashion statement) is the point.","rarity":"Niche","see_also":["Normcore","Deconstructed Fashion","Martin Margiela Aesthetic"],"colors":["#5B5B5B Anti Grey","#1A1A1A Refusal Black","#FAF8F5 Blank White","#8B7355 Deliberate Brown"],"media":["The September Issue (2009) — documentary"]},"Eco-Activist Fashion":{"summary":"The environmental movement's fashion expression — sustainable materials, repair culture, and the clothing of someone who protests pipelines and composts.","era":"c.2000s–present","mood":"Environmentally committed, repair-cultured","visual":"Repaired and visibly mended clothing (visible mending as aesthetic choice). Organic or sustainable fabrics. Secondhand and thrifted. Earth tones. The aesthetic of someone who practices environmental values through every purchase.","garments":["Visibly mended clothing","Organic or sustainable fabric","Thrifted or secondhand","Earth-tone palette","Reusable everything"],"habitat":"Environmental activist communities, climate movement, sustainable fashion.","context":"Eco-Activist Fashion makes environmental values visible through dress — visible mending, sustainable materials, and secondhand shopping as both practical and symbolic choices.","rarity":"Niche","see_also":["Activist Dress","Sustainable Fashion Aesthetic","Solarpunk"],"colors":["#4A7C59 Eco Green","#8B7355 Earth Brown","#E8D5B0 Natural","#5B5B5B Organic Grey"],"media":["The True Cost (2015) — documentary"]},"Antifa Aesthetic":{"summary":"The all-black, face-covered, anonymity-focused dress of anti-fascist protest — the 'black bloc' as both tactical and symbolic uniform.","era":"c.1980s–present, global","mood":"Anonymously militant, anti-fascist uniformed","visual":"All black clothing. Face covering — mask, balaclava, or bandana. Black hoodie. Black boots. The black bloc is simultaneously tactical (anonymity, group identity, difficulty for surveillance) and symbolic (solidarity, anti-hierarchy).","garments":["All-black hoodie","Face covering mask","Black combat boots","Black trousers","Black gloves"],"habitat":"Anti-fascist organising, counter-protests. SENSITIVE: Antifa is not a single organisation but a range of autonomous groups united by opposition to fascism. Its tactics, including property destruction, are debated across the political spectrum.","context":"The antifa black bloc originated in 1980s German autonomous movements (Autonomen). The tactic spread globally. The all-black uniform serves practical (anonymity, solidarity) and symbolic (anti-hierarchy, collective identity) purposes.","rarity":"Niche","see_also":["Anarchist Aesthetic","Protest Fashion","Revolutionary Fashion"],"colors":["#1A1A1A Bloc Black","#8B0000 Anti-Fascist Red","#FAF8F5 Banner White","#5B5B5B Mask Grey"],"media":["Antifa documentary — documentary"]}};
